#define GLUE_TYPE_NAMED 8

/**
 * 类型 ref 是否为模块内具 layout 的命名 struct（Pair 等）。
 */
static int32_t glue_type_ref_is_named_struct_layout_elf_c(struct ast_ASTArena *arena, struct ast_Module *mod,
                                                            int32_t ty_ref) {
  uint8_t nm[64];
  int32_t nlen;
  int32_t k;
  int32_t ln;
  int32_t j;
  if (ty_ref <= 0 || !mod || !arena)
    return 0;
  if (pipeline_type_kind_ord_at(arena, ty_ref) != GLUE_TYPE_NAMED)
    return 0;
  nlen = pipeline_type_named_name_into(arena, ty_ref, nm);
  if (nlen <= 0)
    return 0;
  for (k = 0; k < pipeline_module_num_struct_layouts_at(mod); k++) {
    ln = pipeline_module_struct_layout_name_len(mod, k);
    if (ln != nlen || ln <= 0)
      continue;
    for (j = 0; j < nlen; j++) {
      if (pipeline_module_struct_layout_name_byte_at(mod, k, j) != nm[j])
        break;
    }
    if (j == nlen)
      return 1;
  }
  return 0;
}

/** 与 typeck.x typeck_x_type_size 一致（前向声明，定义见本文件后部）。 */
static int32_t glue_type_size_simple(struct ast_Module *m, struct ast_ASTArena *a, int32_t ty_ref, int32_t depth);

/**
 * CALL 实参 VAR：块内 let struct / 定长数组 T[N] 须 lea 传地址；标量 / *T / 形参 struct 指针槽须 load。
 */
static int32_t glue_call_arg_var_use_lea_not_load_elf_c(struct ast_ASTArena *arena, int32_t expr_ref,
                                                        struct backend_AsmFuncCtx *ctx) {
  int32_t decl_ty;
  int32_t scope_br;
  uint8_t vname[64];
  int32_t vlen;
  if (!arena || !ctx || expr_ref <= 0)
    return 0;
  if (asm_local_var_slot_holds_indirect_ptr(arena, expr_ref, g_pipeline_asm_emit_module, (uint8_t *)ctx) != 0)
    return 0;
  if (pipeline_expr_kind_ord_at(arena, expr_ref) != 3)
    return 0;
  vlen = pipeline_expr_var_name_len(arena, expr_ref);
  if (vlen <= 0 || vlen > 63)
    return 0;
  pipeline_expr_var_name_into(arena, expr_ref, vname);
  /** emit 中 *T 形参 CALL 须 load 槽内指针，勿 lea 栈地址（v: *Vec3f_soa → reserve_one）。 */
  if (g_pipeline_asm_emit_module && g_pipeline_asm_emit_func_index >= 0 &&
      g_pipeline_asm_emit_func_index < (int32_t)g_pipeline_asm_emit_module->num_funcs) {
    int32_t pty = pipeline_module_func_param_type_ref_for_name(g_pipeline_asm_emit_module,
                                                               g_pipeline_asm_emit_func_index, vname, vlen);
    if (pty > 0 && pipeline_type_kind_ord_at(arena, pty) == 9)
      return 0;
  }
  scope_br = asm_ctx_scope_block_ref_at((uint8_t *)ctx);
  decl_ty = 0;
  if (scope_br > 0)
    decl_ty = pipeline_block_resolve_var_type_ref(arena, scope_br, vname, vlen);
  /** main 等无 scope sidecar：用 skip-typeck 回填的 VAR resolved_type_ref（hello msg: u8[12]）。 */
  if (decl_ty <= 0)
    decl_ty = pipeline_expr_resolved_type_ref(arena, expr_ref);
  if (decl_ty <= 0)
    return 0;
  if (glue_type_ref_is_named_struct_layout_elf_c(arena, g_pipeline_asm_emit_module, decl_ty)) {
    /** ≤8B POD struct 按值经寄存器传参（load 槽内 8 字节），勿 lea 传栈地址。 */
    int32_t sz = glue_type_size_simple(g_pipeline_asm_emit_module, arena, decl_ty, 0);
    if (sz > 0 && sz <= 8)
      return 0;
    return 1;
  }
  if (glue_type_is_fixed_array(arena, decl_ty))
    return 1;
  return 0;
}

/**
 * VAR 按值装入 rax（及 9–16B struct 的 rdx）：局部 let 双 half 栈 load；形参 hidden pointer 则 deref。
 * or_i32/and_i32 三元 `r : other` 与 `return r` 须完整 SysV 双寄存器，单 load 会丢 err 半或误用指针。
 */
static int32_t glue_load_var_as_value_to_rax_rdx_elf_c(struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                        struct ast_ASTArena *arena, struct backend_AsmFuncCtx *ctx,
                                                        int32_t var_expr_ref, int32_t off, int32_t ta) {
  int32_t tr;
  int32_t sz;
  if (!elf_ctx || off < 0)
    return -1;
  if (glue_local_var_slot_needs_ptr_load_elf_c(arena, var_expr_ref, off, ctx) != 0) {
    if (backend_enc_load_rbp_to_rax_arch(elf_ctx, off, ta) != 0)
      return -1;
    tr = glue_var_decl_type_ref_elf_c(arena, ctx, var_expr_ref);
    if (tr <= 0)
      tr = pipeline_expr_resolved_type_ref(arena, var_expr_ref);
    sz = glue_type_size_simple(g_pipeline_asm_emit_module, arena, tr, 0);
    if (sz > 8 && sz <= 16 && ta == 0)
      return pipeline_asm_deref_struct16_rax_ptr_elf_c(elf_ctx, ta);
    return 0;
  }
  if (backend_enc_load_rbp_to_rax_arch(elf_ctx, off, ta) != 0)
    return -1;
  if (ta != 0 || !arena || !ctx)
    return 0;
  tr = glue_var_decl_type_ref_elf_c(arena, ctx, var_expr_ref);
  if (tr <= 0)
      tr = pipeline_expr_resolved_type_ref(arena, var_expr_ref);
  sz = glue_type_size_simple(g_pipeline_asm_emit_module, arena, tr, 0);
  if (sz > 8 && sz <= 16)
    return backend_enc_load_rbp_to_rdx_arch(elf_ctx, off - 8, ta);
  return 0;
}

/** CALL 形参 named struct 是否 >8B（含 dep 模块 layout 回落；import Allocator 等）。 */
static int32_t glue_type_named_layout_size_any_module_elf_c(struct ast_ASTArena *arena, int32_t ty_ref) {
  uint8_t name[64];
  int32_t nlen;
  int32_t sz;
  int32_t di;
  int32_t nd;
  int32_t k;
  int32_t j;
  struct ast_Module *dm;
  if (!arena || ty_ref <= 0 || pipeline_type_kind_ord_at(arena, ty_ref) != GLUE_TYPE_NAMED)
    return 0;
  sz = glue_type_size_simple(g_pipeline_asm_emit_module, arena, ty_ref, 0);
  if (sz > 8)
    return sz;
  nlen = pipeline_type_named_name_into(arena, ty_ref, name);
  if (nlen <= 0 || nlen > 63)
    return sz;
  if (g_pipeline_asm_emit_dep_pipe) {
    nd = pipeline_dep_ctx_ndep(g_pipeline_asm_emit_dep_pipe);
    for (di = 0; di < nd; di++) {
      dm = pipeline_dep_ctx_module_at(g_pipeline_asm_emit_dep_pipe, di);
      if (!dm)
        continue;
      sz = glue_type_size_simple(dm, arena, ty_ref, 0);
      if (sz > 8)
        return sz;
      for (k = 0; k < (int32_t)dm->num_struct_layouts; k++) {
        int32_t ln = pipeline_module_struct_layout_name_len(dm, k);
        if (ln != nlen)
          continue;
        for (j = 0; j < nlen; j++) {
          if (pipeline_module_struct_layout_name_byte_at(dm, k, j) != name[j])
            break;
        }
        if (j == nlen) {
          sz = typeck_x_type_size_from_layout_glue(dm, arena, k, 1);
          if (sz > 8)
            return sz;
        }
      }
    }
  }
  return 0;
}

static int32_t glue_call_param_named_struct_pass_addr_elf_c(struct ast_ASTArena *arena, int32_t pty) {
  return glue_type_named_layout_size_any_module_elf_c(arena, pty) > 8 ? 1 : 0;
}

/**
 * CALL 实参 emit 入口：let struct VAR 须 lea 传地址；其余委托 rec（标量 load、*T/形参 struct load 指针）。
 */
int32_t pipeline_asm_emit_expr_elf_for_call_args(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                 int32_t expr_ref, struct backend_AsmFuncCtx *ctx, int32_t ta) {
  int32_t pty;
  /** SHUX_ABI_F32_XMM=1：f32 实参发 32-bit 位型；否则 legacy f64 widen 经 gp 寄存器。 */
  int32_t call_abi_widen_f64 = pipeline_asm_abi_f32_xmm_enabled_c() != 0 ? 0 : 1;
  /** f32 实参：typeck resolved 或 callee 形参表；勿 f64 movabs（低 32 位=0 致 heap 列全 0）。 */
  if (arena && pipeline_expr_kind_ord_at(arena, expr_ref) == 1) {
    int32_t tr = pipeline_expr_resolved_type_ref(arena, expr_ref);
    if (tr > 0 && pipeline_type_kind_ord_at(arena, tr) == GLUE_TYPE_KIND_F32_ORD)
      return glue_emit_float_lit_to_rax_elf_c(arena, elf_ctx, expr_ref, ta, tr, call_abi_widen_f64);
    pty = g_pipeline_asm_emit_call_param_ty_ref;
    if (pty > 0 && pipeline_type_kind_ord_at(arena, pty) == GLUE_TYPE_KIND_F32_ORD)
      return glue_emit_float_lit_to_rax_elf_c(arena, elf_ctx, expr_ref, ta, pty, call_abi_widen_f64);
  }
  pty = g_pipeline_asm_emit_call_param_ty_ref;
  if (arena && ctx && pipeline_expr_kind_ord_at(arena, expr_ref) == 3) {
    uint8_t vname[64];
    int32_t vlen;
    int32_t off;
    off = glue_call_arg_resolve_var_stack_off_elf_c(arena, ctx, expr_ref);
    if (off >= 0) {
      vlen = pipeline_expr_var_name_len(arena, expr_ref);
      if (vlen > 0 && vlen <= 63) {
        pipeline_expr_var_name_into(arena, expr_ref, vname);
        if (glue_call_arg_var_use_lea_not_load_elf_c(arena, expr_ref, ctx) != 0)
          return backend_enc_lea_rbp_to_rax_arch(elf_ctx, off, ta);
        if (pty > 0 && pipeline_type_kind_ord_at(arena, pty) == GLUE_TYPE_KIND_F32_ORD)
          return glue_load_f32_var_slot_to_rax_elf_c(elf_ctx, arena, ctx, expr_ref, off, ta);
        return backend_enc_load_rbp_to_rax_arch(elf_ctx, off, ta);
      }
    }
  }
  /**
   * FIELD_ACCESS struct 字段 CALL 实参（v.al → alloc）：>8B struct 须 lea 字段地址。
   * 优先按 callee 形参 type_ref；pty 缺失时按字段类型 layout（import heap.Allocator 等）。
   */
  if (arena && ctx && pipeline_expr_kind_ord_at(arena, expr_ref) == 44) {
    int32_t use_lea = 0;
    if (pty > 0 && glue_call_param_named_struct_pass_addr_elf_c(arena, pty) != 0)
      use_lea = 1;
    if (use_lea == 0) {
      int32_t fty = glue_field_access_field_type_ref_c(arena, g_pipeline_asm_emit_module, expr_ref);
      if (fty > 0 && glue_call_param_named_struct_pass_addr_elf_c(arena, fty) != 0)
        use_lea = 1;
    }
    if (use_lea == 0) {
      int32_t fty = glue_field_access_field_type_ref_c(arena, g_pipeline_asm_emit_module, expr_ref);
      if (fty > 0 && pipeline_type_kind_ord_at(arena, fty) == GLUE_TYPE_NAMED)
        use_lea = 1;
    }
    if (use_lea != 0)
      return pipeline_asm_emit_lvalue_eff_addr_elf_c(arena, elf_ctx, expr_ref, ctx, ta);
  }
  return pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, expr_ref, ctx, ta);
}

/** 类型 ref 是否为标量 f32。 */
static int32_t glue_type_ref_is_scalar_f32_c(struct ast_ASTArena *arena, int32_t type_ref) {
  if (!arena || type_ref <= 0)
    return 0;
  return pipeline_type_kind_ord_at(arena, type_ref) == GLUE_TYPE_KIND_F32_ORD ? 1 : 0;
}

/** 表达式 resolved_type 是否为标量 f32。 */
static int32_t glue_expr_resolved_is_scalar_f32_c(struct ast_ASTArena *arena, int32_t expr_ref) {
  return glue_type_ref_is_scalar_f32_c(arena, pipeline_expr_resolved_type_ref(arena, expr_ref));
}

/**
 * binop/assign：判定操作数是否为标量 f32（resolved / 局部声明 / SoA INDEX *f32）。
 * heap Vec3f sum_x 等路径 INDEX 常无 resolved_type，须回落字段 *f32 与 VAR let/形参类型。
 */
static int32_t glue_binop_operand_is_scalar_f32_elf_c(struct ast_ASTArena *arena, struct backend_AsmFuncCtx *ctx,
                                                       int32_t expr_ref) {
  int32_t ko;
  int32_t tr;
  int32_t base_ref;
  if (!arena || expr_ref <= 0)
    return 0;
  if (glue_expr_resolved_is_scalar_f32_c(arena, expr_ref))
    return 1;
  ko = pipeline_expr_kind_ord_at(arena, expr_ref);
  if (ko == GLUE_EXPR_KIND_VAR && ctx) {
    tr = glue_var_decl_type_ref_elf_c(arena, ctx, expr_ref);
    return glue_type_ref_is_scalar_f32_c(arena, tr);
  }
  /** AoS arr[i].x：FIELD_ACCESS 回落字段类型（SoA 外堆/栈 f32 列扫描须 addss）。 */
  if (ko == 44) {
    tr = glue_field_access_field_type_ref_c(arena, g_pipeline_asm_emit_module, expr_ref);
    if (glue_type_ref_is_scalar_f32_c(arena, tr))
      return 1;
    tr = pipeline_expr_resolved_type_ref(arena, expr_ref);
    return glue_type_ref_is_scalar_f32_c(arena, tr);
  }
  if (ko == 47) {
    tr = pipeline_expr_resolved_type_ref(arena, expr_ref);
    if (glue_type_ref_is_scalar_f32_c(arena, tr))
      return 1;
    if (pipeline_asm_index_elem_byte_sz_c(arena, expr_ref) != 4)
      return 0;
    base_ref = pipeline_expr_index_base_ref(arena, expr_ref);
    if (base_ref > 0 && pipeline_expr_kind_ord_at(arena, base_ref) == 44) {
      tr = glue_field_access_field_type_ref_c(arena, g_pipeline_asm_emit_module, base_ref);
      if (tr > 0 && pipeline_type_kind_ord_at(arena, tr) == GLUE_TYPE_KIND_PTR) {
        tr = pipeline_type_elem_ref_at(arena, tr);
        return glue_type_ref_is_scalar_f32_c(arena, tr);
      }
    }
  }
  if (ko == 1)
    return glue_type_ref_is_scalar_f32_c(arena, pipeline_expr_resolved_type_ref(arena, expr_ref));
  /** f32 加法链：(t.x+t.y)+t.z 左子为 ADD 时 skip typeck 无 resolved_type，须递归判定。 */
  if (ko == 4) {
    int32_t lr = pipeline_expr_binop_left_ref_at(arena, expr_ref);
    int32_t rr = pipeline_expr_binop_right_ref_at(arena, expr_ref);
    if (lr > 0 && rr > 0 &&
        glue_binop_operand_is_scalar_f32_elf_c(arena, ctx, lr) &&
        glue_binop_operand_is_scalar_f32_elf_c(arena, ctx, rr))
      return 1;
  }
  return 0;
}

/** f32 ADD 双操作数均为 f32 时走 addss，否则整数 add。 */
static int32_t glue_emit_binop_add_rax_rbx_elf_c(struct ast_ASTArena *arena,
                                                   struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                   struct backend_AsmFuncCtx *ctx, int32_t left_ref,
                                                   int32_t right_ref, int32_t ta) {
  if (ta == 0 && glue_binop_operand_is_scalar_f32_elf_c(arena, ctx, left_ref) &&
      glue_binop_operand_is_scalar_f32_elf_c(arena, ctx, right_ref))
    return backend_enc_addss_rax_rbx_arch(elf_ctx, ta);
  return backend_enc_add_rax_rbx_arch(elf_ctx, ta);
}

/**
 * assign/复合赋值：将待写入 lhs 的值装入 rax（plain 为 rhs；a+=10 为 lhs+rhs）。
 * 避免 EXPR_*_ASSIGN 落 backend_emit_expr_elf_slow 与 rec 互递归 SIGSEGV。
 */
static int32_t glue_emit_assign_rhs_to_rax_elf_c(struct ast_ASTArena *arena,
                                                  struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                  int32_t assign_expr_ref, int32_t left_ref, int32_t right_ref,
                                                  struct backend_AsmFuncCtx *ctx, int32_t ta) {
  int32_t ako;
  int32_t vr;
  if (!arena || !elf_ctx || !ctx || assign_expr_ref <= 0 || left_ref <= 0 || right_ref <= 0)
    return -1;
  ako = pipeline_expr_kind_ord_at(arena, assign_expr_ref);
  if (ako == 28)
    return glue_emit_assign_rhs_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta);
  vr = glue_try_binop_left_rax_right_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta);
  if (vr == -1)
    return -1;
  if (vr == -2) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_push_rax_arch(elf_ctx, ta) != 0)
      return -1;
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_pop_rbx_arch(elf_ctx, ta) != 0)
      return -1;
  }
  switch (ako) {
  case 29:
    return glue_emit_binop_add_rax_rbx_elf_c(arena, elf_ctx, ctx, left_ref, right_ref, ta);
  case 30:
    return backend_enc_sub_rax_rbx_arch(elf_ctx, ta);
  case 31:
    return backend_enc_imul_rbx_rax_arch(elf_ctx, ta);
  case 32:
    if (pipeline_asm_emit_divisor_zero_check_rbx_elf_c(elf_ctx, ctx, ta) != 0)
      return -1;
    return backend_enc_idiv_rbx_arch(elf_ctx, ta);
  case 33:
    if (pipeline_asm_emit_divisor_zero_check_rbx_elf_c(elf_ctx, ctx, ta) != 0)
      return -1;
    return backend_enc_rem_mod_arch(elf_ctx, ta);
  case 34:
    return backend_enc_and_rbx_rax_arch(elf_ctx, ta);
  case 35:
    return backend_enc_or_rbx_rax_arch(elf_ctx, ta);
  case 36:
    return backend_enc_xor_rbx_rax_arch(elf_ctx, ta);
  case 37:
    glue_binop_var_slot_cache_clear();
    if (backend_enc_mov_rbx_to_ecx_arch(elf_ctx, ta) != 0)
      return -1;
    return backend_enc_shl_cl_eax_arch(elf_ctx, ta);
  case 38:
    glue_binop_var_slot_cache_clear();
    if (backend_enc_mov_rbx_to_ecx_arch(elf_ctx, ta) != 0)
      return -1;
    return backend_enc_shr_cl_eax_arch(elf_ctx, ta);
  default:
    return -1;
  }
}

static int32_t pipeline_asm_emit_binop_add_elf_c(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                   int32_t left_ref, int32_t right_ref, struct backend_AsmFuncCtx *ctx,
                                                   int32_t ta) {
  int32_t lit_imm;
  int32_t vr;
  int32_t inl;
  /** WPO-S3：p.a + p.b 同 VAR 字段求和（cross_ret 等 import struct）。 */
  inl = try_inline_var_field_sum_binop_elf(arena, elf_ctx, left_ref, right_ref, ctx, ta);
  if (inl != 0)
    return inl < 0 ? -1 : 0;
  if (pipeline_asm_expr_lit_i32_at_c(arena, left_ref, &lit_imm)) {
    /** 先 emit 右子树再装左字面量到 w1，避免嵌套 MUL 等把 w1 覆盖（如 1+2*3）。 */
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rbx();
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    if (glue_emit_binop_add_rax_rbx_elf_c(arena, elf_ctx, ctx, left_ref, right_ref, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    return 0;
  }
  if (pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rbx();
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    if (glue_emit_binop_add_rax_rbx_elf_c(arena, elf_ctx, ctx, left_ref, right_ref, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    return 0;
  }
  /**
   * 7.3：左结合 add 链 ((…)+VAR) — 先完整发射左子树（rax），右 VAR 走槽缓存装 rbx。
   * 须含 SUB（如 (i-j)+k）；若走交换律先装右 VAR 再 emit 左 SUB 会 clobber rbx 且未重载 k。
   */
  if ((pipeline_expr_kind_ord_at(arena, left_ref) == 4 ||
       pipeline_expr_kind_ord_at(arena, left_ref) == 5) &&
      pipeline_expr_kind_ord_at(arena, right_ref) == GLUE_EXPR_KIND_VAR) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    glue_binop_var_slot_cache_invalidate_rbx();
    glue_asm73_left_assoc_spill_rbx_before_var_load_elf_c(arena, ctx, right_ref, ta, elf_ctx);
    if (glue_try_binop_load_operand_elf_c(arena, elf_ctx, right_ref, ctx, ta, 1) != 0)
      return -1;
    if (glue_emit_binop_add_rax_rbx_elf_c(arena, elf_ctx, ctx, left_ref, right_ref, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    return 0;
  }
  vr = glue_try_binop_commutative_rax_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta);
  if (vr == 0) {
    if (glue_emit_binop_add_rax_rbx_elf_c(arena, elf_ctx, ctx, left_ref, right_ref, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    return 0;
  }
  if (vr == -1)
    return -1;
  if (glue_finish_binop_commutative_slow_rax_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta) != 0)
    return -1;
  if (glue_emit_binop_add_rax_rbx_elf_c(arena, elf_ctx, ctx, left_ref, right_ref, ta) != 0)
    return -1;
  glue_binop_var_slot_cache_invalidate_rax();
  return 0;
}

static int32_t pipeline_asm_emit_binop_sub_elf_c(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                   int32_t left_ref, int32_t right_ref, struct backend_AsmFuncCtx *ctx,
                                                   int32_t ta) {
  int32_t lit_imm;
  /** 左字面量：先 emit 右子树，再 rbx=左立即数，结果 rbx-rax（如 42-i）。 */
  if (pipeline_asm_expr_lit_i32_at_c(arena, left_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    return backend_enc_sub_rbx_rax_then_mov_arch(elf_ctx, ta);
  }
  /** 右字面量：rax=左子树，rbx=立即数，结果 rax-rbx（如 i-1）。 */
  if (pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    return backend_enc_sub_rax_rbx_arch(elf_ctx, ta);
  }
  {
    int32_t loff;
    int32_t roff;
    loff = glue_var_expr_stack_off_elf_c(arena, ctx, left_ref);
    roff = glue_var_expr_stack_off_elf_c(arena, ctx, right_ref);
    if (loff >= 0 && roff >= 0) {
      if (backend_enc_load_rbp_to_rbx_arch(elf_ctx, loff, ta) != 0)
        return -1;
      if (backend_enc_load_rbp_to_rax_arch(elf_ctx, roff, ta) != 0)
        return -1;
      return backend_enc_sub_rbx_rax_then_mov_arch(elf_ctx, ta);
    }
    if (loff >= 0) {
      /** 左 VAR、右复合：先 emit 右子树到 rax，再 rax=i、rbx=右，sub rax-rbx（如 i-(j+k)）。 */
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
        return -1;
      glue_binop_var_slot_cache_invalidate_rax();
      glue_binop_var_slot_cache_invalidate_rbx();
      if (backend_enc_mov_rax_to_rbx_arch(elf_ctx, ta) != 0)
        return -1;
      if (backend_enc_load_rbp_to_rax_arch(elf_ctx, loff, ta) != 0)
        return -1;
      return backend_enc_sub_rax_rbx_arch(elf_ctx, ta);
    }
    if (roff >= 0) {
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
        return -1;
      if (backend_enc_mov_rax_to_rbx_arch(elf_ctx, ta) != 0)
        return -1;
      if (backend_enc_load_rbp_to_rax_arch(elf_ctx, roff, ta) != 0)
        return -1;
      return backend_enc_sub_rbx_rax_then_mov_arch(elf_ctx, ta);
    }
  }
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_push_rax_arch(elf_ctx, ta) != 0)
    return -1;
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_pop_rbx_arch(elf_ctx, ta) != 0)
    return -1;
  return backend_enc_sub_rbx_rax_then_mov_arch(elf_ctx, ta);
}

static int32_t pipeline_asm_emit_binop_mul_elf_c(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                   int32_t left_ref, int32_t right_ref, struct backend_AsmFuncCtx *ctx,
                                                   int32_t ta) {
  int32_t lit_imm;
  int32_t vr;
  if (pipeline_asm_expr_lit_i32_at_c(arena, left_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    return backend_enc_imul_rbx_rax_arch(elf_ctx, ta);
  }
  if (pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    return backend_enc_imul_rbx_rax_arch(elf_ctx, ta);
  }
  /**
   * 7.3：左结合 mul 链 ((…)*VAR) — 与 add 同序，结果在 rax，保留 rbx 右 VAR 槽。
   */
  if (pipeline_expr_kind_ord_at(arena, left_ref) == 6 &&
      pipeline_expr_kind_ord_at(arena, right_ref) == GLUE_EXPR_KIND_VAR) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    glue_asm73_left_assoc_spill_rbx_before_var_load_elf_c(arena, ctx, right_ref, ta, elf_ctx);
    if (glue_try_binop_load_operand_elf_c(arena, elf_ctx, right_ref, ctx, ta, 1) != 0)
      return -1;
    if (backend_enc_imul_rbx_rax_arch(elf_ctx, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    return 0;
  }
  vr = glue_try_binop_commutative_rax_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta);
  if (vr == 0) {
    if (backend_enc_imul_rbx_rax_arch(elf_ctx, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    return 0;
  }
  if (vr == -1)
    return -1;
  if (glue_finish_binop_commutative_slow_rax_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_imul_rbx_rax_arch(elf_ctx, ta) != 0)
    return -1;
  glue_binop_var_slot_cache_invalidate_rax();
  return 0;
}

/**
 * 发射 call shux_panic_(code, msg)；msg_ref==0 时第二参为 0。
 * x86/arm64 均先装 arg1 再 arg0，避免 arm64 覆盖 w0。
 */
static int32_t pipeline_asm_emit_shux_panic_call_elf_c(struct ast_ASTArena *arena,
                                                            struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                            struct backend_AsmFuncCtx *ctx, int32_t ta, int32_t code,
                                                            int32_t msg_ref) {
  static const uint8_t panic_nm[] = "shux_panic_";

  if (msg_ref > 0) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, msg_ref, ctx, ta) != 0)
      return -1;
  } else if (backend_enc_mov_imm32_to_w0_arch(elf_ctx, 0, ta) != 0) {
    return -1;
  }
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 1, ta) != 0)
    return -1;
  if (backend_enc_mov_imm32_to_w0_arch(elf_ctx, code, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 0, ta) != 0)
    return -1;
  return backend_enc_call_arch(elf_ctx, (uint8_t *)panic_nm, 14, ta);
}

/**
 * EXPR_PANIC：panic() → shux_panic_(0,0)；panic(expr) → shux_panic_(1, expr)。
 */
int32_t pipeline_asm_emit_panic_elf_c(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                      int32_t expr_ref, struct backend_AsmFuncCtx *ctx, int32_t ta) {
  int32_t op_ref;
  int32_t code;
  if (!arena || !elf_ctx || !ctx || expr_ref <= 0)
    return -1;
  op_ref = pipeline_expr_unary_operand_ref_at(arena, expr_ref);
  code = (op_ref > 0) ? 1 : 0;
  return pipeline_asm_emit_shux_panic_call_elf_c(arena, elf_ctx, ctx, ta, code, op_ref);
}

/**
 * UB 收窄：发射 shux_panic_(1, 0)（与 C codegen 整数除零检查一致）。
 */
static int32_t pipeline_asm_emit_panic_int_div_zero_elf_c(struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t ta) {
  return pipeline_asm_emit_shux_panic_call_elf_c(0, elf_ctx, 0, ta, 1, 0);
}

/**
 * 除数已在 rbx/w1 时做零检查；为零则 panic，否则继续 idiv/rem。
 * 须 enc_test_rbx（勿 mov rbx→rax），VAR 快速路径被除数仍在 w0/rax。
 */
static int32_t pipeline_asm_emit_divisor_zero_check_rbx_elf_c(struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                                struct backend_AsmFuncCtx *ctx, int32_t ta) {
  uint8_t ok_lbl[64];
  int32_t ok_len;

  ok_len = pipeline_asm_emit_next_label_c(ctx, ok_lbl, 64);
  if (ok_len <= 0)
    return -1;
  if (backend_enc_test_rbx_rbx_arch(elf_ctx, ta) != 0)
    return -1;
  if (backend_enc_jne_arch(elf_ctx, ok_lbl, ok_len, ta) != 0)
    return -1;
  if (pipeline_asm_emit_panic_int_div_zero_elf_c(elf_ctx, ta) != 0)
    return -1;
  if (backend_enc_label_arch(elf_ctx, ok_lbl, ok_len, 0, ta) != 0)
    return -1;
  return 0;
}

static int32_t pipeline_asm_emit_binop_div_elf_c(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                   int32_t left_ref, int32_t right_ref, struct backend_AsmFuncCtx *ctx,
                                                   int32_t ta) {
  int32_t lit_imm;
  int32_t vr;
  if (pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm)) {
    if (lit_imm == 0)
      return pipeline_asm_emit_panic_int_div_zero_elf_c(elf_ctx, ta);
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    return backend_enc_idiv_rbx_arch(elf_ctx, ta);
  }
  vr = glue_try_binop_left_rax_right_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta);
  if (vr == -1)
    return -1;
  if (vr == 0) {
    if (pipeline_asm_emit_divisor_zero_check_rbx_elf_c(elf_ctx, ctx, ta) != 0)
      return -1;
    return backend_enc_idiv_rbx_arch(elf_ctx, ta);
  }
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_push_rax_arch(elf_ctx, ta) != 0)
    return -1;
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_rbx_arch(elf_ctx, ta) != 0)
    return -1;
  if (pipeline_asm_emit_divisor_zero_check_rbx_elf_c(elf_ctx, ctx, ta) != 0)
    return -1;
  if (backend_enc_pop_rax_arch(elf_ctx, ta) != 0)
    return -1;
  return backend_enc_idiv_rbx_arch(elf_ctx, ta);
}

/** 按位与二元运算 ELF 发射（i & 1 等；与 add 同栈序 pop_rbx）。 */
static int32_t pipeline_asm_emit_binop_and_elf_c(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                 int32_t left_ref, int32_t right_ref, struct backend_AsmFuncCtx *ctx,
                                                 int32_t ta) {
  int32_t lit_imm;
  int32_t vr;
  if (pipeline_asm_expr_lit_i32_at_c(arena, left_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    return backend_enc_and_rbx_rax_arch(elf_ctx, ta);
  }
  if (pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    return backend_enc_and_rbx_rax_arch(elf_ctx, ta);
  }
  /** 7.3：左结合 & 链 ((…)&VAR) — 与 add/mul 同序。 */
  if (pipeline_expr_kind_ord_at(arena, left_ref) == 11 &&
      pipeline_expr_kind_ord_at(arena, right_ref) == GLUE_EXPR_KIND_VAR) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    glue_asm73_left_assoc_spill_rbx_before_var_load_elf_c(arena, ctx, right_ref, ta, elf_ctx);
    if (glue_try_binop_load_operand_elf_c(arena, elf_ctx, right_ref, ctx, ta, 1) != 0)
      return -1;
    if (backend_enc_and_rbx_rax_arch(elf_ctx, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    return 0;
  }
  vr = glue_try_binop_commutative_rax_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta);
  if (vr == 0) {
    if (backend_enc_and_rbx_rax_arch(elf_ctx, ta) != 0)
      return -1;
    glue_binop_var_slot_cache_invalidate_rax();
    return 0;
  }
  if (vr == -1)
    return -1;
  if (glue_finish_binop_commutative_slow_rax_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_and_rbx_rax_arch(elf_ctx, ta) != 0)
    return -1;
  glue_binop_var_slot_cache_invalidate_rax();
  return 0;
}

/** 按位或/异或 ELF 发射（VAR 快速路径 rax/rbx；slow 与历史栈序一致）。 */
static int32_t pipeline_asm_emit_binop_bitwise_elf_c(struct ast_ASTArena *arena,
                                                       struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t left_ref,
                                                       int32_t right_ref, struct backend_AsmFuncCtx *ctx, int32_t ta,
                                                       int32_t is_xor) {
  int32_t lit_imm;
  int32_t vr;
  if (pipeline_asm_expr_lit_i32_at_c(arena, left_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    return is_xor ? backend_enc_xor_rbx_rax_arch(elf_ctx, ta) : backend_enc_or_rbx_rax_arch(elf_ctx, ta);
  }
  if (pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    return is_xor ? backend_enc_xor_rbx_rax_arch(elf_ctx, ta) : backend_enc_or_rbx_rax_arch(elf_ctx, ta);
  }
  /** 7.3：左结合 | / ^ 链 ((…){op}VAR) — 与 add/mul 同序。 */
  if ((!is_xor && pipeline_expr_kind_ord_at(arena, left_ref) == 12) ||
      (is_xor && pipeline_expr_kind_ord_at(arena, left_ref) == 13)) {
    if (pipeline_expr_kind_ord_at(arena, right_ref) == GLUE_EXPR_KIND_VAR) {
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
        return -1;
      glue_binop_var_slot_cache_invalidate_rax();
      glue_asm73_left_assoc_spill_rbx_before_var_load_elf_c(arena, ctx, right_ref, ta, elf_ctx);
      if (glue_try_binop_load_operand_elf_c(arena, elf_ctx, right_ref, ctx, ta, 1) != 0)
        return -1;
      if (is_xor) {
        if (backend_enc_xor_rbx_rax_arch(elf_ctx, ta) != 0)
          return -1;
      } else if (backend_enc_or_rbx_rax_arch(elf_ctx, ta) != 0) {
        return -1;
      }
      glue_binop_var_slot_cache_invalidate_rax();
      return 0;
    }
  }
  vr = glue_try_binop_commutative_rax_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta);
  if (vr == 0) {
    if (is_xor) {
      if (backend_enc_xor_rbx_rax_arch(elf_ctx, ta) != 0)
        return -1;
    } else if (backend_enc_or_rbx_rax_arch(elf_ctx, ta) != 0) {
      return -1;
    }
    glue_binop_var_slot_cache_invalidate_rax();
    return 0;
  }
  if (vr == -1)
    return -1;
  glue_binop_var_slot_cache_clear();
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_push_rax_arch(elf_ctx, ta) != 0)
    return -1;
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_rbx_arch(elf_ctx, ta) != 0)
    return -1;
  if (backend_enc_pop_rax_arch(elf_ctx, ta) != 0)
    return -1;
  if (is_xor) {
    if (backend_enc_xor_rbx_rax_arch(elf_ctx, ta) != 0)
      return -1;
  } else if (backend_enc_or_rbx_rax_arch(elf_ctx, ta) != 0) {
    return -1;
  }
  glue_binop_var_slot_cache_clear();
  return 0;
}

/**
 * 移位二元运算 ELF：value 在 rax/w0，count 在 rbx/w1，x86 再 mov 到 cl，arm64 mov w2,w1。
 * op: 0=shl, 1=shr（逻辑右移）。
 */
static int32_t pipeline_asm_emit_binop_shift_elf_c(struct ast_ASTArena *arena,
                                                    struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t left_ref,
                                                    int32_t right_ref, struct backend_AsmFuncCtx *ctx, int32_t ta,
                                                    int32_t op) {
  int32_t lit_imm;
  int32_t vr;
  if (pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
  } else {
    vr = glue_try_binop_left_rax_right_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta);
    if (vr == -1)
      return -1;
    if (vr == -2) {
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
        return -1;
      if (backend_enc_push_rax_arch(elf_ctx, ta) != 0)
        return -1;
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
        return -1;
      if (backend_enc_mov_rax_to_rbx_arch(elf_ctx, ta) != 0)
        return -1;
      if (backend_enc_pop_rax_arch(elf_ctx, ta) != 0)
        return -1;
    }
  }
  glue_binop_var_slot_cache_clear();
  if (backend_enc_mov_rbx_to_ecx_arch(elf_ctx, ta) != 0)
    return -1;
  return op != 0 ? backend_enc_shr_cl_eax_arch(elf_ctx, ta) : backend_enc_shl_cl_eax_arch(elf_ctx, ta);
}

static int32_t pipeline_asm_emit_binop_mod_elf_c(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                   int32_t left_ref, int32_t right_ref, struct backend_AsmFuncCtx *ctx,
                                                   int32_t ta) {
  int32_t lit_imm;
  int32_t vr;
  if (pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm)) {
    if (lit_imm == 0)
      return pipeline_asm_emit_panic_int_div_zero_elf_c(elf_ctx, ta);
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_rbx_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    return backend_enc_rem_mod_arch(elf_ctx, ta);
  }
  vr = glue_try_binop_left_rax_right_rbx_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta);
  if (vr == -1)
    return -1;
  if (vr == 0) {
    if (pipeline_asm_emit_divisor_zero_check_rbx_elf_c(elf_ctx, ctx, ta) != 0)
      return -1;
    return backend_enc_rem_mod_arch(elf_ctx, ta);
  }
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_push_rax_arch(elf_ctx, ta) != 0)
    return -1;
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_rbx_arch(elf_ctx, ta) != 0)
    return -1;
  if (pipeline_asm_emit_divisor_zero_check_rbx_elf_c(elf_ctx, ctx, ta) != 0)
    return -1;
  if (backend_enc_pop_rax_arch(elf_ctx, ta) != 0)
    return -1;
  return backend_enc_rem_mod_arch(elf_ctx, ta);
}

/**
 * layout 扫描：按字段名在 module struct 表查 field type_ref（glue_field_access_field_type_ref 失败时回落）。
 */
static int32_t glue_field_access_layout_field_type_ref_by_name_c(struct ast_ASTArena *arena,
                                                                  struct ast_Module *mod, int32_t fa_ref) {
  struct ast_Expr *ex;
  int32_t flen;
  uint8_t field_name[64];
  int32_t k;
  int32_t j;
  if (!arena || !mod || fa_ref <= 0)
    return 0;
  ex = pipeline_arena_expr_ptr(arena, fa_ref);
  if (!ex)
    return 0;
  flen = ex->field_access_field_len;
  if (flen <= 0 || flen > 63)
    return 0;
  memcpy(field_name, ex->field_access_field_name, (size_t)flen);
  for (k = 0; k < (int32_t)mod->num_struct_layouts; k++) {
    for (j = 0; j < pipeline_module_struct_layout_num_fields(mod, k); j++) {
      int32_t fnlen = pipeline_module_struct_layout_field_name_len(mod, k, j);
      int32_t feq = 1;
      int32_t fi;
      if (fnlen != flen)
        continue;
      for (fi = 0; fi < fnlen; fi++) {
        uint8_t fb[64];
        pipeline_module_struct_layout_field_name_into(mod, k, j, fb);
        if (fb[fi] != field_name[fi]) {
          feq = 0;
          break;
        }
      }
      if (feq)
        return pipeline_module_struct_layout_field_type_ref(mod, k, j);
    }
  }
  return 0;
}

/** CALL 实参：named struct 字段须 lea 传址（v.al→alloc）。 */
static int32_t glue_field_access_call_arg_struct_by_addr_elf_c(struct ast_ASTArena *arena, int32_t fa_ref) {
  int32_t fty;
  if (!pipeline_asm_emit_call_arg_active_c())
    return 0;
  if (g_pipeline_asm_emit_call_param_ty_ref > 0) {
    if (pipeline_type_kind_ord_at(arena, g_pipeline_asm_emit_call_param_ty_ref) == GLUE_TYPE_NAMED)
      return 1;
    if (glue_call_param_named_struct_pass_addr_elf_c(arena, g_pipeline_asm_emit_call_param_ty_ref) != 0)
      return 1;
  }
  fty = glue_field_access_field_type_ref_c(arena, g_pipeline_asm_emit_module, fa_ref);
  if (fty <= 0 && g_pipeline_asm_emit_module)
    fty = glue_field_access_layout_field_type_ref_by_name_c(arena, g_pipeline_asm_emit_module, fa_ref);
  if (fty > 0 && pipeline_type_kind_ord_at(arena, fty) == GLUE_TYPE_NAMED)
    return 1;
  return 0;
}

/**
 * VAR 基底字段访问（lex.pos、l.line 等）：经 asm_ctx 查栈槽 + 字段偏移 load，勿落 backend slow 的 ast_arena_expr_get 按值拷贝。
 */
static int32_t pipeline_asm_emit_var_field_access_elf_c(struct ast_ASTArena *arena,
                                                        struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t expr_ref,
                                                        struct backend_AsmFuncCtx *ctx, int32_t ta) {
  int32_t base_ref;
  int32_t vlen;
  int32_t var_off;
  int32_t field_off;
  int32_t load_sz;
  uint8_t vname[64];

  base_ref = pipeline_expr_field_access_base_ref(arena, expr_ref);
  if (base_ref <= 0 || pipeline_expr_kind_ord_at(arena, base_ref) != 3)
    return PIPELINE_ASM_ELF_EXPR_FAST_UNHANDLED;
  vlen = pipeline_expr_var_name_len(arena, base_ref);
  if (vlen <= 0 || vlen > 63)
    return PIPELINE_ASM_ELF_EXPR_FAST_UNHANDLED;
  pipeline_expr_var_name_into(arena, base_ref, vname);
  var_off = asm_ctx_local_find_offset_scoped((uint8_t *)ctx, arena, vname, vlen);
  /** while/for 体内访问外层 let：scoped min_slot 可能排除形参/外层槽，退化为全表搜索。 */
  if (var_off < 0)
    var_off = asm_ctx_local_find_offset((uint8_t *)ctx, vname, vlen);
  if (var_off < 0) {
    if (getenv("SHUX_ASM_EMIT_TRACE"))
      fprintf(stderr, "shux: var_field_access miss var='%.*s'\n", (int)vlen, (char *)vname);
    return PIPELINE_ASM_ELF_EXPR_FAST_UNHANDLED;
  }
  field_off = glue_field_access_effective_offset_c(arena, g_pipeline_asm_emit_module, expr_ref);
  if (glue_enc_local_slot_ptr_or_addr_elf_c(arena, elf_ctx, base_ref, var_off, ctx, ta) != 0)
    return -1;
  if (field_off != 0 && backend_enc_add_imm_to_rax_arch(elf_ctx, field_off, ta) != 0)
    return -1;
  if (glue_field_access_call_arg_struct_by_addr_elf_c(arena, expr_ref) != 0)
    return 0;
  load_sz = pipeline_expr_field_access_load_byte_sz(arena, g_pipeline_asm_emit_module, expr_ref);
  if (load_sz == 1)
    return backend_enc_load_zext8_from_rax_arch(elf_ctx, ta);
  if (load_sz == 8)
    return backend_enc_load_64_from_rax_arch(elf_ctx, ta);
  return backend_enc_load_32_from_rax_arch(elf_ctx, ta);
}

/**
 * EXPR_FIELD_ACCESS 快速路径：枚举 TokenKind/ExprKind/TypeKind、VAR 字段（lex.pos），勿落 backend slow。
 */
static int32_t pipeline_asm_emit_field_access_elf_fast_c(struct ast_ASTArena *arena,
                                                           struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                           int32_t expr_ref, struct backend_AsmFuncCtx *ctx,
                                                           int32_t ta) {
  int32_t fa_base2;
  int32_t blen2;
  if (pipeline_expr_field_access_is_enum_variant(arena, expr_ref) != 0)
    return backend_enc_mov_imm32_to_w0_arch(elf_ctx, pipeline_expr_enum_variant_tag_at(arena, expr_ref), ta);
  fa_base2 = pipeline_expr_field_access_base_ref(arena, expr_ref);
  /** DOD-S1：SoA `arr[i].field` 读路径（列基址 + index*stride；失败/无 stride 时回落 lvalue 寻址）。 */
  if (fa_base2 > 0 && pipeline_expr_kind_ord_at(arena, fa_base2) == 47) {
    int32_t load_sz;
    /** emit 时 stride 仍缺：再跑 SoA typeck（skip .x typeck / 形参 T[N] 回填遗漏）。 */
    if (pipeline_expr_field_access_soa_stride(arena, expr_ref) <= 0 && g_pipeline_asm_emit_module != NULL)
      (void)pipeline_typeck_field_soa_index_c(g_pipeline_asm_emit_module, arena, expr_ref, fa_base2);
    if (pipeline_expr_field_access_soa_stride(arena, expr_ref) > 0) {
      if (glue_emit_soa_index_field_addr_elf_c(arena, elf_ctx, fa_base2, expr_ref, ctx, ta) != 0 &&
          pipeline_asm_emit_lvalue_eff_addr_elf_c(arena, elf_ctx, expr_ref, ctx, ta) != 0)
        return PIPELINE_ASM_ELF_EXPR_FAST_UNHANDLED;
    } else if (pipeline_asm_emit_lvalue_eff_addr_elf_c(arena, elf_ctx, expr_ref, ctx, ta) != 0) {
      return PIPELINE_ASM_ELF_EXPR_FAST_UNHANDLED;
    }
    load_sz = pipeline_expr_field_access_load_byte_sz(arena, g_pipeline_asm_emit_module, expr_ref);
    if (load_sz == 1)
      return backend_enc_load_zext8_from_rax_arch(elf_ctx, ta);
    if (load_sz == 8)
      return backend_enc_load_64_from_rax_arch(elf_ctx, ta);
    return backend_enc_load_i32_indirect_to_rax_arch(elf_ctx, ta);
  }
  /** 局部/形参 struct 字段（listener.fd 等）；枚举 TokenKind/TypeKind/ExprKind 须先于 var_field_access（skip typeck 无 is_enum_variant）。 */
  if (fa_base2 > 0 && pipeline_expr_kind_ord_at(arena, fa_base2) == 3) {
    blen2 = pipeline_expr_var_name_len(arena, fa_base2);
    if (blen2 >= 9) {
      uint8_t bn[64];
      uint8_t fb[64];
      int32_t flen2 = pipeline_expr_field_access_name_len(arena, expr_ref);
      int32_t tk;
      pipeline_expr_var_name_into(arena, fa_base2, bn);
      if (memcmp(bn, "TokenKind", 9) == 0 && flen2 > 0) {
        pipeline_expr_field_access_name_into(arena, expr_ref, fb);
        tk = pipeline_token_kind_variant_tag(fb, flen2);
        if (tk < 0) {
          /** parser 偶发 field_len 多 1（含尾零）；前缀一致再试 NUL 终止长。 */
          int32_t sl = (int32_t)strlen((const char *)fb);
          if (sl > 0 && sl < flen2)
            tk = pipeline_token_kind_variant_tag(fb, sl);
        }
        if (tk >= 0)
          return backend_enc_mov_imm32_to_w0_arch(elf_ctx, tk, ta);
      }
    }
    if (blen2 >= 8) {
      uint8_t bn[64];
      uint8_t fb[64];
      int32_t flen2 = pipeline_expr_field_access_name_len(arena, expr_ref);
      int32_t ev_tag;
      pipeline_expr_var_name_into(arena, fa_base2, bn);
      if (memcmp(bn, "TypeKind", 8) == 0 && flen2 > 0) {
        pipeline_expr_field_access_name_into(arena, expr_ref, fb);
        ev_tag = pipeline_asm_typekind_variant_tag(fb, flen2);
        if (ev_tag >= 0)
          return backend_enc_mov_imm32_to_w0_arch(elf_ctx, ev_tag, ta);
      }
      if (memcmp(bn, "ExprKind", 8) == 0 && flen2 > 0) {
        ev_tag = pipeline_expr_enum_namespace_field_tag(arena, expr_ref);
        if (ev_tag >= 0)
          return backend_enc_mov_imm32_to_w0_arch(elf_ctx, ev_tag, ta);
      }
    }
    {
      int32_t vr = pipeline_asm_emit_var_field_access_elf_c(arena, elf_ctx, expr_ref, ctx, ta);
      if (vr != PIPELINE_ASM_ELF_EXPR_FAST_UNHANDLED)
        return vr;
    }
  }
  /** skip typeck：enum namespace 未标 is_enum_variant 时的最后回落。 */
  {
    int32_t ns_tag = pipeline_expr_enum_namespace_field_tag(arena, expr_ref);
    if (ns_tag >= 0)
      return backend_enc_mov_imm32_to_w0_arch(elf_ctx, ns_tag, ta);
  }
  /** 链式 FIELD_ACCESS（v.al.kind 等）：lvalue 寻址 + load；勿落 backend slow（与 rec 互递归 SIGSEGV）。 */
  {
    int32_t load_sz;
    if (pipeline_asm_emit_lvalue_eff_addr_elf_c(arena, elf_ctx, expr_ref, ctx, ta) != 0)
      return PIPELINE_ASM_ELF_EXPR_FAST_UNHANDLED;
    if (glue_field_access_call_arg_struct_by_addr_elf_c(arena, expr_ref) != 0)
      return 0;
    load_sz = pipeline_expr_field_access_load_byte_sz(arena, g_pipeline_asm_emit_module, expr_ref);
    if (load_sz == 1)
      return backend_enc_load_zext8_from_rax_arch(elf_ctx, ta);
    if (load_sz == 8)
      return backend_enc_load_64_from_rax_arch(elf_ctx, ta);
    return backend_enc_load_32_from_rax_arch(elf_ctx, ta);
  }
}

/**
 * emit_expr_elf 统一 C 入口（fast + rec）；供日后 X 薄包装，勿在 rec 内再回调本符号。
 */
int32_t pipeline_asm_emit_expr_elf_c(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                     int32_t expr_ref, struct backend_AsmFuncCtx *ctx, int32_t ta) {
  return pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, expr_ref, ctx, ta);
}

/**
 * emit_expr_elf 快速路径：LIT/const_fold/RETURN/算术二元；未命中返回 -99 由 .x 尾 return 结束函数。
 */
int32_t pipeline_asm_emit_expr_elf_fast(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                        int32_t expr_ref, struct backend_AsmFuncCtx *ctx, int32_t ta) {
  struct ast_Expr *e;
  int32_t ko;
  if (expr_ref == 0)
    return -1;
  if (!arena || expr_ref <= 0 || expr_ref > arena->num_exprs)
    return PIPELINE_ASM_ELF_EXPR_FAST_UNHANDLED;
  e = pipeline_arena_expr_ptr(arena, expr_ref);
  if (!e)
    return -1;
  ko = pipeline_expr_kind_ord_at(arena, expr_ref);
  /** 形参/局部 VAR 勿走 CTFE 快速路径（池字段未初始化或与 C 布局错位时会误折叠为 0）。 */
  if (e->const_folded_valid != 0 && ko != (int32_t)ast_ExprKind_EXPR_VAR)
    return backend_enc_mov_imm32_to_w0_arch(elf_ctx, e->const_folded_val, ta);
  if (ko == 0 || ko == 2)
    return backend_enc_mov_imm32_to_w0_arch(elf_ctx, pipeline_expr_int_val_at(arena, expr_ref), ta);
  if (ko == 1)
    return glue_emit_float_lit_to_rax_elf_c(arena, elf_ctx, expr_ref, ta, 0, 0);
  if (ko == 50)
    return backend_enc_mov_imm32_to_w0_arch(elf_ctx, pipeline_expr_enum_variant_tag_at(arena, expr_ref), ta);
  if (ko == 44)
    return pipeline_asm_emit_field_access_elf_fast_c(arena, elf_ctx, expr_ref, ctx, ta);
  /** EXPR_VAR：走 C 读名 + sidecar 偏移，勿 ast_arena_expr_get + local_offset slow。 */
  if (ko == 3) {
    uint8_t vname[64];
    int32_t vlen = pipeline_expr_var_name_len(arena, expr_ref);
    int32_t off;
    if (vlen <= 0)
      return -1;
    pipeline_expr_var_name_into(arena, expr_ref, vname);
    off = glue_call_arg_resolve_var_stack_off_elf_c(arena, ctx, expr_ref);
    if (off < 0) {
      int32_t mod_imm;
      /** 库模块多函数：顶层 const 仅 hoist 进首个函数体，其它函数 VAR 回落模块 const 字面量。 */
      if (g_pipeline_asm_emit_module &&
          asm_module_top_level_const_lit_i32(g_pipeline_asm_emit_module, arena, vname, vlen, &mod_imm) != 0)
        return backend_enc_mov_imm32_to_w0_arch(elf_ctx, mod_imm, ta);
      return -1;
    }
    {
      int32_t vtr = glue_var_decl_type_ref_elf_c(arena, ctx, expr_ref);
      if (vtr > 0 && pipeline_type_kind_ord_at(arena, vtr) == GLUE_TYPE_KIND_F32_ORD)
        return glue_load_f32_var_slot_to_rax_elf_c(elf_ctx, arena, ctx, expr_ref, off, ta);
    }
    return glue_load_var_as_value_to_rax_rdx_elf_c(elf_ctx, arena, ctx, expr_ref, off, ta);
  }
  /* EXPR_RETURN 走 slow（emit 操作数 + jmp tail_join）；fast 仅剥壳会漏 jmp 导致 SIGSEGV。 */
  if (ko == (int32_t)ast_ExprKind_EXPR_RETURN)
    return PIPELINE_ASM_ELF_EXPR_FAST_UNHANDLED;
  if (ko == 4)
    return pipeline_asm_emit_binop_add_elf_c(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, expr_ref),
                                              pipeline_expr_binop_right_ref_at(arena, expr_ref), ctx, ta);
  if (ko == 5)
    return pipeline_asm_emit_binop_sub_elf_c(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, expr_ref),
                                              pipeline_expr_binop_right_ref_at(arena, expr_ref), ctx, ta);
  if (ko == 6)
    return pipeline_asm_emit_binop_mul_elf_c(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, expr_ref),
                                              pipeline_expr_binop_right_ref_at(arena, expr_ref), ctx, ta);
  if (ko == 7)
    return pipeline_asm_emit_binop_div_elf_c(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, expr_ref),
                                              pipeline_expr_binop_right_ref_at(arena, expr_ref), ctx, ta);
  if (ko == 8)
    return pipeline_asm_emit_binop_mod_elf_c(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, expr_ref),
                                              pipeline_expr_binop_right_ref_at(arena, expr_ref), ctx, ta);
  if (ko == 11)
    return pipeline_asm_emit_binop_and_elf_c(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, expr_ref),
                                              pipeline_expr_binop_right_ref_at(arena, expr_ref), ctx, ta);
  if (ko == 9)
    return pipeline_asm_emit_binop_shift_elf_c(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, expr_ref),
                                               pipeline_expr_binop_right_ref_at(arena, expr_ref), ctx, ta, 0);
  if (ko == 10)
    return pipeline_asm_emit_binop_shift_elf_c(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, expr_ref),
                                               pipeline_expr_binop_right_ref_at(arena, expr_ref), ctx, ta, 1);
  if (ko == 12)
    return pipeline_asm_emit_binop_bitwise_elf_c(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, expr_ref),
                                                 pipeline_expr_binop_right_ref_at(arena, expr_ref), ctx, ta, 0);
  if (ko == 13)
    return pipeline_asm_emit_binop_bitwise_elf_c(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, expr_ref),
                                                 pipeline_expr_binop_right_ref_at(arena, expr_ref), ctx, ta, 1);
  return PIPELINE_ASM_ELF_EXPR_FAST_UNHANDLED;
}

/**
 * 读取 arena.types[ref-1].array_size（数组长度、向量 lane 数等）。
 * ref 无效时返回 0。
 */
int32_t pipeline_type_array_size_at(struct ast_ASTArena *arena, int32_t ref) {
  struct ast_Type *t;
  if (!arena || ref <= 0 || ref > arena->num_types)
    return 0;
  t = pipeline_arena_type_ptr(arena, ref);
  return t ? t->array_size : 0;
}

/** func 形参 / arena copy_slot 实现见 ast_pool.c（#include 进本 TU）。 */

/**
 * 将 src 前 n 字节（最多 src_cap）复制到 dst[0..63]，余下清零。
 * parse_one_function_library X 真 emit 时勿对局部 Type/Expr 数组逐元素 ASSIGN（asm INDEX 发射失败）。
 */
void pipeline_module_fill_u8_64_from_src_c(uint8_t *dst, const uint8_t *src, int32_t n, int32_t src_cap) {
  int32_t i;
  if (!dst)
    return;
  if (n < 0)
    n = 0;
  if (src_cap < 0)
    src_cap = 0;
  for (i = 0; i < 64; i++) {
    if (src && i < n && i < src_cap)
      dst[i] = src[i];
    else
      dst[i] = 0;
  }
}

/** parse_one_function_library X emit：在 arena 写 TYPE_BOOL，避免 X 局部 Type 大结构体 get/set。 */
void pipeline_parser_library_init_bool_type_c(struct ast_ASTArena *arena, int32_t type_ref) {
  struct ast_Type *t;
  if (!arena || type_ref <= 0)
    return;
  t = pipeline_arena_type_ptr(arena, type_ref);
  if (!t)
    return;
  t->kind = (int32_t)ast_TypeKind_TYPE_BOOL;
  t->name_len = 0;
  t->elem_type_ref = 0;
  t->array_size = 0;
}

/** parse_one_function_library X emit：在 arena 写 TYPE_NAMED + 名字节。 */
void pipeline_parser_library_init_named_type_c(struct ast_ASTArena *arena, int32_t type_ref, const uint8_t *name,
                                               int32_t name_len) {
  struct ast_Type *t;
  if (!arena || type_ref <= 0)
    return;
  t = pipeline_arena_type_ptr(arena, type_ref);
  if (!t)
    return;
  t->kind = (int32_t)ast_TypeKind_TYPE_NAMED;
  t->name_len = name_len;
  pipeline_module_fill_u8_64_from_src_c(t->name, name, name_len, 64);
  t->elem_type_ref = 0;
  t->array_size = 0;
}

/** parse_one_function_library X emit：VAR Expr + param 名。 */
void pipeline_parser_library_init_var_expr_c(struct ast_ASTArena *arena, int32_t expr_ref, int32_t type_ref,
                                            const uint8_t *param_name, int32_t param_name_len) {
  struct ast_Expr *ve;
  if (!arena || expr_ref <= 0)
    return;
  ve = pipeline_arena_expr_ptr(arena, expr_ref);
  if (!ve)
    return;
  ve->kind = (int32_t)ast_ExprKind_EXPR_VAR;
  ve->resolved_type_ref = type_ref;
  ve->line = 0;
  ve->col = 0;
  ve->var_name_len = param_name_len;
  pipeline_module_fill_u8_64_from_src_c(ve->var_name, param_name, param_name_len, 32);
  ve->match_arm_base = 0;
  ve->enum_variant_tag = 0;
  ve->field_access_base_ref = 0;
  ve->field_access_field_len = 0;
  ve->field_access_is_enum_variant = 0;
  ve->field_access_offset = 0;
}

/** parse_one_function_library X emit：FIELD_ACCESS Expr。 */
void pipeline_parser_library_init_field_access_expr_c(struct ast_ASTArena *arena, int32_t expr_ref, int32_t base_ref,
                                                     const uint8_t *field_name, int32_t field_len) {
  struct ast_Expr *fe;
  if (!arena || expr_ref <= 0)
    return;
  fe = pipeline_arena_expr_ptr(arena, expr_ref);
  if (!fe)
    return;
  fe->kind = (int32_t)ast_ExprKind_EXPR_FIELD_ACCESS;
  fe->resolved_type_ref = 0;
  fe->line = 0;
  fe->col = 0;
  fe->field_access_base_ref = base_ref;
  fe->field_access_field_len = field_len;
  pipeline_module_fill_u8_64_from_src_c(fe->field_access_field_name, field_name, field_len, 64);
  fe->field_access_is_enum_variant = 0;
  fe->field_access_offset = 0;
  fe->match_arm_base = 0;
  fe->enum_variant_tag = 0;
  fe->binop_left_ref = 0;
  fe->binop_right_ref = 0;
}

/** parse_one_function_library X emit：ENUM_VARIANT 占位 Expr。 */
void pipeline_parser_library_init_enum_variant_expr_c(struct ast_ASTArena *arena, int32_t expr_ref) {
  struct ast_Expr *ene;
  if (!arena || expr_ref <= 0)
    return;
  ene = pipeline_arena_expr_ptr(arena, expr_ref);
  if (!ene)
    return;
  ene->kind = (int32_t)ast_ExprKind_EXPR_ENUM_VARIANT;
  ene->resolved_type_ref = 0;
  ene->line = 0;
  ene->col = 0;
  ene->enum_variant_tag = 0;
  ene->match_arm_base = 0;
  ene->field_access_base_ref = 0;
  ene->field_access_field_len = 0;
}

/** parse_one_function_library X emit：EQ binop Expr。 */
void pipeline_parser_library_init_eq_expr_c(struct ast_ASTArena *arena, int32_t expr_ref, int32_t bool_type_ref,
                                             int32_t left_ref, int32_t right_ref) {
  struct ast_Expr *eqe;
  if (!arena || expr_ref <= 0)
    return;
  eqe = pipeline_arena_expr_ptr(arena, expr_ref);
  if (!eqe)
    return;
  eqe->kind = (int32_t)ast_ExprKind_EXPR_EQ;
  eqe->resolved_type_ref = bool_type_ref;
  eqe->line = 0;
  eqe->col = 0;
  eqe->binop_left_ref = left_ref;
  eqe->binop_right_ref = right_ref;
  eqe->match_arm_base = 0;
  eqe->enum_variant_tag = 0;
  eqe->field_access_base_ref = 0;
  eqe->field_access_field_len = 0;
}

/** parse_one_function_library X emit：library 形态 labeled return Block。 */
int32_t pipeline_parser_library_init_labeled_block_c(struct ast_ASTArena *arena, int32_t block_ref, int32_t eq_ref) {
  struct ast_Block *b;
  if (!arena || block_ref <= 0)
    return -1;
  b = pipeline_arena_block_ptr(arena, block_ref);
  if (!b)
    return -1;
  b->num_consts = 0;
  b->num_lets = 0;
  b->num_early_lets = 0;
  b->num_loops = 0;
  b->num_for_loops = 0;
  b->num_if_stmts = 0;
  b->num_defers = 0;
  if (ast_pipeline_block_append_labeled(arena, block_ref, 0, 0, 0, eq_ref) < 0)
    return -1;
  b = pipeline_arena_block_ptr(arena, block_ref);
  if (!b)
    return -1;
  b->num_expr_stmts = 0;
  b->final_expr_ref = 0;
  b->num_stmt_order = 0;
  return 0;
}

/**
 * parse_one_extern_and_add_into X emit：写 arena Func 槽并登记 module，避免 X `f.name[i]` INDEX ASSIGN。
 * 返回 module func 下标；池满或参数非法时返回 -1。
 */
int32_t pipeline_parser_extern_init_arena_func_and_register_c(struct ast_ASTArena *arena, struct ast_Module *module,
                                                             int32_t func_ref, const uint8_t *name, int32_t name_len,
                                                             int32_t num_params, int32_t return_ty_ref) {
  struct ast_Func *fp;
  int32_t fi;
  if (!arena || !module || func_ref <= 0)
    return -1;
  if (name_len < 0 || name_len > 64)
    return -1;
  fp = pipeline_arena_func_ptr(arena, func_ref);
  if (!fp)
    return -1;
  pipeline_module_fill_u8_64_from_src_c(fp->name, name, name_len, 64);
  fp->name_len = name_len;
  fp->num_params = num_params;
  fp->return_type_ref = return_ty_ref;
  fp->body_ref = 0;
  fp->body_expr_ref = 0;
  fp->is_extern = 1;
  fp->is_async = 0;
  fi = pipeline_module_func_alloc_slot(module);
  if (fi < 0)
    return -1;
  pipeline_module_func_name_write(module, fi, (uint8_t *)name, name_len);
  pipeline_module_func_set_num_params(module, fi, num_params);
  pipeline_module_func_set_return_type(module, fi, return_ty_ref);
  pipeline_module_func_set_body_ref(module, fi, 0);
  pipeline_module_func_set_body_expr_ref(module, fi, 0);
  pipeline_module_func_set_is_extern(module, fi, 1);
  pipeline_module_func_set_is_async(module, fi, 0);
  pipeline_module_func_ref_set(module, fi, func_ref);
  return fi;
}

void pipeline_module_func_name_write(struct ast_Module *m, int32_t func_index, uint8_t *name_bytes,
                                     int32_t name_len) {
  struct ast_Func *f;
  if (!m || func_index < 0)
    return;
  if (name_len < 0 || name_len > 64)
    return;
  if (name_len > 0 && !name_bytes)
    return;
  f = pipeline_module_func_ptr(m, func_index);
  if (!f)
    return;
  f->name_len = name_len;
  memset(f->name, 0, sizeof(f->name));
  if (name_len > 0)
    memcpy(f->name, name_bytes, (size_t)name_len);
}

/** 自举 codegen：将 module->funcs[fi].name[64] 拷入 dst，避免 .x 对嵌套大数组下标 typeck/asm GEP 失败。 */
void pipeline_module_func_name_copy64(struct ast_Module *m, int32_t func_index, uint8_t *dst) {
  struct ast_Func *f;
  if (!m || !dst || func_index < 0)
    return;
  if (func_index >= (int32_t)m->num_funcs)
    return;
  f = pipeline_module_func_ptr(m, func_index);
  if (!f)
    return;
  memcpy(dst, f->name, (size_t)64);
}

int32_t pipeline_module_func_name_len_at(struct ast_Module *m, int32_t func_index) {
  struct ast_Func *f;
  if (!m || func_index < 0)
    return 0;
  if (func_index >= (int32_t)m->num_funcs)
    return 0;
  f = pipeline_module_func_ptr(m, func_index);
  return f ? (int32_t)f->name_len : 0;
}

int32_t pipeline_module_func_is_extern_at(struct ast_Module *m, int32_t func_index) {
  struct ast_Func *f;
  if (!m || func_index < 0)
    return 0;
  if (func_index >= (int32_t)m->num_funcs)
    return 0;
  f = pipeline_module_func_ptr(m, func_index);
  return f ? (int32_t)f->is_extern : 0;
}

int32_t pipeline_module_func_body_ref_at(struct ast_Module *m, int32_t func_index) {
  struct ast_Func *f;
  if (!m || func_index < 0)
    return 0;
  if (func_index >= (int32_t)m->num_funcs)
    return 0;
  f = pipeline_module_func_ptr(m, func_index);
  return f ? (int32_t)f->body_ref : 0;
}

/** struct_layout / import / top_level / enum / func 形参池实现见 ast_pool.c（文件末尾 #include）。 */

/** 读 arena expr 槽；无效 ref 返回 NULL。 */
static struct ast_Expr *glue_arena_expr_at_ref(struct ast_ASTArena *a, int32_t expr_ref) {
  if (!a || expr_ref <= 0 || expr_ref > a->num_exprs)
    return NULL;
  return pipeline_arena_expr_ptr(a, expr_ref);
}

extern int32_t pipeline_block_const_init_ref(struct ast_ASTArena *a, int32_t br, int32_t ci);
extern int32_t pipeline_block_const_name_len(struct ast_ASTArena *a, int32_t br, int32_t ci);
extern void pipeline_block_const_name_copy64(struct ast_ASTArena *a, int32_t br, int32_t ci, uint8_t *dst);
extern int32_t pipeline_expr_array_lit_num_elems_at(struct ast_ASTArena *a, int32_t expr_ref);
extern int32_t pipeline_expr_array_lit_elem_ref(struct ast_ASTArena *a, int32_t expr_ref, int32_t idx);
extern void lsp_diag_report_typeck(int line, int col, const char *fmt, ...);

/**
 * 判断表达式是否为常量表达式（字面量、引用已定义 const 名、或其运算）。
 * names[0..n_const_names) 为当前块内已声明 const 名（不含 let）。
 */
static int glue_is_const_expr_ref(struct ast_ASTArena *a, int32_t expr_ref, const char *const_names[], int n_const_names) {
  struct ast_Expr *e;
  int i, j, ne;
  enum ast_ExprKind kd;

  e = glue_arena_expr_at_ref(a, expr_ref);
  if (!e)
    return 0;
  kd = e->kind;
  if (kd == ast_ExprKind_EXPR_LIT || kd == ast_ExprKind_EXPR_FLOAT_LIT || kd == ast_ExprKind_EXPR_BOOL_LIT)
    return 1;
  if (kd == ast_ExprKind_EXPR_VAR) {
    for (i = 0; i < n_const_names; i++) {
      if (!const_names[i])
        continue;
      if (e->var_name_len > 0 && strcmp(const_names[i], e->var_name) == 0)
        return 1;
    }
    return 0;
  }
  if (kd >= ast_ExprKind_EXPR_ADD && kd <= ast_ExprKind_EXPR_LOGOR)
    return glue_is_const_expr_ref(a, e->binop_left_ref, const_names, n_const_names) &&
           glue_is_const_expr_ref(a, e->binop_right_ref, const_names, n_const_names);
  if (kd == ast_ExprKind_EXPR_NEG || kd == ast_ExprKind_EXPR_BITNOT || kd == ast_ExprKind_EXPR_LOGNOT)
    return glue_is_const_expr_ref(a, e->unary_operand_ref, const_names, n_const_names);
  if (kd == ast_ExprKind_EXPR_ARRAY_LIT) {
    ne = e->array_lit_num_elems;
    for (i = 0; i < ne; i++) {
      if (!glue_is_const_expr_ref(a, pipeline_expr_array_lit_elem_ref(a, expr_ref, i), const_names, n_const_names))
        return 0;
    }
    return 1;
  }
  return 0;
}

/** block 内第 const_idx 条 const 的 init 是否为常量表达式；是返回 1，否返回 0。 */
int32_t pipeline_typeck_block_const_init_is_const_c(struct ast_ASTArena *arena, int32_t block_ref, int32_t const_idx) {
  const char *names[64];
  char name_bufs[64][64];
  int n = 0;
  int i;
  int32_t init_ref;

  if (!arena || const_idx < 0)
    return 0;
  for (i = 0; i < const_idx && n < 64; i++) {
    int32_t nlen = pipeline_block_const_name_len(arena, block_ref, i);
    if (nlen <= 0 || nlen >= 64)
      continue;
    pipeline_block_const_name_copy64(arena, block_ref, i, (uint8_t *)name_bufs[n]);
    name_bufs[n][nlen] = '\0';
    names[n] = name_bufs[n];
    n++;
  }
  init_ref = pipeline_block_const_init_ref(arena, block_ref, const_idx);
  if (init_ref <= 0)
    return 1;
  return glue_is_const_expr_ref(arena, init_ref, names, n) ? 1 : 0;
}

/** const 初值非常量表达式时报错（与 typeck.c TYPECK_ERR_AT 措辞一致）。 */
void pipeline_typeck_const_init_not_constant_c(int32_t line, int32_t col) {
  lsp_diag_report_typeck((int)line, (int)col, "const init must be constant expression");
}

/** 读 struct_lit 字段数；避免 X 内 `let e: Expr = ast_arena_expr_get` 后字段访问 typeck 失败。 */
int32_t pipeline_expr_struct_lit_num_fields(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  return ex ? ex->struct_lit_num_fields : 0;
}

/** 读 struct_lit 类型名长度。 */
int32_t pipeline_expr_struct_lit_type_name_len(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  return ex ? ex->struct_lit_struct_name_len : 0;
}

/** memcpy struct_lit 类型名到 out64。 */
void pipeline_expr_struct_lit_type_name_into(struct ast_ASTArena *a, int32_t expr_ref, uint8_t *out64) {
  struct ast_Expr *ex;
  if (!out64)
    return;
  ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex) {
    memset(out64, 0, 64);
    return;
  }
  memcpy(out64, ex->struct_lit_struct_name, 64);
}

extern void driver_diagnostic_typeck_struct_padding_before(uint8_t *sname, int32_t sname_len, int32_t gap,
                                                           uint8_t *fname, int32_t fname_len);
extern void driver_diagnostic_typeck_struct_padding_trailing(uint8_t *sname, int32_t sname_len, int32_t gap);
extern void driver_diagnostic_typeck_struct_field_bad_size(uint8_t *sname, int32_t sname_len, uint8_t *fname,
                                                           int32_t fname_len);

static int32_t glue_type_align_simple(struct ast_Module *m, struct ast_ASTArena *a, int32_t ty_ref, int32_t depth);
static int32_t glue_type_size_simple(struct ast_Module *m, struct ast_ASTArena *a, int32_t ty_ref, int32_t depth);

/**
 * C 版 struct_layout_metrics：与 typeck.x typeck_struct_layout_metrics 语义一致。
 * asm 栈槽宽 / frame_size 热路径走此实现，避免 gen2 自举 X metrics 在 Stage2 上极慢挂死。
 */
static int32_t glue_struct_layout_metrics_c(struct ast_Module *module, struct ast_ASTArena *arena, int32_t li,
                                            int32_t depth, int32_t check_pad, int32_t *out_sz, int32_t *out_al) {
  int32_t nf;
  int32_t allow;
  int32_t layout_nlen;
  int32_t current;
  int32_t max_align;
  int32_t j;
  uint8_t layout_nm[64];
  uint8_t field_nm[64];
  if (!module || !arena || !out_sz || !out_al)
    return -1;
  if (li < 0 || li >= pipeline_module_num_struct_layouts_at(module) || depth > 64)
    return -1;
  nf = pipeline_module_struct_layout_num_fields(module, li);
  allow = pipeline_module_struct_layout_allow_padding_at(module, li);
  layout_nlen = pipeline_module_struct_layout_name_len(module, li);
  pipeline_module_struct_layout_name_into(module, li, layout_nm);
  current = 0;
  max_align = 1;
  /** packed：无隐式 padding，结构体对齐 1（与 typeck.x typeck_struct_layout_metrics 一致）。 */
  if (pipeline_module_struct_layout_packed_at(module, li)) {
    for (j = 0; j < nf; j++) {
      int32_t ftr;
      int32_t flen;
      int32_t fsize;
      ftr = pipeline_module_struct_layout_field_type_ref(module, li, j);
      pipeline_module_struct_layout_field_name_into(module, li, j, field_nm);
      flen = pipeline_module_struct_layout_field_name_len(module, li, j);
      fsize = glue_type_size_simple(module, arena, ftr, depth);
      if (fsize <= 0) {
        if (driver_asm_build_skip_typeck() == 0)
          driver_diagnostic_typeck_struct_field_bad_size(layout_nm, layout_nlen, field_nm, flen);
        return -1;
      }
      current = current + fsize;
    }
    *out_sz = current;
    *out_al = 1;
    return 0;
  }
  for (j = 0; j < nf; j++) {
    int32_t ftr;
    int32_t flen;
    int32_t A;
    int32_t rem;
    int32_t gap;
    int32_t fsize;
    ftr = pipeline_module_struct_layout_field_type_ref(module, li, j);
    pipeline_module_struct_layout_field_name_into(module, li, j, field_nm);
    flen = pipeline_module_struct_layout_field_name_len(module, li, j);
    {
      int32_t fa = pipeline_module_struct_layout_field_align_at(module, li, j);
      A = glue_type_align_simple(module, arena, ftr, depth);
      if (A <= 0)
        A = 1;
      if (fa > A)
        A = fa;
    }
    rem = current % A;
    gap = A - rem;
    gap = gap % A;
    if (check_pad != 0 && gap > 0 && allow == 0) {
      driver_diagnostic_typeck_struct_padding_before(layout_nm, layout_nlen, gap, field_nm, flen);
      return -1;
    }
    current = current + gap;
    fsize = glue_type_size_simple(module, arena, ftr, depth);
    if (fsize <= 0) {
      /** build_shux_asm SKIP_TYPECK：layout 热路径勿刷屏（LexerResult 等已 parse-only merge dep 后仍偶发失败）。 */
      if (driver_asm_build_skip_typeck() == 0)
        driver_diagnostic_typeck_struct_field_bad_size(layout_nm, layout_nlen, field_nm, flen);
      return -1;
    }
    current = current + fsize;
    if (A > max_align)
      max_align = A;
  }
  if (max_align > 0 && (current % max_align) != 0) {
    int32_t end_pad = max_align - (current % max_align);
    if (check_pad != 0 && end_pad > 0 && allow == 0) {
      driver_diagnostic_typeck_struct_padding_trailing(layout_nm, layout_nlen, end_pad);
      return -1;
    }
    current = current + end_pad;
  }
  *out_sz = current;
  *out_al = max_align > 0 ? max_align : 1;
  return 0;
}

extern void driver_diagnostic_warn_pad_fields_same_cache_line(uint8_t *sname, int32_t sname_len, uint8_t *f0,
                                                              int32_t f0_len, uint8_t *f1, int32_t f1_len);

/** SHUX_PAD_FIELDS=1 时启用 -pad-fields 伪共享警告。 */
static int glue_pad_fields_warn_enabled(void) {
  const char *e = getenv("SHUX_PAD_FIELDS");
  return e && e[0] == '1' && e[1] == '\0';
}

/** 4/8 字节标量视作 atomic 计数器候选（u32/i32/u64/i64）。 */
static int glue_field_type_atomic_sized(struct ast_Module *m, struct ast_ASTArena *a, int32_t ftr) {
  int32_t sz;
  if (!m || !a || ftr <= 0)
    return 0;
  sz = glue_type_size_simple(m, a, ftr, 0);
  return sz == 4 || sz == 8;
}

/**
 * DOD-CL -pad-fields：相邻字段落在同一 64B cache line 且均无 align(64) 时打印 warning。
 * 典型场景：atomic head 与普通 data 字段伪共享。
 */
void pipeline_typeck_pad_fields_warn_layout(struct ast_Module *module, struct ast_ASTArena *arena, int32_t li) {
  int32_t nf;
  int32_t j;
  uint8_t layout_nm[64];
  int32_t layout_nlen;
  if (!glue_pad_fields_warn_enabled() || !module || !arena || li < 0)
    return;
  nf = pipeline_module_struct_layout_num_fields(module, li);
  if (nf < 2)
    return;
  layout_nlen = pipeline_module_struct_layout_name_len(module, li);
  pipeline_module_struct_layout_name_into(module, li, layout_nm);
  for (j = 0; j + 1 < nf; j++) {
    int32_t off0 = pipeline_module_struct_layout_field_offset_at(module, li, j);
    int32_t off1 = pipeline_module_struct_layout_field_offset_at(module, li, j + 1);
    int32_t ftr0 = pipeline_module_struct_layout_field_type_ref(module, li, j);
    int32_t ftr1 = pipeline_module_struct_layout_field_type_ref(module, li, j + 1);
    int32_t al0 = pipeline_module_struct_layout_field_align_at(module, li, j);
    int32_t al1 = pipeline_module_struct_layout_field_align_at(module, li, j + 1);
    uint8_t fn0[64];
    uint8_t fn1[64];
    int32_t fl0;
    int32_t fl1;
    if (al0 >= 64 || al1 >= 64)
      continue;
    if (off0 / 64 != off1 / 64)
      continue;
    if (!glue_field_type_atomic_sized(module, arena, ftr0) && !glue_field_type_atomic_sized(module, arena, ftr1))
      continue;
    pipeline_module_struct_layout_field_name_into(module, li, j, fn0);
    pipeline_module_struct_layout_field_name_into(module, li, j + 1, fn1);
    fl0 = pipeline_module_struct_layout_field_name_len(module, li, j);
    fl1 = pipeline_module_struct_layout_field_name_len(module, li, j + 1);
    driver_diagnostic_warn_pad_fields_same_cache_line(layout_nm, layout_nlen, fn0, fl0, fn1, fl1);
  }
}

extern void driver_diagnostic_warn_hot_reorder_field(uint8_t *sname, int32_t sname_len, uint8_t *hot, int32_t hot_len,
                                                    uint8_t *cold, int32_t cold_len);

/** SHUX_HOT_REORDER=1 时启用热字段重排 hint。 */
static int glue_hot_reorder_warn_enabled(void) {
  const char *e = getenv("SHUX_HOT_REORDER");
  return e && e[0] == '1' && e[1] == '\0';
}

/**
 * DOD-CL-S2 -hot-reorder：热字段（≤4B 标量）出现在大字段（≥8B）之后时 hint。
 * 建议 hot 字段置前以减少 cache line 浪费。
 */
void pipeline_typeck_hot_reorder_warn_layout(struct ast_Module *module, struct ast_ASTArena *arena, int32_t li) {
  int32_t nf;
  int32_t j;
  int32_t i;
  uint8_t layout_nm[64];
  int32_t layout_nlen;
  if (!glue_hot_reorder_warn_enabled() || !module || !arena || li < 0)
    return;
  nf = pipeline_module_struct_layout_num_fields(module, li);
  if (nf < 2)
    return;
  layout_nlen = pipeline_module_struct_layout_name_len(module, li);
  pipeline_module_struct_layout_name_into(module, li, layout_nm);
  j = 1;
  while (j < nf) {
    int32_t ftr = pipeline_module_struct_layout_field_type_ref(module, li, j);
    int32_t sz = glue_type_size_simple(module, arena, ftr, 0);
    uint8_t hot_nm[64];
    int32_t hot_len;
    if (sz <= 0 || sz > 4) {
      j = j + 1;
      continue;
    }
    i = 0;
    while (i < j) {
      int32_t ftr_c = pipeline_module_struct_layout_field_type_ref(module, li, i);
      int32_t sz_c = glue_type_size_simple(module, arena, ftr_c, 0);
      uint8_t cold_nm[64];
      int32_t cold_len;
      if (sz_c >= 8) {
        pipeline_module_struct_layout_field_name_into(module, li, j, hot_nm);
        pipeline_module_struct_layout_field_name_into(module, li, i, cold_nm);
        hot_len = pipeline_module_struct_layout_field_name_len(module, li, j);
        cold_len = pipeline_module_struct_layout_field_name_len(module, li, i);
        driver_diagnostic_warn_hot_reorder_field(layout_nm, layout_nlen, hot_nm, hot_len, cold_nm, cold_len);
        break;
      }
      i = i + 1;
    }
    j = j + 1;
  }
}

/** 与 typeck.x typeck_x_type_align 一致（§11.1 布局步进）。 */
static int32_t glue_type_align_simple(struct ast_Module *m, struct ast_ASTArena *a, int32_t ty_ref, int32_t depth) {
  int32_t kind_ord;
  if (!a || ty_ref <= 0 || ty_ref > a->num_types || depth > 64)
    return 1;
  kind_ord = pipeline_type_kind_ord_at(a, ty_ref);
  if (kind_ord == 2)
    return 1;
  /** i32/u32/u8/f32 对齐 4；勿将 f32(14) 误为 8（否则 AoS 三 f32 字段落成 0/8/16）。 */
  if (kind_ord == 0 || kind_ord == 3 || kind_ord == 1 || kind_ord == 14)
    return 4;
  if (kind_ord == 5 || kind_ord == 4 || kind_ord == 6 || kind_ord == 7 || kind_ord == 15 || kind_ord == 9)
    return 8;
  if (kind_ord == 11)
    return 8;
  /** ARRAY / LINEAR / VECTOR：对齐取 elem（与 typeck.x ko==10/12/13 一致）。 */
  if (kind_ord == 10 || kind_ord == 12 || kind_ord == 13) {
    int32_t elem_ref = pipeline_type_elem_ref_at(a, ty_ref);
    if (elem_ref <= 0)
      return 1;
    return glue_type_align_simple(m, a, elem_ref, depth + 1);
  }
  if (kind_ord == 8) {
    int32_t sz_out = 0;
    int32_t al_out = 1;
    int32_t nlen;
    uint8_t name[64];
    int32_t k;
    nlen = pipeline_type_named_name_into(a, ty_ref, name);
    if (nlen <= 0 || nlen > 63)
      return 4;
    for (k = 0; m && k < (int32_t)m->num_struct_layouts; k++) {
      int32_t ln = pipeline_module_struct_layout_name_len(m, k);
      int32_t j;
      int32_t eq = 1;
      if (ln != nlen)
        continue;
      for (j = 0; j < nlen; j++) {
        if (pipeline_module_struct_layout_name_byte_at(m, k, j) != name[j]) {
          eq = 0;
          break;
        }
      }
      if (!eq)
        continue;
      if (glue_struct_layout_metrics_c(m, a, k, depth + 1, 0, &sz_out, &al_out) != 0)
        return 1;
      return al_out > 0 ? al_out : 1;
    }
    return 4;
  }
  return 1;
}

/** DOD-S1：SoAStruct[N] 列主序总字节数；非 SoA 时返回 0 由调用方回落 AoS。 */
extern int32_t typeck_soa_array_storage_size_glue(struct ast_Module *module, struct ast_ASTArena *arena,
                                                  int32_t elem_type_ref, int32_t array_len, int32_t depth);

/** 与 typeck.x typeck_x_type_size 一致。 */
static int32_t glue_type_size_simple(struct ast_Module *m, struct ast_ASTArena *a, int32_t ty_ref, int32_t depth) {
  int32_t kind_ord;
  if (!a || ty_ref <= 0 || ty_ref > a->num_types || depth > 64)
    return 0;
  kind_ord = pipeline_type_kind_ord_at(a, ty_ref);
  if (kind_ord == 16)
    return 0;
  if (kind_ord == 2)
    return 1;
  if (kind_ord == 0 || kind_ord == 3 || kind_ord == 1 || kind_ord == 13 || kind_ord == 14)
    return 4;
  if (kind_ord == 5 || kind_ord == 4 || kind_ord == 6 || kind_ord == 7 || kind_ord == 15 || kind_ord == 9)
    return 8;
  if (kind_ord == 11)
    return 16;
  if (kind_ord == 10 || kind_ord == 12) {
    int32_t elem_ref = pipeline_type_elem_ref_at(a, ty_ref);
    int32_t asz = pipeline_type_array_size_at(a, ty_ref);
    int32_t es;
    int32_t soa_sz;
    if (elem_ref <= 0 || asz <= 0)
      return 0;
    soa_sz = typeck_soa_array_storage_size_glue(m, a, elem_ref, asz, depth + 1);
    if (soa_sz > 0)
      return soa_sz;
    es = glue_type_size_simple(m, a, elem_ref, depth + 1);
    return es > 0 ? asz * es : 0;
  }
  if (kind_ord == 8) {
    uint8_t name[64];
    int32_t nlen;
    int32_t k;
    nlen = pipeline_type_named_name_into(a, ty_ref, name);
    if (nlen <= 0 || nlen > 63)
      return 4;
    for (k = 0; m && k < (int32_t)m->num_struct_layouts; k++) {
      int32_t ln = pipeline_module_struct_layout_name_len(m, k);
      int32_t j;
      int32_t eq = 1;
      if (ln != nlen)
        continue;
      for (j = 0; j < nlen; j++) {
        if (pipeline_module_struct_layout_name_byte_at(m, k, j) != name[j]) {
          eq = 0;
          break;
        }
      }
      if (!eq)
        continue;
      return typeck_x_type_size_from_layout_glue(m, a, k, depth + 1);
    }
    return 4;
  }
  return 0;
}

/**
 * 函数 func_index 返回类型字节宽；void/未知返回 0。
 */
static int32_t glue_func_return_byte_size_c(struct ast_Module *mod, struct ast_ASTArena *arena, int32_t func_index) {
  int32_t rty;
  if (!mod || !arena || func_index < 0 || func_index >= (int32_t)mod->num_funcs)
    return 0;
  rty = pipeline_module_func_return_type_at(mod, func_index);
  if (rty <= 0 || pipeline_type_kind_ord_at(arena, rty) == 15)
    return 0;
  return glue_type_size_simple(mod, arena, rty, 0);
}

/**
 * CALL 目标返回类型字节宽；解析失败返回 -1。
 */
static int32_t glue_call_return_byte_size_c(struct ast_ASTArena *arena, int32_t call_expr_ref) {
  struct ast_Module *mod;
  int32_t fi;
  int32_t dep_ix;
  int32_t rty;
  int32_t sz;
  struct ast_Module *sz_mod;
  if (!arena || call_expr_ref <= 0)
    return -1;
  if (glue_asm_resolve_call_target_module_c(arena, call_expr_ref, &mod, &fi, &dep_ix) != 0)
    return -1;
  if (!mod || fi < 0)
    return -1;
  rty = pipeline_module_func_return_type_at(mod, fi);
  if (rty <= 0 || pipeline_type_kind_ord_at(arena, rty) == 15)
    return 0;
  /** dep callee 的 type_ref 须映到 caller arena，否则 glue_type_size_simple 回落 4。 */
  if (dep_ix >= 0 && g_pipeline_asm_emit_dep_pipe) {
    int32_t mapped =
        pipeline_typeck_get_dep_return_type_in_caller_arena_c(dep_ix, rty, arena, g_pipeline_asm_emit_dep_pipe);
    if (mapped > 0)
      rty = mapped;
  }
  sz_mod = g_pipeline_asm_emit_module ? g_pipeline_asm_emit_module : mod;
  sz = glue_type_size_simple(sz_mod, arena, rty, 0);
  if (sz <= 0)
    sz = glue_type_size_simple(mod, arena, rty, 0);
  return sz > 0 ? sz : -1;
}

/**
 * SysV sret 写回：rbx 指向源 struct，memcpy 到 g_pipeline_asm_sret_home_off 保存的 hidden dest 指针。
 */
static int32_t glue_emit_sret_memcpy_rbx_to_home_elf_c(struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t sz,
                                                       int32_t ta) {
  static const uint8_t memcpy_sym[] = "memcpy";
  if (ta != 0 || !elf_ctx || sz <= 16 || g_pipeline_asm_sret_home_off < 0)
    return -1;
  if (backend_enc_mov_rbx_to_rax_arch(elf_ctx, ta) != 0)
    return -1;
  if (backend_enc_push_rax_arch(elf_ctx, ta) != 0)
    return -1;
  if (backend_enc_load_rbp_to_rax_arch(elf_ctx, g_pipeline_asm_sret_home_off, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 0, ta) != 0)
    return -1;
  if (backend_enc_pop_rax_arch(elf_ctx, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 1, ta) != 0)
    return -1;
  if (backend_enc_mov_imm64_to_rax_arch(elf_ctx, sz, 0, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 2, ta) != 0)
    return -1;
  return backend_enc_call_arch(elf_ctx, (uint8_t *)memcpy_sym, (int32_t)(sizeof(memcpy_sym) - 1), ta);
}

/**
 * sret 返回路径：`return local_var` 时把按值局部 struct 拷到 caller hidden dest。
 */
static int32_t glue_emit_sret_return_from_var_elf_c(struct ast_ASTArena *arena,
                                                    struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t var_expr_ref,
                                                    struct backend_AsmFuncCtx *ctx, int32_t ta) {
  uint8_t vname[64];
  int32_t vlen;
  int32_t off;
  int32_t tr;
  int32_t sz;
  if (!arena || !elf_ctx || !ctx || var_expr_ref <= 0 || !g_pipeline_asm_func_sret_active)
    return -1;
  vlen = pipeline_expr_var_name_len(arena, var_expr_ref);
  if (vlen <= 0 || vlen > 63)
    return -1;
  pipeline_expr_var_name_into(arena, var_expr_ref, vname);
  off = asm_ctx_local_find_offset_scoped((uint8_t *)ctx, arena, vname, vlen);
  if (off < 0)
    off = asm_ctx_local_find_offset((uint8_t *)ctx, vname, vlen);
  if (off < 0)
    return -1;
  tr = glue_var_decl_type_ref_elf_c(arena, ctx, var_expr_ref);
  if (tr <= 0)
    tr = pipeline_expr_resolved_type_ref(arena, var_expr_ref);
  sz = glue_type_size_simple(g_pipeline_asm_emit_module, arena, tr, 0);
  if (sz <= 16)
    return -1;
  if (glue_enc_local_slot_ptr_or_addr_rbx_elf_c(arena, elf_ctx, var_expr_ref, off, ctx, ta) != 0)
    return -1;
  return glue_emit_sret_memcpy_rbx_to_home_elf_c(elf_ctx, sz, ta);
}

/**
 * 大 struct（>16B）按值返回：callee 在 rax 放指向栈上结果的指针，memcpy 到 let 槽。
 */
static int32_t glue_copy_large_struct_from_rax_ptr_elf_c(struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t slot_off,
                                                         int32_t sz, int32_t ta) {
  static const uint8_t memcpy_sym[] = "memcpy";
  if (ta != 0 || sz <= 16)
    return -1;
  if (backend_enc_push_rax_arch(elf_ctx, ta) != 0)
    return -1;
  if (backend_enc_lea_rbp_to_rax_arch(elf_ctx, slot_off, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 0, ta) != 0)
    return -1;
  if (backend_enc_pop_rax_arch(elf_ctx, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 1, ta) != 0)
    return -1;
  if (backend_enc_mov_imm64_to_rax_arch(elf_ctx, sz, 0, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 2, ta) != 0)
    return -1;
  return backend_enc_call_arch(elf_ctx, (uint8_t *)memcpy_sym, (int32_t)(sizeof(memcpy_sym) - 1), ta);
}

/**
 * CALL/expr 结果落 let 栈槽：先写 rax 半；9–16B struct（SysV x86）再写 rdx 半；>16B 经 rax 指针 memcpy。
 */
static int32_t glue_store_retval_pair_to_rbp_elf_c(struct ast_Module *m, struct ast_ASTArena *arena,
                                                   struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t ty_ref,
                                                   int32_t slot_off, int32_t ta, int32_t init_ref) {
  int32_t sz;
  if (!elf_ctx)
    return -1;
  sz = glue_type_size_simple(m, arena, ty_ref, 0);
  if (sz > 16 && init_ref > 0 && arena && pipeline_expr_kind_ord_at(arena, init_ref) == 48)
    return glue_copy_large_struct_from_rax_ptr_elf_c(elf_ctx, slot_off, sz, ta);
  if (sz > 8 && sz <= 16 && init_ref > 0 && arena &&
      glue_call_struct16_ret_needs_rax_deref_c(arena, init_ref) != 0) {
    if (glue_deref_struct16_rax_ptr_elf_c(elf_ctx, ta) != 0)
      return -1;
  }
  if (backend_enc_store_rax_to_rbp_arch(elf_ctx, slot_off, ta) != 0)
    return -1;
  if (ta != 0 || !m || !arena || ty_ref <= 0)
    return 0;
  if (sz > 8 && sz <= 16) {
    /** fp 负偏移：slot_off 越大地址越低；第二 half 在 struct+8 即 slot_off-8。 */
    if (backend_enc_store_rdx_to_rbp_arch(elf_ctx, slot_off - 8, ta) != 0)
      return -1;
  }
  return 0;
}

/** 导出给 backend_call_dispatch：形参/局部 type_ref 字节大小（与 typeck 一致）。 */
int32_t pipeline_asm_type_ref_byte_size_c(struct ast_ASTArena *arena, int32_t ty_ref) {
  return glue_type_size_simple(g_pipeline_asm_emit_module, arena, ty_ref, 0);
}

/**
 * 按 §11.1 + field_align(N) 动态计算 layout li 第 fj 字段字节偏移（权威值，勿信仅 fi*8 回退）。
 * 未命中 layout/字段时返回 fj*8。
 */
static int32_t glue_struct_layout_compute_field_offset_c(struct ast_Module *m, struct ast_ASTArena *a, int32_t li,
                                                       int32_t fj) {
  int32_t current;
  int32_t j;
  int32_t nf;
  if (!m || !a || li < 0 || li >= pipeline_module_num_struct_layouts_at(m) || fj < 0)
    return fj >= 0 ? fj * 8 : 0;
  nf = pipeline_module_struct_layout_num_fields(m, li);
  if (fj >= nf)
    return fj * 8;
  current = 0;
  for (j = 0; j <= fj; j++) {
    int32_t ftr = pipeline_module_struct_layout_field_type_ref(m, li, j);
    int32_t A = glue_type_align_simple(m, a, ftr, 0);
    int32_t fa;
    int32_t rem;
    int32_t gap;
    int32_t fsize;
    if (A <= 0)
      A = 1;
    fa = pipeline_module_struct_layout_field_align_at(m, li, j);
    if (fa > A)
      A = fa;
    rem = current % A;
    gap = A - rem;
    gap = gap % A;
    if (j == fj)
      return current + gap;
    current = current + gap;
    fsize = glue_type_size_simple(m, a, ftr, 0);
    if (fsize <= 0)
      fsize = 4;
    current = current + fsize;
  }
  return fj * 8;
}

/**
 * 将 module 各 struct layout 的 field_offset 同步为 glue_struct_layout_compute_field_offset_c 结果。
 * skip .x typeck 的 asm emit 前调用，使 align(64) 等字段偏移落盘（DOD-CL-S1）。
 */
static void glue_sync_struct_layout_field_offsets_c(struct ast_Module *m, struct ast_ASTArena *a) {
  int32_t li;
  int32_t nf;
  int32_t j;
  if (!m || !a)
    return;
  for (li = 0; li < pipeline_module_num_struct_layouts_at(m); li++) {
    nf = pipeline_module_struct_layout_num_fields(m, li);
    for (j = 0; j < nf; j++) {
      int32_t off = glue_struct_layout_compute_field_offset_c(m, a, li, j);
      pipeline_module_struct_layout_set_field_offset(m, li, j, off);
    }
    if (getenv("SHUX_ASM_DEBUG") && li == 0) {
      uint8_t fn0[64];
      uint8_t fn1[64];
      memset(fn0, 0, sizeof(fn0));
      memset(fn1, 0, sizeof(fn1));
      if (nf > 0)
        pipeline_module_struct_layout_field_name_into(m, li, 0, fn0);
      if (nf > 1)
        pipeline_module_struct_layout_field_name_into(m, li, 1, fn1);
      fprintf(stderr, "shux: layout0 nf=%d f0=%.4s off0=%d fa0=%d f1=%.4s off1=%d fa1=%d\n", (int)nf, fn0,
              (int)glue_struct_layout_compute_field_offset_c(m, a, li, 0),
              (int)pipeline_module_struct_layout_field_align_at(m, li, 0), fn1,
              nf > 1 ? (int)glue_struct_layout_compute_field_offset_c(m, a, li, 1) : -1,
              nf > 1 ? (int)pipeline_module_struct_layout_field_align_at(m, li, 1) : -1);
    }
  }
}

/**
 * 在 layout li 中按字段名查动态偏移；未命中返回 -1。
 */
static int32_t glue_struct_layout_field_offset_by_name_c(struct ast_Module *m, struct ast_ASTArena *a, int32_t li,
                                                         uint8_t *field_name, int32_t flen) {
  int32_t j;
  if (!m || !a || li < 0 || !field_name || flen <= 0)
    return -1;
  for (j = 0; j < pipeline_module_struct_layout_num_fields(m, li); j++) {
    int32_t fnlen = pipeline_module_struct_layout_field_name_len(m, li, j);
    int32_t feq = 1;
    int32_t fi;
    if (fnlen != flen)
      continue;
    for (fi = 0; fi < fnlen; fi++) {
      uint8_t fb[64];
      pipeline_module_struct_layout_field_name_into(m, li, j, fb);
      if (fb[fi] != field_name[fi]) {
        feq = 0;
        break;
      }
    }
    if (!feq)
      continue;
    return glue_struct_layout_compute_field_offset_c(m, a, li, j);
  }
  return -1;
}

/**
 * 按 struct 类型名查 layout 下标；单 layout 入口模块时 layout 名偶发空仍返回 0（DOD-CL-S1 fallback）。
 */
static int32_t glue_struct_layout_index_by_type_name_c(struct ast_Module *m, uint8_t *struct_name, int32_t nlen) {
  int32_t k;
  int32_t j;
  if (!m || !struct_name || nlen <= 0 || nlen > 63)
    return -1;
  for (k = 0; k < (int32_t)m->num_struct_layouts; k++) {
    int32_t ln = pipeline_module_struct_layout_name_len(m, k);
    int32_t eq = 1;
    if (ln != nlen)
      continue;
    for (j = 0; j < nlen; j++) {
      if (pipeline_module_struct_layout_name_byte_at(m, k, j) != struct_name[j]) {
        eq = 0;
        break;
      }
    }
    if (eq)
      return k;
  }
  if (m->num_struct_layouts == 1)
    return 0;
  return -1;
}

/**
 * 在 layout_idx 上为下一字段（类型 new_field_type_ref）计算 §11.1 对齐后的字节偏移；
 * field_align_req 为 align(N) 指定的最小对齐（0 表示仅类型对齐）。
 */
int32_t pipeline_struct_layout_next_field_offset_ex(struct ast_Module *m, struct ast_ASTArena *a, int32_t layout_idx,
                                                    int32_t new_field_type_ref, int32_t field_align_req) {
  int32_t current;
  int32_t nf;
  int32_t j;
  int32_t A;
  int32_t rem;
  int32_t gap;
  if (!m || layout_idx < 0)
    return 0;
  current = 0;
  nf = pipeline_module_struct_layout_num_fields(m, layout_idx);
  /** packed：字段紧密排列，无对齐填充（内存契约 §11.1 packed）。 */
  if (pipeline_module_struct_layout_packed_at(m, layout_idx)) {
    for (j = 0; j < nf; j++) {
      int32_t ftr = pipeline_module_struct_layout_field_type_ref(m, layout_idx, j);
      int32_t fsize = glue_type_size_simple(m, a, ftr, 0);
      if (fsize <= 0)
        fsize = 4;
      current = current + fsize;
    }
    return current;
  }
  for (j = 0; j < nf; j++) {
    int32_t ftr = pipeline_module_struct_layout_field_type_ref(m, layout_idx, j);
    int32_t fsize;
    int32_t fa = pipeline_module_struct_layout_field_align_at(m, layout_idx, j);
    A = glue_type_align_simple(m, a, ftr, 0);
    if (A <= 0)
      A = 1;
    if (fa > A)
      A = fa;
    fsize = glue_type_size_simple(m, a, ftr, 0);
    if (fsize <= 0)
      fsize = 4;
    rem = current % A;
    gap = A - rem;
    gap = gap % A;
    current = current + gap + fsize;
  }
  A = glue_type_align_simple(m, a, new_field_type_ref, 0);
  if (A <= 0)
    A = 1;
  if (field_align_req > A)
    A = field_align_req;
  rem = current % A;
  gap = A - rem;
  gap = gap % A;
  return current + gap;
}

/**
 * 在 layout_idx 上为下一字段（类型 new_field_type_ref）计算 §11.1 对齐后的字节偏移；
 * parser struct 定义与 struct_lit 登记须用此值，勿 off+=8。
 */
int32_t pipeline_struct_layout_next_field_offset(struct ast_Module *m, struct ast_ASTArena *a, int32_t layout_idx,
                                               int32_t new_field_type_ref) {
  return pipeline_struct_layout_next_field_offset_ex(m, a, layout_idx, new_field_type_ref, 0);
}

/**
 * EXPR_STRUCT_LIT 按 module.struct_layouts 计算的字节大小；用于 asm 小结构体按值经 x0 返回（≤8）。
 * 未命中布局时返回 0，由 backend 退回指针语义。
 */
int32_t pipeline_expr_struct_lit_value_bytes(struct ast_ASTArena *a, struct ast_Module *m, int32_t expr_ref) {
  struct ast_Expr *ex;
  int32_t nlen;
  uint8_t name[64];
  int32_t k;
  int32_t sz_out;
  int32_t al_out;
  if (!a || !m || expr_ref <= 0)
    return 0;
  ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex || ex->kind != ast_ExprKind_EXPR_STRUCT_LIT)
    return 0;
  nlen = ex->struct_lit_struct_name_len;
  if (nlen <= 0 || nlen > 63)
    return 0;
  memcpy(name, ex->struct_lit_struct_name, (size_t)nlen);
  for (k = 0; k < (int32_t)m->num_struct_layouts; k++) {
    int32_t ln;
    int32_t j;
    int32_t eq;
    ln = pipeline_module_struct_layout_name_len(m, k);
    if (ln != nlen)
      continue;
    eq = 1;
    for (j = 0; j < nlen; j++) {
      if (pipeline_module_struct_layout_name_byte_at(m, k, j) != name[j]) {
        eq = 0;
        break;
      }
    }
    if (!eq)
      continue;
    sz_out = 0;
    al_out = 1;
    if (glue_struct_layout_metrics_c(m, a, k, 0, 0, &sz_out, &al_out) != 0)
      return 0;
    return sz_out > 0 ? sz_out : 0;
  }
  return 0;
}

/**
 * STRUCT_LIT 第 field_ix 字段在布局中的字节偏移；供 asm 按 layout 存字段（勿用 fi*8）。
 */
int32_t pipeline_expr_struct_lit_field_offset_at(struct ast_ASTArena *a, struct ast_Module *m, int32_t expr_ref,
                                                 int32_t field_ix) {
  struct ast_Expr *ex;
  int32_t nlen;
  uint8_t name[64];
  int32_t k;
  if (!a || !m || expr_ref <= 0 || field_ix < 0)
    return field_ix * 8;
  ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex || ex->kind != ast_ExprKind_EXPR_STRUCT_LIT)
    return field_ix * 8;
  nlen = ex->struct_lit_struct_name_len;
  if (nlen <= 0 || nlen > 63) {
    /** 类型名缺失时单 layout 入口模块仍可按 field_ix 查 offset（DOD-CL-S1）。 */
    if (m->num_struct_layouts == 1 && field_ix < pipeline_module_struct_layout_num_fields(m, 0))
      return glue_struct_layout_compute_field_offset_c(m, a, 0, field_ix);
    return field_ix * 8;
  }
  memcpy(name, ex->struct_lit_struct_name, (size_t)nlen);
  k = glue_struct_layout_index_by_type_name_c(m, name, nlen);
  if (k >= 0 && field_ix < pipeline_module_struct_layout_num_fields(m, k))
    return glue_struct_layout_compute_field_offset_c(m, a, k, field_ix);
  return field_ix * 8;
}

/** STRUCT_LIT 第 field_ix 字段在 layout 中的类型 ref；未命中时返回 0。 */
int32_t pipeline_expr_struct_lit_field_type_ref_at(struct ast_ASTArena *a, struct ast_Module *m, int32_t expr_ref,
                                                 int32_t field_ix) {
  struct ast_Expr *ex;
  int32_t nlen;
  uint8_t name[64];
  int32_t k;
  if (!a || !m || expr_ref <= 0 || field_ix < 0)
    return 0;
  ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex || ex->kind != ast_ExprKind_EXPR_STRUCT_LIT)
    return 0;
  nlen = ex->struct_lit_struct_name_len;
  if (nlen <= 0 || nlen > 63)
    return 0;
  memcpy(name, ex->struct_lit_struct_name, (size_t)nlen);
  for (k = 0; k < (int32_t)m->num_struct_layouts; k++) {
    int32_t ln;
    int32_t j;
    int32_t eq;
    ln = pipeline_module_struct_layout_name_len(m, k);
    if (ln != nlen)
      continue;
    eq = 1;
    for (j = 0; j < nlen; j++) {
      if (pipeline_module_struct_layout_name_byte_at(m, k, j) != name[j]) {
        eq = 0;
        break;
      }
    }
    if (!eq)
      continue;
    if (field_ix < pipeline_module_struct_layout_num_fields(m, k))
      return pipeline_module_struct_layout_field_type_ref(m, k, field_ix);
    return 0;
  }
  return 0;
}

/** struct_lit 字段名/init 读 API 见 ast_pool.c（侧车池）。 */

/** 读 expr.kind 序数；无效 ref 返回 -1。 */
int32_t pipeline_expr_kind_ord_at(struct ast_ASTArena *a, int32_t expr_ref) {
  enum ast_ExprKind kd;
  if (!a || expr_ref <= 0 || expr_ref > a->num_exprs)
    return -1;
  kd = glue_arena_expr_kind_at_ref(a, expr_ref);
  return (int32_t)kd;
}

/** 读 EXPR_LIT/EXPR_BOOL_LIT 的 int_val；backend asm 勿 ast_arena_expr_get 整颗 Expr（大模块栈溢出）。 */
int32_t pipeline_expr_int_val_at(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  return ex ? (int32_t)ex->int_val : 0;
}

/** 读 EXPR_LIT 完整 i64 字面量（避免 int32 截断，P0-4 INT64_MIN 大常数）。 */
int64_t pipeline_expr_int64_val_at(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  return ex ? ex->int_val : 0;
}

/**
 * EXPR_LIT 默认 resolved 类型：|v|≤i32 用 i32，否则 i64。
 * typeck_gen seed 与 typeck.x 共用，避免 seed 漂移时大整数字面量误推 i32。
 */
int32_t pipeline_typeck_check_expr_int_lit_c(struct ast_ASTArena *arena, int32_t expr_ref) {
  struct ast_Expr *ex;
  int64_t v;
  int32_t ty;

  if (!arena || expr_ref <= 0 || expr_ref > arena->num_exprs)
    return 0;
  ex = glue_arena_expr_at_ref(arena, expr_ref);
  if (!ex || ex->resolved_type_ref != 0)
    return 0;
  v = ex->int_val;
  if (v > (int64_t)INT32_MAX || v < (int64_t)INT32_MIN)
    ty = pipeline_type_ensure_by_kind_ord(arena, (int32_t)ast_TypeKind_TYPE_I64);
  else
    ty = pipeline_type_ensure_by_kind_ord(arena, (int32_t)ast_TypeKind_TYPE_I32);
  if (ty != 0)
    ex->resolved_type_ref = ty;
  return 0;
}

/**
 * 读 expr.unary_operand_ref；无效 ref 返回 0。
 * typeck.x check_block_impl 块末 `return;` 判定须用此 glue，勿 `let fin_ex: Expr = ast_arena_expr_get` 再读字段（自举 asm FIELD_ACCESS 失败）。
 */
int32_t pipeline_expr_unary_operand_ref_at(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  return ex ? ex->unary_operand_ref : 0;
}

/** FIELD_ACCESS 字段名 memcpy 到 out64（最多 63 字节 + 清零）。 */
void pipeline_expr_field_access_name_into(struct ast_ASTArena *a, int32_t expr_ref, uint8_t *out64) {
  struct ast_Expr *ex;
  int32_t nlen;
  if (!out64)
    return;
  ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex) {
    memset(out64, 0, 64);
    return;
  }
  nlen = ex->field_access_field_len;
  if (nlen < 0)
    nlen = 0;
  if (nlen > 63)
    nlen = 63;
  memset(out64, 0, 64);
  if (nlen > 0)
    memcpy(out64, ex->field_access_field_name, (size_t)nlen);
}

/** FIELD_ACCESS 字段名长度；非 FIELD_ACCESS 或无效 ref 返回 0。 */
int32_t pipeline_expr_field_access_name_len(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex || ex->kind != ast_ExprKind_EXPR_FIELD_ACCESS)
    return 0;
  return ex->field_access_field_len;
}

/** FIELD_ACCESS base_ref；非 FIELD_ACCESS 返回 0。 */
int32_t pipeline_expr_field_access_base_ref(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex || ex->kind != ast_ExprKind_EXPR_FIELD_ACCESS)
    return 0;
  return ex->field_access_base_ref;
}

/** EXPR_VAR 变量名 memcpy 到 out64（最多 63 字节 + 清零）。 */
void pipeline_expr_var_name_into(struct ast_ASTArena *a, int32_t expr_ref, uint8_t *out64) {
  struct ast_Expr *ex;
  int32_t nlen;
  if (!out64)
    return;
  ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex) {
    memset(out64, 0, 64);
    return;
  }
  nlen = ex->var_name_len;
  if (nlen < 0)
    nlen = 0;
  if (nlen > 63)
    nlen = 63;
  memset(out64, 0, 64);
  if (nlen > 0)
    memcpy(out64, ex->var_name, (size_t)nlen);
}

/** STRING_LIT（kind 59）字节长度；非字面量返回 0。 */
int32_t pipeline_expr_var_name_len_for_string_lit_c(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex || (int32_t)ex->kind != 59)
    return 0;
  return ex->var_name_len;
}

/** EXPR_VAR 名长度；非 VAR 或无效 ref 返回 0。 */
int32_t pipeline_expr_var_name_len(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex || ex->kind != ast_ExprKind_EXPR_VAR)
    return 0;
  return ex->var_name_len;
}

/** 读 expr.binop_left_ref；无效 ref 返回 0。 */
int32_t pipeline_expr_binop_left_ref_at(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  return ex ? ex->binop_left_ref : 0;
}

/** 读 expr.binop_right_ref；无效 ref 返回 0。 */
int32_t pipeline_expr_binop_right_ref_at(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  return ex ? ex->binop_right_ref : 0;
}

/**
 * 比较表达式 ELF 发射（EQ/NE/LT/LE/GT/GE 全在 C 内，避免 backend.x 经 shux-c -E 后
 * EXPR_NE(15) 与字面量/分支条件误合并，导致 != 恒与 0 比较）。
 */
/** 比较 TypeKind 变体名；flen 允许多 1 尾字节，与 glue_enum_field_name_equal 一致。 */
static int32_t pipeline_asm_typekind_variant_tag(const uint8_t *field_buf, int32_t flen) {
  if (!field_buf || flen < 7)
    return -1;
  if (flen >= 7 && memcmp(field_buf, "TYPE_I32", 7) == 0)
    return 0;
  if (flen >= 8 && memcmp(field_buf, "TYPE_BOOL", 8) == 0)
    return 1;
  if (flen >= 6 && memcmp(field_buf, "TYPE_U8", 6) == 0)
    return 2;
  if (flen >= 7 && memcmp(field_buf, "TYPE_U32", 7) == 0)
    return 3;
  if (flen >= 7 && memcmp(field_buf, "TYPE_U64", 7) == 0)
    return 4;
  if (flen >= 7 && memcmp(field_buf, "TYPE_I64", 7) == 0)
    return 5;
  if (flen >= 9 && memcmp(field_buf, "TYPE_USIZE", 9) == 0)
    return 6;
  if (flen >= 9 && memcmp(field_buf, "TYPE_ISIZE", 9) == 0)
    return 7;
  if (flen >= 9 && memcmp(field_buf, "TYPE_NAMED", 9) == 0)
    return 8;
  if (flen >= 7 && memcmp(field_buf, "TYPE_PTR", 7) == 0)
    return 9;
  if (flen >= 9 && memcmp(field_buf, "TYPE_ARRAY", 9) == 0)
    return 10;
  if (flen >= 9 && memcmp(field_buf, "TYPE_SLICE", 9) == 0)
    return 11;
  if (flen >= 11 && memcmp(field_buf, "TYPE_VECTOR", 11) == 0)
    return 12;
  if (flen >= 7 && memcmp(field_buf, "TYPE_F32", 7) == 0)
    return 13;
  if (flen >= 7 && memcmp(field_buf, "TYPE_F64", 7) == 0)
    return 14;
  if (flen >= 8 && memcmp(field_buf, "TYPE_VOID", 8) == 0)
    return 15;
  return -1;
}

/** 右操作数为 TypeKind/ExprKind 枚举 FIELD_ACCESS 时返回 tag，否则 -1（不查 module 字段，避免 typeck_x_ast 中 module.x 误触）。 */
static int32_t pipeline_asm_cmp_enum_rhs_tag_c(struct ast_ASTArena *arena, int32_t expr_ref) {
  struct ast_Expr *ex;
  uint8_t base_buf[32];
  uint8_t field_buf[64];
  int32_t blen;
  int32_t flen;
  int32_t tag;
  if (!arena || expr_ref <= 0 || pipeline_expr_kind_ord_at(arena, expr_ref) != 44)
    return -1;
  ex = glue_arena_expr_at_ref(arena, expr_ref);
  if (!ex || ex->field_access_base_ref <= 0)
    return -1;
  if (pipeline_expr_kind_ord_at(arena, ex->field_access_base_ref) != 3)
    return -1;
  blen = pipeline_expr_var_name_len(arena, ex->field_access_base_ref);
  if (blen != 8)
    return -1;
  pipeline_expr_var_name_into(arena, ex->field_access_base_ref, base_buf);
  flen = pipeline_expr_field_access_name_len(arena, expr_ref);
  if (flen <= 0 || flen > 63)
    return -1;
  pipeline_expr_field_access_name_into(arena, expr_ref, field_buf);
  if (memcmp(base_buf, "TypeKind", 8) == 0)
    return pipeline_asm_typekind_variant_tag(field_buf, flen);
  if (memcmp(base_buf, "ExprKind", 8) != 0)
    return -1;
  tag = pipeline_expr_enum_namespace_field_tag(arena, expr_ref);
  return tag;
}

/**
 * 判断 TypeKind 是否为 64-bit 整数/指针类型（需 64-bit cmpq）。
 * TYPE_U64=4, TYPE_I64=5, TYPE_USIZE=6, TYPE_ISIZE=7, TYPE_PTR=9。
 */
static int32_t glue_type_kind_is_64bit_int(int32_t kind) {
  return kind == 4 || kind == 5 || kind == 6 || kind == 7 || kind == 9;
}

/**
 * 【Why】x86_64 的 enc_cmp_rbx_rax 硬编码 32-bit cmpl（39 C3），i64/u64/usize/isize/ptr
 *        比较时高 32 位被截断，导致 mmap 返回地址等 64-bit 值的 <= 比较误判为负。
 *        修复：64-bit 比较前发射 REX.W 前缀（0x48），使 cmpl 升级为 cmpq。
 * 【Invariant】仅在 ta==0（x86_64）且 is_64bit 时发射 1 字节 0x48；其他架构 no-op。
 *              REX.W 必须紧贴 cmp 指令前，中间不得插入其他字节。
 * 【Asm/Perf】48 39 C3 = cmpq %rax, %rbx（64-bit 比较，置标志位供后续 setcc 用）。
 */
static int32_t glue_emit_rex_w_if_64bit(struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t is_64bit, int32_t ta) {
  if (is_64bit && ta == 0) {
    uint8_t rex_w[1] = { 0x48 };
    return pipeline_elf_ctx_append_bytes((uint8_t *)elf_ctx, rex_w, 1);
  }
  return 0;
}

int32_t pipeline_asm_emit_cmp_elf(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                  int32_t cmp_expr_ref, struct backend_AsmFuncCtx *ctx, int32_t ta) {
  int32_t right_ref;
  int32_t left_ref;
  int32_t lit_imm;
  int32_t cc;
  int32_t enum_tag;
  int32_t cmp_ko;
  int32_t is_cmp_64bit;
  int32_t lt_ref;
  int32_t lt_kind;
  struct ast_Expr *e;
  if (!arena || cmp_expr_ref <= 0)
    return -1;
  e = glue_arena_expr_at_ref(arena, cmp_expr_ref);
  if (e && e->const_folded_valid != 0)
    return backend_enc_mov_imm32_to_w0_arch(elf_ctx, e->const_folded_val, ta);
  cmp_ko = pipeline_expr_kind_ord_at(arena, cmp_expr_ref);
  left_ref = pipeline_expr_binop_left_ref_at(arena, cmp_expr_ref);
  right_ref = pipeline_expr_binop_right_ref_at(arena, cmp_expr_ref);
  /* 获取左操作数类型判断是否 64-bit 比较（i64/u64/usize/isize/ptr），
   * 64-bit 时 x86_64 需 REX.W 前缀将 cmpl 升级为 cmpq，避免高 32 位截断。 */
  is_cmp_64bit = 0;
  if (left_ref > 0) {
    struct ast_Expr *le = pipeline_arena_expr_ptr(arena, left_ref);
    if (le) {
      lt_ref = le->resolved_type_ref;
      if (lt_ref > 0) {
        lt_kind = pipeline_type_kind_ord_at(arena, lt_ref);
        is_cmp_64bit = glue_type_kind_is_64bit_int(lt_kind);
      }
    }
  }
  /**
   * CALL 与字面量 0 比较（while/if 内 pipeline_loop_* / sync_one 等）：
   * 勿 mov rax→rbx + imm 0 cmp（CALL 后 tear/patch 易失败）；test eax + setcc 归一化 bool。
   */
  if (left_ref > 0 && right_ref > 0 && pipeline_expr_kind_ord_at(arena, left_ref) == 48) {
    int32_t lit_ok = pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm);
    if (getenv("SHUX_ASM_DEBUG") && cmp_ko == 15)
      fprintf(stderr, "shux: cmp_call0 left=%d lit_ok=%d lit=%d cmp_ko=%d\n", (int)left_ref, (int)lit_ok, (int)lit_imm,
              (int)cmp_ko);
  }
  if (left_ref > 0 && right_ref > 0 && pipeline_expr_kind_ord_at(arena, left_ref) == 48 &&
      pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm) && lit_imm == 0 &&
      (cmp_ko == 14 || cmp_ko == 15)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
      return -1;
    cc = pipeline_asm_cmp_cc_for_expr_kind_ord(cmp_ko);
    if (cc < 0)
      return -1;
    if (glue_emit_rex_w_if_64bit(elf_ctx, is_cmp_64bit, ta) != 0)
      return -1;
    if (backend_enc_test_eax_eax_arch(elf_ctx, ta) != 0)
      return -1;
    if (backend_enc_cmp_setcc_movzbl_arch(elf_ctx, cc, ta) != 0)
      return -1;
    return 0;
  }
  /** TypeKind.TYPE_I32 等枚举右操作数：左+立即数 cmp，避免 push/rec 右子树。 */
  if (right_ref > 0 && (enum_tag = pipeline_asm_cmp_enum_rhs_tag_c(arena, right_ref)) >= 0) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, cmp_expr_ref), ctx,
                                       ta) != 0)
      return -1;
    if (backend_enc_mov_rax_to_rbx_arch(elf_ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_w0_arch(elf_ctx, enum_tag, ta) != 0)
      return -1;
    cc = pipeline_asm_cmp_cc_for_expr_kind_ord(pipeline_expr_kind_ord_at(arena, cmp_expr_ref));
    if (cc < 0)
      return -1;
    if (glue_emit_rex_w_if_64bit(elf_ctx, is_cmp_64bit, ta) != 0)
      return -1;
    if (backend_enc_cmp_rbx_rax_arch(elf_ctx, ta) != 0)
      return -1;
    return backend_enc_cmp_setcc_movzbl_arch(elf_ctx, cc, ta);
  }
  /** while 头 VAR vs 字面量：rbp 直 load+cmp，勿 rec emit left 再 mov rax→rbx（tear 易失败）。 */
  if (left_ref > 0 && right_ref > 0 && pipeline_expr_kind_ord_at(arena, left_ref) == GLUE_EXPR_KIND_VAR &&
      pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm)) {
    int32_t var_off = glue_var_expr_stack_off_elf_c(arena, ctx, left_ref);
    if (var_off >= 0) {
      cc = pipeline_asm_cmp_cc_for_expr_kind_ord(cmp_ko);
      if (cc < 0)
        return -1;
      if (backend_enc_load_rbp_to_rbx_arch(elf_ctx, var_off, ta) != 0)
        return -1;
      if (backend_enc_mov_imm32_to_w0_arch(elf_ctx, lit_imm, ta) != 0)
        return -1;
      if (glue_emit_rex_w_if_64bit(elf_ctx, is_cmp_64bit, ta) != 0)
        return -1;
      if (backend_enc_cmp_rbx_rax_arch(elf_ctx, ta) != 0)
        return -1;
      return backend_enc_cmp_setcc_movzbl_arch(elf_ctx, cc, ta);
    }
  }
  if (right_ref != 0 && pipeline_asm_expr_lit_i32_at_c(arena, right_ref, &lit_imm)) {
    if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, pipeline_expr_binop_left_ref_at(arena, cmp_expr_ref), ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_rax_to_rbx_arch(elf_ctx, ta) != 0)
      return -1;
    if (backend_enc_mov_imm32_to_w0_arch(elf_ctx, lit_imm, ta) != 0)
      return -1;
    cc = pipeline_asm_cmp_cc_for_expr_kind_ord(pipeline_expr_kind_ord_at(arena, cmp_expr_ref));
    if (cc < 0)
      return -1;
    if (glue_emit_rex_w_if_64bit(elf_ctx, is_cmp_64bit, ta) != 0)
      return -1;
    if (backend_enc_cmp_rbx_rax_arch(elf_ctx, ta) != 0)
      return -1;
    return backend_enc_cmp_setcc_movzbl_arch(elf_ctx, cc, ta);
  }
  {
    int32_t left_ref;
    int32_t vr;
    left_ref = pipeline_expr_binop_left_ref_at(arena, cmp_expr_ref);
    vr = glue_try_binop_cmp_rbx_rax_elf_c(arena, elf_ctx, left_ref, right_ref, ctx, ta);
    if (vr == -1)
      return -1;
    if (vr == -2) {
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, left_ref, ctx, ta) != 0)
        return -1;
      if (backend_enc_push_rax_arch(elf_ctx, ta) != 0)
        return -1;
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, right_ref, ctx, ta) != 0)
        return -1;
      if (backend_enc_pop_rbx_arch(elf_ctx, ta) != 0)
        return -1;
    }
  }
  cc = pipeline_asm_cmp_cc_for_expr_kind_ord(pipeline_expr_kind_ord_at(arena, cmp_expr_ref));
  if (cc < 0)
    return -1;
  if (glue_emit_rex_w_if_64bit(elf_ctx, is_cmp_64bit, ta) != 0)
    return -1;
  if (backend_enc_cmp_rbx_rax_arch(elf_ctx, ta) != 0)
    return -1;
  return backend_enc_cmp_setcc_movzbl_arch(elf_ctx, cc, ta);
}

int32_t ast_pipeline_block_if_cond_ref(struct ast_ASTArena *a, int32_t br, int32_t ii);
int32_t ast_pipeline_block_if_then_body_ref(struct ast_ASTArena *a, int32_t br, int32_t ii);
int32_t ast_pipeline_block_if_else_body_ref(struct ast_ASTArena *a, int32_t br, int32_t ii);
int32_t ast_ast_block_num_consts(struct ast_ASTArena *a, int32_t br);
int32_t ast_ast_block_num_lets(struct ast_ASTArena *a, int32_t br);
int32_t ast_ast_block_num_stmt_order(struct ast_ASTArena *a, int32_t br);
uint8_t ast_ast_block_stmt_order_kind(struct ast_ASTArena *a, int32_t br, int32_t si);
int32_t ast_ast_block_stmt_order_idx(struct ast_ASTArena *a, int32_t br, int32_t si);
int32_t ast_ast_block_num_loops(struct ast_ASTArena *a, int32_t br);
int32_t ast_ast_block_num_for_loops(struct ast_ASTArena *a, int32_t br);
int32_t ast_ast_block_num_if_stmts(struct ast_ASTArena *a, int32_t br);
int32_t ast_ast_block_num_regions(struct ast_ASTArena *a, int32_t br);
int32_t ast_ast_block_region_body_ref(struct ast_ASTArena *a, int32_t br, int32_t ri);
int32_t ast_ast_block_num_expr_stmts(struct ast_ASTArena *a, int32_t br);
int32_t ast_ast_block_while_cond_ref(struct ast_ASTArena *a, int32_t br, int32_t wi);
int32_t ast_ast_block_while_body_ref(struct ast_ASTArena *a, int32_t br, int32_t wi);
int32_t ast_ast_block_for_init_ref(struct ast_ASTArena *a, int32_t br, int32_t fi);
int32_t ast_ast_block_for_cond_ref(struct ast_ASTArena *a, int32_t br, int32_t fi);
int32_t ast_ast_block_for_step_ref(struct ast_ASTArena *a, int32_t br, int32_t fi);
int32_t ast_ast_block_for_body_ref(struct ast_ASTArena *a, int32_t br, int32_t fi);
int32_t ast_ast_block_if_cond_ref(struct ast_ASTArena *a, int32_t br, int32_t ii);
int32_t ast_ast_block_if_then_body_ref(struct ast_ASTArena *a, int32_t br, int32_t ii);
/** WPO-S3 typeck_block_tree_has_var_c 等于 10313 块；定义见 ast_ast_block_if_else_body_ref。 */
int32_t ast_ast_block_if_else_body_ref(struct ast_ASTArena *a, int32_t br, int32_t ii);
int32_t ast_pipeline_block_const_init_ref(struct ast_ASTArena *a, int32_t br, int32_t ci);
int32_t ast_pipeline_block_let_init_ref(struct ast_ASTArena *a, int32_t br, int32_t li);
int32_t ast_pipeline_block_const_name_len(struct ast_ASTArena *a, int32_t br, int32_t ci);
void ast_pipeline_block_const_name_copy64(struct ast_ASTArena *a, int32_t br, int32_t ci, uint8_t *dst);
int32_t ast_pipeline_block_let_name_len(struct ast_ASTArena *a, int32_t br, int32_t li);
void ast_pipeline_block_let_name_copy64(struct ast_ASTArena *a, int32_t br, int32_t li, uint8_t *dst);
int32_t pipeline_block_let_name_len(struct ast_ASTArena *a, int32_t br, int32_t li);
void pipeline_block_let_name_copy64(struct ast_ASTArena *a, int32_t br, int32_t li, uint8_t *dst);
int32_t pipeline_block_let_type_ref(struct ast_ASTArena *a, int32_t br, int32_t li);
int32_t pipeline_expr_resolved_type_ref(struct ast_ASTArena *a, int32_t expr_ref);
int32_t pipeline_expr_kind_ord_at(struct ast_ASTArena *a, int32_t expr_ref);
int32_t ast_pipeline_expr_array_lit_num_elems_at(struct ast_ASTArena *a, int32_t expr_ref);
int32_t ast_pipeline_block_expr_stmt_ref(struct ast_ASTArena *a, int32_t br, int32_t ei);

int32_t pipeline_asm_emit_block_if_stmt_elf(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                            int32_t cur_block, int32_t if_idx, struct backend_AsmFuncCtx *ctx,
                                            int32_t ta, int32_t stmt_i);

/**
 * 定长数组 T[N] 在栈 temp 区占用字节（array_size * elem_sz）；非 ARRAY 返回 0。
 */
static int32_t glue_fixed_array_temp_bytes(struct ast_ASTArena *arena, int32_t type_ref) {
  struct ast_Type *t;
  int32_t elem_ref;
  int32_t esz;
  int32_t bytes;
  if (!arena || type_ref <= 0 || type_ref > arena->num_types)
    return 0;
  t = pipeline_arena_type_ptr(arena, type_ref);
  if (!t || t->array_size <= 0)
    return 0;
  /** Struct[N]：与 typeck / asm_local_slot_bytes 同宽（SoA 列主序或 AoS N×layout）。 */
  if (pipeline_type_kind_ord_at(arena, type_ref) == 10) {
    bytes = glue_type_size_simple(g_pipeline_asm_emit_module, arena, type_ref, 0);
    if (bytes > 0)
      return bytes;
  }
  elem_ref = t->elem_type_ref;
  esz = 4;
  if (elem_ref > 0 && elem_ref <= arena->num_types) {
    struct ast_Type *et = pipeline_arena_type_ptr(arena, elem_ref);
    if (et) {
      if (pipeline_type_kind_ord_at(arena, elem_ref) == 2)
        esz = 1;
      else if (pipeline_type_kind_ord_at(arena, elem_ref) == 8 ||
               pipeline_type_kind_ord_at(arena, elem_ref) == 4 ||
               pipeline_type_kind_ord_at(arena, elem_ref) == 5 ||
               pipeline_type_kind_ord_at(arena, elem_ref) == 6 ||
               pipeline_type_kind_ord_at(arena, elem_ref) == 14)
        esz = 8;
      else
        esz = 4;
    }
  }
  bytes = t->array_size * esz;
  return bytes > 0 ? bytes : 0;
}

/**
 * 从 let 初始化表达式推导数组 temp 字节（let type_ref 缺失时回退到 init 的 resolved_type）。
 */
static int32_t glue_array_temp_bytes_for_let_init(struct ast_ASTArena *arena, int32_t let_type_ref,
                                                  int32_t init_ref) {
  int32_t bytes;
  bytes = glue_fixed_array_temp_bytes(arena, let_type_ref);
  if (bytes > 0)
    return bytes;
  if (init_ref > 0) {
    int32_t rt;
    rt = pipeline_expr_resolved_type_ref(arena, init_ref);
    bytes = glue_fixed_array_temp_bytes(arena, rt);
    if (bytes > 0)
      return bytes;
    if (pipeline_expr_kind_ord_at(arena, init_ref) == 46) {
      int32_t ne;
      int32_t esz;
      ne = ast_pipeline_expr_array_lit_num_elems_at(arena, init_ref);
      if (ne > 0) {
        esz = 4;
        {
          int32_t inner;
          inner = pipeline_asm_array_lit_elem_type_ref(arena, init_ref);
          if (inner > 0 && pipeline_type_kind_ord_at(arena, inner) == 2)
            esz = 1;
          else if (inner > 0 && (pipeline_type_kind_ord_at(arena, inner) == 8 ||
                                 pipeline_type_kind_ord_at(arena, inner) == 4))
            esz = 8;
        }
        bytes = ne * esz;
        if (bytes > 0)
          return bytes;
      }
    }
  }
  return 0;
}

/** 将 ctx->next_offset 向上对齐到 8 字节边界。 */
static void glue_align_next_offset(struct backend_AsmFuncCtx *ctx) {
  pipeline_glue_AsmFuncCtxLayout *ly;
  int32_t m;
  if (!ctx)
    return;
  ly = pipeline_asm_ctx_layout(ctx);
  if (!ly)
    return;
  m = ly->next_offset % 8;
  if (m != 0)
    ly->next_offset += (8 - m);
}

/**
 * let 定长数组初始化后推进 temp 区，避免连续 `let a:u8[N]=[]; let b:[M]u8=[...]` 共用 ctx.next_offset
 *（csv main 中 buf/line 重叠导致 escape 写坏 buf[1]）。
 */
/**
 * EXPR_ARRAY_LIT 发射完成后推进 temp 区（在 emit_expr_elf_slow 末尾调用，编译期 ctx）。
 */
void pipeline_asm_bump_next_offset_for_array_lit(struct ast_ASTArena *arena, int32_t expr_ref,
                                                 struct backend_AsmFuncCtx *ctx) {
  int32_t bytes;
  pipeline_glue_AsmFuncCtxLayout *ly;
  if (!ctx || expr_ref <= 0)
    return;
  ly = pipeline_asm_ctx_layout(ctx);
  if (!ly)
    return;
  bytes = glue_array_temp_bytes_for_let_init(arena, pipeline_expr_resolved_type_ref(arena, expr_ref), expr_ref);
  if (bytes <= 0)
    return;
  ly->next_offset += bytes;
  glue_align_next_offset(ctx);
}

void pipeline_asm_bump_next_offset_after_let_init(struct ast_ASTArena *arena, int32_t block_ref, int32_t let_idx,
                                                  int32_t init_ref, struct backend_AsmFuncCtx *ctx) {
  int32_t tref;
  int32_t bytes;
  pipeline_glue_AsmFuncCtxLayout *ly;
  if (!ctx)
    return;
  ly = pipeline_asm_ctx_layout(ctx);
  if (!ly)
    return;
  /** EXPR_ARRAY_LIT 已在 emit_expr_elf_slow 末尾 bump；STRUCT_LIT let 直写栈槽，勿再占 temp 区。 */
  if (init_ref > 0) {
    int32_t iko = pipeline_expr_kind_ord_at(arena, init_ref);
    if (iko == 46 || iko == 45)
      return;
  }
  tref = pipeline_block_let_type_ref(arena, block_ref, let_idx);
  bytes = glue_array_temp_bytes_for_let_init(arena, tref, init_ref);
  if (bytes <= 0)
    return;
  ly->next_offset += bytes;
  glue_align_next_offset(ctx);
}

/**
 * 无 init_ref 的定长数组 let：在 ctx->next_offset 处 lea 并写入局部指针槽（如 `let buf:u8[64]=[]` 被省略 init 时）。
 */
static int32_t glue_emit_array_let_empty_init(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                              struct backend_AsmFuncCtx *ctx, int32_t ta, int32_t stack_slot_off) {
  int32_t temp_off;
  pipeline_glue_AsmFuncCtxLayout *ly;
  (void)arena;
  if (!elf_ctx || !ctx)
    return -1;
  ly = pipeline_asm_ctx_layout(ctx);
  if (!ly)
    return -1;
  temp_off = ly->next_offset;
  if (backend_enc_lea_rbp_to_rax_arch(elf_ctx, temp_off, ta) != 0)
    return -1;
  if (backend_enc_store_rax_to_rbp_arch(elf_ctx, stack_slot_off, ta) != 0)
    return -1;
  return 0;
}

/**
 * stmt_order 中是否含 EXPR_RETURN（任意操作数）；用于 if-then 含 return 时勿 jmp 到 if 后语句。
 */
static int glue_block_stmt_order_has_return(struct ast_ASTArena *arena, int32_t block_ref) {
  int32_t nso;
  int32_t i;
  if (!arena || block_ref <= 0)
    return 0;
  nso = ast_ast_block_num_stmt_order(arena, block_ref);
  for (i = 0; i < nso; i++) {
    if (ast_ast_block_stmt_order_kind(arena, block_ref, i) == 2) {
      int32_t idx = ast_ast_block_stmt_order_idx(arena, block_ref, i);
      int32_t expr_ref;
      if (idx < 0 || idx >= ast_ast_block_num_expr_stmts(arena, block_ref))
        continue;
      expr_ref = ast_pipeline_block_expr_stmt_ref(arena, block_ref, idx);
      if (expr_ref != 0 && pipeline_expr_kind_ord_at(arena, expr_ref) == 41)
        return 1;
    }
  }
  return 0;
}

/**
 * let s: T[] = arr（定长栈数组）：asm 栈槽写入 { .data = &arr, .length = N }。
 * 对齐 codegen.c codegen_init / codegen_try_emit_slice_init_from_array_var。
 * @return 1 已写入；0 不适用；-1 失败。
 */
static int32_t glue_emit_slice_from_array_let_init_elf_c(struct ast_ASTArena *arena,
                                                         struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                         int32_t block_ref, int32_t let_idx, int32_t init_ref,
                                                         int32_t let_type_ref, struct backend_AsmFuncCtx *ctx,
                                                         int32_t ta, int32_t slice_slot_off) {
  int32_t arr_sz = 0;
  int32_t li;
  int32_t vlen;
  int32_t arr_off;
  uint8_t vname[64];

  if (!arena || !elf_ctx || !ctx || block_ref <= 0 || let_type_ref <= 0 || init_ref <= 0)
    return 0;
  if (pipeline_type_kind_ord_at(arena, let_type_ref) != GLUE_TYPE_KIND_SLICE)
    return 0;
  if (pipeline_expr_kind_ord_at(arena, init_ref) != GLUE_EXPR_KIND_VAR)
    return 0;
  vlen = pipeline_expr_var_name_len(arena, init_ref);
  if (vlen <= 0 || vlen > 63)
    return 0;
  pipeline_expr_var_name_into(arena, init_ref, vname);
  for (li = 0; li < let_idx; li++) {
    int32_t nlen = pipeline_block_let_name_len(arena, block_ref, li);
    if (nlen == vlen && nlen > 0) {
      int32_t match = 1;
      int32_t ci;
      uint8_t nb[64];
      pipeline_block_let_name_copy64(arena, block_ref, li, nb);
      for (ci = 0; ci < nlen; ci++) {
        if (nb[ci] != vname[ci]) {
          match = 0;
          break;
        }
      }
      if (match) {
        int32_t tr = pipeline_block_let_type_ref(arena, block_ref, li);
        if (pipeline_type_kind_ord_at(arena, tr) == (int32_t)ast_TypeKind_TYPE_ARRAY)
          arr_sz = pipeline_type_array_size_at(arena, tr);
        if (arr_sz > 0)
          break;
      }
    }
  }
  if (arr_sz <= 0) {
    int32_t init_tr = pipeline_expr_resolved_type_ref(arena, init_ref);
    if (init_tr > 0 && pipeline_type_kind_ord_at(arena, init_tr) == 10)
      arr_sz = pipeline_type_array_size_at(arena, init_tr);
  }
  if (arr_sz <= 0)
    return 0;
  arr_off = glue_var_expr_stack_off_elf_c(arena, ctx, init_ref);
  if (arr_off < 0)
    return -1;
  if (glue_enc_local_slot_ptr_or_addr_elf_c(arena, elf_ctx, init_ref, arr_off, ctx, ta) != 0)
    return -1;
  if (backend_enc_store_rax_to_rbp_arch(elf_ctx, slice_slot_off, ta) != 0)
    return -1;
  if (backend_enc_mov_imm64_to_rax_arch(elf_ctx, arr_sz, 0, ta) != 0)
    return -1;
  if (backend_enc_store_rax_to_rbp_arch(elf_ctx, slice_slot_off + 8, ta) != 0)
    return -1;
  return 1;
}

/**
 * ELF 路径：块的 const/let 初始化（C 实现）；TYPE_VECTOR+ARRAY_LIT 直写栈槽，避免 8B 指针 + 重叠 temp。
 */
int32_t pipeline_asm_emit_block_inits_elf_c(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                            int32_t block_ref, struct backend_AsmFuncCtx *ctx, int32_t ta,
                                            int32_t slot_base) {
  int32_t nconst;
  int32_t nlet;
  int32_t idx;
  int32_t i;
  pipeline_glue_AsmFuncCtxLayout *ly;
  if (!arena || !elf_ctx || !ctx || block_ref <= 0)
    return -1;
  ly = pipeline_asm_ctx_layout(ctx);
  if (!ly)
    return -1;
  nconst = ast_ast_block_num_consts(arena, block_ref);
  nlet = ast_ast_block_num_lets(arena, block_ref);
  idx = 0;
  for (i = 0; i < nconst && (slot_base + idx) < ly->num_locals; i++) {
    int32_t init_ref = ast_pipeline_block_const_init_ref(arena, block_ref, i);
    if (init_ref != 0 && !glue_init_is_empty_array_lit(arena, init_ref)) {
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0)
        return -1;
      if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot_base + idx), ta) != 0)
        return -1;
    }
    idx++;
  }
  for (i = 0; i < nlet && (slot_base + idx) < ly->num_locals; i++) {
    int32_t init_ref = ast_pipeline_block_let_init_ref(arena, block_ref, i);
    int32_t slot = slot_base + idx;
    int32_t type_ref;
    uint8_t lnb[64];
    int32_t llen;
    if (init_ref == 0 || glue_init_is_empty_array_lit(arena, init_ref)) {
      idx++;
      continue;
    }
    /** stmt_order==0 路径：fill_local_slots 可能因 block_ref 碰撞跳过，懒登记真实栈偏移。 */
    llen = pipeline_block_let_name_len(arena, block_ref, i);
    if (llen > 0) {
      pipeline_block_let_name_copy64(arena, block_ref, i, lnb);
      if (glue_lazy_append_block_let_local(arena, ctx, block_ref, i, lnb, llen) != 0)
        return -1;
    }
    type_ref = pipeline_block_let_type_ref(arena, block_ref, i);
    if (glue_block_let_is_simd_vector_type(arena, block_ref, i)) {
      int32_t vst = glue_emit_vector_type_let_init_elf_c(arena, elf_ctx, init_ref, ctx, ta,
                                                         backend_asm_ctx_slot_offset(ctx, slot), type_ref);
      if (vst == 0) {
        /* 向量 ARRAY_LIT / VAR 拷贝 / 逐 lane binop 已直写 let 槽 */
      } else if (vst == -1) {
        return -1;
      } else if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0) {
        return -1;
      } else if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot), ta) != 0) {
        return -1;
      }
    } else if (glue_block_let_is_fixed_array_type(arena, block_ref, i) &&
               pipeline_expr_kind_ord_at(arena, init_ref) == 46) {
      /** T[N] = [..]：逐元素直写内联栈槽，勿 temp 指针 + 后续 let 重叠。 */
      if (pipeline_asm_emit_vector_let_init_elf_c(arena, elf_ctx, init_ref, ctx, ta,
                                                  backend_asm_ctx_slot_offset(ctx, slot)) != 0)
        return -1;
    } else {
      int32_t slice_st = glue_emit_slice_from_array_let_init_elf_c(arena, elf_ctx, block_ref, i, init_ref,
                                                                   type_ref, ctx, ta,
                                                                   backend_asm_ctx_slot_offset(ctx, slot));
      if (slice_st == 1) {
        /* slice from array var 已写入 { data, length } */
      } else if (slice_st < 0) {
        return -1;
      } else {
      int32_t st =
          glue_emit_struct_type_let_init_elf_c(arena, elf_ctx, init_ref, ctx, ta, type_ref,
                                               backend_asm_ctx_slot_offset(ctx, slot));
      if (st == 0) {
        /* struct 字面量或 mk(...) 内联已写入 let 槽 */
      } else if (st == -1) {
        return -1;
      } else if (pipeline_expr_kind_ord_at(arena, init_ref) == 46) {
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0)
        return -1;
      if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot), ta) != 0)
        return -1;
      pipeline_asm_bump_next_offset_after_let_init(arena, block_ref, i, init_ref, ctx);
      } else {
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0)
        return -1;
      if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot), ta) != 0)
        return -1;
      }
      }
    }
    idx++;
  }
  return 0;
}

/**
 * 同步块体末尾：若块仅有 final_expr_ref（如 return offset;）且 stmt_order 未含 RETURN，补发射。
 */
static int glue_emit_block_final_expr_elf(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                          int32_t block_ref, struct backend_AsmFuncCtx *ctx, int32_t ta) {
  struct ast_Block *blk;
  if (!arena || !elf_ctx || !ctx || block_ref <= 0)
    return 0;
  blk = pipeline_arena_block_ptr(arena, block_ref);
  if (!blk || blk->final_expr_ref == 0)
    return 0;
  if (glue_block_stmt_order_has_return(arena, block_ref))
    return 0;
  {
    pipeline_glue_AsmFuncCtxLayout *ly = pipeline_asm_ctx_layout(ctx);
    if (ly && ly->module_ref)
      g_pipeline_asm_emit_module = ly->module_ref;
    if (ly && ly->dep_pipe)
      g_pipeline_asm_emit_dep_pipe = (struct ast_PipelineDepCtx *)ly->dep_pipe;
  }
  glue_asm_ctx_set_scope_block((uint8_t *)ctx, block_ref);
  /** 保留 assign 留下的 rbx 址缓存，供 final return 的 EXPR_INDEX 对称复用（7.3）。 */
  if (glue_index_scratch_spills_cleanup_all_elf_c(elf_ctx, ta) != 0)
    return -1;
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, blk->final_expr_ref, ctx, ta) != 0)
    return -1;
  /** 隐式尾表达式（非 EXPR_RETURN）：结果在 rax，须 jmp 到 tail_join。if-expr 分支块由 done 标签汇合。 */
  if (glue_if_expr_arm_emit_depth <= 0 &&
      pipeline_expr_kind_ord_at(arena, blk->final_expr_ref) != 41) {
    pipeline_glue_AsmFuncCtxLayout *ly = pipeline_asm_ctx_layout(ctx);
    if (ly->tail_join_label_len > 0 &&
        backend_enc_jmp_arch(elf_ctx, ly->tail_join_label, ly->tail_join_label_len, ta) != 0)
      return -1;
  }
  return 0;
}

/** MEM-C1：with_arena emit 栈深度与当前 scope 内栈上 Arena64 偏移（供 default_alloc 内联）。 */
#define GLUE_WA_SCOPE_STACK_MAX 16
static int32_t g_glue_wa_scope_off_stack[GLUE_WA_SCOPE_STACK_MAX];
static int32_t g_glue_wa_scope_n;
static int32_t g_glue_wa_temp_base;
static int32_t g_glue_wa_temp_next;
static int32_t g_glue_wa_func_body_ref;

/** 当前是否在 with_arena scope 内（backend_try_inline default_alloc 用）。 */
int32_t glue_with_arena_scope_active_c(void) {
  return g_glue_wa_scope_n > 0 ? 1 : 0;
}

/** 栈顶 with_arena 临时 Arena64 的 rbp 负偏移；无 scope 时返回 0。 */
int32_t glue_with_arena_scope_top_off_c(void) {
  return g_glue_wa_scope_n > 0 ? g_glue_wa_scope_off_stack[g_glue_wa_scope_n - 1] : 0;
}

/** 函数体 emit 入口：重置 wa 临时区游标（须在 fill_block_locals_tree 之后调用）。 */
static void glue_wa_emit_begin_func_c(struct backend_AsmFuncCtx *ctx, struct ast_ASTArena *arena, int32_t body_ref) {
  pipeline_glue_AsmFuncCtxLayout *ly;
  g_glue_wa_scope_n = 0;
  g_glue_wa_temp_next = 0;
  g_glue_wa_func_body_ref = body_ref;
  /**
   * Arena64 栈槽在全部 let 之后：next_offset 为上一局部 slot_off（= lea 基址），
   * 须 +24 再作 wa 起点，避免与 Vec_u8 等 struct 的 [fp-(off+sz),fp-off) 重叠。
   */
  ly = pipeline_asm_ctx_layout(ctx);
  if (!ly)
    return;
  g_glue_wa_temp_base = ly->next_offset + asm_sum_block_array_temp_bytes(arena, body_ref) + 24;
}

/** 为本 with_arena 块分配栈上 Arena64 槽偏移（24B 步进，8 对齐；须在所有块内 let 之后）。 */
static int32_t glue_wa_scope_alloc_off_c(struct backend_AsmFuncCtx *ctx) {
  int32_t off = g_glue_wa_temp_base + g_glue_wa_temp_next;
  pipeline_glue_AsmFuncCtxLayout *ly;
  g_glue_wa_temp_next += 24;
  if (g_glue_wa_temp_next % 8 != 0)
    g_glue_wa_temp_next += 8 - (g_glue_wa_temp_next % 8);
  /** 与 compute_frame_size 一致：游标越过 wa 区，避免后续 fill 与 Arena64 重叠。 */
  if (ctx) {
    int32_t end = off + 24;
    if (end % 8 != 0)
      end += 8 - (end % 8);
    ly = pipeline_asm_ctx_layout(ctx);
    if (ly && end > ly->next_offset)
      ly->next_offset = end;
  }
  return off;
}

static void glue_wa_scope_push_c(int32_t wa_off) {
  if (g_glue_wa_scope_n >= GLUE_WA_SCOPE_STACK_MAX)
    return;
  g_glue_wa_scope_off_stack[g_glue_wa_scope_n++] = wa_off;
}

static void glue_wa_scope_pop_c(void) {
  if (g_glue_wa_scope_n > 0)
    g_glue_wa_scope_n--;
}

/** heap_arena_init_c(a, cap)：a=rbp+wa_off，cap 由 cap_ref 表达式求值。 */
static int32_t glue_emit_with_arena_init_elf(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                             struct backend_AsmFuncCtx *ctx, int32_t wa_off, int32_t cap_ref,
                                             int32_t ta) {
  static const uint8_t init_sym[] = "heap_arena_init_c";
  if (backend_enc_lea_rbp_to_rax_arch(elf_ctx, wa_off, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 0, ta) != 0)
    return -1;
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, cap_ref, ctx, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 1, ta) != 0)
    return -1;
  return backend_enc_call_arch(elf_ctx, (uint8_t *)init_sym, (int32_t)(sizeof(init_sym) - 1), ta);
}

/** heap_arena64_deinit_c(a)：释放 with_arena 栈上 Arena64 chunk。 */
static int32_t glue_emit_with_arena_deinit_elf(struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t wa_off, int32_t ta) {
  static const uint8_t deinit_sym[] = "heap_arena64_deinit_c";
  if (backend_enc_lea_rbp_to_rax_arch(elf_ctx, wa_off, ta) != 0)
    return -1;
  if (backend_enc_mov_rax_to_arg_reg_arch(elf_ctx, 0, ta) != 0)
    return -1;
  return backend_enc_call_arch(elf_ctx, (uint8_t *)deinit_sym, (int32_t)(sizeof(deinit_sym) - 1), ta);
}

/**
 * 按 stmt_order 同步发射块体（C for 循环）：避免 shux-c -E 使 backend.x 内 while(i<nso) 只跑一轮，
 * 导致 while 体内仅首条 if/赋值被发射（escape 的 else 与 j++ 丢失）。
 */
int32_t pipeline_asm_emit_block_body_sync_elf(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                              int32_t block_ref, struct backend_AsmFuncCtx *ctx, int32_t ta) {
  int32_t nconst;
  int32_t nlet;
  int32_t slot_base;
  int32_t nso;
  int32_t i;
  /** 父 cfg 块 Chaitin 着色 / live_cfg_parent 快照（if 子块 emit 后须恢复）。 */
  int32_t saved_cfg_color_active;
  int32_t saved_cfg_live_parent;
  if (!arena || !elf_ctx || !ctx || block_ref <= 0)
    return -1;
  if (getenv("SHUX_ASM_DEBUG") != NULL) {
    static int32_t dbg_block_sync_n;
    if (dbg_block_sync_n < 12) {
      int32_t fn_body_dbg = 0;
      if (g_pipeline_asm_emit_module && g_pipeline_asm_emit_func_index >= 0)
        fn_body_dbg = pipeline_module_func_body_ref_at(g_pipeline_asm_emit_module, g_pipeline_asm_emit_func_index);
      fprintf(stderr, "shux: emit_block_body_sync br=%d nso=%d nif=%d ta=%d\n", (int)block_ref,
              (int)ast_ast_block_num_stmt_order(arena, block_ref),
              (int)ast_ast_block_num_if_stmts(arena, block_ref), (int)ta);
      fprintf(stderr, "shux: emit_block_scope fi=%d fn_body=%d block=%d nlet=%d nconst=%d\n",
              (int)g_pipeline_asm_emit_func_index, (int)fn_body_dbg, (int)block_ref,
              (int)ast_ast_block_num_lets(arena, block_ref), (int)ast_ast_block_num_consts(arena, block_ref));
      fflush(stderr);
      dbg_block_sync_n++;
    }
  }
  saved_cfg_color_active = glue_asm73_cfg_coloring_active;
  saved_cfg_live_parent = glue_block_live_cfg_parent;
  glue_index_assign_addr_cache_clear();
  glue_binop_var_slot_cache_clear();
  glue_binop_stack_spill_clear();
  glue_asm73_pin_spill_off[0] = -1;
  glue_asm73_pin_spill_off[1] = -1;
  glue_asm73_pin_spill_off[2] = -1;
  glue_asm73_pin_spill_off[3] = -1;
  glue_asm73_pin_spill_off[4] = -1;
  glue_asm73_pin_spill_off[5] = -1;
  /** cfg 父块着色表在入口 Chaitin 后保留；if/while 子块 emit 勿清空（此前会 wipe 导致 final_expr 无 which=6）。 */
  if (!glue_asm73_cfg_coloring_active)
    glue_asm73_clear_spill_color_map();
  (void)glue_index_scratch_spills_cleanup_all_elf_c(elf_ctx, ta);
  glue_index_subadd3_sum_cache_clear();
  glue_index_minus_pair_cache_clear();
  glue_index_scratch_stack_depth = 0;
  glue_asm_ctx_set_scope_block((uint8_t *)ctx, block_ref);
  /** 预登记本块及 if/while/for 子树全部 let（修复 get_field_offset_from_layout 内层 `j` 未入 ctx）。 */
  pipeline_asm_fill_block_locals_tree(ctx, arena, block_ref);
  /** MEM-C1：函数根块体 emit 开始时预留 with_arena 临时 Arena64 区基址。 */
  if (g_pipeline_asm_emit_module && g_pipeline_asm_emit_func_index >= 0) {
    int32_t fn_body = pipeline_module_func_body_ref_at(g_pipeline_asm_emit_module, g_pipeline_asm_emit_func_index);
    if (fn_body == block_ref)
      glue_wa_emit_begin_func_c(ctx, arena, block_ref);
  }
  nconst = ast_ast_block_num_consts(arena, block_ref);
  nlet = ast_ast_block_num_lets(arena, block_ref);
  slot_base = backend_block_slot_base_for(ctx, arena, block_ref);
  nso = ast_ast_block_num_stmt_order(arena, block_ref);
  glue_block_live_cfg_parent = glue_block_stmt_order_has_cfg(arena, block_ref);
  glue_block_live_fwd_active = 1;
  glue_live_fwd_clear(&glue_block_live_fwd);
  if (glue_block_live_cfg_parent && !saved_cfg_color_active) {
    /** 仅最外层 cfg 父块重算 Chaitin；嵌套 if+while 子块勿 wipe 父块着色表。 */
    glue_block_compute_cfg_peak_live_and_color(arena, ctx, block_ref, slot_base, nconst, nlet);
    /**
     * final_expr peak < 4：cfg 前向 next-use 在 emit 中不稳定；本块改线性 live+pin，着色表仍供 then/else 继承。
     */
    if (glue_asm73_cfg_peak_live.n >= 4)
      glue_asm73_cfg_coloring_active = 1;
    else {
      glue_asm73_cfg_coloring_active = 0;
      glue_block_compute_linear_live_in(arena, ctx, block_ref, slot_base, nconst, nlet);
      glue_asm73_compute_spill_color_pins();
    }
  } else if (saved_cfg_color_active) {
    /** cfg 子块（含内层 while/for）：继承父块着色与 final_expr 阈值，不重算 Chaitin。 */
    glue_asm73_cfg_coloring_active = 1;
    /**
     * 线性 then/else 体：须本块 live_at_stmt；否则 before_stmt 误读父 cfg 块槽位 SIGSEGV。
     */
    if (!glue_block_live_cfg_parent)
      glue_block_compute_linear_live_in(arena, ctx, block_ref, slot_base, nconst, nlet);
  } else {
    glue_asm73_cfg_coloring_active = 0;
    glue_block_compute_linear_live_in(arena, ctx, block_ref, slot_base, nconst, nlet);
    glue_asm73_compute_spill_color_pins();
  }
  /**
   * 两遍 emit：const/let 先于 if/loop（parser stmt_order 偶发 let 晚于 if → with_arena_vec 未初始化 push SIGSEGV）。
   * INDEX 初值 let 除外：须在 stmt_order 原位 emit，以便复用/失效上一笔 INDEX assign 址缓存（read-between）。
   */
  /** const 按声明下标序预先落栈；stmt_order 乱序时避免 `const B = A + 2` 在 A 之前 emit。 */
  for (i = 0; i < nconst; i++) {
    int32_t init_ref = ast_pipeline_block_const_init_ref(arena, block_ref, i);
    if (init_ref != 0 && !glue_init_is_empty_array_lit(arena, init_ref)) {
      glue_index_assign_addr_cache_clear();
      if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0)
        return -1;
      if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot_base + i), ta) != 0)
        return -1;
    }
  }
  if (getenv("SHUX_ASM_DEBUG2") != NULL) {
    int32_t dbg_fn_body2 = 0;
    if (g_pipeline_asm_emit_module && g_pipeline_asm_emit_func_index >= 0)
      dbg_fn_body2 = pipeline_module_func_body_ref_at(g_pipeline_asm_emit_module, g_pipeline_asm_emit_func_index);
    fprintf(stderr, "shux: SO-BEGIN fi=%d br=%d nso=%d is_fn_body=%d\n",
            (int)g_pipeline_asm_emit_func_index, (int)block_ref, (int)nso, (int)(dbg_fn_body2 == block_ref));
    fflush(stderr);
    for (i = 0; i < nso; i++) {
      uint8_t dk = ast_ast_block_stmt_order_kind(arena, block_ref, i);
      int32_t dix = ast_ast_block_stmt_order_idx(arena, block_ref, i);
      int32_t init_ko = -1;
      if (dk == 1 && dix >= 0 && dix < nlet) {
        int32_t iref = ast_pipeline_block_let_init_ref(arena, block_ref, dix);
        init_ko = iref > 0 ? pipeline_expr_kind_ord_at(arena, iref) : -1;
      }
      fprintf(stderr, "shux: SO fi=%d br=%d [%d] kind=%d idx=%d init_ko=%d\n",
              (int)g_pipeline_asm_emit_func_index, (int)block_ref, (int)i, (int)dk, (int)dix, (int)init_ko);
      fflush(stderr);
    }
  }
  {
    int32_t pass;
    for (pass = 0; pass < 2; pass++) {
  for (i = 0; i < nso; i++) {
    uint8_t item_kind = ast_ast_block_stmt_order_kind(arena, block_ref, i);
    int32_t idx = ast_ast_block_stmt_order_idx(arena, block_ref, i);
    if (pass == 0) {
      if (item_kind == 0)
        continue;
      if (item_kind != 1)
        continue;
      /** EXPR_INDEX 初值 let 留 pass 1，勿抢在块内前置 INDEX assign 之前读。 */
      if (item_kind == 1 && idx >= 0 && idx < nlet) {
        int32_t ix_init_ref = ast_pipeline_block_let_init_ref(arena, block_ref, idx);
        int32_t ix_ko = ix_init_ref > 0 ? pipeline_expr_kind_ord_at(arena, ix_init_ref) : 0;
        if (ix_ko == 47)
          continue;
        /** CALL 初值须按 stmt_order 原位 emit（timer_elapsed 越过 sleep、next_field 实参顺序等）。 */
        if (ix_ko == 48)
          continue;
      }
    } else if (item_kind == 0) {
      continue;
    } else if (item_kind == 1) {
      /** pass 0 已发射纯字面/数组 let；pass 1 补 INDEX 与 CALL 初值（须保 stmt_order 顺序）。 */
      if (idx < 0 || idx >= nlet)
        continue;
      {
        int32_t ix_init_ref = ast_pipeline_block_let_init_ref(arena, block_ref, idx);
        int32_t ix_ko = ix_init_ref > 0 ? pipeline_expr_kind_ord_at(arena, ix_init_ref) : 0;
        if (ix_init_ref <= 0 || (ix_ko != 47 && ix_ko != 48))
          continue;
      }
    }
    glue_block_emit_stmt_i = i;
    glue_block_live_fwd_before_stmt(i, ta, elf_ctx);
    if (item_kind == 0) {
      if (idx >= 0 && idx < nconst) {
        int32_t init_ref = ast_pipeline_block_const_init_ref(arena, block_ref, idx);
        if (init_ref != 0) {
          if (glue_init_is_empty_array_lit(arena, init_ref)) {
            /* 空 [] 初值：无 store，与 emit_block_inits_elf 一致。 */
          } else {
            glue_index_assign_addr_cache_clear();
            if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0)
              return -1;
            else if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot_base + idx), ta) !=
                0)
              return -1;
            glue_block_live_fwd_apply_top_stmt(arena, ctx, block_ref, slot_base, nconst, nlet, i);
          }
        }
      }
    } else if (item_kind == 1) {
      if (idx >= 0 && idx < nlet) {
        int32_t slot = slot_base + nconst + idx;
        int32_t init_ref = ast_pipeline_block_let_init_ref(arena, block_ref, idx);
        uint8_t lnb[64];
        int32_t llen = pipeline_block_let_name_len(arena, block_ref, idx);
        /** emit 前懒登记 let 栈槽（if 体内 let 可能未进 fill_tree 子树）。 */
        if (llen > 0) {
          pipeline_block_let_name_copy64(arena, block_ref, idx, lnb);
          if (glue_lazy_append_block_let_local(arena, ctx, block_ref, idx, lnb, llen) != 0)
            return -1;
        }
        if (init_ref != 0) {
          if (glue_init_is_empty_array_lit(arena, init_ref)) {
            int32_t tref_empty;
            tref_empty = pipeline_block_let_type_ref(arena, block_ref, idx);
            /** T[N] = [] 内联 blob；prologue 已清零栈，勿 pointer+temp（会错位 offset 0）。 */
            if (glue_block_let_is_fixed_array_type(arena, block_ref, idx)) {
              /* 无 emit */
            } else if (glue_array_temp_bytes_for_let_init(arena, tref_empty, 0) > 0) {
              if (glue_emit_array_let_empty_init(arena, elf_ctx, ctx, ta, backend_asm_ctx_slot_offset(ctx, slot)) != 0)
                return -1;
              pipeline_asm_bump_next_offset_after_let_init(arena, block_ref, idx, 0, ctx);
            }
          } else if (glue_block_let_is_fixed_array_type(arena, block_ref, idx) &&
                     pipeline_expr_kind_ord_at(arena, init_ref) == 46) {
            if (pipeline_asm_emit_vector_let_init_elf_c(arena, elf_ctx, init_ref, ctx, ta,
                                                        backend_asm_ctx_slot_offset(ctx, slot)) != 0)
              return -1;
          } else if (glue_block_let_is_simd_vector_type(arena, block_ref, idx)) {
            int32_t vtype_ref = pipeline_block_let_type_ref(arena, block_ref, idx);
            int32_t vst =
                glue_emit_vector_type_let_init_elf_c(arena, elf_ctx, init_ref, ctx, ta,
                                                     backend_asm_ctx_slot_offset(ctx, slot), vtype_ref);
            if (vst == 0) {
              /* 向量 let 直写栈槽 */
            } else if (vst == -1) {
              return -1;
            } else {
              glue_index_assign_addr_cache_clear();
              if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0) {
              return -1;
            } else if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot), ta) != 0) {
              return -1;
            }
            }
          } else {
            int32_t slice_st =
                glue_emit_slice_from_array_let_init_elf_c(arena, elf_ctx, block_ref, idx, init_ref,
                                                          pipeline_block_let_type_ref(arena, block_ref, idx), ctx, ta,
                                                          backend_asm_ctx_slot_offset(ctx, slot));
            if (slice_st == 1) {
              /* slice from array var 已写入 { data, length } */
            } else if (slice_st < 0) {
              return -1;
            } else {
            int32_t st =
                glue_emit_struct_type_let_init_elf_c(arena, elf_ctx, init_ref, ctx, ta,
                                                     pipeline_block_let_type_ref(arena, block_ref, idx),
                                                     backend_asm_ctx_slot_offset(ctx, slot));
            if (st == 0) {
              /* struct 字面量或 mk(...) 内联已写入 let 槽 */
            } else if (st == -1) {
              return -1;
            } else if (pipeline_expr_kind_ord_at(arena, init_ref) == 46) {
            /** u8[N] = [..] 非空 ARRAY_LIT：走 rec（pipeline_asm_emit_array_lit_elf_c）。 */
            glue_index_assign_addr_cache_clear();
            if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0) {
              if (getenv("SHUX_ASM_DEBUG"))
                fprintf(stderr,
                        "shux: block let array_lit slow fail block_ref=%d let_idx=%d init_ref=%d nlet=%d\n",
                        (int)block_ref, (int)idx, (int)init_ref, (int)ast_ast_block_num_lets(arena, block_ref));
              return -1;
            }
            if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot), ta) != 0)
              return -1;
            pipeline_asm_bump_next_offset_after_let_init(arena, block_ref, idx, init_ref, ctx);
            } else {
            int32_t ix_init;
            ix_init = glue_try_block_let_index_init_from_assign_cache_elf_c(arena, elf_ctx, ctx, init_ref, ta);
            if (ix_init < 0)
              return -1;
            if (ix_init == 0) {
              int32_t let_ty;
              int32_t init_ko;
              glue_index_assign_addr_cache_clear();
              let_ty = pipeline_block_let_type_ref(arena, block_ref, idx);
              init_ko = pipeline_expr_kind_ord_at(arena, init_ref);
              if (let_ty > 0 && pipeline_type_kind_ord_at(arena, let_ty) == GLUE_TYPE_KIND_F32_ORD && init_ko == 1) {
                if (glue_emit_float_lit_to_rax_elf_c(arena, elf_ctx, init_ref, ta, let_ty, 0) != 0)
                  return -1;
              } else if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0) {
                if (getenv("SHUX_ASM_DEBUG"))
                  fprintf(stderr,
                          "shux: block let init emit fail block_ref=%d let_idx=%d name=%.*s init_ref=%d kind_ord=%d nlet=%d\n",
                          (int)block_ref, (int)idx, (int)(llen > 0 ? llen : 0),
                          (char *)(llen > 0 ? lnb : (uint8_t *)""), (int)init_ref,
                          (int)pipeline_expr_kind_ord_at(arena, init_ref),
                          (int)ast_ast_block_num_lets(arena, block_ref));
                return -1;
              }
            }
            {
              int32_t let_ty2 = pipeline_block_let_type_ref(arena, block_ref, idx);
              if (let_ty2 > 0 && pipeline_type_kind_ord_at(arena, let_ty2) == GLUE_TYPE_KIND_F32_ORD) {
                if (backend_enc_store_eax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot), ta) != 0)
                  return -1;
              } else if (glue_store_retval_pair_to_rbp_elf_c(glue_emit_module_from_ctx(ctx), arena, elf_ctx, let_ty2,
                                                             backend_asm_ctx_slot_offset(ctx, slot), ta,
                                                             init_ref) != 0) {
                return -1;
              }
            }
            glue_binop_var_slot_cache_kill_def_at_slot(backend_asm_ctx_slot_offset(ctx, slot));
            glue_live_fwd_forward_after_def(arena, ctx, backend_asm_ctx_slot_offset(ctx, slot), init_ref);
            }
            }
          }
        } else if (glue_array_temp_bytes_for_let_init(arena, pipeline_block_let_type_ref(arena, block_ref, idx),
                                                      0) > 0) {
          if (glue_emit_array_let_empty_init(arena, elf_ctx, ctx, ta, backend_asm_ctx_slot_offset(ctx, slot)) != 0)
            return -1;
          pipeline_asm_bump_next_offset_after_let_init(arena, block_ref, idx, 0, ctx);
        }
        /** WPO-S3：let mid = await … 边界 emit save/suspend/restore。 */
        if (init_ref != 0 && glue_expr_is_await_at_c(arena, init_ref)) {
          if (glue_async_cps_emit_after_await(arena, elf_ctx, ctx, ta) != 0)
            return -1;
        }
      }
    } else if (item_kind == 2) {
      if (idx >= 0 && idx < ast_ast_block_num_expr_stmts(arena, block_ref)) {
        int32_t expr_ref = ast_pipeline_block_expr_stmt_ref(arena, block_ref, idx);
        if (expr_ref != 0) {
          int32_t stmt_ko = pipeline_expr_kind_ord_at(arena, expr_ref);
          /**
           * 赋值类：仅 kill 左值 VAR 槽（7.3 线性活跃性）；plain ASSIGN(28) 可保留 INDEX 址 cache。
           * 其它语句可能 clobber rbx/rax，清空全部 binop/INDEX 缓存。
           */
          if (glue_expr_kind_is_assign_like_ord(stmt_ko)) {
            glue_binop_kill_assign_lhs_slots_elf_c(arena, ctx, expr_ref);
            if (stmt_ko != 28)
              glue_index_assign_addr_cache_clear();
          } else {
            glue_index_assign_addr_cache_clear();
            glue_binop_var_slot_cache_clear();
          }
          if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, expr_ref, ctx, ta) != 0) {
            if (getenv("SHUX_ASM_DEBUG")) {
              uint8_t fnb[64];
              int32_t flen = 0;
              if (g_pipeline_asm_emit_module && g_pipeline_asm_emit_func_index >= 0) {
                pipeline_asm_module_func_name_copy64(g_pipeline_asm_emit_module, g_pipeline_asm_emit_func_index,
                                                     fnb);
                flen = pipeline_asm_module_func_name_len_at(g_pipeline_asm_emit_module, g_pipeline_asm_emit_func_index);
              }
              fprintf(stderr,
                      "shux: block expr_stmt emit fail func=%.*s fi=%d block_ref=%d ex_i=%d expr_ref=%d kind=%d\n",
                      (int)flen, (char *)fnb, (int)g_pipeline_asm_emit_func_index, (int)block_ref, (int)idx,
                      (int)expr_ref, (int)pipeline_expr_kind_ord_at(arena, expr_ref));
            }
            return -1;
          }
          glue_block_live_fwd_apply_top_stmt(arena, ctx, block_ref, slot_base, nconst, nlet, i);
        }
      }
    } else if (item_kind == 3) {
      glue_index_assign_addr_cache_clear();
      if (idx >= 0 && idx < ast_ast_block_num_loops(arena, block_ref)) {
        glue_live_fwd_copy(&glue_live_snap_before_if, &glue_block_live_fwd);
        if (backend_emit_while_loop_elf_sync(arena, elf_ctx, block_ref, idx, ctx, ta) != 0)
          return -1;
      }
    } else if (item_kind == 4) {
      glue_index_assign_addr_cache_clear();
      if (idx >= 0 && idx < ast_ast_block_num_for_loops(arena, block_ref)) {
        glue_live_fwd_copy(&glue_live_snap_before_if, &glue_block_live_fwd);
        if (backend_emit_for_loop_elf_sync(arena, elf_ctx, block_ref, idx, ctx, ta) != 0)
          return -1;
      }
    } else if (item_kind == 5) {
      glue_index_assign_addr_cache_clear();
      if (idx >= 0 && idx < ast_ast_block_num_if_stmts(arena, block_ref)) {
        glue_live_fwd_copy(&glue_live_snap_before_if, &glue_block_live_fwd);
        if (pipeline_asm_emit_block_if_stmt_elf(arena, elf_ctx, block_ref, idx, ctx, ta, i) != 0)
          return -1;
      }
    } else if (item_kind == 6) {
      /**
       * M-3 / MEM-C1：region / with_arena（parser stmt_order kind=6）。
       * with_arena(cap>0)：栈上 Arena64 init → 块体 → deinit；块内 default_alloc 内联为 scope bump。
       */
      glue_index_assign_addr_cache_clear();
      if (idx >= 0 && idx < ast_ast_block_num_regions(arena, block_ref)) {
        int32_t reg_body = ast_ast_block_region_body_ref(arena, block_ref, idx);
        int32_t wa_cap = pipeline_block_region_with_arena_cap_ref(arena, block_ref, idx);
        if (reg_body > 0) {
          int32_t wa_off = 0;
          glue_live_fwd_copy(&glue_live_snap_before_if, &glue_block_live_fwd);
          backend_ensure_block_local_slots(ctx, arena, reg_body);
          /** 块内 let 须先于 wa 槽分配（func 入口 fill 已含 region 子块；此处仅 ensure sidecar）。 */
          if (wa_cap > 0) {
            wa_off = glue_wa_scope_alloc_off_c(ctx);
            if (glue_emit_with_arena_init_elf(arena, elf_ctx, ctx, wa_off, wa_cap, ta) != 0)
              return -1;
            glue_wa_scope_push_c(wa_off);
          }
          glue_asm_ctx_set_scope_block((uint8_t *)ctx, reg_body);
          if (pipeline_asm_emit_block_body_sync_elf(arena, elf_ctx, reg_body, ctx, ta) != 0)
            return -1;
          if (wa_cap > 0) {
            if (glue_emit_with_arena_deinit_elf(elf_ctx, wa_off, ta) != 0)
              return -1;
            glue_wa_scope_pop_c();
          }
        }
      }
    }
  }
    }
  }
  /** 7.3：在 final_expr 修剪前快照子块出口活跃集（含 cfg 体内 if/while 汇合结果）。 */
  glue_live_fwd_clear(&glue_block_live_sub_exit_snap);
  if (glue_block_live_fwd_active)
    glue_live_fwd_copy(&glue_block_live_sub_exit_snap, &glue_block_live_fwd);
  else if (!glue_block_stmt_order_has_cfg(arena, block_ref))
    glue_block_compute_live_end_linear(arena, ctx, block_ref, &glue_block_live_sub_exit_snap);
  if (glue_block_live_fwd_active) {
    struct ast_Block *blk_live = pipeline_arena_block_ptr(arena, block_ref);
    glue_block_emit_stmt_i = nso;
    glue_live_fwd_clear(&glue_block_live_fwd);
    if (blk_live && blk_live->final_expr_ref > 0)
      glue_live_fwd_collect_expr_uses(arena, ctx, blk_live->final_expr_ref, &glue_block_live_fwd);
    glue_binop_cache_intersect_live_fwd();
  }
  if (glue_emit_block_final_expr_elf(arena, elf_ctx, block_ref, ctx, ta) != 0) {
    if (getenv("SHUX_ASM_DEBUG"))
      fprintf(stderr, "shux: block final_expr emit fail block_ref=%d nlet=%d nso=%d\n", (int)block_ref,
              (int)ast_ast_block_num_lets(arena, block_ref), (int)ast_ast_block_num_stmt_order(arena, block_ref));
    return -1;
  }
  glue_asm73_cfg_coloring_active = saved_cfg_color_active;
  glue_block_live_fwd_active = 0;
  glue_block_live_cfg_parent = saved_cfg_live_parent;
  (void)glue_index_scratch_spills_cleanup_all_elf_c(elf_ctx, ta);
  return 0;
}

/**
 * backend.x emit_block_body_elf 入口：转发 C 同步块体发射（避免 X while 在自举 asm 下只跑一轮）。
 */
int32_t backend_emit_block_body_sync_elf(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                         int32_t block_ref, struct backend_AsmFuncCtx *ctx, int32_t ta) {
  pipeline_glue_AsmFuncCtxLayout *ly = pipeline_asm_ctx_layout(ctx);
  /** 供 FIELD_ACCESS layout 查表；与 backend.x ctx.module_ref / dep_pipe 对齐。 */
  if (ly && ly->module_ref)
    g_pipeline_asm_emit_module = ly->module_ref;
  if (ly && ly->dep_pipe)
    g_pipeline_asm_emit_dep_pipe = (struct ast_PipelineDepCtx *)ly->dep_pipe;
  return pipeline_asm_emit_block_body_sync_elf(arena, elf_ctx, block_ref, ctx, ta);
}

/** backend.x：读 Block.final_expr_ref（勿 ast_arena_block_get 按值拷贝）。 */
int32_t pipeline_asm_block_final_expr_ref_at(struct ast_ASTArena *a, int32_t br) {
  struct ast_Block *blk = pipeline_arena_block_ptr(a, br);
  return blk ? blk->final_expr_ref : 0;
}

/** backend.x：读 Block.num_stmt_order（与 ast_ast_block_num_stmt_order 一致）。 */
int32_t pipeline_asm_block_num_stmt_order_at(struct ast_ASTArena *a, int32_t br) {
  return ast_ast_block_num_stmt_order(a, br);
}

/** stmt_order 已含 EXPR_RETURN 时勿再 emit final_expr（避免 return 1+2 后重复 emit 占位 LIT 1）。 */
int32_t pipeline_asm_block_stmt_order_has_return(struct ast_ASTArena *a, int32_t br) {
  return glue_block_stmt_order_has_return(a, br);
}

/**
 * 块级 if ELF 发射（then-first + jz）：避免 backend.x 经 shux-c -E 后 jnz/else/then 顺序错乱，
 * 导致 cond 为真时跳进错误分支（escape/unescape 等 while 内 if 返回 -1）。
 */
int32_t pipeline_asm_emit_block_if_stmt_elf(struct ast_ASTArena *arena, struct platform_elf_ElfCodegenCtx *elf_ctx,
                                            int32_t cur_block, int32_t if_idx, struct backend_AsmFuncCtx *ctx,
                                            int32_t ta, int32_t stmt_i) {
  int32_t cond_if;
  int32_t then_ref;
  int32_t else_ref;
  uint8_t else_lbl[64];
  uint8_t done_lbl[64];
  int32_t else_len;
  int32_t done_len;
  (void)stmt_i;
  if (!arena || !elf_ctx || !ctx || cur_block <= 0)
    return -1;
  /** 连续 if：进入每条 if 前恢复父块 scope（上一条 if 的 then 可能未还原）。 */
  glue_asm_ctx_set_scope_block((uint8_t *)ctx, cur_block);
  cond_if = ast_pipeline_block_if_cond_ref(arena, cur_block, if_idx);
  then_ref = ast_pipeline_block_if_then_body_ref(arena, cur_block, if_idx);
  else_ref = ast_pipeline_block_if_else_body_ref(arena, cur_block, if_idx);
  if (getenv("SHUX_ASM_DEBUG") && g_pipeline_asm_emit_module && g_pipeline_asm_emit_func_index >= 0 &&
      pipeline_module_func_name_equal_at(g_pipeline_asm_emit_module, g_pipeline_asm_emit_func_index,
                                         (uint8_t *)"vec_u8_push", 11)) {
    int32_t ck = pipeline_expr_kind_ord_at(arena, cond_if);
    int32_t lr = pipeline_expr_binop_left_ref_at(arena, cond_if);
    int32_t rr = pipeline_expr_binop_right_ref_at(arena, cond_if);
    fprintf(stderr, "shux: vec_u8_push block_if cond=%d kind=%d left=%d lk=%d right=%d rk=%d\n", (int)cond_if, (int)ck,
            (int)lr, lr > 0 ? (int)pipeline_expr_kind_ord_at(arena, lr) : -1, (int)rr,
            rr > 0 ? (int)pipeline_expr_kind_ord_at(arena, rr) : -1);
  }
  if (cond_if == 0 || then_ref == 0)
    return -1;
  if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, cond_if, ctx, ta) != 0) {
    if (getenv("SHUX_ASM_DEBUG"))
      fprintf(stderr, "shux: if cond emit fail block=%d if_idx=%d cond_ref=%d\n", (int)cur_block, (int)if_idx,
              (int)cond_if);
    return -1;
  }
  else_len = pipeline_asm_emit_next_label_c(ctx, else_lbl, 64);
  done_len = pipeline_asm_emit_next_label_c(ctx, done_lbl, 64);
  if (else_len <= 0 || done_len <= 0)
    return -1;
  if (else_ref != 0) {
    if (glue_enc_jz_after_bool_in_eax(elf_ctx, else_lbl, else_len, ta) != 0)
      return -1;
  } else {
    if (glue_enc_jz_after_bool_in_eax(elf_ctx, done_lbl, done_len, ta) != 0)
      return -1;
  }
  backend_ensure_block_local_slots(ctx, arena, then_ref);
  pipeline_asm_fill_block_locals_tree(ctx, arena, then_ref);
  glue_asm_ctx_set_scope_block((uint8_t *)ctx, then_ref);
  {
    GlueBlockLiveFwd then_live_end;
    GlueBlockLiveFwd else_live_end;
    if (pipeline_asm_emit_block_body_sync_elf(arena, elf_ctx, then_ref, ctx, ta) != 0)
      return -1;
    glue_block_fill_live_end_for_merge(arena, ctx, then_ref, &then_live_end);
    /** then 已 return 时 done 落在 if 后语句上，不能再 jmp done（否则引号/无引号双路径）。 */
    if (!glue_block_stmt_order_has_return(arena, then_ref)) {
      if (backend_enc_jmp_arch(elf_ctx, done_lbl, done_len, ta) != 0)
        return -1;
    }
    if (else_ref != 0) {
      if (backend_enc_label_arch(elf_ctx, else_lbl, else_len, 0, ta) != 0)
        return -1;
      backend_ensure_block_local_slots(ctx, arena, else_ref);
      pipeline_asm_fill_block_locals_tree(ctx, arena, else_ref);
      glue_asm_ctx_set_scope_block((uint8_t *)ctx, else_ref);
      if (pipeline_asm_emit_block_body_sync_elf(arena, elf_ctx, else_ref, ctx, ta) != 0)
        return -1;
      glue_block_fill_live_end_for_merge(arena, ctx, else_ref, &else_live_end);
    } else
      glue_live_fwd_copy(&else_live_end, &glue_live_snap_before_if);
    if (backend_enc_label_arch(elf_ctx, done_lbl, done_len, 0, ta) != 0)
      return -1;
    glue_asm_cache_invalidate_at_cfg_merge_selective(arena, ctx, then_ref, else_ref);
    glue_asm_if_phi_invalidate_both_branch_defs(arena, ctx, then_ref, else_ref);
    glue_asm_if_merge_live_union_from_ends(arena, ctx, &then_live_end, &else_live_end);
  }
  /** 连续 if（with_arena 内 push 链）：then 体 emit 后 scope 仍停在 then 子块，须恢复 cur_block 否则后续 if 不落码。 */
  glue_asm_ctx_set_scope_block((uint8_t *)ctx, cur_block);
  return 0;
}

/** EXPR_FLOAT_LIT 低 32 位；emit 时从 float_val 重算，避免 X parser 未持久化 float_bits_*。 */
int32_t pipeline_expr_float_bits_lo_at(struct ast_ASTArena *a, int32_t expr_ref) {
  struct ast_Expr *ex = glue_arena_expr_at_ref(a, expr_ref);
  if (!ex)
    return 0;
  if (ex->kind == ast_ExprKind_EXPR_FLOAT_LIT)
    return typeck_float64_bits_lo(ex->float_val);
  return ex->float_bits_lo;
}

