/**
 * 非 hoist 目标函数：将 module 顶层 let/const 登记到 asm sidecar（g_mem_fence_seq 等跨函数 VAR）。
 */
static void pipeline_asm_register_module_top_level_lets_c(struct backend_AsmFuncCtx *ctx, struct ast_Module *m,
                                                           struct ast_ASTArena *a, int32_t func_index) {
  int32_t tl;
  int32_t n;
  int32_t off;
  uint8_t name_buf[64];
  pipeline_glue_AsmFuncCtxLayout *ly;
  if (!ctx || !m || !a || m->num_top_level_lets <= 0)
    return;
  ly = pipeline_asm_ctx_layout(ctx);
  if (!ly)
    return;
  if (func_index == pipeline_asm_hoist_target_func_index(m))
    return;
  off = ly->next_offset;
  n = m->num_top_level_lets;
  for (tl = 0; tl < n; tl++) {
    int32_t name_len;
    int32_t type_ref;
    int32_t init_ref;
    int32_t slot_off;
    int32_t k;
    name_len = pipeline_module_top_level_let_name_len(m, tl);
    if (name_len <= 0 || name_len > 64)
      continue;
    for (k = 0; k < name_len; k++)
      name_buf[k] = pipeline_module_top_level_let_name_byte_at(m, tl, k);
    if (asm_ctx_local_find_offset((uint8_t *)ctx, name_buf, name_len) >= 0)
      continue;
    type_ref = pipeline_module_top_level_let_type_ref(m, tl);
    init_ref = pipeline_module_top_level_let_init_ref(m, tl);
    /* 【Why】模块级 const（init 为 EXPR_LIT/EXPR_BOOL_LIT）不登记到非 hoist target
     *        函数的局部变量表：const 值不会被 store 到栈上（仅 hoist target 在 body
     *        中 store），登记偏移会导致 glue_var_expr_stack_off_elf_c 返回未初始化
     *        栈槽偏移，读取垃圾值（bug ①）。const 应通过 asm_module_top_level_const_lit_i32
     *        emit 立即数。非字面量 let 仍需登记（值在 hoist target 中 store）。
     * 【Invariant】仅跳过 init_kind==0(EXPR_LIT) 或 2(EXPR_BOOL_LIT)；其他 init 不跳过。
     * 【Asm/Perf】跳过登记后 const 引用走 mov $imm32,%eax 立即数路径，零访存。 */
    if (init_ref > 0 && init_ref <= a->num_exprs) {
      int32_t init_kind = pipeline_expr_kind_ord_at(a, init_ref);
      if (init_kind == 0 || init_kind == 2)
        continue;
    }
    slot_off = asm_local_slot_reg_offset(a, type_ref, off, &off);
    if (asm_ctx_local_append((uint8_t *)ctx, name_buf, name_len, slot_off) < 0)
      return;
    off += pipeline_asm_let_init_stack_reserve_bytes(a, type_ref, init_ref);
  }
  ly->next_offset = off;
  ly->num_locals = asm_ctx_local_count((uint8_t *)ctx);
}

/**
 * 栈帧大小：模拟 fill_param + 块树 fill_local 后的 next_offset（真实 struct/vector 槽宽）+ 数组 temp + 64B。
 */
static int32_t glue_func_return_byte_size_c(struct ast_Module *mod, struct ast_ASTArena *arena, int32_t func_index);

int32_t pipeline_asm_compute_frame_size_c(int32_t num_params, struct ast_ASTArena *arena, int32_t block_ref,
                                          struct ast_Module *mod, int32_t func_index) {
  uint8_t ctx_buf[128];
  int32_t next_off;
  int32_t num_loc;
  int32_t size;
  int32_t arr_temp;
  struct ast_Module *prev_mod;
  if (!arena || block_ref <= 0)
    return 64;
  memset(ctx_buf, 0, sizeof(ctx_buf));
  /** module_ref @ AsmFuncCtx+16，与 asm_ctx_ensure_block_locals 一致。 */
  *(struct ast_Module **)(ctx_buf + 16) = mod;
  prev_mod = g_pipeline_asm_emit_module;
  g_pipeline_asm_emit_module = mod;
  asm_ctx_local_reset(ctx_buf);
  next_off = 8;
  if (num_params > 0)
    next_off = 8 + num_params * 8;
  /** 与 mega_body emit 一致：>16B 返回函数在形参后预留 8B 存 hidden rdi。 */
  if (mod && func_index >= 0 && glue_func_return_byte_size_c(mod, arena, func_index) > 16)
    next_off += 8;
  if (mod && func_index >= 0 && func_index != pipeline_asm_hoist_target_func_index(mod))
    next_off = pipeline_asm_sum_module_top_level_lets_stack(arena, mod, next_off);
  num_loc = 0;
  asm_ctx_fill_locals_block_tree(ctx_buf, arena, block_ref, &next_off, &num_loc);
  arr_temp = asm_sum_block_array_temp_bytes(arena, block_ref);
  g_pipeline_asm_emit_module = prev_mod;
  {
    int32_t wa_temp = asm_sum_block_wa_temp_bytes(arena, block_ref);
    size = next_off + arr_temp + wa_temp;
  }
  if (size > 0 && size % 16 != 0)
    size += 16 - (size % 16);
  /** struct16 CALL spill 区在 emit 中随 next_offset 增长；须预留 scratch 避免写穿栈帧。 */
  size += 512;
  return size + 64;
}

/**
 * 将函数形参填入 asm 局部 sidecar（偏移 8,16,…）；与 backend.x fill_param_slots 一致。
 */
void pipeline_asm_fill_param_slots(struct backend_AsmFuncCtx *ctx, struct ast_Module *mod, int32_t func_index) {
  int32_t off;
  int32_t np;
  int32_t i;
  uint8_t pname_buf[32];
  int32_t plen;
  pipeline_glue_AsmFuncCtxLayout *ly;
  if (!ctx || !mod)
    return;
  ly = pipeline_asm_ctx_layout(ctx);
  if (!ly)
    return;
  g_pipeline_asm_emit_module = mod;
  off = 8;
  np = pipeline_asm_module_func_num_params_at(mod, func_index);
  for (i = 0; i < np; i++) {
    pipeline_asm_module_func_param_name_copy32(mod, func_index, i, pname_buf);
    plen = pipeline_asm_module_func_param_name_len_at(mod, func_index, i);
    if (asm_ctx_local_append((uint8_t *)ctx, pname_buf, plen, off) < 0)
      return;
    ly->num_locals = asm_ctx_local_count((uint8_t *)ctx);
    off += 8;
  }
  ly->next_offset = off;
}

/** 函数形参 type_ref 是否为 f32（SysV xmm ABI 分轨用）。 */
static int32_t glue_func_param_is_f32_c(struct ast_ASTArena *arena, struct ast_Module *mod, int32_t func_index,
                                        int32_t param_index) {
  int32_t pty;
  if (!arena || !mod || func_index < 0 || param_index < 0)
    return 0;
  pty = pipeline_module_func_param_type_ref_at(mod, func_index, param_index);
  if (pty <= 0)
    return 0;
  return pipeline_type_kind_ord_at(arena, pty) == GLUE_TYPE_KIND_F32_ORD ? 1 : 0;
}

/**
 * SysV x86_64：第 param_index 个形参的寄存器/栈归属（0=gp 1=xmm 2=stack）。
 * reg_k / stack_k 为对应类内序号（与 backend_call_dispatch glue_sysv_x86_call_arg_slot 一致）。
 */
static void glue_sysv_x86_func_param_slot_c(struct ast_ASTArena *arena, struct ast_Module *mod, int32_t func_index,
                                            int32_t np, int32_t param_index, int32_t *out_kind, int32_t *out_reg_k,
                                            int32_t *out_stack_k) {
  int32_t gp;
  int32_t xmm;
  int32_t stk;
  int32_t j;
  gp = 0;
  xmm = 0;
  stk = 0;
  for (j = 0; j <= param_index && j < np; j++) {
    if (j == param_index) {
      if (glue_func_param_is_f32_c(arena, mod, func_index, j)) {
        if (xmm < 8) {
          *out_kind = 1;
          *out_reg_k = xmm;
        } else {
          *out_kind = 2;
          *out_stack_k = stk;
        }
      } else if (gp < 6) {
        *out_kind = 0;
        *out_reg_k = gp;
      } else {
        *out_kind = 2;
        *out_stack_k = stk;
      }
      return;
    }
    if (glue_func_param_is_f32_c(arena, mod, func_index, j)) {
      if (xmm < 8)
        xmm++;
      else
        stk++;
    } else if (gp < 6) {
      gp++;
    } else {
      stk++;
    }
  }
  *out_kind = 2;
  *out_reg_k = 0;
  *out_stack_k = 0;
}

/**
 * SysV x86 + SHUX_ABI_F32_XMM=1：gp/xmm 分轨形参 homing（f32 从 xmm0–7 movd 落 32-bit 栈槽）。
 */
static int32_t pipeline_asm_emit_param_home_elf_sysv_f32_xmm_c(struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                               struct backend_AsmFuncCtx *ctx,
                                                               struct ast_Module *mod, int32_t func_index,
                                                               int32_t np) {
  struct ast_ASTArena *arena;
  int32_t i;
  int32_t off;
  int32_t kind;
  int32_t reg_k;
  int32_t stack_k;
  int32_t sret_shift;
  int32_t rk;
  arena = g_pipeline_asm_emit_arena;
  if (!arena)
    return -1;
  sret_shift = g_pipeline_asm_func_sret_active ? 1 : 0;
  for (i = 0; i < np; i++) {
    off = 8 + i * 8;
    glue_sysv_x86_func_param_slot_c(arena, mod, func_index, np, i, &kind, &reg_k, &stack_k);
    rk = i + sret_shift;
    if (kind == 0) {
      if (backend_enc_mov_arg_reg_to_rax_arch(elf_ctx, rk, 0) != 0)
        return -1;
      if (backend_enc_store_rax_to_rbp_arch(elf_ctx, off, 0) != 0)
        return -1;
    } else if (kind == 1) {
      /** xmm 槽不受 hidden rdi 影响（integer reg 占 rdi 时 xmm 仍从 xmm0 起）。 */
      if (backend_enc_mov_xmm_arg_reg_to_eax_arch(elf_ctx, reg_k, 0) != 0)
        return -1;
      if (backend_enc_store_eax_to_rbp_arch(elf_ctx, off, 0) != 0)
        return -1;
    } else {
      if (backend_enc_load_rbp_pos_to_rax_arch(elf_ctx, 16 + (rk - 6) * 8, 0) != 0)
        return -1;
      if (glue_func_param_is_f32_c(arena, mod, func_index, i)) {
        if (backend_enc_store_eax_to_rbp_arch(elf_ctx, off, 0) != 0)
          return -1;
      } else if (backend_enc_store_rax_to_rbp_arch(elf_ctx, off, 0) != 0) {
        return -1;
      }
    }
  }
  return 0;
}

/**
 * prologue 后形参 homing：寄存器实参写入 fill_param_slots 栈槽，栈上传参从 [fp+#] 拷入。
 * AAPCS64：x0-x7 @ [fp-8..-64]；第 9+ 个 @ [x29,#16] 起。SysV x86：rdi..r9；第 7+ @ [rbp+16] 起。
 * SHUX_ABI_F32_XMM=1：SysV gp/xmm 分轨（f32 走 xmm0–7）。
 */
int32_t pipeline_asm_emit_param_home_elf_c(struct platform_elf_ElfCodegenCtx *elf_ctx,
                                           struct backend_AsmFuncCtx *ctx, struct ast_Module *mod,
                                           int32_t func_index, int32_t ta) {
  int32_t np;
  int32_t reg_max;
  int32_t i;
  int32_t off;
  if (!elf_ctx || !ctx || !mod || func_index < 0)
    return -1;
  /** seed partial mega 可能未调 backend.x 的 emit_set_func_index；形参 *T field 识别依赖此下标。 */
  pipeline_asm_emit_set_func_index(func_index);
  np = pipeline_asm_module_func_num_params_at(mod, func_index);
  /** SysV >16B sret：incoming rdi 为 hidden dest；与形参个数无关须先于 homing 保存。 */
  if (ta == 0 && g_pipeline_asm_func_sret_active && g_pipeline_asm_sret_home_off >= 0) {
    if (backend_enc_mov_arg_reg_to_rax_arch(elf_ctx, 0, ta) != 0)
      return -1;
    if (backend_enc_store_rax_to_rbp_arch(elf_ctx, g_pipeline_asm_sret_home_off, ta) != 0)
      return -1;
  }
  if (np <= 0)
    return 0;
  if (ta == 0 && pipeline_asm_abi_f32_xmm_enabled_c() != 0)
    return pipeline_asm_emit_param_home_elf_sysv_f32_xmm_c(elf_ctx, ctx, mod, func_index, np);
  reg_max = (ta == 0) ? 6 : 8;
  {
    int32_t sret_shift = (ta == 0 && g_pipeline_asm_func_sret_active) ? 1 : 0;
    for (i = 0; i < np; i++) {
      int32_t rk;
      off = 8 + i * 8;
      rk = i + sret_shift;
      if (rk < reg_max) {
        if (ta == 1) {
          if (backend_enc_store_x_reg_to_rbp_arch(elf_ctx, rk, off, ta) != 0)
            return -1;
        } else if (ta == 0) {
          if (backend_enc_mov_arg_reg_to_rax_arch(elf_ctx, rk, ta) != 0)
            return -1;
          if (backend_enc_store_rax_to_rbp_arch(elf_ctx, off, ta) != 0)
            return -1;
        }
      } else if (ta == 1) {
        if (backend_enc_load_x29_pos_to_rax_arch(elf_ctx, 16 + (rk - reg_max) * 8, ta) != 0)
          return -1;
        if (backend_enc_store_rax_to_rbp_arch(elf_ctx, off, ta) != 0)
          return -1;
      } else if (ta == 0) {
        if (backend_enc_load_rbp_pos_to_rax_arch(elf_ctx, 16 + (rk - reg_max) * 8, ta) != 0)
          return -1;
        if (backend_enc_store_rax_to_rbp_arch(elf_ctx, off, ta) != 0)
          return -1;
      } else {
        return -1;
      }
    }
  }
  return 0;
}

/**
 * 将块内 const/let 填入 asm 局部 sidecar；与 backend.x fill_local_slots 一致（+8 槽 + lit temp 预留）。
 */
void pipeline_asm_fill_local_slots(struct backend_AsmFuncCtx *ctx, struct ast_ASTArena *arena, int32_t block_ref) {
  int32_t off;
  int32_t i;
  int32_t nconst;
  int32_t nlet;
  uint8_t name_buf[64];
  int32_t nlen;
  int32_t init_ref;
  int32_t slot_base;
  pipeline_glue_AsmFuncCtxLayout *ly;
  if (!ctx || !arena || block_ref <= 0)
    return;
  ly = pipeline_asm_ctx_layout(ctx);
  if (!ly)
    return;
  /** 与 asm_ctx_ensure_block_locals 互斥，避免 stmt_order 路径重复登记偏移。 */
  if (asm_ctx_block_slot_get((uint8_t *)ctx, block_ref) >= 0)
    return;
  slot_base = asm_ctx_local_count((uint8_t *)ctx);
  off = ly->next_offset;
  nconst = ast_ast_block_num_consts(arena, block_ref);
  for (i = 0; i < nconst; i++) {
    int32_t type_ref;
    ast_pipeline_block_const_name_copy64(arena, block_ref, i, name_buf);
    nlen = ast_pipeline_block_const_name_len(arena, block_ref, i);
    type_ref = pipeline_block_const_type_ref(arena, block_ref, i);
    {
      int32_t slot_off = asm_local_slot_reg_offset(arena, type_ref, off, &off);
      if (asm_ctx_local_append((uint8_t *)ctx, name_buf, nlen, slot_off) < 0)
        return;
    }
    ly->num_locals = asm_ctx_local_count((uint8_t *)ctx);
    init_ref = ast_pipeline_block_const_init_ref(arena, block_ref, i);
    off += pipeline_asm_let_init_stack_reserve_bytes(arena, type_ref, init_ref);
  }
  nlet = ast_ast_block_num_lets(arena, block_ref);
  for (i = 0; i < nlet; i++) {
    int32_t type_ref;
    ast_pipeline_block_let_name_copy64(arena, block_ref, i, name_buf);
    nlen = ast_pipeline_block_let_name_len(arena, block_ref, i);
    type_ref = pipeline_block_let_type_ref(arena, block_ref, i);
    {
      int32_t slot_off = asm_local_slot_reg_offset(arena, type_ref, off, &off);
      if (asm_ctx_local_append((uint8_t *)ctx, name_buf, nlen, slot_off) < 0)
        return;
    }
    ly->num_locals = asm_ctx_local_count((uint8_t *)ctx);
    init_ref = ast_pipeline_block_let_init_ref(arena, block_ref, i);
    off += pipeline_asm_let_init_stack_reserve_bytes(arena, type_ref, init_ref);
  }
  ly->next_offset = off;
  asm_ctx_block_slot_set((uint8_t *)ctx, block_ref, slot_base);
}

/**
 * 将无符号十进制写入 buf[off..]，最多 max 字节；返回写入长度，失败 -1。
 * 供 pipeline_asm_emit_next_label_c 格式化 ".Lf<scope>_<id>" 后缀。
 */
static int32_t glue_format_u32_to_buf(uint8_t *buf, int32_t off, int32_t max, uint32_t val) {
  char tmp[16];
  int n;
  int i;
  if (!buf || max <= 0 || off < 0)
    return -1;
  n = snprintf(tmp, sizeof(tmp), "%u", val);
  if (n <= 0 || n > max)
    return -1;
  for (i = 0; i < n; i++)
    buf[off + i] = (uint8_t)tmp[i];
  return n;
}

/**
 * 将有符号 i32 十进制写入 buf[off..]；供 format_label_id 等 match 标签格式化。
 */
static int32_t glue_format_i32_to_buf(uint8_t *buf, int32_t off, int32_t max, int32_t val) {
  char tmp[16];
  int n;
  int i;
  if (!buf || max <= 0 || off < 0)
    return -1;
  n = snprintf(tmp, sizeof(tmp), "%d", val);
  if (n <= 0 || n > max)
    return -1;
  for (i = 0; i < n; i++)
    buf[off + i] = (uint8_t)tmp[i];
  return n;
}

/**
 * 生成唯一局部标签 ".Lf<scope>_<n>" 到 buf；多 Module 共用 elf_ctx 时 scope 由 pipeline_elf_label_mod_scope_begin_module 分配。
 */
int32_t pipeline_asm_emit_next_label_c(struct backend_AsmFuncCtx *ctx, uint8_t *buf, int32_t buf_size) {
  pipeline_glue_AsmFuncCtxLayout *ly;
  int32_t n;
  int32_t id;
  int32_t scope;
  int32_t off;
  if (!ctx || !buf || buf_size < 8)
    return -1;
  ly = pipeline_asm_ctx_layout(ctx);
  scope = pipeline_elf_label_mod_scope_active();
  buf[0] = (uint8_t)'.';
  buf[1] = (uint8_t)'L';
  buf[2] = (uint8_t)'f';
  off = 3;
  n = glue_format_u32_to_buf(buf, off, buf_size - off, (uint32_t)scope);
  if (n <= 0)
    n = 1;
  off = off + n;
  if (off + 2 >= buf_size)
    return -1;
  buf[off] = (uint8_t)'_';
  off = off + 1;
  id = ly->label_counter;
  ly->label_counter = id + 1;
  n = glue_format_u32_to_buf(buf, off, buf_size - off, (uint32_t)id);
  if (n <= 0)
    n = 1;
  return off + n;
}

/**
 * 将 label 序号格式化为 ".L_<id>" 写入 buf；与 backend.x format_label_id 一致（不推进 label_counter）。
 */
int32_t pipeline_asm_format_label_id_c(uint8_t *buf, int32_t buf_size, int32_t id) {
  int32_t n;
  if (!buf || buf_size < 4)
    return -1;
  buf[0] = (uint8_t)'.';
  buf[1] = (uint8_t)'L';
  buf[2] = (uint8_t)'_';
  n = glue_format_i32_to_buf(buf, 3, buf_size - 3, id);
  if (n <= 0)
    n = 1;
  return 3 + n;
}

/**
 * if 语句 then 块 ELF 发射：暂存/恢复 locals，fill + sync block body；与 backend.x emit_if_then_block_body_elf 一致。
 */
int32_t pipeline_asm_emit_if_then_block_body_elf_c(struct ast_ASTArena *arena,
                                                   struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                   int32_t then_block_ref, struct backend_AsmFuncCtx *ctx,
                                                   int32_t ta) {
  int32_t sv_locs;
  int32_t sv_next;
  int32_t r;
  pipeline_glue_AsmFuncCtxLayout *ly;
  if (!ctx || !arena || then_block_ref <= 0)
    return -1;
  ly = pipeline_asm_ctx_layout(ctx);
  if (!ly)
    return -1;
  sv_locs = ly->num_locals;
  sv_next = ly->next_offset;
  pipeline_asm_fill_local_slots(ctx, arena, then_block_ref);
  r = backend_emit_block_body_sync_elf(arena, elf_ctx, then_block_ref, ctx, ta);
  ly->num_locals = sv_locs;
  ly->next_offset = sv_next;
  return r;
}

/**
 * stmt_order 中单条 const(item_kind=0) 或 let(item_kind=1) 的 ELF 初始化。
 * while/for 循环体每轮须按 stmt_order 重跑 let（含 struct/mk 内联），与块体主路径一致。
 */
static int32_t glue_emit_block_stmt_order_let_const_elf(struct ast_ASTArena *arena,
                                                        struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                        int32_t block_ref, struct backend_AsmFuncCtx *ctx, int32_t ta,
                                                        uint8_t item_kind, int32_t idx, int32_t slot_base,
                                                        int32_t nconst, int32_t nlet) {
  if (item_kind == 0) {
    if (idx >= 0 && idx < nconst) {
      int32_t init_ref = ast_pipeline_block_const_init_ref(arena, block_ref, idx);
      if (init_ref != 0) {
        if (glue_init_is_empty_array_lit(arena, init_ref)) {
          /* 空 [] 初值：无 store。 */
        } else if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0)
          return -1;
        else if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot_base + idx), ta) != 0)
          return -1;
      }
    }
    return 0;
  }
  if (item_kind != 1 || idx < 0 || idx >= nlet)
    return 0;
  {
    int32_t slot = slot_base + nconst + idx;
    int32_t init_ref = ast_pipeline_block_let_init_ref(arena, block_ref, idx);
    uint8_t lnb[64];
    int32_t llen = pipeline_block_let_name_len(arena, block_ref, idx);
    /** emit 前懒登记 let 栈槽（循环/if 体内 let 可能未进 fill_tree 子树）。 */
    if (llen > 0) {
      pipeline_block_let_name_copy64(arena, block_ref, idx, lnb);
      if (glue_lazy_append_block_let_local(arena, ctx, block_ref, idx, lnb, llen) != 0)
        return -1;
    }
    if (init_ref != 0) {
      if (glue_init_is_empty_array_lit(arena, init_ref)) {
        int32_t tref_empty = pipeline_block_let_type_ref(arena, block_ref, idx);
        if (glue_block_let_is_fixed_array_type(arena, block_ref, idx)) {
          /* T[N] = [] 内联 blob，无 pointer init */
        } else if (glue_array_temp_bytes_for_let_init(arena, tref_empty, 0) > 0) {
          if (glue_emit_array_let_empty_init(arena, elf_ctx, ctx, ta, backend_asm_ctx_slot_offset(ctx, slot)) != 0)
            return -1;
          pipeline_asm_bump_next_offset_after_let_init(arena, block_ref, idx, 0, ctx);
        }
      } else if (glue_block_let_is_fixed_array_type(arena, block_ref, idx) &&
                 pipeline_expr_kind_ord_at(arena, init_ref) == 46) {
        if (pipeline_asm_emit_vector_let_init_elf_c(arena, elf_ctx, init_ref, ctx, ta,
                                                    backend_asm_ctx_slot_offset(ctx, slot)) != 0)
          return -1;
      } else if (glue_block_let_is_simd_vector_type(arena, block_ref, idx)) {
        int32_t vtype_ref = pipeline_block_let_type_ref(arena, block_ref, idx);
        int32_t vst =
            glue_emit_vector_type_let_init_elf_c(arena, elf_ctx, init_ref, ctx, ta,
                                                 backend_asm_ctx_slot_offset(ctx, slot), vtype_ref);
        if (vst == 0) {
          /* 向量 let 直写栈槽 */
        } else if (vst == -1) {
          return -1;
        } else if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0) {
          return -1;
        } else if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot), ta) != 0) {
          return -1;
        }
      } else {
        int32_t st = glue_emit_struct_type_let_init_elf_c(arena, elf_ctx, init_ref, ctx, ta,
                                                          pipeline_block_let_type_ref(arena, block_ref, idx),
                                                          backend_asm_ctx_slot_offset(ctx, slot));
        if (st == 0) {
          /* struct 字面量或 mk(...) 内联已写入 let 槽 */
        } else if (st == -1) {
          return -1;
        } else if (pipeline_expr_kind_ord_at(arena, init_ref) == 46) {
          if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0)
            return -1;
          if (backend_enc_store_rax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot), ta) != 0)
            return -1;
          pipeline_asm_bump_next_offset_after_let_init(arena, block_ref, idx, init_ref, ctx);
        } else {
          int32_t let_ty;
          int32_t init_ko;
          let_ty = pipeline_block_let_type_ref(arena, block_ref, idx);
          init_ko = pipeline_expr_kind_ord_at(arena, init_ref);
          if (let_ty > 0 && pipeline_type_kind_ord_at(arena, let_ty) == GLUE_TYPE_KIND_F32_ORD && init_ko == 1) {
            if (glue_emit_float_lit_to_rax_elf_c(arena, elf_ctx, init_ref, ta, let_ty, 0) != 0)
              return -1;
            if (backend_enc_store_eax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot), ta) != 0)
              return -1;
          } else if (pipeline_asm_emit_expr_elf_rec(arena, elf_ctx, init_ref, ctx, ta) != 0)
            return -1;
          else if (let_ty > 0 && pipeline_type_kind_ord_at(arena, let_ty) == GLUE_TYPE_KIND_F32_ORD) {
            if (backend_enc_store_eax_to_rbp_arch(elf_ctx, backend_asm_ctx_slot_offset(ctx, slot), ta) != 0)
              return -1;
          } else if (glue_store_retval_pair_to_rbp_elf_c(glue_emit_module_from_ctx(ctx), arena, elf_ctx, let_ty,
                                                         backend_asm_ctx_slot_offset(ctx, slot), ta, init_ref) != 0)
            return -1;
        }
      }
    } else if (glue_array_temp_bytes_for_let_init(arena, pipeline_block_let_type_ref(arena, block_ref, idx), 0) > 0) {
      if (glue_emit_array_let_empty_init(arena, elf_ctx, ctx, ta, backend_asm_ctx_slot_offset(ctx, slot)) != 0)
        return -1;
      pipeline_asm_bump_next_offset_after_let_init(arena, block_ref, idx, 0, ctx);
    }
  }
  return 0;
}

/**
 * ELF 循环体 stmt_order（expr/while/for/if + final_expr）；C for 循环，避免 partial 薄包装递归。
 */
int32_t backend_emit_loop_body_content_elf_sync(struct ast_ASTArena *arena,
                                                struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t body_ref,
                                                struct backend_AsmFuncCtx *ctx, int32_t ta) {
  if (!arena || !elf_ctx || !ctx)
    return -1;
  /** 空 while 体合法（`while (c) {}`）；勿因 body_ref==0  abort 整函数 codegen。 */
  if (body_ref <= 0)
    return 0;
  {
    pipeline_glue_AsmFuncCtxLayout *ly = pipeline_asm_ctx_layout(ctx);
    if (ly && ly->module_ref)
      g_pipeline_asm_emit_module = ly->module_ref;
  }
  /**
   * 与 pipeline_asm_emit_block_if_stmt_elf 的 then 分支一致：先铺局部槽再按 stmt_order 发射，
   * 否则 while 体内赋值/调用在 asm 路径静默失败（body_ref 有效但 code_len 停在 cond+jz）。
   */
  backend_ensure_block_local_slots(ctx, arena, body_ref);
  pipeline_asm_fill_block_locals_tree(ctx, arena, body_ref);
  /** 循环体 scoped 查局部（while 内 let p 的 p.a 等 FIELD_ACCESS）。 */
  glue_asm_ctx_set_scope_block((uint8_t *)ctx, body_ref);
  if (pipeline_asm_emit_block_body_sync_elf(arena, elf_ctx, body_ref, ctx, ta) != 0)
    return -1;
  return 0;
}

/** 两 VAR expr ref 是否同名（B-CMP LCG xor while 模式匹配）。 */
static int32_t glue_fold_expr_var_refs_same_c(struct ast_ASTArena *arena, int32_t a_ref, int32_t b_ref) {
  int32_t alen;
  int32_t blen;
  uint8_t abuf[64];
  uint8_t bbuf[64];
  int32_t k;
  if (a_ref <= 0 || b_ref <= 0 || !arena)
    return 0;
  if (pipeline_expr_kind_ord_at(arena, a_ref) != GLUE_EXPR_KIND_VAR ||
      pipeline_expr_kind_ord_at(arena, b_ref) != GLUE_EXPR_KIND_VAR)
    return 0;
  alen = pipeline_expr_var_name_len(arena, a_ref);
  blen = pipeline_expr_var_name_len(arena, b_ref);
  if (alen <= 0 || blen <= 0 || alen != blen || alen > 63)
    return 0;
  pipeline_expr_var_name_into(arena, a_ref, abuf);
  pipeline_expr_var_name_into(arena, b_ref, bbuf);
  k = 0;
  while (k < alen) {
    if (abuf[k] != bbuf[k])
      return 0;
    k++;
  }
  return 1;
}

/** 解析 `while (i < n)`：左 VAR i，右 LIT 或 VAR n。 */
static int32_t glue_fold_parse_while_lt_i_n_c(struct ast_ASTArena *arena, int32_t cond_ref, int32_t *out_i_ref,
                                              int32_t *out_n_is_lit, int32_t *out_n_lit, int32_t *out_n_ref) {
  int32_t i_ref;
  int32_t n_side;
  if (!arena || cond_ref <= 0)
    return 0;
  if (pipeline_expr_kind_ord_at(arena, cond_ref) != 16)
    return 0;
  i_ref = pipeline_expr_binop_left_ref_at(arena, cond_ref);
  n_side = pipeline_expr_binop_right_ref_at(arena, cond_ref);
  if (pipeline_expr_kind_ord_at(arena, i_ref) != GLUE_EXPR_KIND_VAR)
    return 0;
  if (out_i_ref)
    *out_i_ref = i_ref;
  if (pipeline_expr_kind_ord_at(arena, n_side) == 0) {
    if (out_n_is_lit)
      *out_n_is_lit = 1;
    if (out_n_lit)
      *out_n_lit = pipeline_expr_int_val_at(arena, n_side);
    if (out_n_ref)
      *out_n_ref = 0;
    return 1;
  }
  if (pipeline_expr_kind_ord_at(arena, n_side) == GLUE_EXPR_KIND_VAR) {
    if (out_n_is_lit)
      *out_n_is_lit = 0;
    if (out_n_lit)
      *out_n_lit = 0;
    if (out_n_ref)
      *out_n_ref = n_side;
    return 1;
  }
  return 0;
}

/** 同块 let 绑定整型字面量初值（`let n: i32 = 100000000`）。 */
static int32_t glue_fold_block_let_init_lit_c(struct ast_ASTArena *arena, int32_t block_ref, int32_t var_ref,
                                              int32_t *out_lit) {
  int32_t vlen;
  int32_t nlet;
  int32_t li;
  uint8_t vbuf[64];
  if (!arena || block_ref <= 0 || var_ref <= 0 || pipeline_expr_kind_ord_at(arena, var_ref) != GLUE_EXPR_KIND_VAR)
    return 0;
  vlen = pipeline_expr_var_name_len(arena, var_ref);
  if (vlen <= 0 || vlen > 63)
    return 0;
  pipeline_expr_var_name_into(arena, var_ref, vbuf);
  nlet = ast_ast_block_num_lets(arena, block_ref);
  li = 0;
  while (li < nlet) {
    int32_t llen = pipeline_block_let_name_len(arena, block_ref, li);
    if (llen == vlen) {
      int32_t is_match = 1;
      uint8_t lb[64];
      int32_t kk;
      int32_t init_ref;
      pipeline_block_let_name_copy64(arena, block_ref, li, lb);
      kk = 0;
      while (kk < vlen) {
        if (lb[kk] != vbuf[kk])
          is_match = 0;
        kk++;
      }
      if (is_match) {
        init_ref = pipeline_block_let_init_ref(arena, block_ref, li);
        if (init_ref > 0 && pipeline_expr_kind_ord_at(arena, init_ref) == 0) {
          if (out_lit)
            *out_lit = pipeline_expr_int_val_at(arena, init_ref);
          return 1;
        }
        return 0;
      }
    }
    li++;
  }
  return 0;
}

/** 解析 `i * c1 + c2` 或 `c1 * i + c2`（loop_i32 LCG 混合项）。 */
static int32_t glue_parse_i_mul_add_lit_c(struct ast_ASTArena *arena, int32_t expr_ref, int32_t i_ref,
                                          int32_t *out_c1, int32_t *out_c2) {
  int32_t ko;
  int32_t left;
  int32_t right;
  int32_t mul_ref;
  int32_t lit_ref;
  int32_t ml;
  int32_t mr;
  if (!arena || expr_ref <= 0 || i_ref <= 0)
    return 0;
  ko = pipeline_expr_kind_ord_at(arena, expr_ref);
  if (ko == 6) {
    ml = pipeline_expr_binop_left_ref_at(arena, expr_ref);
    mr = pipeline_expr_binop_right_ref_at(arena, expr_ref);
    if (glue_fold_expr_var_refs_same_c(arena, ml, i_ref) && pipeline_expr_kind_ord_at(arena, mr) == 0) {
      if (out_c1)
        *out_c1 = pipeline_expr_int_val_at(arena, mr);
      if (out_c2)
        *out_c2 = 0;
      return 1;
    }
    return 0;
  }
  if (ko != 4)
    return 0;
  left = pipeline_expr_binop_left_ref_at(arena, expr_ref);
  right = pipeline_expr_binop_right_ref_at(arena, expr_ref);
  if (pipeline_expr_kind_ord_at(arena, left) == 6 && pipeline_expr_kind_ord_at(arena, right) == 0) {
    mul_ref = left;
    lit_ref = right;
  } else {
    return 0;
  }
  ml = pipeline_expr_binop_left_ref_at(arena, mul_ref);
  mr = pipeline_expr_binop_right_ref_at(arena, mul_ref);
  if (glue_fold_expr_var_refs_same_c(arena, ml, i_ref) && pipeline_expr_kind_ord_at(arena, mr) == 0) {
    if (out_c1)
      *out_c1 = pipeline_expr_int_val_at(arena, mr);
    if (out_c2)
      *out_c2 = pipeline_expr_int_val_at(arena, lit_ref);
    return 1;
  }
  if (glue_fold_expr_var_refs_same_c(arena, mr, i_ref) && pipeline_expr_kind_ord_at(arena, ml) == 0) {
    if (out_c1)
      *out_c1 = pipeline_expr_int_val_at(arena, ml);
    if (out_c2)
      *out_c2 = pipeline_expr_int_val_at(arena, lit_ref);
    return 1;
  }
  return 0;
}

/** 是否为 `target = target + 1`。 */
static int32_t glue_is_assign_var_add_one_c(struct ast_ASTArena *arena, int32_t expr_ref, int32_t target_ref) {
  int32_t left_ref;
  int32_t add_l;
  int32_t add_r;
  if (!arena || expr_ref <= 0 || pipeline_expr_kind_ord_at(arena, expr_ref) != 28)
    return 0;
  left_ref = pipeline_expr_binop_left_ref_at(arena, expr_ref);
  add_l = pipeline_expr_binop_left_ref_at(arena, pipeline_expr_binop_right_ref_at(arena, expr_ref));
  add_r = pipeline_expr_binop_right_ref_at(arena, pipeline_expr_binop_right_ref_at(arena, expr_ref));
  if (!glue_fold_expr_var_refs_same_c(arena, left_ref, target_ref))
    return 0;
  if (pipeline_expr_kind_ord_at(arena, pipeline_expr_binop_right_ref_at(arena, expr_ref)) != 4)
    return 0;
  if (!glue_fold_expr_var_refs_same_c(arena, add_l, target_ref))
    return 0;
  if (pipeline_expr_kind_ord_at(arena, add_r) != 0 || pipeline_expr_int_val_at(arena, add_r) != 1)
    return 0;
  return 1;
}

/** expr 是否为 func 第 0 形参的字段访问。 */
static int32_t glue_expr_is_param0_field_access_c(struct ast_ASTArena *arena, struct ast_Module *mod,
                                                  int32_t func_idx, int32_t expr_ref) {
  if (!arena || !mod || func_idx < 0 || expr_ref <= 0 || pipeline_expr_kind_ord_at(arena, expr_ref) != 44)
    return 0;
  return glue_expr_is_func_param_at_c(arena, mod, func_idx,
                                     pipeline_expr_field_access_base_ref(arena, expr_ref), 0);
}

/** 函数体是否为 `return p.a + p.b`。 */
static int32_t glue_fold_func_returns_param0_field_sum_c(struct ast_ASTArena *arena, struct ast_Module *mod,
                                                         int32_t func_idx) {
  int32_t ret_ref;
  int32_t al;
  int32_t ar;
  ret_ref = glue_fold_func_return_operand_ref_c(arena, mod, func_idx);
  if (ret_ref <= 0 || pipeline_expr_kind_ord_at(arena, ret_ref) != 4)
    return 0;
  al = pipeline_expr_binop_left_ref_at(arena, ret_ref);
  ar = pipeline_expr_binop_right_ref_at(arena, ret_ref);
  if (!glue_expr_is_param0_field_access_c(arena, mod, func_idx, al))
    return 0;
  return glue_expr_is_param0_field_access_c(arena, mod, func_idx, ar) ? 1 : 0;
}

/** 是否为 `pair.field = src_ref`（field 单字符）。 */
static int32_t glue_is_field_assign_from_var_c(struct ast_ASTArena *arena, int32_t er, int32_t pair_ref,
                                               uint8_t field_ch, int32_t src_ref) {
  int32_t left_ref;
  int32_t right_ref;
  uint8_t fn[64];
  if (!arena || er <= 0 || pair_ref <= 0 || src_ref <= 0 || pipeline_expr_kind_ord_at(arena, er) != 28)
    return 0;
  left_ref = pipeline_expr_binop_left_ref_at(arena, er);
  right_ref = pipeline_expr_binop_right_ref_at(arena, er);
  if (pipeline_expr_kind_ord_at(arena, left_ref) != 44)
    return 0;
  if (!glue_fold_expr_var_refs_same_c(arena, pipeline_expr_field_access_base_ref(arena, left_ref), pair_ref))
    return 0;
  if (pipeline_expr_field_access_name_len(arena, left_ref) != 1)
    return 0;
  pipeline_expr_field_access_name_into(arena, left_ref, fn);
  if (fn[0] != field_ch)
    return 0;
  return glue_fold_expr_var_refs_same_c(arena, right_ref, src_ref) ? 1 : 0;
}

/** 是否为 `pair.b = i + 1`。 */
static int32_t glue_is_field_assign_i_plus_one_c(struct ast_ASTArena *arena, int32_t er, int32_t pair_ref,
                                                 int32_t i_ref) {
  int32_t left_ref;
  int32_t right_ref;
  int32_t add_l;
  int32_t add_r;
  uint8_t fn[64];
  if (!arena || er <= 0 || pipeline_expr_kind_ord_at(arena, er) != 28)
    return 0;
  left_ref = pipeline_expr_binop_left_ref_at(arena, er);
  right_ref = pipeline_expr_binop_right_ref_at(arena, er);
  if (pipeline_expr_kind_ord_at(arena, left_ref) != 44)
    return 0;
  if (!glue_fold_expr_var_refs_same_c(arena, pipeline_expr_field_access_base_ref(arena, left_ref), pair_ref))
    return 0;
  if (pipeline_expr_field_access_name_len(arena, left_ref) != 1)
    return 0;
  pipeline_expr_field_access_name_into(arena, left_ref, fn);
  if (fn[0] != (uint8_t)'b')
    return 0;
  if (pipeline_expr_kind_ord_at(arena, right_ref) != 4)
    return 0;
  add_l = pipeline_expr_binop_left_ref_at(arena, right_ref);
  add_r = pipeline_expr_binop_right_ref_at(arena, right_ref);
  if (!glue_fold_expr_var_refs_same_c(arena, add_l, i_ref))
    return 0;
  if (pipeline_expr_kind_ord_at(arena, add_r) != 0 || pipeline_expr_int_val_at(arena, add_r) != 1)
    return 0;
  return 1;
}

/** 是否为 `s = s + add_pair(pair)`。 */
static int32_t glue_is_assign_s_plus_pair_field_sum_call_c(struct ast_ASTArena *arena, struct ast_Module *mod,
                                                           int32_t er, int32_t *out_s_ref, int32_t pair_ref) {
  int32_t left_ref;
  int32_t right_ref;
  int32_t add_l;
  int32_t inner;
  int32_t callee_ref;
  int32_t arg0;
  uint8_t cname[64];
  int32_t clen;
  if (!arena || !mod || er <= 0 || pair_ref <= 0 || pipeline_expr_kind_ord_at(arena, er) != 28)
    return 0;
  left_ref = pipeline_expr_binop_left_ref_at(arena, er);
  right_ref = pipeline_expr_binop_right_ref_at(arena, er);
  if (pipeline_expr_kind_ord_at(arena, right_ref) != 4)
    return 0;
  add_l = pipeline_expr_binop_left_ref_at(arena, right_ref);
  inner = pipeline_expr_binop_right_ref_at(arena, right_ref);
  if (!glue_fold_expr_var_refs_same_c(arena, add_l, left_ref))
    return 0;
  if (pipeline_expr_kind_ord_at(arena, inner) != 48 || pipeline_expr_call_num_args_at(arena, inner) != 1)
    return 0;
  arg0 = pipeline_expr_call_arg_ref(arena, inner, 0);
  if (!glue_fold_expr_var_refs_same_c(arena, arg0, pair_ref))
    return 0;
  callee_ref = pipeline_expr_call_callee_ref_at(arena, inner);
  if (callee_ref <= 0 || pipeline_expr_kind_ord_at(arena, callee_ref) != GLUE_EXPR_KIND_VAR)
    return 0;
  clen = pipeline_expr_var_name_len(arena, callee_ref);
  if (clen != 8)
    return 0;
  pipeline_expr_var_name_into(arena, callee_ref, cname);
  if (cname[0] != (uint8_t)'a' || cname[1] != (uint8_t)'d' || cname[2] != (uint8_t)'d' || cname[3] != (uint8_t)'_' ||
      cname[4] != (uint8_t)'p' || cname[5] != (uint8_t)'a' || cname[6] != (uint8_t)'i' || cname[7] != (uint8_t)'r')
    return 0;
  if (out_s_ref)
    *out_s_ref = left_ref;
  return 1;
}

/** 从字段赋值 expr 取 pair 基址 VAR ref。 */
static int32_t glue_field_assign_pair_base_ref_c(struct ast_ASTArena *arena, int32_t er) {
  int32_t left_ref;
  if (!arena || er <= 0 || pipeline_expr_kind_ord_at(arena, er) != 28)
    return 0;
  left_ref = pipeline_expr_binop_left_ref_at(arena, er);
  if (pipeline_expr_kind_ord_at(arena, left_ref) != 44)
    return 0;
  return pipeline_expr_field_access_base_ref(arena, left_ref);
}

/** 是否为 `buf[i] = (i as u8)`。 */
static int32_t glue_is_assign_u8_index_store_cast_i_c(struct ast_ASTArena *arena, int32_t er, int32_t *out_buf_ref,
                                                      int32_t i_ref) {
  int32_t left_ref;
  int32_t right_ref;
  int32_t as_op;
  if (!arena || er <= 0 || pipeline_expr_kind_ord_at(arena, er) != 28)
    return 0;
  left_ref = pipeline_expr_binop_left_ref_at(arena, er);
  right_ref = pipeline_expr_binop_right_ref_at(arena, er);
  if (pipeline_expr_kind_ord_at(arena, left_ref) != 47)
    return 0;
  if (pipeline_expr_kind_ord_at(arena, pipeline_expr_index_base_ref(arena, left_ref)) != GLUE_EXPR_KIND_VAR)
    return 0;
  if (!glue_fold_expr_var_refs_same_c(arena, pipeline_expr_index_index_ref(arena, left_ref), i_ref))
    return 0;
  if (!glue_expr_is_x_as_cast_at_c(arena, right_ref))
    return 0;
  as_op = pipeline_expr_as_operand_ref_at(arena, right_ref);
  if (!glue_fold_expr_var_refs_same_c(arena, as_op, i_ref))
    return 0;
  if (out_buf_ref)
    *out_buf_ref = pipeline_expr_index_base_ref(arena, left_ref);
  return 1;
}

/** 是否为 `sum = sum + (buf[j] as i32)`。 */
static int32_t glue_is_assign_sum_plus_u8_index_cast_c(struct ast_ASTArena *arena, int32_t er, int32_t *out_sum_ref,
                                                       int32_t *out_buf_ref, int32_t j_ref) {
  int32_t left_ref;
  int32_t right_ref;
  int32_t add_l;
  int32_t as_op;
  int32_t ix_ref;
  if (!arena || er <= 0 || pipeline_expr_kind_ord_at(arena, er) != 28)
    return 0;
  left_ref = pipeline_expr_binop_left_ref_at(arena, er);
  right_ref = pipeline_expr_binop_right_ref_at(arena, er);
  if (pipeline_expr_kind_ord_at(arena, right_ref) != 4)
    return 0;
  add_l = pipeline_expr_binop_left_ref_at(arena, right_ref);
  as_op = pipeline_expr_binop_right_ref_at(arena, right_ref);
  if (!glue_fold_expr_var_refs_same_c(arena, add_l, left_ref))
    return 0;
  if (!glue_expr_is_x_as_cast_at_c(arena, as_op))
    return 0;
  ix_ref = pipeline_expr_as_operand_ref_at(arena, as_op);
  if (pipeline_expr_kind_ord_at(arena, ix_ref) != 47)
    return 0;
  if (pipeline_expr_kind_ord_at(arena, pipeline_expr_index_base_ref(arena, ix_ref)) != GLUE_EXPR_KIND_VAR)
    return 0;
  if (!glue_fold_expr_var_refs_same_c(arena, pipeline_expr_index_index_ref(arena, ix_ref), j_ref))
    return 0;
  if (out_sum_ref)
    *out_sum_ref = left_ref;
  if (out_buf_ref)
    *out_buf_ref = pipeline_expr_index_base_ref(arena, ix_ref);
  return 1;
}

