/** 编译期计算 mem_copy 外层 rounds×内层 u8 累加的最终 i32 结果（含 wrap）。 */
static int32_t glue_mem_copy_fold_final_sum_i32(int32_t rounds, int32_t size) {
  uint64_t per;
  int32_t j;
  if (rounds <= 0 || size <= 0)
    return 0;
  per = 0;
  for (j = 0; j < size; j++)
    per += (uint32_t)(j & 0xff);
  return (int32_t)(uint32_t)(per * (uint64_t)(uint32_t)rounds);
}

