extern int codegen_wpo_mono_sym_format(const char *base, int nargs, const int *args, char *out, int cap);

/** WPO-S2 mono thunk 槽（glue 收集，避免 codegen ASTModule 与 ast_Module 布局差异）。 */
#define GLUE_WPO_MONO_MAX_THUNKS 64
#define GLUE_WPO_MONO_SYM_MAX 128
#define GLUE_WPO_MONO_MAX_ARGS 8

typedef struct GlueWpoMonoThunk {
  char sym[GLUE_WPO_MONO_SYM_MAX];
  int32_t result_imm;
  unsigned char valid;
} GlueWpoMonoThunk;

typedef struct GlueWpoMonoThunks {
  GlueWpoMonoThunk thunks[GLUE_WPO_MONO_MAX_THUNKS];
  int n;
} GlueWpoMonoThunks;

/** 当前 ELF codegen 已匹配的全常量 call→mono 注册表（emit 末尾写 thunk 体）。 */
static GlueWpoMonoThunks g_glue_wpo_mono_pending;

/** 单态 sym 是否已在 bag 中。 */
static int glue_wpo_mono_has_sym(const GlueWpoMonoThunks *bag, const char *sym) {
  int i;
  if (!bag || !sym)
    return 0;
  for (i = 0; i < bag->n; i++)
    if (bag->thunks[i].valid && strcmp(bag->thunks[i].sym, sym) == 0)
      return 1;
  return 0;
}

/** 新 ELF 模块 codegen 开始前清空 mono 注册表。 */
void glue_wpo_mono_reset_pending(void) {
  memset(&g_glue_wpo_mono_pending, 0, sizeof(g_glue_wpo_mono_pending));
}

/** try_call 匹配时登记单态 thunk（sym + 编译期 fold 结果；任意 nargs）。 */
void glue_wpo_mono_register_thunk_n(const char *base, int32_t nargs, const int32_t *args, int32_t folded) {
  char sym[GLUE_WPO_MONO_SYM_MAX];
  int sym_len;
  GlueWpoMonoThunk *slot;
  if (!base || !getenv("SHUX_WPO_MONO"))
    return;
  if (nargs < 0)
    nargs = 0;
  if (nargs > GLUE_WPO_MONO_MAX_ARGS)
    nargs = GLUE_WPO_MONO_MAX_ARGS;
  sym_len = codegen_wpo_mono_sym_format(base, (int)nargs, args, sym, (int)sizeof(sym));
  if (sym_len <= 0 || glue_wpo_mono_has_sym(&g_glue_wpo_mono_pending, sym))
    return;
  if (g_glue_wpo_mono_pending.n >= GLUE_WPO_MONO_MAX_THUNKS)
    return;
  slot = &g_glue_wpo_mono_pending.thunks[g_glue_wpo_mono_pending.n];
  memset(slot, 0, sizeof(*slot));
  memcpy(slot->sym, sym, (size_t)sym_len + 1);
  slot->result_imm = folded;
  slot->valid = 1;
  g_glue_wpo_mono_pending.n++;
}

/** 标量双参 mono 登记（scale 等）；委托 glue_wpo_mono_register_thunk_n。 */
void glue_wpo_mono_register_thunk(const char *base, int32_t av0, int32_t av1, int32_t folded) {
  int32_t args[2];
  args[0] = av0;
  args[1] = av1;
  glue_wpo_mono_register_thunk_n(base, 2, args, folded);
}


extern int32_t pipeline_dep_ctx_ndep(struct ast_PipelineDepCtx *ctx);
extern struct ast_Module *pipeline_dep_ctx_module_at(struct ast_PipelineDepCtx *ctx, int32_t idx);

/**
 * WPO-S2 monomorphize：在常规函数 emit 完成后追加单态 thunk（mov folded_imm; ret）。
 * 仅当 SHUX_WPO_MONO 非空时由 pipeline_backend_asm_codegen_ast_to_elf_c 调用。
 */
int32_t pipeline_asm_emit_wpo_mono_thunks_elf_c(struct ast_Module *entry, struct ast_ASTArena *arena,
                                                 struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                 struct ast_PipelineDepCtx *pipeline_ctx) {
  const GlueWpoMonoThunks *thunks;
  int ta;
  int ti;
  (void)entry;
  (void)arena;
  if (!elf_ctx || !pipeline_ctx)
    return -1;
  if (!getenv("SHUX_WPO_MONO"))
    return 0;
  thunks = &g_glue_wpo_mono_pending;
  ta = pipeline_ctx->target_arch;
  for (ti = 0; ti < thunks->n; ti++) {
    const GlueWpoMonoThunk *th = &thunks->thunks[ti];
    int32_t hi;
    uint8_t sym[GLUE_WPO_MONO_SYM_MAX];
    int32_t sym_len;
    if (!th->valid)
      continue;
    sym_len = (int32_t)strlen(th->sym);
    if (sym_len <= 0 || sym_len >= GLUE_WPO_MONO_SYM_MAX)
      return -1;
    memcpy(sym, th->sym, (size_t)sym_len);
    if (backend_enc_label_arch(elf_ctx, sym, sym_len, 1, ta) != 0)
      return -1;
    if (backend_enc_prologue_arch(elf_ctx, 0, ta) != 0)
      return -1;
    hi = (th->result_imm < 0) ? -1 : 0;
    if (backend_enc_mov_imm64_to_rax_arch(elf_ctx, th->result_imm, hi, ta) != 0)
      return -1;
    if (backend_enc_epilogue_arch(elf_ctx, ta) != 0)
      return -1;
  }
  return 0;
}

/**
 * 重置 per-func AsmFuncCtx；等价 backend.x ctx_reset（label_counter 保留以免 .L_N 重名）。
 */
static void pipeline_asm_ctx_reset_for_func_c(pipeline_glue_AsmFuncCtxLayout *ctx, struct ast_Module *mod) {
  if (!ctx)
    return;
  ctx->frame_size = 0;
  ctx->next_offset = 0;
  ctx->num_locals = 0;
  ctx->module_ref = mod;
  ctx->break_len = 0;
  ctx->continue_len = 0;
  ctx->loop_label_depth = 0;
  ctx->dep_pipe = NULL;
  ctx->tail_join_label_len = 0;
  asm_ctx_local_reset((uint8_t *)ctx);
}

/**
 * M8-tail ELF mega 主循环 C 体：打破 seed_mega→backend_asm_codegen_ast_to_elf→pipeline 递归 SIGSEGV。
 * 端口 backend.x asm_codegen_ast_to_elf_seed_mega（2517+）。
 */
/** co-emit dep 导出符号前缀；定义见 backend_call_dispatch.c。 */
extern int32_t glue_asm_build_dep_export_sym_c(const uint8_t *name, int32_t name_len, uint8_t *out, int32_t out_cap);
extern int32_t glue_asm_build_func_export_sym_c(struct ast_Module *m, struct ast_ASTArena *a, int32_t func_ix,
                                                uint8_t *out, int32_t out_cap);
extern int32_t pipeline_typeck_pick_overload_func_index_for_call_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                                  int32_t call_expr_ref);
extern int32_t pipeline_typeck_resolve_call_func_index_for_emit_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                                  int32_t call_expr_ref);

int32_t pipeline_backend_asm_codegen_ast_to_elf_mega_body_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                             struct platform_elf_ElfCodegenCtx *elf_ctx,
                                                             struct ast_PipelineDepCtx *pipeline_ctx) {
  int32_t ta;
  pipeline_glue_AsmFuncCtxLayout ctx;
  uint8_t fname_buf[64];
  int32_t start_skip;
  int32_t emit_n;
  int32_t k;

  if (!m || !a || !elf_ctx || !pipeline_ctx)
    return -1;
  ta = pipeline_ctx->target_arch;
  if (ta == 1) {
    elf_ctx->e_machine = 183;
    elf_ctx->reloc_type_r_pc32 = 283;
  } else if (ta == 2) {
    elf_ctx->e_machine = 243;
    elf_ctx->reloc_type_r_pc32 = 32;
  } else {
    elf_ctx->e_machine = 62;
    elf_ctx->reloc_type_r_pc32 = 2;
  }
  memset(&ctx, 0, sizeof(ctx));
  pipeline_asm_wpo_pgo_emit_order_prepare(m);
  start_skip = asm_diag_start_func_skip();
  emit_n = pipeline_asm_wpo_pgo_emit_order_count(m);
  if (getenv("SHUX_ASM_DEBUG"))
    fprintf(stderr, "shux: mega_body_c start emit_n=%d start_skip=%d nf=%d\n", (int)emit_n, (int)start_skip,
            (int)pipeline_module_num_funcs(m));
  for (k = 0; k < emit_n; k++) {
    int32_t i = pipeline_asm_wpo_pgo_emit_order_at(m, k);
    int32_t body_ref;
    int32_t frame_sz;
    int32_t fname_len;
    int32_t export_sym_len;
    int32_t result_ref;
    uint8_t export_sym[64];
    struct backend_AsmFuncCtx *bctx = (struct backend_AsmFuncCtx *)&ctx;

    if (i < 0)
      continue;
    if (i < start_skip)
      continue;
    pipeline_elf_ctx_set_emit_hot((uint8_t *)elf_ctx, pipeline_asm_wpo_pgo_is_hot_func(m, i));
    pipeline_asm_module_func_name_copy64(m, i, fname_buf);
    fname_len = pipeline_asm_module_func_name_len_at(m, i);
    driver_diagnostic_asm_set_current_func(fname_buf, fname_len);
    pipeline_asm_emit_set_func_index(i);
    pipeline_debug_trace_named_func_bodies("mega_pre_reset", m, a);
    pipeline_asm_ctx_reset_for_func_c(&ctx, m);
    ctx.dep_pipe = pipeline_ctx;
    g_pipeline_asm_func_sret_active = 0;
    g_pipeline_asm_sret_home_off = -1;
    g_pipeline_asm_func_sret_ret_sz = 0;
    pipeline_asm_fill_param_slots(bctx, m, i);
    pipeline_debug_trace_named_func_bodies("mega_post_param_slots", m, a);
    /** SysV >16B 返回：预留 8B 保存 incoming hidden rdi（须在 top-level lets 之前）。 */
    if (ta == 0) {
      int32_t fn_ret_sz = glue_func_return_byte_size_c(m, a, i);
      if (fn_ret_sz > 16) {
        g_pipeline_asm_func_sret_ret_sz = fn_ret_sz;
        g_pipeline_asm_func_sret_active = 1;
        g_pipeline_asm_sret_home_off = ctx.next_offset;
        ctx.next_offset += 8;
      }
    }
    pipeline_asm_register_module_top_level_lets_c(bctx, m, a, i);
    pipeline_debug_trace_named_func_bodies("mega_post_register_top_level", m, a);
    export_sym_len = glue_asm_build_func_export_sym_c(m, a, i, export_sym, 64);
    if (export_sym_len <= 0)
      return -1;
    if (backend_enc_label_arch(elf_ctx, export_sym, export_sym_len, 1, ta) != 0) {
      if (getenv("SHUX_ASM_DEBUG"))
        fprintf(stderr, "shux: mega_body_c enc_label fail func=%.*s\n", (int)export_sym_len, (char *)export_sym);
      return -1;
    }
    if (asm_skip_heavy_module_func_body(m, a, i) != 0) {
      if (backend_enc_prologue_arch(elf_ctx, 0, ta) != 0)
        return -1;
      if (pipeline_asm_emit_skip_heavy_or_thin_stub_elf_c(elf_ctx, ta, m, i) != 0)
        return -1;
      continue;
    }
    body_ref = pipeline_asm_module_func_body_ref_at(m, i);
    frame_sz = 0;
    if (body_ref != 0) {
      frame_sz = pipeline_asm_compute_frame_size_c(pipeline_asm_module_func_num_params_at(m, i), a, body_ref, m,
                                                    i);
      pipeline_debug_trace_named_func_bodies("mega_post_frame_size", m, a);
      if (pipeline_asm_block_num_stmt_order_at(a, body_ref) == 0)
        pipeline_asm_fill_local_slots(bctx, a, body_ref);
      pipeline_debug_trace_named_func_bodies("mega_post_fill_local_slots", m, a);
    }
    if (backend_enc_prologue_arch(elf_ctx, frame_sz, ta) != 0)
      return -1;
    if (pipeline_asm_emit_param_home_elf_c(elf_ctx, bctx, m, i, ta) != 0)
      return -1;
    if (pipeline_asm_emit_async_cps_entry_elf_c(a, elf_ctx, bctx, m, i, ta) != 0)
      return -1;
    if (body_ref != 0) {
      ctx.tail_join_label_len = pipeline_asm_emit_next_label_c(bctx, ctx.tail_join_label, 64);
      if (pipeline_asm_block_num_stmt_order_at(a, body_ref) > 0) {
        pipeline_debug_trace_named_func_bodies("mega_pre_emit_block_body", m, a);
        if (backend_emit_block_body_sync_elf(a, elf_ctx, body_ref, bctx, ta) != 0) {
          if (getenv("SHUX_ASM_DEBUG"))
            fprintf(stderr, "shux: mega_body_c emit_block_body fail func=%.*s fi=%d body_ref=%d\n",
                    (int)fname_len, (char *)fname_buf, (int)i, (int)body_ref);
          return -1;
        }
      } else {
        int32_t slot_base =
            ctx.num_locals - ast_ast_block_num_consts(a, body_ref) - ast_ast_block_num_lets(a, body_ref);
        if (slot_base < 0)
          return -1;
        if (pipeline_asm_emit_block_inits_elf_c(a, elf_ctx, body_ref, bctx, ta, slot_base) != 0)
          return -1;
      }
      if (backend_enc_label_arch(elf_ctx, ctx.tail_join_label, ctx.tail_join_label_len, 0, ta) != 0)
        return -1;
    }
    result_ref = 0;
    if (body_ref == 0 || pipeline_asm_block_num_stmt_order_at(a, body_ref) == 0)
      result_ref = pipeline_asm_get_return_expr_ref_at(a, m, i);
    if (result_ref != 0) {
      if (pipeline_asm_emit_expr_elf_c(a, elf_ctx, result_ref, bctx, ta) != 0)
        return -1;
    }
    if (backend_enc_epilogue_arch(elf_ctx, ta) != 0) {
      if (getenv("SHUX_ASM_DEBUG"))
        fprintf(stderr, "shux: mega_body_c epilogue fail func=%.*s fi=%d\n", (int)fname_len, (char *)fname_buf,
                (int)i);
      return -1;
    }
    pipeline_asm_emit_async_cps_end_func_elf_c();
  }
  if (getenv("SHUX_ASM_DEBUG"))
    fprintf(stderr, "shux: mega_body_c done emit_n=%d rc=0\n", (int)emit_n);
  return 0;
}

