extern void lsp_diag_report_typeck(int line, int col, const char *fmt, ...);

/** M-3：slice 域冲突（expect/src 均带 label 且不同）返回 1。 */
static int32_t pipeline_typeck_slice_region_conflict_c(struct ast_ASTArena *arena, int32_t expect_ref,
                                                       int32_t src_ref) {
  int32_t ek;
  int32_t sk;
  uint8_t eb[64];
  uint8_t sb[64];
  if (!arena || expect_ref <= 0 || src_ref <= 0)
    return 0;
  if (pipeline_type_kind_ord_at(arena, expect_ref) != (int32_t)ast_TypeKind_TYPE_SLICE ||
      pipeline_type_kind_ord_at(arena, src_ref) != (int32_t)ast_TypeKind_TYPE_SLICE)
    return 0;
  ek = pipeline_type_region_label_len_at(arena, expect_ref);
  sk = pipeline_type_region_label_len_at(arena, src_ref);
  if (ek <= 0 || sk <= 0)
    return 0;
  if (pipeline_type_region_label_into(arena, expect_ref, eb) != ek ||
      pipeline_type_region_label_into(arena, src_ref, sb) != sk)
    return 0;
  return (ek != sk || memcmp(eb, sb, (size_t)ek) != 0) ? 1 : 0;
}

/** M-3：域绑定 slice 逃逸到未标注域（src 有 label、expect 无）返回 1。 */
static int32_t pipeline_typeck_slice_region_escape_c(struct ast_ASTArena *arena, int32_t expect_ref,
                                                     int32_t src_ref) {
  if (!arena || expect_ref <= 0 || src_ref <= 0)
    return 0;
  if (pipeline_type_kind_ord_at(arena, expect_ref) != (int32_t)ast_TypeKind_TYPE_SLICE ||
      pipeline_type_kind_ord_at(arena, src_ref) != (int32_t)ast_TypeKind_TYPE_SLICE)
    return 0;
  return (pipeline_type_region_label_len_at(arena, src_ref) > 0 &&
          pipeline_type_region_label_len_at(arena, expect_ref) <= 0)
             ? 1
             : 0;
}

/**
 * M-3：.x typeck 统一 slice 域 assign/let/实参检查；与 typeck.c typeck_check_slice_region_assign 措辞一致。
 * site_expr_ref 用于 line/col；返回 0 可接受，-1 已打印 typeck error。
 */
static void pipeline_typeck_expr_diag_line_col_c(struct ast_ASTArena *a, int32_t expr_ref, int32_t *line,
                                                 int32_t *col);

int32_t pipeline_typeck_check_slice_region_assign_c(struct ast_ASTArena *arena, int32_t site_expr_ref,
                                                    int32_t expect_ref, int32_t src_ref) {
  int32_t line;
  int32_t col;
  uint8_t sb[64];
  int32_t slen;
  uint8_t eb[64];
  int32_t elen;
  if (!arena || expect_ref <= 0 || src_ref <= 0)
    return 0;
  if (pipeline_type_kind_ord_at(arena, expect_ref) != (int32_t)ast_TypeKind_TYPE_SLICE ||
      pipeline_type_kind_ord_at(arena, src_ref) != (int32_t)ast_TypeKind_TYPE_SLICE)
    return 0;
  line = 0;
  col = 0;
  pipeline_typeck_expr_diag_line_col_c(arena, site_expr_ref, &line, &col);
  if (pipeline_typeck_slice_region_escape_c(arena, expect_ref, src_ref)) {
    slen = pipeline_type_region_label_into(arena, src_ref, sb);
    sb[slen > 0 && slen < 64 ? slen : 0] = '\0';
    lsp_diag_report_typeck((int)line, (int)col,
                           "slice region escape: cannot assign <%.*s> slice to unbound T[]", (int)(slen > 0 ? slen : 0),
                           (const char *)sb);
    return -1;
  }
  if (pipeline_typeck_slice_region_conflict_c(arena, expect_ref, src_ref)) {
    elen = pipeline_type_region_label_into(arena, expect_ref, eb);
    slen = pipeline_type_region_label_into(arena, src_ref, sb);
    eb[elen > 0 && elen < 64 ? elen : 0] = '\0';
    sb[slen > 0 && slen < 64 ? slen : 0] = '\0';
    lsp_diag_report_typeck((int)line, (int)col, "slice region mismatch: expected <%.*s>, found <%.*s>",
                           (int)(elen > 0 ? elen : 0), (const char *)eb, (int)(slen > 0 ? slen : 0),
                           (const char *)sb);
    return -1;
  }
  return 0;
}

/** M-4：线性类型 use-once move 跟踪（按变量名；每函数 reset）。 */
#define TYPECK_LINEAR_MOVED_MAX 128
static int g_typeck_linear_moved_n;
static char g_typeck_linear_moved_names[TYPECK_LINEAR_MOVED_MAX][64];
static int32_t g_typeck_linear_moved_lens[TYPECK_LINEAR_MOVED_MAX];

/** WPO-S3：typeck 活跃 module/ctx（call slice 检查等 C glue 无 ctx 参数时回落）。 */
static struct ast_PipelineDepCtx *g_typeck_active_ctx;

/** WPO-S3：进入函数 typeck 前设置活跃 ctx（typeck_x_ast 每函数调用）。 */
void pipeline_typeck_set_active_ctx_c(struct ast_Module *module, struct ast_PipelineDepCtx *ctx) {
  g_typeck_active_module = module;
  g_typeck_active_ctx = ctx;
}

/** M-4：进入新函数 typeck 前清零 moved 集合。 */
void pipeline_typeck_linear_reset_c(void) {
  g_typeck_linear_moved_n = 0;
}

static int typeck_linear_name_already_moved(const uint8_t *name, int32_t name_len) {
  int i;
  for (i = 0; i < g_typeck_linear_moved_n; i++)
    if (g_typeck_linear_moved_lens[i] == name_len && name_len > 0 &&
        memcmp(g_typeck_linear_moved_names[i], name, (size_t)name_len) == 0)
      return 1;
  return 0;
}

/**
 * M-4：VAR 读取 Linear(T) 时检查 double-move；成功则标记 moved。返回 0 可接受，-1 已报错。
 */
int32_t pipeline_typeck_linear_use_var_c(struct ast_ASTArena *arena, int32_t type_ref, int32_t expr_ref,
                                         uint8_t *name, int32_t name_len) {
  int32_t line;
  int32_t col;
  if (!arena || name_len <= 0 || name_len > 63 || !name)
    return 0;
  if (type_ref <= 0 || pipeline_type_kind_ord_at(arena, type_ref) != (int32_t)ast_TypeKind_TYPE_LINEAR)
    return 0;
  if (typeck_linear_name_already_moved(name, name_len)) {
    line = 0;
    col = 0;
    if (expr_ref > 0 && expr_ref <= arena->num_exprs) {
      line = pipeline_expr_line_at(arena, expr_ref);
      col = pipeline_expr_col_at(arena, expr_ref);
    }
    lsp_diag_report_typeck((int)line, (int)col, "linear value used after move");
    return -1;
  }
  if (g_typeck_linear_moved_n < TYPECK_LINEAR_MOVED_MAX) {
    memcpy(g_typeck_linear_moved_names[g_typeck_linear_moved_n], name, (size_t)name_len);
    g_typeck_linear_moved_lens[g_typeck_linear_moved_n] = name_len;
    g_typeck_linear_moved_n++;
  }
  return 0;
}

/** M-4：Linear(T) let 是否接受内层 T 或 Linear(T) 初值。 */
int32_t pipeline_typeck_linear_accepts_init_c(struct ast_ASTArena *arena, int32_t decl_ref,
                                                int32_t init_ref) {
  if (!arena || decl_ref <= 0 || init_ref <= 0)
    return 0;
  if (pipeline_type_kind_ord_at(arena, decl_ref) != (int32_t)ast_TypeKind_TYPE_LINEAR)
    return 0;
  if (pipeline_typeck_type_refs_equal_c(arena, decl_ref, init_ref))
    return 1;
  return pipeline_typeck_type_refs_equal_c(arena, pipeline_type_elem_ref_at(arena, decl_ref), init_ref);
}

/**
 * M-4：ADDR_OF 操作数为 Linear 变量时拒绝（须在 pipeline_typeck_linear_use_var_c 之前）。
 * 返回 0 可继续；-1 已打印诊断。
 */
int32_t pipeline_typeck_reject_addr_of_linear_c(struct ast_ASTArena *arena, int32_t op_ref,
    int32_t addr_expr_ref, struct ast_Module *module, struct ast_PipelineDepCtx *ctx) {
  int32_t vnlen;
  int32_t block_ref;
  int32_t vd_tr;
  int32_t func_ix;
  int32_t pr;
  int32_t line;
  int32_t col;
  uint8_t vbuf[64];
  extern void driver_diagnostic_typeck_linear_addr_of(int32_t line, int32_t col);
  if (!arena || !module || !ctx || op_ref <= 0 || op_ref > arena->num_exprs)
    return 0;
  if (pipeline_expr_kind_ord_at(arena, op_ref) != 3)
    return 0;
  vnlen = pipeline_expr_var_name_len(arena, op_ref);
  if (vnlen <= 0 || vnlen > 63)
    return 0;
  pipeline_expr_var_name_into(arena, op_ref, vbuf);
  block_ref = ctx->current_block_ref;
  if (block_ref > 0 && block_ref <= arena->num_blocks) {
    vd_tr = pipeline_block_resolve_var_type_ref(arena, block_ref, vbuf, vnlen);
    if (vd_tr > 0 && pipeline_type_kind_ord_at(arena, vd_tr) == (int32_t)ast_TypeKind_TYPE_LINEAR)
      goto reject;
  }
  func_ix = ctx->current_func_index;
  if (func_ix >= 0 && func_ix < module->num_funcs) {
    pr = pipeline_module_func_param_type_ref_for_name(module, func_ix, vbuf, vnlen);
    if (pr > 0 && pipeline_type_kind_ord_at(arena, pr) == (int32_t)ast_TypeKind_TYPE_LINEAR)
      goto reject;
  }
  return 0;
reject:
  line = 0;
  col = 0;
  if (addr_expr_ref > 0 && addr_expr_ref <= arena->num_exprs) {
    line = pipeline_expr_line_at(arena, addr_expr_ref);
    col = pipeline_expr_col_at(arena, addr_expr_ref);
  }
  driver_diagnostic_typeck_linear_addr_of(line, col);
  return -1;
}

/** WPO-S3：*T 栈局部域标签（与 slice region_label 共用 Type 槽；仅 TYPE_PTR）。 */
static const uint8_t TYPECK_STACK_LOCAL_PTR_LBL[] = "stack_local";

static int32_t pipeline_typeck_resolve_call_func_index_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                         int32_t call_expr_ref);
static int32_t pipeline_typeck_check_call_struct_stack_escape_c(struct ast_Module *module,
                                                                struct ast_ASTArena *arena,
                                                                int32_t call_expr_ref,
                                                                struct ast_PipelineDepCtx *ctx);

/** WPO-S3：类型是否为模块内已登记的 struct（TYPE_NAMED 且匹配 struct_layout）。 */
static int32_t typeck_type_is_named_struct_c(struct ast_Module *m, struct ast_ASTArena *a, int32_t ty_ref) {
  uint8_t name[64];
  int32_t nlen;
  int32_t k;
  int32_t j;
  if (!m || !a || ty_ref <= 0)
    return 0;
  if (pipeline_type_kind_ord_at(a, ty_ref) != (int32_t)ast_TypeKind_TYPE_NAMED)
    return 0;
  nlen = pipeline_type_named_name_into(a, ty_ref, name);
  if (nlen <= 0 || nlen > 63)
    return 0;
  for (k = 0; k < (int32_t)m->num_struct_layouts; k++) {
    int32_t ln = pipeline_module_struct_layout_name_len(m, k);
    int32_t eq = 1;
    if (ln != nlen)
      continue;
    for (j = 0; j < nlen; j++) {
      if (pipeline_module_struct_layout_name_byte_at(m, k, j) != name[j]) {
        eq = 0;
        break;
      }
    }
    if (eq)
      return 1;
  }
  return 0;
}

/** WPO-S3：查找或分配带 stack_local 域标签的 *elem_ref。 */
static int32_t typeck_find_or_alloc_ptr_stack_local_c(struct ast_ASTArena *a, int32_t elem_ref) {
  int32_t k;
  struct ast_Type *t;
  static const int32_t lbl_len = 11;
  if (!a || elem_ref <= 0)
    return 0;
  for (k = 1; k <= a->num_types; k++) {
    t = pipeline_arena_type_ptr(a, k);
    if (t && t->kind == ast_TypeKind_TYPE_PTR && t->elem_type_ref == elem_ref && t->name_len == 0 &&
        t->region_label_len == lbl_len &&
        memcmp(t->region_label, TYPECK_STACK_LOCAL_PTR_LBL, (size_t)lbl_len) == 0)
      return k;
  }
  k = pipeline_arena_type_alloc(a);
  if (k <= 0)
    return 0;
  t = pipeline_arena_type_ptr(a, k);
  if (!t)
    return 0;
  memset(t, 0, sizeof(*t));
  t->kind = ast_TypeKind_TYPE_PTR;
  t->elem_type_ref = elem_ref;
  memcpy(t->region_label, TYPECK_STACK_LOCAL_PTR_LBL, (size_t)lbl_len);
  t->region_label_len = lbl_len;
  return k;
}

/** WPO-S3：ptr 类型是否带 stack_local 域（局部 struct 取址标记）。 */
static int32_t typeck_ptr_has_stack_local_label_c(struct ast_ASTArena *a, int32_t ty_ref) {
  struct ast_Type *t;
  static const int32_t lbl_len = 11;
  if (!a || ty_ref <= 0 || ty_ref > a->num_types)
    return 0;
  t = pipeline_arena_type_ptr(a, ty_ref);
  if (!t || t->kind != ast_TypeKind_TYPE_PTR)
    return 0;
  return (t->region_label_len == lbl_len &&
          memcmp(t->region_label, TYPECK_STACK_LOCAL_PTR_LBL, (size_t)lbl_len) == 0)
             ? 1
             : 0;
}

/** WPO-S3：块子树（含 while/for/if/region 体）内是否存在 let/const 名 vname。 */
static int32_t typeck_block_tree_has_var_c(struct ast_ASTArena *a, int32_t block_ref, uint8_t *vname,
                                           int32_t vlen) {
  int32_t nso;
  int32_t i;
  if (!a || block_ref <= 0 || !vname || vlen <= 0)
    return 0;
  if (pipeline_block_resolve_var_type_ref(a, block_ref, vname, vlen) > 0)
    return 1;
  nso = ast_ast_block_num_stmt_order(a, block_ref);
  for (i = 0; i < nso; i++) {
    uint8_t sk = ast_ast_block_stmt_order_kind(a, block_ref, i);
    int32_t idx = ast_ast_block_stmt_order_idx(a, block_ref, i);
    int32_t br = 0;
    if (sk == 3 && idx >= 0 && idx < ast_ast_block_num_loops(a, block_ref))
      br = ast_ast_block_while_body_ref(a, block_ref, idx);
    else if (sk == 4 && idx >= 0 && idx < ast_ast_block_num_for_loops(a, block_ref))
      br = ast_ast_block_for_body_ref(a, block_ref, idx);
    else if (sk == 5 && idx >= 0 && idx < ast_ast_block_num_if_stmts(a, block_ref)) {
      int32_t tr = ast_ast_block_if_then_body_ref(a, block_ref, idx);
      int32_t er = ast_ast_block_if_else_body_ref(a, block_ref, idx);
      if (tr > 0 && typeck_block_tree_has_var_c(a, tr, vname, vlen))
        return 1;
      if (er > 0 && typeck_block_tree_has_var_c(a, er, vname, vlen))
        return 1;
      continue;
    } else if (sk == 6 && idx >= 0 && idx < ast_ast_block_num_regions(a, block_ref))
      br = ast_ast_block_region_body_ref(a, block_ref, idx);
    if (br > 0 && typeck_block_tree_has_var_c(a, br, vname, vlen))
      return 1;
  }
  return 0;
}

/** WPO-S3：VAR 是否为块内 let/const 且非形参。 */
static int32_t typeck_var_is_block_local_c(struct ast_Module *m, struct ast_ASTArena *a,
                                           struct ast_PipelineDepCtx *ctx, int32_t expr_ref) {
  int32_t vlen;
  uint8_t vbuf[64];
  int32_t func_ix;
  int32_t body_ref;
  if (!m || !a || !ctx || expr_ref <= 0)
    return 0;
  if (pipeline_expr_kind_ord_at(a, expr_ref) != GLUE_EXPR_KIND_VAR)
    return 0;
  vlen = pipeline_expr_var_name_len(a, expr_ref);
  if (vlen <= 0 || vlen > 63)
    return 0;
  pipeline_expr_var_name_into(a, expr_ref, vbuf);
  func_ix = ctx->current_func_index;
  if (func_ix >= 0 && pipeline_module_func_param_type_ref_for_name(m, func_ix, vbuf, vlen) > 0)
    return 0;
  if (ctx->current_block_ref > 0 &&
      pipeline_block_resolve_var_type_ref(a, ctx->current_block_ref, vbuf, vlen) > 0)
    return 1;
  /** post-scan 等路径 ctx 块可能未 push：回落函数体根块及子块查 let。 */
  if (func_ix >= 0) {
    body_ref = pipeline_module_func_body_ref_at(m, func_ix);
    if (body_ref > 0 && typeck_block_tree_has_var_c(a, body_ref, vbuf, vlen))
      return 1;
  }
  return 0;
}

/** WPO-S3：expr 是否为 &块内局部（call 逃逸检测用；*Struct 形参侧另判）。 */
static int32_t typeck_expr_is_addr_of_block_local_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                   struct ast_PipelineDepCtx *ctx, int32_t expr_ref) {
  int32_t op_ref;
  if (!m || !a || !ctx || expr_ref <= 0)
    return 0;
  if (typeck_ptr_has_stack_local_label_c(a, pipeline_expr_resolved_type_ref(a, expr_ref)))
    return 1;
  if (pipeline_expr_kind_ord_at(a, expr_ref) != (int32_t)ast_ExprKind_EXPR_ADDR_OF)
    return 0;
  op_ref = pipeline_expr_unary_operand_ref_at(a, expr_ref);
  return op_ref > 0 && typeck_var_is_block_local_c(m, a, ctx, op_ref) ? 1 : 0;
}

/** WPO-S3：left 是否为第 dst_pi 形参（*T）上的字段写入左值（含 field 链基为形参）。 */
static int32_t typeck_lval_is_param_ptr_field_c(struct ast_Module *m, struct ast_ASTArena *a, int32_t func_ix,
                                                int32_t left_ref, int32_t dst_pi) {
  int32_t base_ref;
  int32_t param_ty;
  int32_t np;
  int32_t pi;
  if (!m || !a || left_ref <= 0 || func_ix < 0 || dst_pi < 0)
    return 0;
  if (pipeline_expr_kind_ord_at(a, left_ref) != (int32_t)ast_ExprKind_EXPR_FIELD_ACCESS)
    return 0;
  base_ref = pipeline_expr_field_access_base_ref(a, left_ref);
  if (glue_expr_is_func_param_at_c(a, m, func_ix, base_ref, dst_pi)) {
    param_ty = pipeline_module_func_param_type_ref_at(m, func_ix, dst_pi);
    return param_ty > 0 && pipeline_type_kind_ord_at(a, param_ty) == (int32_t)ast_TypeKind_TYPE_PTR ? 1 : 0;
  }
  /** field 链：slot.x.ptr 等，沿 base 找 *T 形参。 */
  np = pipeline_module_func_num_params_at(m, func_ix);
  for (pi = 0; pi < np; pi++) {
    if (glue_expr_is_func_param_at_c(a, m, func_ix, base_ref, pi)) {
      param_ty = pipeline_module_func_param_type_ref_at(m, func_ix, pi);
      if (param_ty > 0 && pipeline_type_kind_ord_at(a, param_ty) == (int32_t)ast_TypeKind_TYPE_PTR)
        return pi == dst_pi ? 1 : 0;
    }
  }
  return 0;
}

/** WPO-S3：扫描块内 expr_stmts 是否存在 param[dst].field = param[src]。 */
static int32_t typeck_block_expr_stmts_store_scan_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                    int32_t block_ref, int32_t func_ix, int32_t dst_pi,
                                                    int32_t src_pi) {
  int32_t nes;
  int32_t ei;
  if (!m || !a || block_ref <= 0 || func_ix < 0)
    return 0;
  nes = ast_ast_block_num_expr_stmts(a, block_ref);
  for (ei = 0; ei < nes; ei++) {
    int32_t er = ast_ast_block_expr_stmt_ref(a, block_ref, ei);
    int32_t left_ref;
    int32_t right_ref;
    if (er <= 0 || !glue_expr_kind_is_assign_like_ord(pipeline_expr_kind_ord_at(a, er)))
      continue;
    left_ref = pipeline_expr_binop_left_ref_at(a, er);
    right_ref = pipeline_expr_binop_right_ref_at(a, er);
    if (typeck_lval_is_param_ptr_field_c(m, a, func_ix, left_ref, dst_pi) &&
        glue_expr_is_func_param_at_c(a, m, func_ix, right_ref, src_pi))
      return 1;
  }
  return 0;
}

/** WPO-S3：块内是否存在 dst_pi 形参字段 = src_pi 形参 的赋值。 */
static int32_t typeck_block_stores_param_into_param_field_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                            int32_t block_ref, int32_t func_ix, int32_t dst_pi,
                                                            int32_t src_pi) {
  int32_t nso;
  int32_t i;
  if (!m || !a || block_ref <= 0 || func_ix < 0)
    return 0;
  if (typeck_block_expr_stmts_store_scan_c(m, a, block_ref, func_ix, dst_pi, src_pi))
    return 1;
  nso = ast_ast_block_num_stmt_order(a, block_ref);
  for (i = 0; i < nso; i++) {
    uint8_t item_kind = ast_ast_block_stmt_order_kind(a, block_ref, i);
    int32_t idx = ast_ast_block_stmt_order_idx(a, block_ref, i);
    if (item_kind == 2 && idx >= 0 && idx < ast_ast_block_num_expr_stmts(a, block_ref)) {
      int32_t er = ast_ast_block_expr_stmt_ref(a, block_ref, idx);
      int32_t left_ref;
      int32_t right_ref;
      if (er <= 0 || !glue_expr_kind_is_assign_like_ord(pipeline_expr_kind_ord_at(a, er)))
        continue;
      left_ref = pipeline_expr_binop_left_ref_at(a, er);
      right_ref = pipeline_expr_binop_right_ref_at(a, er);
      if (typeck_lval_is_param_ptr_field_c(m, a, func_ix, left_ref, dst_pi) &&
          glue_expr_is_func_param_at_c(a, m, func_ix, right_ref, src_pi))
        return 1;
    } else if (item_kind == 3 && idx >= 0 && idx < ast_ast_block_num_loops(a, block_ref)) {
      int32_t body_ref = ast_ast_block_while_body_ref(a, block_ref, idx);
      if (body_ref > 0 &&
          typeck_block_stores_param_into_param_field_c(m, a, body_ref, func_ix, dst_pi, src_pi))
        return 1;
    } else if (item_kind == 4 && idx >= 0 && idx < ast_ast_block_num_for_loops(a, block_ref)) {
      int32_t body_ref = ast_ast_block_for_body_ref(a, block_ref, idx);
      if (body_ref > 0 &&
          typeck_block_stores_param_into_param_field_c(m, a, body_ref, func_ix, dst_pi, src_pi))
        return 1;
    } else if (item_kind == 5 && idx >= 0 && idx < ast_ast_block_num_regions(a, block_ref)) {
      int32_t body_ref = ast_ast_block_region_body_ref(a, block_ref, idx);
      if (body_ref > 0 &&
          typeck_block_stores_param_into_param_field_c(m, a, body_ref, func_ix, dst_pi, src_pi))
        return 1;
    }
  }
  return 0;
}

/** WPO-S3：扫描块 final_expr 是否为 param[dst].field = param[src]。 */
static int32_t typeck_block_final_expr_store_scan_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                    int32_t block_ref, int32_t func_ix, int32_t dst_pi,
                                                    int32_t src_pi) {
  int32_t fin;
  int32_t left_ref;
  int32_t right_ref;
  if (!m || !a || block_ref <= 0 || func_ix < 0)
    return 0;
  fin = pipeline_asm_block_final_expr_ref_at(a, block_ref);
  if (fin <= 0 || !glue_expr_kind_is_assign_like_ord(pipeline_expr_kind_ord_at(a, fin)))
    return 0;
  left_ref = pipeline_expr_binop_left_ref_at(a, fin);
  right_ref = pipeline_expr_binop_right_ref_at(a, fin);
  return typeck_lval_is_param_ptr_field_c(m, a, func_ix, left_ref, dst_pi) &&
                 glue_expr_is_func_param_at_c(a, m, func_ix, right_ref, src_pi)
             ? 1
             : 0;
}

/** WPO-S3：callee 是否将 src 形参写入 dst 形参（*T）指向对象的字段。 */
static int32_t typeck_func_stores_param_into_param_field_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                           int32_t func_ix, int32_t dst_pi, int32_t src_pi) {
  int32_t body_ref;
  if (!m || !a || func_ix < 0)
    return 0;
  body_ref = pipeline_module_func_body_ref_at(m, func_ix);
  if (body_ref <= 0)
    return 0;
  if (typeck_block_expr_stmts_store_scan_c(m, a, body_ref, func_ix, dst_pi, src_pi))
    return 1;
  if (typeck_block_final_expr_store_scan_c(m, a, body_ref, func_ix, dst_pi, src_pi))
    return 1;
  return typeck_block_stores_param_into_param_field_c(m, a, body_ref, func_ix, dst_pi, src_pi);
}

/**
 * WPO-S3：&local struct 时返回 stack_local *T，否则 0（调用方回落普通 *T）。
 */
int32_t pipeline_typeck_ptr_for_addr_of_operand_c(struct ast_ASTArena *arena, int32_t op_ref, int32_t elem_ty,
                                                  struct ast_Module *module, struct ast_PipelineDepCtx *ctx) {
  if (!arena || !module || !ctx || op_ref <= 0 || elem_ty <= 0)
    return 0;
  if (!typeck_var_is_block_local_c(module, arena, ctx, op_ref))
    return 0;
  if (!typeck_type_is_named_struct_c(module, arena, elem_ty))
    return 0;
  return typeck_find_or_alloc_ptr_stack_local_c(arena, elem_ty);
}

/**
 * WPO-S3：assign 路径 — 禁止将局部 struct 指针写入形参 *T 的字段（外层槽逃逸）。
 */
int32_t pipeline_typeck_check_struct_stack_escape_assign_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                           int32_t site_expr_ref, int32_t left_ref, int32_t right_ref,
                                                           struct ast_PipelineDepCtx *ctx) {
  int32_t func_ix;
  int32_t np;
  int32_t pi;
  int32_t line;
  int32_t col;
  if (!module || !arena || !ctx || left_ref <= 0 || right_ref <= 0)
    return 0;
  if (!typeck_expr_is_addr_of_block_local_c(module, arena, ctx, right_ref))
    return 0;
  func_ix = ctx->current_func_index;
  if (func_ix < 0)
    return 0;
  np = pipeline_module_func_num_params_at(module, func_ix);
  for (pi = 0; pi < np; pi++) {
    if (typeck_lval_is_param_ptr_field_c(module, arena, func_ix, left_ref, pi)) {
      line = 0;
      col = 0;
      if (site_expr_ref > 0 && site_expr_ref <= arena->num_exprs) {
        line = pipeline_expr_line_at(arena, site_expr_ref);
        col = pipeline_expr_col_at(arena, site_expr_ref);
      }
      lsp_diag_report_typeck((int)line, (int)col,
                             "struct stack escape: cannot store address of local struct in outer lifetime");
      return -1;
    }
  }
  return 0;
}

/** MEM-A3：block ancestor 是否为 block descendant 的严格外层父链祖先。 */
static int32_t typeck_block_is_strict_ancestor_c(struct ast_ASTArena *a, int32_t ancestor, int32_t descendant) {
  struct ast_Block *b;
  int32_t cur;
  int32_t depth;
  if (!a || ancestor <= 0 || descendant <= 0 || ancestor == descendant)
    return 0;
  cur = descendant;
  depth = 0;
  while (cur > 0 && cur <= a->num_blocks && depth < 128) {
    b = pipeline_arena_block_ptr(a, cur);
    if (!b)
      break;
    if (b->parent_block_ref == ancestor)
      return 1;
    cur = b->parent_block_ref;
    depth++;
  }
  return 0;
}

/** MEM-A3：自 lvalue expr 沿 field/index 链取根 VAR 名。 */
static int32_t typeck_expr_lval_root_var_c(struct ast_ASTArena *a, int32_t expr_ref, uint8_t *out, int32_t *out_len) {
  int32_t cur;
  int32_t k;
  if (!a || expr_ref <= 0 || !out || !out_len)
    return 0;
  cur = expr_ref;
  for (;;) {
    k = pipeline_expr_kind_ord_at(a, cur);
    if (k == GLUE_EXPR_KIND_VAR) {
      *out_len = pipeline_expr_var_name_len(a, cur);
      if (*out_len <= 0 || *out_len > 63)
        return 0;
      pipeline_expr_var_name_into(a, cur, out);
      return 1;
    }
    if (k == (int32_t)ast_ExprKind_EXPR_FIELD_ACCESS)
      cur = pipeline_expr_field_access_base_ref(a, cur);
    else if (k == (int32_t)ast_ExprKind_EXPR_INDEX)
      cur = pipeline_expr_index_base_ref(a, cur);
    else
      return 0;
    if (cur <= 0)
      return 0;
  }
}

/** MEM-A3：typeck 诊断 line/col（assign 等 site expr line=0 时回退子树）。 */
static void pipeline_typeck_expr_diag_line_col_c(struct ast_ASTArena *a, int32_t expr_ref, int32_t *line,
                                                 int32_t *col) {
  int32_t k;
  if (!a || expr_ref <= 0 || !line || !col) {
    if (line)
      *line = 0;
    if (col)
      *col = 0;
    return;
  }
  *line = pipeline_expr_line_at(a, expr_ref);
  *col = pipeline_expr_col_at(a, expr_ref);
  if (*line > 0)
    return;
  k = pipeline_expr_kind_ord_at(a, expr_ref);
  if (glue_expr_kind_is_assign_like_ord(k)) {
    pipeline_typeck_expr_diag_line_col_c(a, pipeline_expr_binop_left_ref_at(a, expr_ref), line, col);
    if (*line > 0)
      return;
    pipeline_typeck_expr_diag_line_col_c(a, pipeline_expr_binop_right_ref_at(a, expr_ref), line, col);
    return;
  }
  if (k == (int32_t)ast_ExprKind_EXPR_ADDR_OF || k == (int32_t)ast_ExprKind_EXPR_RETURN ||
      k == (int32_t)ast_ExprKind_EXPR_NEG || k == (int32_t)ast_ExprKind_EXPR_LOGNOT)
    pipeline_typeck_expr_diag_line_col_c(a, pipeline_expr_unary_operand_ref_at(a, expr_ref), line, col);
}

/**
 * MEM-A3：assign — 禁止内层块局部地址写入外层块变量（scope borrow 逃逸）。
 */
int32_t pipeline_typeck_check_scope_borrow_assign_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                  int32_t site_expr_ref, int32_t left_ref, int32_t right_ref,
                                                  struct ast_PipelineDepCtx *ctx) {
  uint8_t lname[64];
  uint8_t rname[64];
  int32_t llen;
  int32_t rlen;
  int32_t op_ref;
  int32_t site_block;
  int32_t lblock;
  int32_t rblock;
  int32_t line;
  int32_t col;
  if (!module || !arena || !ctx || left_ref <= 0 || right_ref <= 0)
    return 0;
  if (!typeck_expr_is_addr_of_block_local_c(module, arena, ctx, right_ref))
    return 0;
  if (!typeck_expr_lval_root_var_c(arena, left_ref, lname, &llen))
    return 0;
  if (pipeline_expr_kind_ord_at(arena, right_ref) != (int32_t)ast_ExprKind_EXPR_ADDR_OF)
    return 0;
  op_ref = pipeline_expr_unary_operand_ref_at(arena, right_ref);
  if (op_ref <= 0 || pipeline_expr_kind_ord_at(arena, op_ref) != GLUE_EXPR_KIND_VAR)
    return 0;
  rlen = pipeline_expr_var_name_len(arena, op_ref);
  if (rlen <= 0 || rlen > 63)
    return 0;
  pipeline_expr_var_name_into(arena, op_ref, rname);
  site_block = ctx->current_block_ref;
  if (site_block <= 0 && ctx->current_func_index >= 0)
    site_block = pipeline_module_func_body_ref_at(module, ctx->current_func_index);
  if (site_block <= 0)
    return 0;
  lblock = pipeline_block_find_var_decl_block_ref(arena, site_block, lname, llen);
  rblock = pipeline_block_find_var_decl_block_ref(arena, site_block, rname, rlen);
  if (lblock <= 0 || rblock <= 0 || lblock == rblock)
    return 0;
  if (!typeck_block_is_strict_ancestor_c(arena, lblock, rblock))
    return 0;
  pipeline_typeck_expr_diag_line_col_c(arena, site_expr_ref, &line, &col);
  lsp_diag_report_typeck((int)line, (int)col, "scope borrow escape");
  return -1;
}

/**
 * MEM-A3：return — 禁止返回块内局部变量地址（指针逃出函数/块生命周期）。
 */
int32_t pipeline_typeck_check_scope_borrow_return_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                    int32_t site_expr_ref, int32_t op_ref, int32_t return_type_ref,
                                                    struct ast_PipelineDepCtx *ctx) {
  int32_t line;
  int32_t col;
  if (!module || !arena || !ctx || site_expr_ref <= 0 || op_ref <= 0)
    return 0;
  if (return_type_ref <= 0 || pipeline_type_kind_ord_at(arena, return_type_ref) != (int32_t)ast_TypeKind_TYPE_PTR)
    return 0;
  if (!typeck_expr_is_addr_of_block_local_c(module, arena, ctx, op_ref))
    return 0;
  pipeline_typeck_expr_diag_line_col_c(arena, site_expr_ref, &line, &col);
  lsp_diag_report_typeck((int)line, (int)col, "scope borrow escape");
  return -1;
}

/** MEM-C1：with_arena 嵌套栈深度（post-typeck scan 用；每模块 scan 前清零）。 */
#define TYPECK_WITH_ARENA_SCOPE_MAX 8
static int32_t g_typeck_with_arena_body_stack[TYPECK_WITH_ARENA_SCOPE_MAX];
static int32_t g_typeck_with_arena_scope_n;

/** MEM-C1：当前 with_arena 栈顶 body 块 ref；无则 0。 */
static int32_t typeck_with_arena_current_body_ref_c(void) {
  return g_typeck_with_arena_scope_n > 0 ? g_typeck_with_arena_body_stack[g_typeck_with_arena_scope_n - 1] : 0;
}

/** MEM-C1：进入 with_arena 块体 scan 前 push body ref。 */
static void typeck_with_arena_scope_push_c(int32_t body_ref) {
  if (body_ref <= 0 || g_typeck_with_arena_scope_n >= TYPECK_WITH_ARENA_SCOPE_MAX)
    return;
  g_typeck_with_arena_body_stack[g_typeck_with_arena_scope_n++] = body_ref;
}

/** MEM-C1：离开 with_arena 块体 scan 后 pop。 */
static void typeck_with_arena_scope_pop_c(void) {
  if (g_typeck_with_arena_scope_n > 0)
    g_typeck_with_arena_scope_n--;
}

/** M-3：region 域栈读/写（定义见下；前置声明供 AL-06 scan/typeck 使用）。 */
int32_t pipeline_dep_ctx_scope_region_push_c(struct ast_PipelineDepCtx *ctx, uint8_t *label, int32_t label_len);
void pipeline_dep_ctx_scope_region_pop_c(struct ast_PipelineDepCtx *ctx);
int32_t pipeline_dep_ctx_scope_region_len_at(struct ast_PipelineDepCtx *ctx);

/** M-3 AL-06：return slice 域检查（定义见下）。 */
int32_t pipeline_typeck_check_return_slice_region_c(struct ast_ASTArena *arena, int32_t ret_site_ref,
                                                    int32_t op_ref, int32_t func_return_ref);

/** MEM-C1：return 类型是否为命名 struct Allocator。 */
static int32_t typeck_type_is_allocator_struct_c(struct ast_ASTArena *arena, int32_t ty_ref) {
  uint8_t nm[64];
  int32_t nlen;
  if (!arena || ty_ref <= 0 || pipeline_type_kind_ord_at(arena, ty_ref) != (int32_t)ast_TypeKind_TYPE_NAMED)
    return 0;
  nlen = pipeline_type_named_name_into(arena, ty_ref, nm);
  return (nlen == 9 && memcmp(nm, "Allocator", 9) == 0) ? 1 : 0;
}

/**
 * MEM-C1 AL-04：with_arena 内 assign — 禁止 arena 域值写入块外变量（allocator region 逃逸）。
 */
int32_t pipeline_typeck_check_allocator_region_assign_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                      int32_t site_expr_ref, int32_t left_ref,
                                                      struct ast_PipelineDepCtx *ctx) {
  uint8_t lname[64];
  int32_t llen;
  int32_t wa_body;
  int32_t site_block;
  int32_t lblock;
  int32_t line;
  int32_t col;
  if (!module || !arena || !ctx || left_ref <= 0 || g_typeck_with_arena_scope_n <= 0)
    return 0;
  if (!typeck_expr_lval_root_var_c(arena, left_ref, lname, &llen))
    return 0;
  wa_body = typeck_with_arena_current_body_ref_c();
  if (wa_body <= 0)
    return 0;
  site_block = ctx->current_block_ref;
  if (site_block <= 0)
    site_block = wa_body;
  lblock = pipeline_block_find_var_decl_block_ref(arena, site_block, lname, llen);
  if (lblock <= 0)
    return 0;
  if (lblock == wa_body || typeck_block_is_strict_ancestor_c(arena, wa_body, lblock))
    return 0;
  if (!typeck_block_is_strict_ancestor_c(arena, lblock, wa_body))
    return 0;
  pipeline_typeck_expr_diag_line_col_c(arena, site_expr_ref, &line, &col);
  lsp_diag_report_typeck((int)line, (int)col, "allocator region escape");
  return -1;
}

/**
 * MEM-C1 AL-04：with_arena 内 return Allocator — 禁止 allocator 域逃出 with_arena 块。
 */
int32_t pipeline_typeck_check_allocator_region_return_c(struct ast_ASTArena *arena, int32_t site_expr_ref,
                                                        int32_t return_type_ref) {
  int32_t line;
  int32_t col;
  if (!arena || site_expr_ref <= 0 || g_typeck_with_arena_scope_n <= 0)
    return 0;
  if (!typeck_type_is_allocator_struct_c(arena, return_type_ref))
    return 0;
  pipeline_typeck_expr_diag_line_col_c(arena, site_expr_ref, &line, &col);
  lsp_diag_report_typeck((int)line, (int)col, "allocator region escape");
  return -1;
}

/**
 * M-3 AL-06：region 内 return 未标注域 slice — 禁止 slice 域逃出 region（scan 路径，不依赖 typeck 已 stamp）。
 */
static int32_t pipeline_typeck_check_return_slice_region_in_scope_c(struct ast_ASTArena *arena, int32_t site_expr_ref,
                                                                  int32_t return_type_ref,
                                                                  struct ast_PipelineDepCtx *ctx) {
  int32_t line;
  int32_t col;
  int32_t rlen;
  if (!arena || !ctx || site_expr_ref <= 0 || return_type_ref <= 0)
    return 0;
  if (pipeline_dep_ctx_scope_region_len_at(ctx) <= 0)
    return 0;
  if (pipeline_type_kind_ord_at(arena, return_type_ref) != (int32_t)ast_TypeKind_TYPE_SLICE)
    return 0;
  if (pipeline_type_region_label_len_at(arena, return_type_ref) > 0)
    return 0;
  pipeline_typeck_expr_diag_line_col_c(arena, site_expr_ref, &line, &col);
  rlen = pipeline_dep_ctx_scope_region_len_at(ctx);
  lsp_diag_report_typeck((int)line, (int)col,
                         "slice region escape: cannot return <%.*s> slice as unbound T[]", (int)rlen,
                         (const char *)ctx->typeck_scope_region_label);
  return -1;
}

/**
 * WPO-S3：CALL 路径 — 局部 struct 指针与另一 *Struct 形参同传时拒绝（callee 可能写入外层槽）。
 */
int32_t pipeline_typeck_check_call_struct_stack_escape_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                         int32_t call_expr_ref, struct ast_PipelineDepCtx *ctx) {
  int32_t func_ix;
  int32_t num_args;
  int32_t np;
  int32_t src_i;
  int32_t dst_j;
  int32_t line;
  int32_t col;
  if (!module || !arena || !ctx || call_expr_ref <= 0)
    return 0;
  func_ix = pipeline_typeck_resolve_call_func_index_c(module, arena, call_expr_ref);
  if (func_ix < 0)
    return 0;
  num_args = pipeline_expr_call_num_args_at(arena, call_expr_ref);
  np = pipeline_module_func_num_params_at(module, func_ix);
  if (num_args != np || num_args < 2)
    return 0;
  if (getenv("SHUX_SKIP_STACK_ESCAPE") != NULL)
    return 0;
  for (src_i = 0; src_i < num_args; src_i++) {
    int32_t arg_ref = pipeline_expr_call_arg_ref(arena, call_expr_ref, src_i);
    int32_t arg_ty;
    int32_t arg_elem;
    if (!typeck_expr_is_addr_of_block_local_c(module, arena, ctx, arg_ref))
      continue;
    /** 仅当 &local 的类型是 *Struct 时才触发（&local_i32 不逃逸）。 */
    arg_ty = pipeline_expr_resolved_type_ref(arena, arg_ref);
    if (arg_ty <= 0)
      continue;
    if (pipeline_type_kind_ord_at(arena, arg_ty) != (int32_t)ast_TypeKind_TYPE_PTR)
      continue;
    arg_elem = pipeline_type_elem_ref_at(arena, arg_ty);
    if (arg_elem <= 0 || !typeck_type_is_named_struct_c(module, arena, arg_elem))
      continue;
    for (dst_j = 0; dst_j < num_args; dst_j++) {
      int32_t param_ref;
      int32_t elem_ref;
      if (dst_j == src_i)
        continue;
      param_ref = pipeline_module_func_param_type_ref_at(module, func_ix, dst_j);
      if (param_ref <= 0 ||
          pipeline_type_kind_ord_at(arena, param_ref) != (int32_t)ast_TypeKind_TYPE_PTR)
        continue;
      elem_ref = pipeline_type_elem_ref_at(arena, param_ref);
      if (elem_ref <= 0 || !typeck_type_is_named_struct_c(module, arena, elem_ref))
        continue;
      line = pipeline_expr_line_at(arena, call_expr_ref);
      col = pipeline_expr_col_at(arena, call_expr_ref);
      lsp_diag_report_typeck((int)line, (int)col,
                             "struct stack escape: cannot pass address of local struct with outer struct pointer");
      return -1;
    }
  }
  return 0;
}

/** WPO-S3：单 expr assign/call 栈逃逸扫描（post-typeck；typeck.o WPO 可能裁掉 inline hook）。 */
static int32_t typeck_scan_expr_stack_escape_c(struct ast_Module *m, struct ast_ASTArena *a,
                                             struct ast_PipelineDepCtx *ctx, int32_t func_ix,
                                             int32_t expr_ref) {
  int32_t k;
  int32_t saved_ix;
  int32_t saved_br;
  if (!m || !a || !ctx || expr_ref <= 0 || func_ix < 0)
    return 0;
  saved_ix = ctx->current_func_index;
  saved_br = ctx->current_block_ref;
  ctx->current_func_index = func_ix;
  k = pipeline_expr_kind_ord_at(a, expr_ref);
  if (glue_expr_kind_is_assign_like_ord(k)) {
    int32_t l = pipeline_expr_binop_left_ref_at(a, expr_ref);
    int32_t r = pipeline_expr_binop_right_ref_at(a, expr_ref);
    if (pipeline_typeck_check_struct_stack_escape_assign_c(m, a, expr_ref, l, r, ctx) != 0) {
      ctx->current_func_index = saved_ix;
      ctx->current_block_ref = saved_br;
      return -1;
    }
    if (pipeline_typeck_check_scope_borrow_assign_c(m, a, expr_ref, l, r, ctx) != 0) {
      ctx->current_func_index = saved_ix;
      ctx->current_block_ref = saved_br;
      return -1;
    }
    if (pipeline_typeck_check_allocator_region_assign_c(m, a, expr_ref, l, ctx) != 0) {
      ctx->current_func_index = saved_ix;
      ctx->current_block_ref = saved_br;
      return -1;
    }
  } else if (k == (int32_t)ast_ExprKind_EXPR_RETURN) {
    int32_t op = pipeline_expr_unary_operand_ref_at(a, expr_ref);
    int32_t func_ret = pipeline_module_func_return_type_at(m, func_ix);
    if (pipeline_typeck_check_scope_borrow_return_c(m, a, expr_ref, op, func_ret, ctx) != 0) {
      ctx->current_func_index = saved_ix;
      ctx->current_block_ref = saved_br;
      return -1;
    }
    if (pipeline_typeck_check_allocator_region_return_c(a, expr_ref, func_ret) != 0) {
      ctx->current_func_index = saved_ix;
      ctx->current_block_ref = saved_br;
      return -1;
    }
    if (pipeline_typeck_check_return_slice_region_in_scope_c(a, expr_ref, func_ret, ctx) != 0) {
      ctx->current_func_index = saved_ix;
      ctx->current_block_ref = saved_br;
      return -1;
    }
    if (pipeline_typeck_check_return_slice_region_c(a, expr_ref, op, func_ret) != 0) {
      ctx->current_func_index = saved_ix;
      ctx->current_block_ref = saved_br;
      return -1;
    }
  } else if (k == (int32_t)ast_ExprKind_EXPR_CALL) {
    if (pipeline_typeck_check_call_struct_stack_escape_c(m, a, expr_ref, ctx) != 0) {
      ctx->current_func_index = saved_ix;
      ctx->current_block_ref = saved_br;
      return -1;
    }
  }
  ctx->current_func_index = saved_ix;
  ctx->current_block_ref = saved_br;
  return 0;
}

/** M-3：typeck region 域嵌套栈（最多 8 层；push/pop 在 C glue 内维护）。 */
#define TYPECK_REGION_SCOPE_MAX 8
static int32_t g_typeck_region_saved_len[TYPECK_REGION_SCOPE_MAX];
static uint8_t g_typeck_region_saved_label[TYPECK_REGION_SCOPE_MAX][64];
static int32_t g_typeck_region_scope_n;

/** M-3：保存 ctx region 并设置新域标签；失败返回 -1。 */
int32_t pipeline_dep_ctx_scope_region_push_c(struct ast_PipelineDepCtx *ctx, uint8_t *label, int32_t label_len) {
  int32_t slot;
  if (!ctx || !label || label_len <= 0 || label_len > 63)
    return -1;
  if (g_typeck_region_scope_n >= TYPECK_REGION_SCOPE_MAX)
    return -1;
  slot = g_typeck_region_scope_n;
  g_typeck_region_saved_len[slot] = ctx->typeck_scope_region_len;
  if (ctx->typeck_scope_region_len > 0 && ctx->typeck_scope_region_len <= 63)
    memcpy(g_typeck_region_saved_label[slot], ctx->typeck_scope_region_label, 64);
  memset(ctx->typeck_scope_region_label, 0, sizeof(ctx->typeck_scope_region_label));
  memcpy(ctx->typeck_scope_region_label, label, (size_t)label_len);
  ctx->typeck_scope_region_len = label_len;
  g_typeck_region_scope_n++;
  return 0;
}

/** M-3：恢复 push 前的 region 域。 */
void pipeline_dep_ctx_scope_region_pop_c(struct ast_PipelineDepCtx *ctx) {
  int32_t slot;
  if (!ctx || g_typeck_region_scope_n <= 0)
    return;
  g_typeck_region_scope_n--;
  slot = g_typeck_region_scope_n;
  ctx->typeck_scope_region_len = g_typeck_region_saved_len[slot];
  memset(ctx->typeck_scope_region_label, 0, sizeof(ctx->typeck_scope_region_label));
  if (g_typeck_region_saved_len[slot] > 0 && g_typeck_region_saved_len[slot] <= 63)
    memcpy(ctx->typeck_scope_region_label, g_typeck_region_saved_label[slot], 64);
}

/** WPO-S3：递归扫描块内 expr_stmt / final_expr / 子块。 */
static int32_t typeck_scan_block_stack_escape_c(struct ast_Module *m, struct ast_ASTArena *a,
                                              struct ast_PipelineDepCtx *ctx, int32_t func_ix,
                                              int32_t block_ref) {
  int32_t nes;
  int32_t ei;
  int32_t fin;
  int32_t nso;
  int32_t i;
  int32_t saved_br;
  if (!m || !a || !ctx || block_ref <= 0 || func_ix < 0)
    return 0;
  saved_br = ctx->current_block_ref;
  ctx->current_block_ref = block_ref;
  nes = ast_ast_block_num_expr_stmts(a, block_ref);
  for (ei = 0; ei < nes; ei++) {
    int32_t er = ast_ast_block_expr_stmt_ref(a, block_ref, ei);
    if (er > 0 && typeck_scan_expr_stack_escape_c(m, a, ctx, func_ix, er) != 0) {
      ctx->current_block_ref = saved_br;
      return -1;
    }
  }
  fin = pipeline_asm_block_final_expr_ref_at(a, block_ref);
  if (fin > 0 && typeck_scan_expr_stack_escape_c(m, a, ctx, func_ix, fin) != 0) {
    ctx->current_block_ref = saved_br;
    return -1;
  }
  nso = ast_ast_block_num_stmt_order(a, block_ref);
  for (i = 0; i < nso; i++) {
    uint8_t k = ast_ast_block_stmt_order_kind(a, block_ref, i);
    int32_t idx = ast_ast_block_stmt_order_idx(a, block_ref, i);
    if (k == 2 && idx >= 0 && idx < ast_ast_block_num_expr_stmts(a, block_ref)) {
      int32_t er = ast_ast_block_expr_stmt_ref(a, block_ref, idx);
      if (er > 0 && typeck_scan_expr_stack_escape_c(m, a, ctx, func_ix, er) != 0) {
        ctx->current_block_ref = saved_br;
        return -1;
      }
    } else if (k == 3 && idx >= 0 && idx < ast_ast_block_num_loops(a, block_ref)) {
      int32_t br = ast_ast_block_while_body_ref(a, block_ref, idx);
      if (br > 0 && typeck_scan_block_stack_escape_c(m, a, ctx, func_ix, br) != 0)
        return -1;
    } else if (k == 4 && idx >= 0 && idx < ast_ast_block_num_for_loops(a, block_ref)) {
      int32_t br = ast_ast_block_for_body_ref(a, block_ref, idx);
      if (br > 0 && typeck_scan_block_stack_escape_c(m, a, ctx, func_ix, br) != 0)
        return -1;
    } else if (k == 5 && idx >= 0 && idx < ast_ast_block_num_if_stmts(a, block_ref)) {
      int32_t tr = ast_ast_block_if_then_body_ref(a, block_ref, idx);
      int32_t er = ast_ast_block_if_else_body_ref(a, block_ref, idx);
      if (tr > 0 && typeck_scan_block_stack_escape_c(m, a, ctx, func_ix, tr) != 0)
        return -1;
      if (er > 0 && typeck_scan_block_stack_escape_c(m, a, ctx, func_ix, er) != 0)
        return -1;
    } else if (k == 6 && idx >= 0 && idx < ast_ast_block_num_regions(a, block_ref)) {
      int32_t wa_cap = pipeline_block_region_with_arena_cap_ref(a, block_ref, idx);
      int32_t br = ast_ast_block_region_body_ref(a, block_ref, idx);
      if (wa_cap > 0) {
        typeck_with_arena_scope_push_c(br);
        if (br > 0 && typeck_scan_block_stack_escape_c(m, a, ctx, func_ix, br) != 0) {
          typeck_with_arena_scope_pop_c();
          ctx->current_block_ref = saved_br;
          return -1;
        }
        typeck_with_arena_scope_pop_c();
      } else {
        uint8_t lbl[64];
        int32_t llen = pipeline_block_region_label_len(a, block_ref, idx);
        if (llen > 0) {
          pipeline_block_region_label_copy64(a, block_ref, idx, lbl);
          if (pipeline_dep_ctx_scope_region_push_c(ctx, lbl, llen) != 0) {
            ctx->current_block_ref = saved_br;
            return -1;
          }
        }
        if (br > 0 && typeck_scan_block_stack_escape_c(m, a, ctx, func_ix, br) != 0) {
          if (llen > 0)
            pipeline_dep_ctx_scope_region_pop_c(ctx);
          ctx->current_block_ref = saved_br;
          return -1;
        }
        if (llen > 0)
          pipeline_dep_ctx_scope_region_pop_c(ctx);
      }
    }
  }
  ctx->current_block_ref = saved_br;
  return 0;
}

/** WPO-S3：模块级 post-typeck 扫描 struct 栈指针逃逸。 */
int32_t pipeline_typeck_scan_module_struct_stack_escape_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                          struct ast_PipelineDepCtx *ctx) {
  int32_t i;
  int32_t nf;
  int32_t body;
  int32_t num_generic_params;
  if (!module || !arena || !ctx)
    return 0;
  if (getenv("SHUX_SKIP_STACK_ESCAPE") != NULL)
    return 0;
  g_typeck_with_arena_scope_n = 0;
  g_typeck_region_scope_n = 0;
  ctx->typeck_scope_region_len = 0;
  memset(ctx->typeck_scope_region_label, 0, sizeof(ctx->typeck_scope_region_label));
  nf = pipeline_module_num_funcs(module);
  for (i = 0; i < nf; i++) {
    if (pipeline_module_func_is_extern_at(module, i) != 0)
      continue;
    num_generic_params = pipeline_module_func_num_generic_params_at(module, i);
    if (num_generic_params > 0)
      continue;
    body = pipeline_module_func_body_ref_at(module, i);
    if (body <= 0)
      continue;
    if (typeck_scan_block_stack_escape_c(module, arena, ctx, i, body) != 0)
      return -1;
  }
  return 0;
}

/** M-5：callee 名是否为 read_ptr slice 生产者（自动绑 io_read_ptr 域）。 */
int32_t pipeline_typeck_is_read_ptr_slice_callee_c(uint8_t *name, int32_t name_len) {
  static const uint8_t n0[] = "read_ptr_slice";
  static const uint8_t n1[] = "shux_io_read_ptr_slice";
  static const uint8_t n2[] = "driver_read_ptr_slice";
  static const uint8_t n3[] = "io_read_ptr_slice";
  if (!name || name_len <= 0)
    return 0;
  if (name_len == 14 && memcmp(name, n0, 14) == 0)
    return 1;
  if (name_len == 19 && memcmp(name, n1, 19) == 0)
    return 1;
  if (name_len == 18 && memcmp(name, n2, 18) == 0)
    return 1;
  if (name_len == 16 && memcmp(name, n3, 16) == 0)
    return 1;
  return 0;
}

/** M-5：u8[]<io_read_ptr> 类型池 ref（read_ptr TLS buf 域）。 */
int32_t pipeline_typeck_read_ptr_slice_return_ref_c(struct ast_ASTArena *arena) {
  static const uint8_t lbl[] = "io_read_ptr";
  int32_t u8_ref;
  if (!arena)
    return 0;
  u8_ref = pipeline_type_ensure_by_kind_ord(arena, 2);
  if (u8_ref <= 0)
    return 0;
  return pipeline_type_find_or_alloc_slice(arena, u8_ref, (uint8_t *)lbl, 11);
}

/**
 * M-3：.x typeck return 路径 slice 域逃逸 / 不一致；ret_site_ref 用于 line/col。
 */
int32_t pipeline_typeck_check_return_slice_region_c(struct ast_ASTArena *arena, int32_t ret_site_ref,
                                                    int32_t op_ref, int32_t func_return_ref) {
  int32_t got_ref;
  int32_t line;
  int32_t col;
  uint8_t sb[64];
  int32_t slen;
  uint8_t eb[64];
  int32_t elen;
  if (!arena || op_ref <= 0 || func_return_ref <= 0)
    return 0;
  if (pipeline_type_kind_ord_at(arena, func_return_ref) != (int32_t)ast_TypeKind_TYPE_SLICE)
    return 0;
  got_ref = pipeline_expr_resolved_type_ref(arena, op_ref);
  if (got_ref <= 0 || pipeline_type_kind_ord_at(arena, got_ref) != (int32_t)ast_TypeKind_TYPE_SLICE)
    return 0;
  line = 0;
  col = 0;
  if (ret_site_ref > 0 && ret_site_ref <= arena->num_exprs) {
    line = pipeline_expr_line_at(arena, ret_site_ref);
    col = pipeline_expr_col_at(arena, ret_site_ref);
  }
  if (pipeline_typeck_slice_region_escape_c(arena, func_return_ref, got_ref)) {
    slen = pipeline_type_region_label_into(arena, got_ref, sb);
    sb[slen > 0 && slen < 64 ? slen : 0] = '\0';
    lsp_diag_report_typeck((int)line, (int)col,
                           "slice region escape: cannot return <%.*s> slice as unbound T[]",
                           (int)(slen > 0 ? slen : 0), (const char *)sb);
    return -1;
  }
  if (pipeline_typeck_slice_region_conflict_c(arena, func_return_ref, got_ref)) {
    elen = pipeline_type_region_label_into(arena, func_return_ref, eb);
    slen = pipeline_type_region_label_into(arena, got_ref, sb);
    eb[elen > 0 && elen < 64 ? elen : 0] = '\0';
    sb[slen > 0 && slen < 64 ? slen : 0] = '\0';
    lsp_diag_report_typeck((int)line, (int)col, "slice region mismatch in return: expected <%.*s>, found <%.*s>",
                           (int)(elen > 0 ? elen : 0), (const char *)eb, (int)(slen > 0 ? slen : 0),
                           (const char *)sb);
    return -1;
  }
  return 0;
}

/** M-3：读 ctx 当前 region 域标签长度；0 表示不在 region 块内。 */
int32_t pipeline_dep_ctx_scope_region_len_at(struct ast_PipelineDepCtx *ctx) {
  if (!ctx)
    return 0;
  return ctx->typeck_scope_region_len > 0 ? ctx->typeck_scope_region_len : 0;
}

/** M-3：为块内 let 声明类型（未标注域的 T[]）打上当前 ctx region 标签。 */
int32_t pipeline_type_stamp_block_let_region_c(struct ast_ASTArena *arena, int32_t block_ref, int32_t let_idx,
                                             struct ast_PipelineDepCtx *ctx) {
  int32_t ty_ref;
  int32_t rlen;
  if (!arena || !ctx || block_ref <= 0 || let_idx < 0)
    return 0;
  rlen = pipeline_dep_ctx_scope_region_len_at(ctx);
  if (rlen <= 0)
    return 0;
  ty_ref = pipeline_block_let_type_ref(arena, block_ref, let_idx);
  if (ty_ref <= 0 || pipeline_type_kind_ord_at(arena, ty_ref) != (int32_t)ast_TypeKind_TYPE_SLICE)
    return 0;
  if (pipeline_type_region_label_len_at(arena, ty_ref) > 0)
    return 0;
  return pipeline_type_set_region_label_at(arena, ty_ref, ctx->typeck_scope_region_label, rlen);
}

/** 统计模块内同名非 extern 函数个数（>1 时须 overload 分派 + mangled 符号）。 */
static int32_t pipeline_module_func_overload_count_c(struct ast_Module *m, uint8_t *name, int32_t name_len) {
  int32_t i;
  int32_t c;
  if (!m || name_len <= 0 || !name)
    return 0;
  c = 0;
  for (i = 0; i < m->num_funcs; i++) {
    if (pipeline_asm_module_func_is_extern_at(m, i) != 0)
      continue;
    if (pipeline_module_func_name_equal_at(m, i, name, name_len))
      c++;
  }
  return c;
}

/**
 * overload 实参是否可赋给形参（对齐 typeck.c type_assignable_to 的子集；精确匹配优先于隐式拓宽）。
 */
static int32_t pipeline_typeck_call_arg_assignable_c(struct ast_ASTArena *arena, int32_t arg_ref, int32_t param_ref) {
  int32_t arg_ty;
  int32_t arg_kind;
  int32_t param_kind;
  int32_t arg_kind_ord;
  int32_t as_tgt;
  if (!arena || arg_ref <= 0 || param_ref <= 0)
    return 0;
  arg_kind = pipeline_expr_kind_ord_at(arena, arg_ref);
  arg_ty = pipeline_typeck_expr_type_ref_c(arena, arg_ref);
  if (arg_kind == (int32_t)ast_ExprKind_EXPR_AS) {
    as_tgt = pipeline_expr_as_target_type_ref_at(arena, arg_ref);
    if (!ast_ref_is_null(as_tgt))
      arg_ty = as_tgt;
  }
  param_kind = pipeline_type_kind_ord_at(arena, param_ref);
  if (arg_ty > 0) {
    if (pipeline_typeck_type_refs_equal_c(arena, arg_ty, param_ref))
      return 1;
    arg_kind_ord = pipeline_type_kind_ord_at(arena, arg_ty);
    if (pipeline_typeck_integer_widen_ok_c(param_kind, arg_kind_ord))
      return 1;
    /** M-3：slice 元素相同即可匹配 overload（域在 CALL 后单独查）。 */
    if (param_kind == (int32_t)ast_TypeKind_TYPE_SLICE && arg_kind_ord == (int32_t)ast_TypeKind_TYPE_SLICE) {
      int32_t pe = pipeline_type_elem_ref_at(arena, param_ref);
      int32_t ae = pipeline_type_elem_ref_at(arena, arg_ty);
      if (pe > 0 && ae > 0 && pipeline_typeck_type_refs_equal_c(arena, pe, ae))
        return 1;
    }
    return 0;
  }
  /** resolved_type 未填时按字面量形态匹配（CALL 分派前常见）。 */
  if (arg_kind == (int32_t)ast_ExprKind_EXPR_LIT) {
    int32_t iv = pipeline_expr_int_val_at(arena, arg_ref);
    if (param_kind == (int32_t)ast_TypeKind_TYPE_I32 || param_kind == (int32_t)ast_TypeKind_TYPE_I64)
      return 1;
    if (param_kind == (int32_t)ast_TypeKind_TYPE_U32 && iv >= 0)
      return 1;
    if (param_kind == (int32_t)ast_TypeKind_TYPE_USIZE && iv >= 0)
      return 1;
    if (param_kind == (int32_t)ast_TypeKind_TYPE_U8 && iv >= 0 && iv <= 255)
      return 1;
  }
  return 0;
}

/** 单候选 overload 与 CALL 实参的匹配得分；不匹配返回 -1（精确 +1000，可赋 +1）。 */
static int32_t pipeline_typeck_overload_match_score_c(struct ast_Module *m, struct ast_ASTArena *a, int32_t func_ix,
                                                      int32_t call_expr_ref) {
  int32_t num_args;
  int32_t np;
  int32_t i;
  int32_t score;
  int32_t arg_ref;
  int32_t param_ref;
  if (!m || !a || func_ix < 0 || call_expr_ref <= 0)
    return -1;
  num_args = pipeline_expr_call_num_args_at(a, call_expr_ref);
  np = pipeline_module_func_num_params_at(m, func_ix);
  if (num_args != np)
    return -1;
  score = 0;
  for (i = 0; i < num_args; i++) {
    arg_ref = pipeline_expr_call_arg_ref(a, call_expr_ref, i);
    param_ref = pipeline_module_func_param_type_ref_at(m, func_ix, i);
    if (!pipeline_typeck_call_arg_assignable_c(a, arg_ref, param_ref))
      return -1;
    if (pipeline_typeck_type_refs_equal_c(
            a, pipeline_typeck_expr_type_ref_c(a, arg_ref),
            param_ref) ||
        (pipeline_expr_kind_ord_at(a, arg_ref) == (int32_t)ast_ExprKind_EXPR_AS &&
         pipeline_typeck_type_refs_equal_c(a, pipeline_expr_as_target_type_ref_at(a, arg_ref), param_ref)))
      score += 1000;
    else
      score += 1;
  }
  return score;
}

/**
 * 按实参类型在模块内选取唯一 overload；成功返回 funcs[] 下标，无 overload/未找到/歧义返回 -1。
 */
static int32_t pipeline_typeck_pick_overload_func_index_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                          int32_t call_expr_ref) {
  int32_t callee_ref;
  struct ast_Expr *callee_ex;
  int32_t i;
  int32_t best_ix;
  int32_t best_score;
  int32_t n_at_best;
  int32_t sc;
  if (!m || !a || call_expr_ref <= 0)
    return -1;
  callee_ref = pipeline_expr_call_callee_ref_at(a, call_expr_ref);
  if (callee_ref <= 0)
    return -1;
  callee_ex = pipeline_arena_expr_ptr(a, callee_ref);
  if (!callee_ex || callee_ex->kind != ast_ExprKind_EXPR_VAR || callee_ex->var_name_len <= 0)
    return -1;
  if (pipeline_module_func_overload_count_c(m, callee_ex->var_name, callee_ex->var_name_len) <= 1)
    return -1;
  best_ix = -1;
  best_score = -1;
  n_at_best = 0;
  for (i = 0; i < m->num_funcs; i++) {
    if (pipeline_asm_module_func_is_extern_at(m, i) != 0)
      continue;
    if (!pipeline_module_func_name_equal_at(m, i, callee_ex->var_name, callee_ex->var_name_len))
      continue;
    sc = pipeline_typeck_overload_match_score_c(m, a, i, call_expr_ref);
    if (sc < 0)
      continue;
    if (sc > best_score) {
      best_ix = i;
      best_score = sc;
      n_at_best = 1;
    } else if (sc == best_score) {
      n_at_best++;
    }
  }
  if (best_ix < 0 || n_at_best > 1)
    return -1;
  return best_ix;
}

static int32_t pipeline_typeck_resolve_call_func_index_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                         int32_t call_expr_ref) {
  int32_t fx;
  int32_t picked;
  int32_t callee_ref;
  struct ast_Expr *callee_ex;
  int32_t i;
  if (!m || !a || call_expr_ref <= 0)
    return -1;
  callee_ref = pipeline_expr_call_callee_ref_at(a, call_expr_ref);
  if (callee_ref > 0) {
    callee_ex = pipeline_arena_expr_ptr(a, callee_ref);
    if (callee_ex && callee_ex->kind == ast_ExprKind_EXPR_VAR && callee_ex->var_name_len > 0 &&
        pipeline_module_func_overload_count_c(m, callee_ex->var_name, callee_ex->var_name_len) > 1) {
      picked = pipeline_typeck_pick_overload_func_index_c(m, a, call_expr_ref);
      if (picked >= 0) {
        pipeline_expr_apply_call_resolve(a, call_expr_ref, -1, picked);
        return picked;
      }
    }
  }
  fx = pipeline_expr_call_resolved_func_index_at(a, call_expr_ref);
  if (fx >= 0)
    return fx;
  if (callee_ref <= 0)
    return -1;
  callee_ex = pipeline_arena_expr_ptr(a, callee_ref);
  if (!callee_ex || callee_ex->kind != ast_ExprKind_EXPR_VAR || callee_ex->var_name_len <= 0)
    return -1;
  for (i = 0; i < m->num_funcs; i++) {
    if (pipeline_module_func_name_equal_at(m, i, callee_ex->var_name, callee_ex->var_name_len))
      return i;
  }
  return -1;
}

/** asm CALL/func emit：解析 CALL 目标 func 下标（含 overload 分派）；供 backend_call_dispatch.c 使用。 */
int32_t pipeline_typeck_resolve_call_func_index_for_emit_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                          int32_t call_expr_ref) {
  return pipeline_typeck_resolve_call_func_index_c(m, a, call_expr_ref);
}

/** WPO call 边 / typeck：按实参类型选取 overload func 下标。 */
int32_t pipeline_typeck_pick_overload_func_index_for_call_c(struct ast_Module *m, struct ast_ASTArena *a,
                                                            int32_t call_expr_ref) {
  return pipeline_typeck_pick_overload_func_index_c(m, a, call_expr_ref);
}

/**
 * CALL emit：解析 callee 所在 module + func 下标（本模块 / typeck 缓存 / dep import 回落）。
 * 供 f32 实参 mov imm32 等须对照 callee 形参表的 emit 路径。
 */
static int32_t glue_asm_resolve_call_target_module_c(struct ast_ASTArena *arena, int32_t call_expr_ref,
                                                      struct ast_Module **mod_out, int32_t *func_ix_out,
                                                      int32_t *dep_ix_out) {
  struct ast_Module *mod;
  int32_t func_ix;
  int32_t dep_ix;
  int32_t callee_ref;
  int32_t i;
  int32_t imax;

  if (!arena || call_expr_ref <= 0 || !mod_out || !func_ix_out)
    return -1;
  *mod_out = 0;
  *func_ix_out = -1;
  if (dep_ix_out)
    dep_ix_out[0] = -1;
  mod = g_pipeline_asm_emit_module;
  if (!mod)
    return -1;

  func_ix = pipeline_expr_call_resolved_func_index_at(arena, call_expr_ref);
  dep_ix = pipeline_expr_call_resolved_dep_index_at(arena, call_expr_ref);
  if (func_ix >= 0) {
    if (dep_ix >= 0 && g_pipeline_asm_emit_dep_pipe) {
      struct ast_Module *dm = pipeline_dep_ctx_module_at(g_pipeline_asm_emit_dep_pipe, dep_ix);
      if (dm)
        mod = dm;
    }
    *mod_out = mod;
    *func_ix_out = func_ix;
    if (dep_ix_out)
      dep_ix_out[0] = dep_ix;
    return 0;
  }

  func_ix = pipeline_typeck_resolve_call_func_index_c(mod, arena, call_expr_ref);
  if (func_ix >= 0) {
    *mod_out = mod;
    *func_ix_out = func_ix;
    if (dep_ix_out)
      dep_ix_out[0] = -1;
    return 0;
  }

  if (!g_pipeline_asm_emit_dep_pipe)
    return -1;
  callee_ref = pipeline_expr_call_callee_ref_at(arena, call_expr_ref);
  if (callee_ref <= 0)
    return -1;

  imax = mod->num_imports;
  if (pipeline_dep_ctx_ndep(g_pipeline_asm_emit_dep_pipe) > imax)
    imax = pipeline_dep_ctx_ndep(g_pipeline_asm_emit_dep_pipe);
  for (i = 0; i < imax; i++) {
    struct ast_Module *dm;
    int32_t fx = 0;
    int32_t callee_ord;

    dm = pipeline_dep_ctx_module_at(g_pipeline_asm_emit_dep_pipe, i);
    if (!dm)
      continue;
    if (pipeline_typeck_find_func_return_type_in_module_c(dm, arena, arena, arena, callee_ref, i,
                                                            g_pipeline_asm_emit_dep_pipe, &fx) != 0) {
      *mod_out = dm;
      *func_ix_out = fx;
      if (dep_ix_out)
        dep_ix_out[0] = i;
      return 0;
    }
    callee_ord = pipeline_expr_kind_ord_at(arena, callee_ref);
    if (i < mod->num_imports && pipeline_module_import_kind_at(mod, i) == GLUE_TYPECK_IMPORT_SELECT &&
        callee_ord == 3) {
      uint8_t cv_nm[64];
      int32_t cv_len = pipeline_expr_var_name_len(arena, callee_ref);
      if (cv_len > 0 && cv_len <= 63) {
        pipeline_expr_var_name_into(arena, callee_ref, cv_nm);
        if (pipeline_typeck_find_func_return_type_in_module_by_name_c(dm, arena, cv_nm, cv_len, i,
                                                                      g_pipeline_asm_emit_dep_pipe, &fx) != 0) {
          *mod_out = dm;
          *func_ix_out = fx;
          if (dep_ix_out)
            dep_ix_out[0] = i;
          return 0;
        }
      }
    }
  }
  return -1;
}

/**
 * C/skip-heavy callee 的 16B struct 返回：rax 为指向 struct 的指针，载入 rax/rdx。
 */
int32_t pipeline_asm_deref_struct16_rax_ptr_elf_c(struct platform_elf_ElfCodegenCtx *elf_ctx, int32_t ta) {
  if (backend_enc_mov_rax_to_rbx_arch(elf_ctx, ta) != 0)
    return -1;
  if (backend_enc_load_qword_from_rbx_to_rax_arch(elf_ctx, ta) != 0)
    return -1;
  return backend_enc_load_qword_rbx8_to_rdx_arch(elf_ctx, ta);
}

/**
 * CALL 返回 16B struct 是否经 rax 指针（C lowering）而非 rax/rdx 按值。
 */
int32_t pipeline_asm_call_struct16_ret_needs_rax_deref_c(struct ast_ASTArena *arena, int32_t call_expr_ref) {
  struct ast_Module *mod;
  int32_t fi;
  int32_t dep_ix;
  uint8_t name[64];
  int32_t nlen;
  if (!arena || call_expr_ref <= 0 || pipeline_expr_kind_ord_at(arena, call_expr_ref) != 48)
    return 0;
  if (glue_asm_resolve_call_target_module_c(arena, call_expr_ref, &mod, &fi, &dep_ix) != 0)
    return 0;
  if (!mod || fi < 0)
    return 0;
  nlen = pipeline_asm_module_func_name_len_at(mod, fi);
  if (nlen > 0 && nlen <= 63) {
    pipeline_asm_module_func_name_copy64(mod, fi, name);
    /** ok_i32/err_i32 等为 asm 双寄存器返回；其余 core.result struct 组合子为 C 指针返回。 */
    if ((nlen == 6 && memcmp(name, "ok_i32", 6) == 0) || (nlen == 7 && memcmp(name, "err_i32", 7) == 0) ||
        (nlen == 5 && memcmp(name, "ok_u8", 5) == 0) || (nlen == 6 && memcmp(name, "err_u8", 6) == 0)) {
      return 0;
    }
    if (glue_type_size_simple(mod, arena, pipeline_module_func_return_type_at(mod, fi), 0) > 8)
      return 1;
  }
  return asm_skip_heavy_module_func_body(mod, arena, fi) != 0 ? 1 : 0;
}

/** CALL emit：查 callee 第 param_index 个形参 type_ref（import dep + 按名回落）。 */
int32_t pipeline_asm_call_param_type_ref_at_c(struct ast_ASTArena *arena, int32_t call_expr_ref,
                                              int32_t param_index) {
  struct ast_Module *mod;
  int32_t func_ix;
  int32_t dep_ix;
  int32_t pty;

  if (!arena || call_expr_ref <= 0 || param_index < 0)
    return 0;
  if (glue_asm_resolve_call_target_module_c(arena, call_expr_ref, &mod, &func_ix, &dep_ix) != 0)
    return 0;
  if (!mod || func_ix < 0)
    return 0;
  pty = pipeline_module_func_param_type_ref_at(mod, func_ix, param_index);
  if (pty <= 0)
    return 0;
  /** dep 形参 type_ref 须映到 caller arena，否则 kind ord 查不到 f32。 */
  if (dep_ix >= 0 && mod != g_pipeline_asm_emit_module && g_pipeline_asm_emit_dep_pipe) {
    int32_t mapped = pipeline_typeck_get_dep_return_type_in_caller_arena_c(dep_ix, pty, arena,
                                                                           g_pipeline_asm_emit_dep_pipe);
    if (mapped > 0)
      return mapped;
  }
  return pty;
}

/**
 * MOD-02：按 TYPE_NAMED 查 struct_layout 下标；未登记返回 -1。
 */
static int32_t typeck_layout_index_for_named_type_c(struct ast_Module *m, struct ast_ASTArena *a, int32_t ty_ref) {
  uint8_t name[64];
  int32_t nlen;
  int32_t k;
  int32_t j;
  if (!m || !a || ty_ref <= 0)
    return -1;
  if (pipeline_type_kind_ord_at(a, ty_ref) != (int32_t)ast_TypeKind_TYPE_NAMED)
    return -1;
  nlen = pipeline_type_named_name_into(a, ty_ref, name);
  if (nlen <= 0 || nlen > 63)
    return -1;
  for (k = 0; k < (int32_t)m->num_struct_layouts; k++) {
    int32_t ln = pipeline_module_struct_layout_name_len(m, k);
    int32_t eq = 1;
    if (ln != nlen)
      continue;
    for (j = 0; j < nlen; j++) {
      if (pipeline_module_struct_layout_name_byte_at(m, k, j) != name[j]) {
        eq = 0;
        break;
      }
    }
    if (eq)
      return k;
  }
  return -1;
}

/** MOD-02：两 struct layout 字段数/偏移/类型等价则视为同布局。 */
static int32_t typeck_struct_layouts_same_shape_c(struct ast_Module *m, struct ast_ASTArena *a, int32_t la,
                                                  int32_t lb) {
  int32_t nfa;
  int32_t nfb;
  int32_t j;
  if (!m || !a || la < 0 || lb < 0)
    return 0;
  nfa = pipeline_module_struct_layout_num_fields(m, la);
  nfb = pipeline_module_struct_layout_num_fields(m, lb);
  if (nfa != nfb || nfa <= 0)
    return 0;
  for (j = 0; j < nfa; j++) {
    if (pipeline_module_struct_layout_field_offset_at(m, la, j) !=
        pipeline_module_struct_layout_field_offset_at(m, lb, j))
      return 0;
    if (!pipeline_typeck_type_refs_equal_c(a, pipeline_module_struct_layout_field_type_ref(m, la, j),
                                           pipeline_module_struct_layout_field_type_ref(m, lb, j)))
      return 0;
  }
  return 1;
}

/** MOD-02：*Struct 形参 vs 实参（含 &local）点ee 类型是否可接受；失败时打印 typeck error。 */
static int32_t typeck_check_call_ptr_struct_compat_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                     int32_t call_expr_ref, int32_t param_ref, int32_t arg_ref) {
  int32_t param_elem;
  int32_t arg_elem;
  int32_t arg_ty;
  int32_t arg_kind;
  int32_t la;
  int32_t lb;
  int32_t line;
  int32_t col;
  if (!module || !arena || param_ref <= 0 || arg_ref <= 0)
    return 0;
  if (pipeline_type_kind_ord_at(arena, param_ref) != (int32_t)ast_TypeKind_TYPE_PTR)
    return 0;
  param_elem = pipeline_type_elem_ref_at(arena, param_ref);
  if (param_elem <= 0 || !typeck_type_is_named_struct_c(module, arena, param_elem))
    return 0;
  arg_ty = pipeline_expr_resolved_type_ref(arena, arg_ref);
  arg_kind = pipeline_expr_kind_ord_at(arena, arg_ref);
  if (arg_ty <= 0 && arg_kind == (int32_t)ast_ExprKind_EXPR_ADDR_OF) {
    int32_t op = pipeline_expr_unary_operand_ref_at(arena, arg_ref);
    if (op > 0)
      arg_ty = pipeline_expr_resolved_type_ref(arena, op);
  }
  if (arg_ty <= 0)
    return 0;
  if (pipeline_type_kind_ord_at(arena, arg_ty) == (int32_t)ast_TypeKind_TYPE_NAMED) {
    arg_elem = arg_ty;
  } else if (pipeline_type_kind_ord_at(arena, arg_ty) == (int32_t)ast_TypeKind_TYPE_PTR) {
    arg_elem = pipeline_type_elem_ref_at(arena, arg_ty);
  } else {
    return 0;
  }
  if (arg_elem <= 0 || !typeck_type_is_named_struct_c(module, arena, arg_elem))
    return 0;
  if (param_elem == arg_elem)
    return 0;
  param_elem = pipeline_typeck_resolve_type_alias_ref_c(arena, param_elem);
  arg_elem = pipeline_typeck_resolve_type_alias_ref_c(arena, arg_elem);
  if (param_elem == arg_elem)
    return 0;
  la = typeck_layout_index_for_named_type_c(module, arena, param_elem);
  lb = typeck_layout_index_for_named_type_c(module, arena, arg_elem);
  if (la < 0 || lb < 0)
    return 0;
  /** 同一 module 内已登记的 layout 下标：extern 形参 TYPE_NAMED 与局部 struct 常为不同 ref。 */
  if (la == lb)
    return 0;
  if (typeck_struct_layouts_same_shape_c(module, arena, la, lb) &&
      pipeline_module_struct_layout_repr_compatible_at(module, la) &&
      pipeline_module_struct_layout_repr_compatible_at(module, lb))
    return 0;
  line = pipeline_expr_line_at(arena, call_expr_ref);
  col = pipeline_expr_col_at(arena, call_expr_ref);
  lsp_diag_report_typeck((int)line, (int)col, "no matching overload (incompatible struct pointer argument)");
  return -1;
}

/**
 * M-3：.x typeck CALL 实参 slice 域检查；解析 callee 后逐实参对照形参域标签。
 */
int32_t pipeline_typeck_check_call_slice_region_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                  int32_t call_expr_ref, struct ast_PipelineDepCtx *ctx) {
  int32_t func_ix;
  int32_t dep_ix;
  int32_t num_args;
  int32_t np;
  int32_t i;
  int32_t arg_ref;
  int32_t param_ref;
  int32_t arg_ty;
  struct ast_Module *callee_mod;
  if (!module || !arena || call_expr_ref <= 0)
    return 0;
  func_ix = pipeline_expr_call_resolved_func_index_at(arena, call_expr_ref);
  dep_ix = pipeline_expr_call_resolved_dep_index_at(arena, call_expr_ref);
  if (func_ix < 0)
    func_ix = pipeline_typeck_resolve_call_func_index_c(module, arena, call_expr_ref);
  if (func_ix < 0)
    return 0;
  callee_mod = module;
  if (dep_ix >= 0 && ctx) {
    struct ast_Module *dm = pipeline_dep_ctx_module_at(ctx, dep_ix);
    if (dm)
      callee_mod = dm;
  }
  num_args = pipeline_expr_call_num_args_at(arena, call_expr_ref);
  np = pipeline_module_func_num_params_at(callee_mod, func_ix);
  if (num_args != np)
    return 0;
  for (i = 0; i < num_args; i++) {
    arg_ref = pipeline_expr_call_arg_ref(arena, call_expr_ref, i);
    param_ref = pipeline_module_func_param_type_ref_at(callee_mod, func_ix, i);
    arg_ty = pipeline_expr_resolved_type_ref(arena, arg_ref);
    if (pipeline_typeck_check_slice_region_assign_c(arena, arg_ref, param_ref, arg_ty) != 0)
      return -1;
    if (typeck_check_call_ptr_struct_compat_c(module, arena, call_expr_ref, param_ref, arg_ref) != 0)
      return -1;
  }
  /** WPO-S3：&local struct 与 *Struct 形参同传 → 拒（外层槽逃逸）。 */
  if (ctx && num_args >= 2 && getenv("SHUX_SKIP_STACK_ESCAPE") == NULL) {
    int32_t src_i;
    int32_t dst_j;
    for (src_i = 0; src_i < num_args; src_i++) {
      int32_t stack_arg = pipeline_expr_call_arg_ref(arena, call_expr_ref, src_i);
      int32_t stack_arg_ty;
      int32_t stack_arg_elem;
      if (!typeck_expr_is_addr_of_block_local_c(module, arena, ctx, stack_arg))
        continue;
      /** 仅当 &local 的类型是 *Struct 时才触发（&local_i32 不逃逸）。 */
      stack_arg_ty = pipeline_expr_resolved_type_ref(arena, stack_arg);
      if (stack_arg_ty <= 0)
        continue;
      if (pipeline_type_kind_ord_at(arena, stack_arg_ty) != (int32_t)ast_TypeKind_TYPE_PTR)
        continue;
      stack_arg_elem = pipeline_type_elem_ref_at(arena, stack_arg_ty);
      if (stack_arg_elem <= 0 || !typeck_type_is_named_struct_c(module, arena, stack_arg_elem))
        continue;
      for (dst_j = 0; dst_j < num_args; dst_j++) {
        int32_t param_ref2;
        int32_t elem_ref;
        int32_t line;
        int32_t col;
        if (dst_j == src_i)
          continue;
        param_ref2 = pipeline_module_func_param_type_ref_at(callee_mod, func_ix, dst_j);
        if (param_ref2 <= 0 ||
            pipeline_type_kind_ord_at(arena, param_ref2) != (int32_t)ast_TypeKind_TYPE_PTR)
          continue;
        elem_ref = pipeline_type_elem_ref_at(arena, param_ref2);
        if (elem_ref <= 0 || !typeck_type_is_named_struct_c(module, arena, elem_ref))
          continue;
        line = pipeline_expr_line_at(arena, call_expr_ref);
        col = pipeline_expr_col_at(arena, call_expr_ref);
        lsp_diag_report_typeck((int)line, (int)col,
                               "struct stack escape: cannot pass address of local struct with outer struct pointer");
        return -1;
      }
    }
  }
  return 0;
}

/**
 * M-3 / MEM-C1：typeck 单条 region 或 with_arena 块。
 * with_arena 无域标签，旧实现 label_len<=0 直接 return 0 会跳过体块 typeck，导致 AL-04 assign 逃逸漏报。
 */
int32_t pipeline_typeck_unsafe_depth_push_c(struct ast_PipelineDepCtx *ctx);
void pipeline_typeck_unsafe_depth_pop_c(struct ast_PipelineDepCtx *ctx, int32_t saved_unsafe_depth);

int32_t pipeline_typeck_check_block_one_region_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                 int32_t block_ref, int32_t region_idx, int32_t return_type_ref,
                                                 struct ast_PipelineDepCtx *ctx) {
  uint8_t label[64];
  int32_t label_len;
  int32_t body_ref;
  int32_t wa_cap;
  int32_t rc;
  extern int32_t typeck_check_block(struct ast_Module *module, struct ast_ASTArena *arena, int32_t block_ref,
                                    int32_t return_type_ref, struct ast_PipelineDepCtx *ctx);
  if (!module || !arena || !ctx || block_ref <= 0 || region_idx < 0)
    return 0;
  body_ref = pipeline_block_region_body_ref(arena, block_ref, region_idx);
  if (body_ref <= 0)
    return 0;
  if (pipeline_block_region_is_unsafe(arena, block_ref, region_idx)) {
    int32_t saved_ud;
    saved_ud = pipeline_typeck_unsafe_depth_push_c(ctx);
    rc = typeck_check_block(module, arena, body_ref, return_type_ref, ctx);
    pipeline_typeck_unsafe_depth_pop_c(ctx, saved_ud);
    return rc;
  }
  wa_cap = pipeline_block_region_with_arena_cap_ref(arena, block_ref, region_idx);
  if (wa_cap > 0) {
    /** MEM-C1：push with_arena 栈，使 check_expr_impl_mega / post-scan 能报 allocator region escape。 */
    typeck_with_arena_scope_push_c(body_ref);
    rc = typeck_check_block(module, arena, body_ref, return_type_ref, ctx);
    typeck_with_arena_scope_pop_c();
    return rc;
  }
  label_len = pipeline_block_region_label_len(arena, block_ref, region_idx);
  if (label_len <= 0)
    return 0;
  pipeline_block_region_label_copy64(arena, block_ref, region_idx, label);
  if (pipeline_dep_ctx_scope_region_push_c(ctx, label, label_len) != 0)
    return -1;
  rc = typeck_check_block(module, arena, body_ref, return_type_ref, ctx);
  pipeline_dep_ctx_scope_region_pop_c(ctx);
  return rc;
}

/** 比较两段字节序列是否逐字节相等（typeck name_equal 的 C 辅助）。 */
static int32_t pipeline_typeck_bytes_equal_c(uint8_t *a, int32_t a_len, uint8_t *b, int32_t b_len) {
  int32_t i;

  if (a_len != b_len || a_len <= 0)
    return 0;
  i = 0;
  while (i < a_len) {
    if (a[i] != b[i])
      return 0;
    i = i + 1;
  }
  return 1;
}

/**
 * typeck.x::typeck_coerce_init_lit_to_decl 的 C 委托（整型字面量分支）。
 */
int32_t pipeline_typeck_coerce_init_lit_to_decl_c(struct ast_ASTArena *arena, int32_t init_ref, int32_t decl_ty_ref,
                                                  int32_t decl_kind, int32_t init_kind) {
  struct ast_Expr *init_ex;
  int32_t int_val;

  if (!arena || init_ref <= 0 || init_ref > arena->num_exprs || decl_ty_ref <= 0)
    return 0;
  if (init_kind != (int32_t)ast_ExprKind_EXPR_LIT)
    return 0;
  init_ex = pipeline_arena_expr_ptr(arena, init_ref);
  if (!init_ex)
    return 0;
  int_val = pipeline_expr_int_val_at(arena, init_ref);
  if (decl_kind == (int32_t)ast_TypeKind_TYPE_PTR && int_val == 0) {
    init_ex->resolved_type_ref = decl_ty_ref;
    return 1;
  }
  if (decl_kind == (int32_t)ast_TypeKind_TYPE_ARRAY && int_val == 0) {
    init_ex->resolved_type_ref = decl_ty_ref;
    return 1;
  }
  if (decl_kind == (int32_t)ast_TypeKind_TYPE_U8 && int_val >= 0 && int_val <= 255) {
    init_ex->resolved_type_ref = decl_ty_ref;
    return 1;
  }
  if (decl_kind == (int32_t)ast_TypeKind_TYPE_I64) {
    init_ex->resolved_type_ref = decl_ty_ref;
    return 1;
  }
  if (int_val >= 0 &&
      (decl_kind == (int32_t)ast_TypeKind_TYPE_USIZE || decl_kind == (int32_t)ast_TypeKind_TYPE_ISIZE ||
       decl_kind == (int32_t)ast_TypeKind_TYPE_U32 || decl_kind == (int32_t)ast_TypeKind_TYPE_U64)) {
    init_ex->resolved_type_ref = decl_ty_ref;
    return 1;
  }
  if (int_val == 0 &&
      (decl_kind == (int32_t)ast_TypeKind_TYPE_F32 || decl_kind == (int32_t)ast_TypeKind_TYPE_F64)) {
    init_ex->resolved_type_ref = decl_ty_ref;
    return 1;
  }
  if (int_val == 0 &&
      (decl_kind == (int32_t)ast_TypeKind_TYPE_NAMED || decl_kind == (int32_t)ast_TypeKind_TYPE_VECTOR)) {
    init_ex->resolved_type_ref = decl_ty_ref;
    return 1;
  }
  return 0;
}

/** typeck.x::typeck_coerce_init_float_lit_to_decl 的 C 委托。 */
int32_t pipeline_typeck_coerce_init_float_lit_to_decl_c(struct ast_ASTArena *arena, int32_t init_ref,
                                                        int32_t decl_ty_ref, int32_t decl_kind, int32_t init_kind) {
  struct ast_Expr *init_ex;

  if (!arena || init_ref <= 0 || init_ref > arena->num_exprs)
    return 0;
  if (init_kind != (int32_t)ast_ExprKind_EXPR_FLOAT_LIT ||
      (decl_kind != (int32_t)ast_TypeKind_TYPE_F32 && decl_kind != (int32_t)ast_TypeKind_TYPE_F64))
    return 0;
  init_ex = pipeline_arena_expr_ptr(arena, init_ref);
  if (!init_ex)
    return 0;
  init_ex->resolved_type_ref = decl_ty_ref;
  return 1;
}

/** typeck.x::typeck_coerce_init_enum_field_to_decl 的 C 委托（枚举 variant 字段访问）。 */
int32_t pipeline_typeck_coerce_init_enum_field_to_decl_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                         int32_t init_ref, int32_t decl_ty_ref, int32_t decl_kind,
                                                         int32_t init_kind) {
  struct ast_Expr *init_ex;
  int32_t base_ix;
  uint8_t decl_nm[64];
  int32_t decl_nlen;
  uint8_t field_nm[64];
  int32_t field_nlen;

  if (!arena || init_ref <= 0 || init_ref > arena->num_exprs)
    return 0;
  if (decl_kind != (int32_t)ast_TypeKind_TYPE_NAMED || init_kind != (int32_t)ast_ExprKind_EXPR_FIELD_ACCESS)
    return 0;
  init_ex = pipeline_arena_expr_ptr(arena, init_ref);
  if (!init_ex)
    return 0;
  base_ix = pipeline_expr_field_access_base_ref(arena, init_ref);
  if (!ast_ref_is_null(base_ix) && base_ix > 0 && base_ix <= arena->num_exprs) {
    decl_nlen = pipeline_type_named_name_into(arena, decl_ty_ref, decl_nm);
    if (pipeline_expr_kind_ord_at(arena, base_ix) == 3) {
      uint8_t vnm[64];
      int32_t vnlen;

      vnlen = pipeline_expr_var_name_len(arena, base_ix);
      pipeline_expr_var_name_into(arena, base_ix, vnm);
      if (pipeline_typeck_bytes_equal_c(decl_nm, decl_nlen, vnm, vnlen)) {
        field_nlen = pipeline_expr_field_access_name_len(arena, init_ref);
        pipeline_expr_field_access_name_into(arena, init_ref, field_nm);
        if (module) {
          int32_t ev_tag =
              pipeline_module_enum_variant_tag_for_names(module, decl_nm, decl_nlen, field_nm, field_nlen);
          if (ev_tag >= 0) {
            init_ex->field_access_is_enum_variant = 1;
            init_ex->enum_variant_tag = ev_tag;
            init_ex->resolved_type_ref = decl_ty_ref;
            return 1;
          }
        }
      }
    }
  }
  if (pipeline_expr_field_access_is_enum_variant(arena, init_ref) != 0) {
    init_ex->resolved_type_ref = decl_ty_ref;
    return 1;
  }
  return 0;
}

/** typeck.x::typeck_coerce_init_named_call_to_decl 的 C 委托。 */
int32_t pipeline_typeck_coerce_init_named_call_to_decl_c(struct ast_ASTArena *arena, int32_t init_ref,
                                                         int32_t decl_ty_ref, int32_t decl_kind, int32_t init_kind) {
  struct ast_Expr *init_ex;

  if (!arena || init_ref <= 0 || init_ref > arena->num_exprs)
    return 0;
  if (decl_kind != (int32_t)ast_TypeKind_TYPE_NAMED || init_kind != (int32_t)ast_ExprKind_EXPR_CALL ||
      !ast_ref_is_null(pipeline_expr_resolved_type_ref(arena, init_ref)))
    return 0;
  init_ex = pipeline_arena_expr_ptr(arena, init_ref);
  if (!init_ex)
    return 0;
  init_ex->resolved_type_ref = decl_ty_ref;
  return 1;
}

/** typeck.x::typeck_coerce_init_array_vector_lit_to_decl 的 C 委托。 */
int32_t pipeline_typeck_coerce_init_array_vector_lit_to_decl_c(struct ast_ASTArena *arena, int32_t init_ref,
                                                               int32_t decl_ty_ref, int32_t decl_kind,
                                                               int32_t init_kind) {
  struct ast_Expr *init_ex;
  int32_t nel_v;
  int32_t decl_asz;

  if (!arena || init_ref <= 0 || init_ref > arena->num_exprs)
    return 0;
  init_ex = pipeline_arena_expr_ptr(arena, init_ref);
  if (!init_ex)
    return 0;
  if (decl_kind == (int32_t)ast_TypeKind_TYPE_ARRAY && init_kind == (int32_t)ast_ExprKind_EXPR_ARRAY_LIT) {
    init_ex->resolved_type_ref = decl_ty_ref;
    return 1;
  }
  if (decl_kind == (int32_t)ast_TypeKind_TYPE_VECTOR && init_kind == (int32_t)ast_ExprKind_EXPR_ARRAY_LIT) {
    nel_v = pipeline_expr_array_lit_num_elems_at(arena, init_ref);
    decl_asz = pipeline_type_array_size_at(arena, decl_ty_ref);
    if (nel_v == decl_asz) {
      init_ex->resolved_type_ref = decl_ty_ref;
      return 1;
    }
  }
  return 0;
}

/** typeck.x::typeck_coerce_init_vector_binop_to_decl 的 C 委托。 */
int32_t pipeline_typeck_coerce_init_vector_binop_to_decl_c(struct ast_ASTArena *arena, int32_t init_ref,
                                                           int32_t decl_ty_ref, int32_t decl_kind, int32_t init_kind) {
  struct ast_Expr *init_ex;
  int32_t lref_c;
  int32_t rref_c;
  int32_t lt_c;
  int32_t rt_c;

  if (!arena || init_ref <= 0 || init_ref > arena->num_exprs)
    return 0;
  if (decl_kind != (int32_t)ast_TypeKind_TYPE_VECTOR)
    return 0;
  if (init_kind != (int32_t)ast_ExprKind_EXPR_ADD && init_kind != (int32_t)ast_ExprKind_EXPR_SUB &&
      init_kind != (int32_t)ast_ExprKind_EXPR_MUL && init_kind != (int32_t)ast_ExprKind_EXPR_DIV)
    return 0;
  init_ex = pipeline_arena_expr_ptr(arena, init_ref);
  if (!init_ex)
    return 0;
  lref_c = pipeline_expr_binop_left_ref_at(arena, init_ref);
  rref_c = pipeline_expr_binop_right_ref_at(arena, init_ref);
  if (!ast_ref_is_null(lref_c) && !ast_ref_is_null(rref_c)) {
    lt_c = pipeline_typeck_expr_type_ref_c(arena, lref_c);
    rt_c = pipeline_typeck_expr_type_ref_c(arena, rref_c);
    if (!ast_ref_is_null(lt_c) && !ast_ref_is_null(rt_c) &&
        pipeline_type_kind_ord_at(arena, lt_c) == (int32_t)ast_TypeKind_TYPE_VECTOR &&
        pipeline_type_kind_ord_at(arena, rt_c) == (int32_t)ast_TypeKind_TYPE_VECTOR &&
        pipeline_type_array_size_at(arena, lt_c) == pipeline_type_array_size_at(arena, rt_c) &&
        pipeline_type_array_size_at(arena, lt_c) == pipeline_type_array_size_at(arena, decl_ty_ref) &&
        pipeline_typeck_type_refs_equal_c(arena, pipeline_type_elem_ref_at(arena, lt_c),
                                          pipeline_type_elem_ref_at(arena, rt_c))) {
      init_ex->resolved_type_ref = decl_ty_ref;
      return 1;
    }
  }
  return 0;
}

/**
 * typeck.x::typeck_coerce_init_int_binop_to_decl 的 C 委托：
 * let 标量整型声明 + 算术二元初值时提升到声明类型（INT64_MIN 等 i64 表达式）。
 */
int32_t pipeline_typeck_coerce_init_int_binop_to_decl_c(struct ast_ASTArena *arena, int32_t init_ref,
                                                        int32_t decl_ty_ref, int32_t decl_kind, int32_t init_kind) {
  struct ast_Expr *init_ex;

  if (!arena || init_ref <= 0 || init_ref > arena->num_exprs)
    return 0;
  if (decl_kind != (int32_t)ast_TypeKind_TYPE_I32 && decl_kind != (int32_t)ast_TypeKind_TYPE_I64 &&
      decl_kind != (int32_t)ast_TypeKind_TYPE_U64 && decl_kind != (int32_t)ast_TypeKind_TYPE_USIZE)
    return 0;
  if (init_kind != (int32_t)ast_ExprKind_EXPR_ADD && init_kind != (int32_t)ast_ExprKind_EXPR_SUB &&
      init_kind != (int32_t)ast_ExprKind_EXPR_MUL && init_kind != (int32_t)ast_ExprKind_EXPR_DIV)
    return 0;
  init_ex = pipeline_arena_expr_ptr(arena, init_ref);
  if (!init_ex)
    return 0;
  init_ex->resolved_type_ref = decl_ty_ref;
  return 1;
}

/**
 * let 初值：匿名 struct 字面量 `{ fd, ... }` 从声明类型 `PollFd` 回填 struct 名与 resolved_type。
 * 须在 typeck_ensure_struct_layout_from_struct_lit 之前写入 struct_lit_struct_name。
 */
int32_t pipeline_typeck_coerce_init_struct_lit_to_decl_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                         int32_t init_ref, int32_t decl_ty_ref) {
  struct ast_Expr *init_ex;
  int32_t decl_kind;
  int32_t init_kind;
  int32_t name_len;
  uint8_t decl_nm[64];
  int32_t decl_nlen;
  int32_t ti;

  if (!arena || init_ref <= 0 || init_ref > arena->num_exprs || decl_ty_ref <= 0 || decl_ty_ref > arena->num_types)
    return 0;
  decl_kind = pipeline_type_kind_ord_at(arena, decl_ty_ref);
  init_kind = pipeline_expr_kind_ord_at(arena, init_ref);
  if (decl_kind != (int32_t)ast_TypeKind_TYPE_NAMED || init_kind != (int32_t)ast_ExprKind_EXPR_STRUCT_LIT)
    return 0;
  init_ex = pipeline_arena_expr_ptr(arena, init_ref);
  if (!init_ex)
    return 0;
  name_len = init_ex->struct_lit_struct_name_len;
  if (name_len > 0)
    return 0;
  decl_nlen = pipeline_type_named_name_into(arena, decl_ty_ref, decl_nm);
  if (decl_nlen <= 0 || decl_nlen > 63)
    return 0;
  init_ex->struct_lit_struct_name_len = decl_nlen;
  ti = 0;
  while (ti < 64) {
    init_ex->struct_lit_struct_name[ti] = (ti < decl_nlen) ? decl_nm[ti] : (uint8_t)0;
    ti = ti + 1;
  }
  if (module && typeck_ensure_struct_layout_from_struct_lit(module, arena, init_ref) != 0)
    return 0;
  init_ex->resolved_type_ref = decl_ty_ref;
  return 1;
}

/** typeck.x::typeck_coerce_init_slice_from_array 的 C 委托。 */
int32_t pipeline_typeck_coerce_init_slice_from_array_c(struct ast_ASTArena *arena, int32_t init_ref, int32_t decl_ty_ref,
                                                       int32_t decl_kind) {
  struct ast_Expr *init_ex;
  int32_t decl_elem;
  int32_t init_res;
  int32_t init_res_kind;
  int32_t init_elem;

  if (!arena || init_ref <= 0 || init_ref > arena->num_exprs)
    return 0;
  if (decl_kind != (int32_t)ast_TypeKind_TYPE_SLICE)
    return 0;
  init_ex = pipeline_arena_expr_ptr(arena, init_ref);
  if (!init_ex)
    return 0;
  decl_elem = pipeline_type_elem_ref_at(arena, decl_ty_ref);
  init_res = pipeline_expr_resolved_type_ref(arena, init_ref);
  if (!ast_ref_is_null(decl_elem) && !ast_ref_is_null(init_res)) {
    init_res_kind = pipeline_type_kind_ord_at(arena, init_res);
    init_elem = pipeline_type_elem_ref_at(arena, init_res);
    if (init_res_kind == (int32_t)ast_TypeKind_TYPE_ARRAY && !ast_ref_is_null(init_elem) &&
        pipeline_typeck_type_refs_equal_c(arena, init_elem, decl_elem)) {
      init_ex->resolved_type_ref = decl_ty_ref;
      return 1;
    }
  }
  return 0;
}

/**
 * typeck.x::typeck_coerce_init_expr_to_decl 的 C 委托（薄分发，对齐 X 子 helper 调用序）：
 * let/const 初值类型与声明对齐；用指针写 Expr 池，避免 ast_arena_expr_get 按值拷贝。
 */
int32_t pipeline_typeck_coerce_init_expr_to_decl_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                   int32_t init_ref, int32_t decl_ty_ref) {
  int32_t decl_kind;
  int32_t init_kind;

  if (ast_ref_is_null(init_ref) || ast_ref_is_null(decl_ty_ref))
    return 0;
  if (!arena || init_ref <= 0 || init_ref > arena->num_exprs || decl_ty_ref <= 0 || decl_ty_ref > arena->num_types)
    return 0;
  decl_kind = pipeline_type_kind_ord_at(arena, decl_ty_ref);
  init_kind = pipeline_expr_kind_ord_at(arena, init_ref);
  if (pipeline_typeck_coerce_init_lit_to_decl_c(arena, init_ref, decl_ty_ref, decl_kind, init_kind) != 0)
    return 1;
  if (pipeline_typeck_coerce_init_float_lit_to_decl_c(arena, init_ref, decl_ty_ref, decl_kind, init_kind) != 0)
    return 1;
  if (pipeline_typeck_coerce_init_enum_field_to_decl_c(module, arena, init_ref, decl_ty_ref, decl_kind, init_kind) != 0)
    return 1;
  if (pipeline_typeck_coerce_init_named_call_to_decl_c(arena, init_ref, decl_ty_ref, decl_kind, init_kind) != 0)
    return 1;
  if (pipeline_typeck_coerce_init_array_vector_lit_to_decl_c(arena, init_ref, decl_ty_ref, decl_kind, init_kind) != 0)
    return 1;
  if (pipeline_typeck_coerce_init_vector_binop_to_decl_c(arena, init_ref, decl_ty_ref, decl_kind, init_kind) != 0)
    return 1;
  if (pipeline_typeck_coerce_init_int_binop_to_decl_c(arena, init_ref, decl_ty_ref, decl_kind, init_kind) != 0)
    return 1;
  if (pipeline_typeck_coerce_init_slice_from_array_c(arena, init_ref, decl_ty_ref, decl_kind) != 0)
    return 1;
  if (pipeline_typeck_coerce_init_struct_lit_to_decl_c(module, arena, init_ref, decl_ty_ref) != 0)
    return 1;
  return 0;
}

/** 前向声明：check_expr_impl C 委托内递归 check 子表达式。 */
int32_t pipeline_typeck_check_expr_c(struct ast_Module *module, struct ast_ASTArena *arena, int32_t expr_ref,
                                     int32_t return_type_ref, struct ast_PipelineDepCtx *ctx);
int32_t pipeline_typeck_check_block_c(struct ast_Module *module, struct ast_ASTArena *arena, int32_t block_ref,
                                      int32_t return_type_ref, struct ast_PipelineDepCtx *ctx);

/** 判定 ExprKind 是否为赋值/复合赋值（与 typeck.x check_block 块尾推断一致）。 */
static int32_t pipeline_typeck_expr_is_any_assign_kind_c(int32_t kind_ord) {
  if (kind_ord == (int32_t)ast_ExprKind_EXPR_ASSIGN)
    return 1;
  if (kind_ord >= (int32_t)ast_ExprKind_EXPR_ADD_ASSIGN && kind_ord <= (int32_t)ast_ExprKind_EXPR_SHR_ASSIGN)
    return 1;
  return 0;
}

/** typeck.o / typeck_x_no_layout 子 helper；kind 分派经 pipeline_typeck_check_expr_impl_mega_c 调用。 */
extern int32_t typeck_check_expr_try_propagate(struct ast_Module *module, struct ast_ASTArena *arena,
                                               int32_t expr_ref, int32_t return_type_ref, struct ast_PipelineDepCtx *ctx);

// #region debug-point D:try-propagate-strong-state
static void debug_try_propagate_report_glue_c(int32_t expr_ref, int32_t func_ix, int32_t return_type_ref, int32_t func_ret,
                                              int32_t enclosing_return_type_ref, int32_t op_ty) {
  FILE *fp;
  char line[512];
  char url[256];
  char session[64];
  char cmd[2048];
  const char *enabled = getenv("SHUX_DEBUG_RESULT_TRY");
  if (!enabled || enabled[0] == '\0' || enabled[0] == '0')
    return;
  snprintf(url, sizeof(url), "%s", "http://127.0.0.1:7777/event");
  snprintf(session, sizeof(session), "%s", "result-try-typeck");
  fp = fopen(".dbg/result-try-typeck.env", "r");
  if (fp) {
    while (fgets(line, sizeof(line), fp)) {
      if (strncmp(line, "DEBUG_SERVER_URL=", 17) == 0) {
        snprintf(url, sizeof(url), "%s", line + 17);
      } else if (strncmp(line, "DEBUG_SESSION_ID=", 17) == 0) {
        snprintf(session, sizeof(session), "%s", line + 17);
      }
    }
    fclose(fp);
  }
  url[strcspn(url, "\r\n")] = '\0';
  session[strcspn(session, "\r\n")] = '\0';
  snprintf(cmd, sizeof(cmd),
           "/usr/bin/curl -s -X POST '%s' -H 'Content-Type: application/json' "
           "-d '{\"sessionId\":\"%s\",\"runId\":\"pre-fix\",\"hypothesisId\":\"D\","
           "\"location\":\"pipeline_glue.c:try_propagate\","
           "\"msg\":\"[DEBUG] try_propagate_state_strong\","
           "\"data\":{\"expr_ref\":%d,\"func_ix\":%d,\"return_type_ref\":%d,\"func_ret\":%d,"
           "\"enclosing_return_type_ref\":%d,\"op_ty\":%d}}' >/dev/null 2>&1",
           url, session, expr_ref, func_ix, return_type_ref, func_ret, enclosing_return_type_ref, op_ty);
  (void)system(cmd);
}
// #endregion

/**
 * ERR-01：Result `?` 传播 — operand 须为 Result_*，enclosing 函数返回类型须与之相同；表达式类型为 Ok 载荷（Result_i32→i32）。
 */
int32_t pipeline_typeck_check_expr_try_propagate_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                   int32_t expr_ref, int32_t return_type_ref,
                                                   struct ast_PipelineDepCtx *ctx) {
  int32_t op_ref;
  int32_t op_ty;
  int32_t enclosing_return_type_ref;
  int32_t func_ix;
  int32_t func_ret;
  int32_t line;
  int32_t col;
  int32_t payload_ty;
  uint8_t rname[64];
  int32_t rlen;
  int32_t si;

  (void)module;
  (void)ctx;
  if (!arena || expr_ref <= 0 || expr_ref > arena->num_exprs)
    return 0;
  op_ref = pipeline_expr_unary_operand_ref_at(arena, expr_ref);
  line = pipeline_expr_line_at(arena, expr_ref);
  col = pipeline_expr_col_at(arena, expr_ref);
  if (pipeline_typeck_check_expr_c(module, arena, op_ref, return_type_ref, ctx) != 0)
    return -1;
  op_ty = pipeline_typeck_expr_type_ref_c(arena, op_ref);
  enclosing_return_type_ref = return_type_ref;
  func_ret = 0;
  func_ix = ctx ? ctx->current_func_index : -1;
  if (module && ctx && func_ix >= 0 && func_ix < pipeline_module_num_funcs(module)) {
    func_ret = pipeline_module_func_return_type_at(module, func_ix);
    if (!ast_ref_is_null(func_ret))
      enclosing_return_type_ref = func_ret;
  }
  debug_try_propagate_report_glue_c(expr_ref, func_ix, return_type_ref, func_ret, enclosing_return_type_ref, op_ty);
  if (ast_ref_is_null(op_ty) || pipeline_type_kind_ord_at(arena, op_ty) != (int32_t)ast_TypeKind_TYPE_NAMED) {
    driver_diagnostic_typeck_try_propagate_bad_enclosing(line, col);
    return -1;
  }
  rlen = pipeline_type_named_name_into(arena, op_ty, rname);
  if (rlen < 7 || rname[0] != 'R' || rname[1] != 'e' || rname[2] != 's' || rname[3] != 'u' || rname[4] != 'l' ||
      rname[5] != 't' || rname[6] != '_') {
    driver_diagnostic_typeck_try_propagate_bad_enclosing(line, col);
    return -1;
  }
  if (ast_ref_is_null(enclosing_return_type_ref) ||
      !pipeline_typeck_type_refs_equal_c(arena, enclosing_return_type_ref, op_ty)) {
    driver_diagnostic_typeck_try_propagate_bad_enclosing(line, col);
    return -1;
  }
  payload_ty = 0;
  if (rlen == 10 && rname[7] == 'i' && rname[8] == '3' && rname[9] == '2')
    payload_ty = pipeline_type_ensure_by_kind_ord(arena, (int32_t)ast_TypeKind_TYPE_I32);
  else if (rlen == 9 && rname[7] == 'u' && rname[8] == '8')
    payload_ty = pipeline_type_ensure_by_kind_ord(arena, (int32_t)ast_TypeKind_TYPE_U8);
  else {
    /** Result_<T> 泛型族：从后缀 T 解析标量（当前 gate 仅 i32/u8）。 */
    for (si = 7; si + 1 < rlen && si + 1 < 64; si++) {
      if (rname[si] == 'i' && rname[si + 1] == '3' && rname[si + 2] == '2') {
        payload_ty = pipeline_type_ensure_by_kind_ord(arena, (int32_t)ast_TypeKind_TYPE_I32);
        break;
      }
      if (rname[si] == 'u' && rname[si + 1] == '8') {
        payload_ty = pipeline_type_ensure_by_kind_ord(arena, (int32_t)ast_TypeKind_TYPE_U8);
        break;
      }
    }
  }
  if (payload_ty != 0)
    pipeline_expr_set_resolved_type_ref(arena, expr_ref, payload_ty);
  else if (!ast_ref_is_null(op_ty))
    pipeline_expr_set_resolved_type_ref(arena, expr_ref, op_ty);
  return 0;
}

int32_t typeck_check_expr_try_propagate(struct ast_Module *module, struct ast_ASTArena *arena, int32_t expr_ref,
                                        int32_t return_type_ref, struct ast_PipelineDepCtx *ctx) {
  return pipeline_typeck_check_expr_try_propagate_c(module, arena, expr_ref, return_type_ref, ctx);
}

/**
 * ERR-01 C codegen：GNU 语句表达式 desugar `expr?` → err 早退 + unwrap value（烟测 C 路径 codegen_x_ast）。
 */
int32_t pipeline_codegen_emit_expr_try_propagate_c(struct ast_ASTArena *arena, struct codegen_CodegenOutBuf *out,
                                                   int32_t expr_ref, struct ast_PipelineDepCtx *ctx) {
  extern int32_t codegen_emit_expr(struct ast_ASTArena *arena, struct codegen_CodegenOutBuf *out, int32_t expr_ref,
                                   struct ast_PipelineDepCtx *ctx);
  extern int32_t codegen_emit_bytes_from_ptr(struct codegen_CodegenOutBuf *out, uint8_t *p, int32_t n);
  int32_t op;
  static const uint8_t pre[] = "({ struct core_result_Result_i32 __shux_q = ";
  static const uint8_t suf[] = "; if (__shux_q.err != 0) return __shux_q; __shux_q.value; })";

  (void)ctx;
  if (!arena || !out || expr_ref <= 0)
    return -1;
  op = pipeline_expr_unary_operand_ref_at(arena, expr_ref);
  if (op <= 0)
    return -1;
  if (codegen_emit_bytes_from_ptr(out, (uint8_t *)pre, (int32_t)(sizeof(pre) - 1)) != 0)
    return -1;
  if (codegen_emit_expr(arena, out, op, ctx) != 0)
    return -1;
  return codegen_emit_bytes_from_ptr(out, (uint8_t *)suf, (int32_t)(sizeof(suf) - 1));
}

/** 两 slice 等长字节比较；len<=0 返回 0。 */
static int32_t glue_slice_equal_c(const uint8_t *a, int32_t alen, const uint8_t *b, int32_t blen) {
  int32_t i;
  if (!a || !b || alen != blen || alen <= 0)
    return 0;
  i = 0;
  while (i < alen) {
    if (a[i] != b[i])
      return 0;
    i = i + 1;
  }
  return 1;
}

/**
 * EXPR_METHOD_CALL：检查 base/实参并解析方法返回类型（trait/impl skip 时 i32.double→i32 fallback）。
 */
int32_t pipeline_typeck_check_expr_method_call_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                 int32_t expr_ref, int32_t return_type_ref,
                                                 struct ast_PipelineDepCtx *ctx) {
  int32_t base_ref;
  int32_t base_rc;
  int32_t base_ty;
  int32_t base_ord;
  int32_t method_nlen;
  uint8_t method_nm[64];
  int32_t ret_ty;
  int32_t num_args;
  int32_t arg_i;
  int32_t ord_i32 = (int32_t)ast_TypeKind_TYPE_I32;
  int32_t ord_var = (int32_t)ast_ExprKind_EXPR_VAR;
  extern int32_t typeck_check_expr(struct ast_Module *module, struct ast_ASTArena *arena, int32_t expr_ref,
                                   int32_t return_type_ref, struct ast_PipelineDepCtx *ctx);

  if (!module || !arena || expr_ref <= 0)
    return 0;
  pipeline_expr_init_call_resolve_at_ref(arena, expr_ref);
  base_ref = pipeline_expr_method_call_base_ref_at(arena, expr_ref);
  base_rc = typeck_check_expr(module, arena, base_ref, 0, ctx);
  base_ty = pipeline_expr_resolved_type_ref(arena, base_ref);
  base_ord = pipeline_expr_kind_ord_at(arena, base_ref);
  method_nlen = pipeline_expr_method_call_name_len(arena, expr_ref);
  if (method_nlen <= 0 || method_nlen > 63)
    return -1;
  pipeline_expr_method_call_name_into(arena, expr_ref, method_nm);
  if (getenv("SHUX_DEBUG_PIPE")) {
    fprintf(stderr,
            "shux: [SHUX_DEBUG_PIPE] method_call expr=%d base=%d base_kind=%d base_rc=%d base_ty=%d method=%.*s\n",
            (int)expr_ref, (int)base_ref, (int)base_ord, (int)base_rc, (int)base_ty, (int)method_nlen, method_nm);
    if (base_ord == ord_var) {
      int32_t dbg_base_nlen = pipeline_expr_var_name_len(arena, base_ref);
      if (dbg_base_nlen > 0 && dbg_base_nlen <= 63) {
        uint8_t dbg_base_nm[64];
        pipeline_expr_var_name_into(arena, base_ref, dbg_base_nm);
        fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] method_call base_var=%.*s imports=%d\n", (int)dbg_base_nlen,
                dbg_base_nm, (int)pipeline_typeck_module_num_imports_c(module));
      }
    }
  }
  ret_ty = 0;
  if (base_ty <= 0 && ctx && base_ord == ord_var) {
    int32_t base_nlen = pipeline_expr_var_name_len(arena, base_ref);
    if (base_nlen > 0 && base_nlen <= 63) {
      uint8_t base_nm[64];
      int32_t j = 0;
      int32_t n_imp = pipeline_typeck_module_num_imports_c(module);
      pipeline_expr_var_name_into(arena, base_ref, base_nm);
      while (j < n_imp) {
        if (getenv("SHUX_DEBUG_PIPE")) {
          int32_t bind_len = pipeline_module_import_binding_name_len(module, j);
          int32_t path_len = pipeline_module_import_path_len(module, j);
          uint8_t bind_nm[64];
          uint8_t path_nm[64];
          int32_t dbg_i = 0;
          while (dbg_i < 64) {
            bind_nm[dbg_i] = 0;
            path_nm[dbg_i] = 0;
            dbg_i = dbg_i + 1;
          }
          dbg_i = 0;
          if (bind_len > 0 && bind_len <= 63)
            while (dbg_i < bind_len) {
              bind_nm[dbg_i] = pipeline_module_import_binding_name_byte_at(module, j, dbg_i);
              dbg_i = dbg_i + 1;
            }
          dbg_i = 0;
          if (path_len > 0 && path_len <= 63)
            while (dbg_i < path_len) {
              path_nm[dbg_i] = pipeline_module_import_path_byte_at(module, j, dbg_i);
              dbg_i = dbg_i + 1;
            }
          fprintf(stderr,
                  "shux: [SHUX_DEBUG_PIPE] method_call scan_import idx=%d kind=%d bind=%.*s path=%.*s\n", (int)j,
                  (int)pipeline_module_import_kind_at(module, j), (int)(bind_len > 0 ? bind_len : 0),
                  (bind_len > 0 ? bind_nm : (uint8_t *)""), (int)(path_len > 0 ? path_len : 0),
                  (path_len > 0 ? path_nm : (uint8_t *)""));
        }
        if (pipeline_module_import_kind_at(module, j) == GLUE_TYPECK_IMPORT_BINDING &&
            pipeline_typeck_import_binding_name_equal_impl(module, j, base_nm, base_nlen)) {
          int32_t dep_slot = pipeline_typeck_resolve_dep_index_for_import_c(module, ctx, j);
          struct ast_Module *dm = dep_slot >= 0 ? pipeline_dep_ctx_module_at(ctx, dep_slot) : 0;
          if (getenv("SHUX_DEBUG_PIPE")) {
            fprintf(stderr,
                    "shux: [SHUX_DEBUG_PIPE] method_call binding_match idx=%d dep_slot=%d dep=%p dep_funcs=%d\n",
                    (int)j, (int)dep_slot, (void *)dm, dm ? (int)dm->num_funcs : -1);
            if (dm) {
              int32_t dbg_fi = 0;
              while (dbg_fi < dm->num_funcs && dbg_fi < 32) {
                int32_t dbg_fn_len = pipeline_module_func_name_len_at(dm, dbg_fi);
                uint8_t dbg_fn[64];
                if (dbg_fn_len > 0 && dbg_fn_len <= 63) {
                  pipeline_module_func_name_copy64(dm, dbg_fi, dbg_fn);
                  fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] method_call dep_func idx=%d name=%.*s\n", (int)dbg_fi,
                          (int)dbg_fn_len, dbg_fn);
                }
                dbg_fi = dbg_fi + 1;
              }
            }
          }
          if (dm) {
            int32_t bind_fn = 0;
            ret_ty = pipeline_typeck_find_func_return_type_in_module_by_name_c(
                dm, arena, method_nm, method_nlen, dep_slot, ctx, &bind_fn);
            if (getenv("SHUX_DEBUG_PIPE"))
              fprintf(stderr,
                      "shux: [SHUX_DEBUG_PIPE] method_call binding_ret idx=%d dep_slot=%d ret_ty=%d bind_fn=%d\n",
                      (int)j, (int)dep_slot, (int)ret_ty, (int)bind_fn);
            if (ret_ty != 0) {
              pipeline_typeck_expr_apply_call_resolve_c(arena, expr_ref, dep_slot, bind_fn);
              break;
            }
          }
        }
        j = j + 1;
      }
    }
  }
  if (base_ty > 0) {
    /** bootstrap：impl 块被 skip 时 trait 测试 i32.double() 仍须 typeck 通过。 */
    if (pipeline_type_kind_ord_at(arena, base_ty) == ord_i32 && method_nlen == 6 &&
        method_nm[0] == (uint8_t)'d' && method_nm[1] == (uint8_t)'o' && method_nm[2] == (uint8_t)'u' &&
        method_nm[3] == (uint8_t)'b' && method_nm[4] == (uint8_t)'l' && method_nm[5] == (uint8_t)'e')
      ret_ty = pipeline_type_ensure_by_kind_ord(arena, ord_i32);
  }
  if (ret_ty != 0)
    pipeline_expr_set_resolved_type_ref(arena, expr_ref, ret_ty);
  num_args = pipeline_expr_method_call_num_args_at(arena, expr_ref);
  arg_i = 0;
  while (arg_i < num_args) {
    int32_t arg_ref = pipeline_expr_method_call_arg_ref(arena, expr_ref, arg_i);
    if (typeck_check_expr(module, arena, arg_ref, return_type_ref, ctx) != 0)
      return -1;
    arg_i = arg_i + 1;
  }
  if (base_rc != 0 && ret_ty == 0)
    return -1;
  return ret_ty != 0 ? 0 : -1;
}

/**
 * 泛型 identity 模式 bootstrap fixup：返回类型名与首形参类型名相同且为 TYPE_NAMED 时，
 * 用首个实参 resolved 类型单态化（id<T>(x:T):T，parser 未存 type_args 时的兜底）。
 */
static int32_t glue_generic_call_fixup_resolved_type_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                       int32_t call_expr_ref) {
  int32_t ord_var = 3;
  int32_t ord_named = (int32_t)ast_TypeKind_TYPE_NAMED;
  int32_t callee_ref;
  int32_t callee_eff;
  int32_t func_idx;
  int32_t ret_ty;
  int32_t param_ty;
  uint8_t ret_nm[64];
  uint8_t param_nm[64];
  int32_t ret_nlen;
  int32_t param_nlen;
  int32_t arg0;
  int32_t arg0_ty;
  uint8_t cnm[64];
  int32_t cnml;
  int32_t j;

  if (!module || !arena || call_expr_ref <= 0)
    return 0;
  callee_ref = pipeline_expr_call_callee_ref_at(arena, call_expr_ref);
  callee_eff = callee_ref;
  if (pipeline_expr_kind_ord_at(arena, callee_eff) != ord_var)
    return 0;
  cnml = pipeline_expr_var_name_len(arena, callee_eff);
  if (cnml <= 0 || cnml > 63)
    return 0;
  pipeline_expr_var_name_into(arena, callee_eff, cnm);
  func_idx = -1;
  j = 0;
  while (j < (int32_t)module->num_funcs) {
    if (pipeline_module_func_name_equal_at(module, j, cnm, cnml) != 0) {
      func_idx = j;
      break;
    }
    j = j + 1;
  }
  if (func_idx < 0)
    return 0;
  ret_ty = pipeline_module_func_return_type_at(module, func_idx);
  if (ret_ty <= 0 || pipeline_type_kind_ord_at(arena, ret_ty) != ord_named)
    return 0;
  if (pipeline_module_func_num_params_at(module, func_idx) < 1)
    return 0;
  param_ty = pipeline_module_func_param_type_ref_at(module, func_idx, 0);
  if (param_ty <= 0 || pipeline_type_kind_ord_at(arena, param_ty) != ord_named)
    return 0;
  ret_nlen = pipeline_type_named_name_into(arena, ret_ty, ret_nm);
  param_nlen = pipeline_type_named_name_into(arena, param_ty, param_nm);
  if (ret_nlen <= 0 || param_nlen <= 0 || !glue_slice_equal_c(ret_nm, ret_nlen, param_nm, param_nlen))
    return 0;
  arg0 = pipeline_expr_call_arg_ref(arena, call_expr_ref, 0);
  if (arg0 <= 0)
    return 0;
  arg0_ty = pipeline_expr_resolved_type_ref(arena, arg0);
  if (arg0_ty <= 0)
    return 0;
  pipeline_expr_set_resolved_type_ref(arena, call_expr_ref, arg0_ty);
  return 0;
}

/**
 * bootstrap typeck 后处理：METHOD_CALL（i32.double→i32）与泛型 CALL 单态化。
 * 在 pipeline return/check 路径调用；parser skip impl / 未存 type_args 时的兜底。
 */
static void pipeline_typeck_bootstrap_expr_fixup_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                   int32_t expr_ref) {
  int32_t kind;
  int32_t base_ref;
  int32_t base_ty;
  int32_t method_nlen;
  uint8_t method_nm[64];
  int32_t ret_ty;
  int32_t ord_i32;
  int32_t ord_method;
  int32_t ord_call;

  if (!module || !arena || expr_ref <= 0)
    return;
  kind = pipeline_expr_kind_ord_at(arena, expr_ref);
  ord_i32 = (int32_t)ast_TypeKind_TYPE_I32;
  ord_method = (int32_t)ast_ExprKind_EXPR_METHOD_CALL;
  ord_call = (int32_t)ast_ExprKind_EXPR_CALL;
  if (kind == ord_method) {
    base_ref = pipeline_expr_method_call_base_ref_at(arena, expr_ref);
    base_ty = pipeline_expr_resolved_type_ref(arena, base_ref);
    method_nlen = pipeline_expr_method_call_name_len(arena, expr_ref);
    if (method_nlen <= 0 || method_nlen > 63)
      return;
    pipeline_expr_method_call_name_into(arena, expr_ref, method_nm);
    ret_ty = 0;
    if (base_ty > 0 && pipeline_type_kind_ord_at(arena, base_ty) == ord_i32 && method_nlen == 6 &&
        method_nm[0] == (uint8_t)'d' && method_nm[1] == (uint8_t)'o' && method_nm[2] == (uint8_t)'u' &&
        method_nm[3] == (uint8_t)'b' && method_nm[4] == (uint8_t)'l' && method_nm[5] == (uint8_t)'e')
      ret_ty = pipeline_type_ensure_by_kind_ord(arena, ord_i32);
    if (ret_ty != 0)
      pipeline_expr_set_resolved_type_ref(arena, expr_ref, ret_ty);
    return;
  }
  if (kind == ord_call)
    (void)glue_generic_call_fixup_resolved_type_c(module, arena, expr_ref);
}

/**
 * EXPR_CALL：委托 typeck_x.o 后做泛型返回类型单态化 fixup（bootstrap parser 未存 call type_args）。
 * LANG-007 v2：S0 内 extern 调用须位于 unsafe { } 块内。
 */
extern void driver_diagnostic_typeck_extern_call_outside_unsafe(int32_t line, int32_t col);
extern void driver_diagnostic_typeck_call_not_generic(int32_t line, int32_t col, const uint8_t *name, int32_t name_len);
extern void driver_diagnostic_typeck_call_wrong_num_type_args(int32_t line, int32_t col, const uint8_t *name,
                                                              int32_t name_len, int32_t expect_n, int32_t got_n);
extern void driver_diagnostic_typeck_call_requires_type_args(int32_t line, int32_t col, const uint8_t *name,
                                                             int32_t name_len);
extern int32_t pipeline_module_func_num_generic_params_at(struct ast_Module *m, int32_t func_index);
extern int32_t pipeline_expr_call_num_type_args_at(struct ast_ASTArena *a, int32_t expr_ref);

static int32_t glue_module_func_index_by_name_c(struct ast_Module *mod, uint8_t *name, int32_t name_len);

static int32_t pipeline_typeck_check_extern_call_unsafe_boundary_c(struct ast_Module *module,
                                                                   struct ast_ASTArena *arena, int32_t expr_ref,
                                                                   struct ast_PipelineDepCtx *ctx) {
  int32_t callee_ref;
  int32_t callee_kind;
  int32_t name_len;
  uint8_t name[64];
  int32_t fi;
  int32_t line;
  int32_t col;

  if (pipeline_dep_ctx_typeck_unsafe_depth_at(ctx) > 0)
    return 0;
  if (!module || !arena || expr_ref <= 0 || expr_ref > arena->num_exprs)
    return 0;
  callee_ref = pipeline_expr_call_callee_ref_at(arena, expr_ref);
  if (callee_ref <= 0 || callee_ref > arena->num_exprs)
    return 0;
  callee_kind = pipeline_expr_kind_ord_at(arena, callee_ref);
  if (callee_kind != (int32_t)ast_ExprKind_EXPR_VAR)
    return 0;
  name_len = pipeline_expr_var_name_len(arena, callee_ref);
  if (name_len <= 0 || name_len > 63)
    return 0;
  pipeline_expr_var_name_into(arena, callee_ref, name);
  fi = glue_module_func_index_by_name_c(module, name, name_len);
  if (fi < 0 || pipeline_module_func_is_extern_at(module, fi) == 0)
    return 0;
  line = pipeline_expr_line_at(arena, expr_ref);
  col = pipeline_expr_col_at(arena, expr_ref);
  driver_diagnostic_typeck_extern_call_outside_unsafe(line, col);
  return -1;
}

static int32_t pipeline_typeck_check_call_generic_type_args_c(struct ast_Module *module,
                                                              struct ast_ASTArena *arena, int32_t expr_ref,
                                                              struct ast_PipelineDepCtx *ctx) {
  struct ast_Module *callee_mod;
  int32_t func_ix;
  int32_t dep_ix;
  int32_t num_generic_params;
  int32_t num_type_args;
  int32_t line;
  int32_t col;
  uint8_t name[64];
  int32_t name_len;

  if (!module || !arena || expr_ref <= 0)
    return 0;
  func_ix = pipeline_expr_call_resolved_func_index_at(arena, expr_ref);
  if (func_ix < 0)
    return 0;
  dep_ix = pipeline_expr_call_resolved_dep_index_at(arena, expr_ref);
  callee_mod = module;
  if (dep_ix >= 0) {
    callee_mod = pipeline_dep_ctx_module_at(ctx, dep_ix);
    if (!callee_mod)
      return 0;
  }
  num_generic_params = pipeline_module_func_num_generic_params_at(callee_mod, func_ix);
  num_type_args = pipeline_expr_call_num_type_args_at(arena, expr_ref);
  if (num_generic_params == 0 && num_type_args == 0)
    return 0;
  line = pipeline_expr_line_at(arena, expr_ref);
  col = pipeline_expr_col_at(arena, expr_ref);
  name_len = pipeline_module_func_name_len_at(callee_mod, func_ix);
  if (name_len > 63)
    name_len = 63;
  if (name_len > 0)
    pipeline_module_func_name_copy64(callee_mod, func_ix, name);
  if (num_type_args > 0 && num_generic_params == 0) {
    driver_diagnostic_typeck_call_not_generic(line, col, name, name_len);
    return -1;
  }
  if (num_generic_params > 0 && num_type_args == 0) {
    driver_diagnostic_typeck_call_requires_type_args(line, col, name, name_len);
    return -1;
  }
  if (num_generic_params != num_type_args) {
    driver_diagnostic_typeck_call_wrong_num_type_args(line, col, name, name_len, num_generic_params, num_type_args);
    return -1;
  }
  return 0;
}

int32_t pipeline_typeck_check_expr_call_c(struct ast_Module *module, struct ast_ASTArena *arena, int32_t expr_ref,
                                          int32_t return_type_ref, struct ast_PipelineDepCtx *ctx) {
  int32_t rc;
  int32_t callee_ref;
  int32_t ret_ty;
  if (pipeline_typeck_check_extern_call_unsafe_boundary_c(module, arena, expr_ref, ctx) != 0)
    return -1;
  /** 勿经 glue typeck_check_expr_call 互递归；直调 seed 子步骤 + glue resolve。 */
  rc = typeck_check_expr_call_arg(module, arena, expr_ref, return_type_ref, ctx, 0,
                                  pipeline_expr_call_num_args_at(arena, expr_ref));
  if (rc != 0)
    return rc;
  rc = typeck_check_expr_call_resolve(module, arena, expr_ref, ctx);
  if (rc != 0)
    return rc;
  if (pipeline_typeck_check_call_generic_type_args_c(module, arena, expr_ref, ctx) != 0)
    return -1;
  if (pipeline_typeck_check_call_slice_region_c(module, arena, expr_ref, ctx) != 0)
    return -1;
  if (ast_ref_is_null(pipeline_expr_resolved_type_ref(arena, expr_ref))) {
    callee_ref = pipeline_expr_call_callee_ref_at(arena, expr_ref);
    ret_ty = pipeline_typeck_resolve_call_callee_return_type_c(module, arena, callee_ref, expr_ref, ctx);
    if (ret_ty != 0)
      (void)(pipeline_expr_set_resolved_type_ref(arena, expr_ref, ret_ty));
  }
  (void)glue_generic_call_fixup_resolved_type_c(module, arena, expr_ref);
  return 0;
}

/** 非 standalone TU 保留旧 glue wrapper；strict_glue 改由 typeck_x.o 作为唯一导出方。 */
#if !defined(SHUX_PIPELINE_GLUE_STANDALONE_TU) && !defined(SHUX_PIPELINE_GLUE_OMIT_X_DUP_EXPORTS)
int32_t typeck_check_expr_call(struct ast_Module *module, struct ast_ASTArena *arena, int32_t expr_ref,
                               int32_t return_type_ref, struct ast_PipelineDepCtx *ctx) {
  return pipeline_typeck_check_expr_call_c(module, arena, expr_ref, return_type_ref, ctx);
}

int32_t typeck_check_expr_deref(struct ast_Module *module, struct ast_ASTArena *arena, int32_t expr_ref,
                                int32_t return_type_ref, struct ast_PipelineDepCtx *ctx) {
  return pipeline_typeck_check_expr_deref_c(module, arena, expr_ref, return_type_ref, ctx);
}

int32_t typeck_check_expr_method_call(struct ast_Module *module, struct ast_ASTArena *arena, int32_t expr_ref,
                                      int32_t return_type_ref, struct ast_PipelineDepCtx *ctx) {
  return pipeline_typeck_check_expr_method_call_c(module, arena, expr_ref, return_type_ref, ctx);
}
#endif

/**
 * typeck.x::check_expr_impl_mega 的 C 委托：按 ExprKind 分派至 typeck_check_expr_* 子 helper；
 * strict+pipeline 链不链整颗 typeck.o 时子 helper 来自 typeck_x_no_layout。
 */
int32_t pipeline_typeck_check_expr_impl_mega_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                    int32_t expr_ref, int32_t return_type_ref,
                                                    struct ast_PipelineDepCtx *ctx) {
  int32_t kind;

  if (!arena || expr_ref <= 0 || expr_ref > arena->num_exprs)
    return 0;
  kind = pipeline_expr_kind_ord_at(arena, expr_ref);
  if (pipeline_typeck_expr_is_any_assign_kind_c(kind)) {
    int32_t left_ref;
    int32_t right_ref;
    int32_t rc;
    left_ref = pipeline_expr_binop_left_ref_at(arena, expr_ref);
    right_ref = pipeline_expr_binop_right_ref_at(arena, expr_ref);
    /** MEM-C1/WPO：逃逸诊断优先于 assign 类型匹配，负例 gate 须在 mismatch 前报 allocator/scope 逃逸。 */
    if (pipeline_typeck_check_struct_stack_escape_assign_c(module, arena, expr_ref, left_ref, right_ref, ctx) != 0)
      return -1;
    if (pipeline_typeck_check_scope_borrow_assign_c(module, arena, expr_ref, left_ref, right_ref, ctx) != 0)
      return -1;
    if (pipeline_typeck_check_allocator_region_assign_c(module, arena, expr_ref, left_ref, ctx) != 0)
      return -1;
    rc = pipeline_typeck_check_expr_assign_c(module, arena, expr_ref, return_type_ref, ctx);
    if (rc != 0)
      return rc;
    return 0;
  }
  if (kind == (int32_t)ast_ExprKind_EXPR_RETURN) {
    int32_t op_ref;
    int32_t rc;
    op_ref = pipeline_expr_unary_operand_ref_at(arena, expr_ref);
    /** MEM-C1/M-3：return 逃逸诊断优先于 return 类型匹配。 */
    if (pipeline_typeck_check_scope_borrow_return_c(module, arena, expr_ref, op_ref, return_type_ref, ctx) != 0)
      return -1;
    if (pipeline_typeck_check_allocator_region_return_c(arena, expr_ref, return_type_ref) != 0)
      return -1;
    if (pipeline_typeck_check_return_slice_region_in_scope_c(arena, expr_ref, return_type_ref, ctx) != 0)
      return -1;
    if (pipeline_typeck_check_return_slice_region_c(arena, expr_ref, op_ref, return_type_ref) != 0)
      return -1;
    rc = pipeline_typeck_check_expr_return_c(module, arena, expr_ref, return_type_ref, ctx);
    if (rc != 0)
      return rc;
    return 0;
  }
  if (kind == (int32_t)ast_ExprKind_EXPR_PANIC)
    return typeck_check_expr_panic(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_MATCH)
    return pipeline_typeck_check_expr_match_c(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_FIELD_ACCESS)
    return typeck_check_expr_field_access(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_INDEX)
    return typeck_check_expr_index(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_CALL) {
    int32_t rc = pipeline_typeck_check_expr_call_c(module, arena, expr_ref, return_type_ref, ctx);
    if (rc != 0)
      return rc;
    return pipeline_typeck_check_call_struct_stack_escape_c(module, arena, expr_ref, ctx);
  }
  if (kind == (int32_t)ast_ExprKind_EXPR_METHOD_CALL)
    return pipeline_typeck_check_expr_method_call_c(module, arena, expr_ref, return_type_ref, ctx);
  if (kind >= (int32_t)ast_ExprKind_EXPR_ADD && kind <= (int32_t)ast_ExprKind_EXPR_LOGOR)
    return typeck_check_expr_binop(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_NEG || kind == (int32_t)ast_ExprKind_EXPR_BITNOT ||
      kind == (int32_t)ast_ExprKind_EXPR_LOGNOT)
    return typeck_check_expr_unary(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_ADDR_OF)
    return typeck_check_expr_addr_of(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_DEREF)
    return pipeline_typeck_check_expr_deref_c(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_VAR)
    return pipeline_typeck_check_expr_var_c(module, arena, expr_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_AS)
    return typeck_check_expr_as(module, arena, expr_ref, ctx);
  if (kind == GLUE_EXPR_KIND_TRY_PROPAGATE || kind == GLUE_EXPR_KIND_C_TRY_PROPAGATE)
    return typeck_check_expr_try_propagate(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_STRUCT_LIT)
    return typeck_check_expr_struct_lit(module, arena, expr_ref, return_type_ref, ctx);
  return 0;
}

extern int32_t typeck_check_expr_impl_mega(struct ast_Module *module, struct ast_ASTArena *arena, int32_t expr_ref,
                                         int32_t return_type_ref, struct ast_PipelineDepCtx *ctx);

/** glue-only 链无 typeck.o 时回退 mega_c；自举 typeck_x.o 提供 typeck_check_expr_impl_mega 覆盖。 */
__attribute__((weak)) int32_t check_expr_impl_mega(struct ast_Module *module, struct ast_ASTArena *arena,
                                                   int32_t expr_ref, int32_t return_type_ref,
                                                   struct ast_PipelineDepCtx *ctx) {
  return typeck_check_expr_impl_mega(module, arena, expr_ref, return_type_ref, ctx);
}

/**
 * typeck.x::check_expr_impl 的 C 委托：简单 kind→typeck_check_expr_*；mega→check_expr_impl_mega。
 * EMIT_HEAVY 第二遍 check_expr_impl 仍 bl 本符号（勿 X 真 emit if+递归 check_expr）。
 */
int32_t pipeline_typeck_check_expr_impl_c(struct ast_Module *module, struct ast_ASTArena *arena, int32_t expr_ref,
                                          int32_t return_type_ref, struct ast_PipelineDepCtx *ctx) {
  int32_t kind;

  if (!arena || expr_ref <= 0 || expr_ref > arena->num_exprs)
    return 0;
  kind = pipeline_expr_kind_ord_at(arena, expr_ref);
  if (kind == (int32_t)ast_ExprKind_EXPR_FLOAT_LIT)
    return typeck_check_expr_float_lit(arena, expr_ref);
  if (kind == (int32_t)ast_ExprKind_EXPR_LIT)
    return typeck_check_expr_int_lit(arena, expr_ref, return_type_ref);
  if (kind == (int32_t)ast_ExprKind_EXPR_BOOL_LIT)
    return typeck_check_expr_bool_lit(arena, expr_ref);
  if (kind == (int32_t)ast_ExprKind_EXPR_BREAK || kind == (int32_t)ast_ExprKind_EXPR_CONTINUE)
    return typeck_check_expr_break_continue(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_ENUM_VARIANT)
    return typeck_check_expr_enum_variant(arena, expr_ref);
  if (kind == (int32_t)ast_ExprKind_EXPR_IF || kind == (int32_t)ast_ExprKind_EXPR_TERNARY)
    return typeck_check_expr_if_ternary(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_BLOCK)
    return typeck_check_expr_block(module, arena, expr_ref, return_type_ref, ctx);
  if (kind == (int32_t)ast_ExprKind_EXPR_MATCH)
    return pipeline_typeck_check_expr_match_c(module, arena, expr_ref, return_type_ref, ctx);
  return check_expr_impl_mega(module, arena, expr_ref, return_type_ref, ctx);
}

/** glue-only 链无 typeck.o 时回退 impl_c；自举 typeck.o 在 EMIT_HEAVY 下 bl→impl_c 覆盖。 */
__attribute__((weak)) int32_t check_expr_impl(struct ast_Module *module, struct ast_ASTArena *arena,
                                              int32_t expr_ref, int32_t return_type_ref,
                                              struct ast_PipelineDepCtx *ctx) {
  return pipeline_typeck_check_expr_impl_c(module, arena, expr_ref, return_type_ref, ctx);
}

/** typeck.x::check_expr 的 C 委托：边界检查后委托 pipeline_typeck_check_expr_impl_c（简单 kind C 处理 + mega 回退）。 */
int32_t pipeline_typeck_check_expr_c(struct ast_Module *module, struct ast_ASTArena *arena, int32_t expr_ref,
                                     int32_t return_type_ref, struct ast_PipelineDepCtx *ctx) {
  int32_t rc;
  int32_t kind;

  if (ast_ref_is_null(expr_ref))
    return 0;
  if (expr_ref <= 0 || !arena || expr_ref > arena->num_exprs)
    return 0;
  kind = pipeline_expr_kind_ord_at(arena, expr_ref);
  if (kind == GLUE_EXPR_KIND_TRY_PROPAGATE || kind == GLUE_EXPR_KIND_C_TRY_PROPAGATE)
    return pipeline_typeck_check_expr_try_propagate_c(module, arena, expr_ref, return_type_ref, ctx);
  rc = pipeline_typeck_check_expr_impl_c(module, arena, expr_ref, return_type_ref, ctx);
  if (rc != 0 && getenv("SHUX_DEBUG_PIPE"))
    fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] check_expr fail func=%d expr=%d kind=%d block=%d\n",
            ctx ? (int)ctx->current_func_index : -1, (int)expr_ref, (int)kind,
            ctx ? (int)ctx->current_block_ref : -1);
  return rc;
}

/** check_block_impl：绑定 ctx.current_block_ref，返回 saved。 */
int32_t pipeline_typeck_block_impl_bind_ctx_c(struct ast_PipelineDepCtx *ctx, int32_t block_ref) {
  int32_t saved;
  if (!ctx)
    return 0;
  saved = ctx->current_block_ref;
  ctx->current_block_ref = block_ref;
  return saved;
}

/** check_block_impl：恢复 ctx.current_block_ref。 */
void pipeline_typeck_block_impl_restore_ctx_c(struct ast_PipelineDepCtx *ctx, int32_t saved_block_ref) {
  if (!ctx)
    return;
  ctx->current_block_ref = saved_block_ref;
}

/** stmt_order 每步：保持 current_block_ref 与正在检查的块一致。 */
void pipeline_typeck_block_impl_touch_ctx_block_c(struct ast_PipelineDepCtx *ctx, int32_t block_ref) {
  if (!ctx)
    return;
  ctx->current_block_ref = block_ref;
}

/** check_block_as_loop_body：typeck_loop_depth++，返回进入前的深度。 */
int32_t pipeline_typeck_loop_depth_push_c(struct ast_PipelineDepCtx *ctx) {
  int32_t saved;
  if (!ctx)
    return 0;
  saved = ctx->typeck_loop_depth;
  ctx->typeck_loop_depth = saved + 1;
  return saved;
}

/** check_block_as_loop_body：恢复 typeck_loop_depth。 */
void pipeline_typeck_loop_depth_pop_c(struct ast_PipelineDepCtx *ctx, int32_t saved_loop_depth) {
  if (!ctx)
    return;
  ctx->typeck_loop_depth = saved_loop_depth;
}

/** LANG-007 v2：读 unsafe { } 嵌套深度侧车。 */
int32_t pipeline_dep_ctx_typeck_unsafe_depth_at(struct ast_PipelineDepCtx *ctx) {
  (void)ctx;
  return g_typeck_unsafe_depth;
}

/** LANG-007 v2：check_block unsafe { }：typeck_unsafe_depth++，返回进入前的深度。 */
int32_t pipeline_typeck_unsafe_depth_push_c(struct ast_PipelineDepCtx *ctx) {
  int32_t saved;
  (void)ctx;
  saved = g_typeck_unsafe_depth;
  g_typeck_unsafe_depth = saved + 1;
  return saved;
}

/** LANG-007 v2：check_block unsafe { }：恢复 typeck_unsafe_depth。 */
void pipeline_typeck_unsafe_depth_pop_c(struct ast_PipelineDepCtx *ctx, int32_t saved_unsafe_depth) {
  (void)ctx;
  g_typeck_unsafe_depth = saved_unsafe_depth;
}

/** 写 ctx.typeck_loop_depth；typeck_loop_depth_push/pop X emit 用。 */
void pipeline_typeck_loop_depth_set_c(struct ast_PipelineDepCtx *ctx, int32_t depth) {
  if (!ctx)
    return;
  ctx->typeck_loop_depth = depth;
}

/** typeck_check_block_one_if 包装：SHUX_DEBUG_PIPE 时打印失败 if 的条件类型，便于 dep prerun 定位。 */
static int32_t pipeline_typeck_check_block_one_if_dbg_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                        int32_t block_ref, int32_t return_type_ref,
                                                        struct ast_PipelineDepCtx *ctx, int32_t idx) {
  int32_t rc;
  int32_t ic_cr;
  int32_t got_ty;

  rc = typeck_check_block_one_if(module, arena, block_ref, return_type_ref, ctx, idx);
  if (rc != 0 && getenv("SHUX_DEBUG_PIPE")) {
    ic_cr = ast_ast_block_if_cond_ref(arena, block_ref, idx);
    got_ty = ast_ref_is_null(ic_cr) ? 0 : pipeline_expr_resolved_type_ref(arena, ic_cr);
    fprintf(stderr,
            "shux: [SHUX_DEBUG_PIPE] check_block_one_if fail func=%d block=%d idx=%d cond=%d got_ty=%d is_bool=%d\n",
            ctx ? (int)ctx->current_func_index : -1, (int)block_ref, (int)idx, (int)ic_cr, (int)got_ty,
            (int)pipeline_typeck_type_ref_is_bool_c(arena, got_ty));
    fflush(stderr);
  }
  return rc;
}

/**
 * typeck.x::check_block_impl 的 C 委托：stmt_order/legacy 编排（C while）+ typeck.o one_* / final。
 * strict+pipeline 链不链整颗 typeck.o 时须自包含，不可 extern X 递归 walker。
 */
int32_t pipeline_typeck_check_block_impl_c(struct ast_Module *module, struct ast_ASTArena *arena, int32_t block_ref,
                                           int32_t return_type_ref, struct ast_PipelineDepCtx *ctx) {
  int32_t saved_block_ref;
  int32_t nc;
  int32_t nl;
  int32_t nlp;
  int32_t nfp;
  int32_t nif;
  int32_t nes;
  int32_t nso;
  int32_t fin0;
  int32_t si;
  int32_t i;
  uint8_t sk;
  int32_t idx;
  int32_t es_ref;

  if (!arena || !ctx || block_ref <= 0)
    return -1;
  saved_block_ref = pipeline_typeck_block_impl_bind_ctx_c(ctx, block_ref);
  nc = ast_ast_block_num_consts(arena, block_ref);
  nl = ast_ast_block_num_lets(arena, block_ref);
  nlp = ast_ast_block_num_loops(arena, block_ref);
  nfp = ast_ast_block_num_for_loops(arena, block_ref);
  nif = ast_ast_block_num_if_stmts(arena, block_ref);
  nes = ast_ast_block_num_expr_stmts(arena, block_ref);
  nso = ast_ast_block_num_stmt_order(arena, block_ref);
  fin0 = ast_ast_block_final_expr_ref(arena, block_ref);
  driver_diagnostic_typeck_block_enter(ctx->current_func_index, block_ref, nc, nl, nlp, nfp, nes, fin0);
  if (nso > 0) {
    si = 0;
    while (si < nso && si < 96) {
      pipeline_typeck_block_impl_touch_ctx_block_c(ctx, block_ref);
      sk = ast_ast_block_stmt_order_kind(arena, block_ref, si);
      idx = ast_ast_block_stmt_order_idx(arena, block_ref, si);
      if (sk == 0) {
        if (idx >= 0 && idx < nc && idx < 128) {
          if (typeck_check_block_one_const(module, arena, block_ref, return_type_ref, ctx, idx) != 0) {
            if (getenv("SHUX_DEBUG_PIPE"))
              fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] check_block fail func=%d sk=const idx=%d\n",
                      (int)ctx->current_func_index, (int)idx);
            pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
            return -1;
          }
        }
      } else if (sk == 1) {
        if (idx >= 0 && idx < nl && idx < 128) {
          if (typeck_check_block_one_let(module, arena, block_ref, return_type_ref, ctx, idx) != 0) {
            if (getenv("SHUX_DEBUG_PIPE"))
              fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] check_block fail func=%d sk=let idx=%d\n",
                      (int)ctx->current_func_index, (int)idx);
            pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
            return -1;
          }
        }
      } else if (sk == 2) {
        if (idx >= 0 && idx < nes) {
          es_ref = ast_ast_block_expr_stmt_ref(arena, block_ref, idx);
          if (pipeline_typeck_check_expr_c(module, arena, es_ref, return_type_ref, ctx) != 0) {
            if (getenv("SHUX_DEBUG_PIPE"))
              fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] check_block fail func=%d sk=expr idx=%d es_ref=%d\n",
                      (int)ctx->current_func_index, (int)idx, (int)es_ref);
            pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
            return -1;
          }
        }
      } else if (sk == 3) {
        if (idx >= 0 && idx < nlp) {
          if (typeck_check_block_one_while(module, arena, block_ref, return_type_ref, ctx, idx) != 0) {
            if (getenv("SHUX_DEBUG_PIPE"))
              fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] check_block fail func=%d sk=while idx=%d\n",
                      (int)ctx->current_func_index, (int)idx);
            pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
            return -1;
          }
        }
      } else if (sk == 4) {
        if (idx >= 0 && idx < nfp) {
          if (typeck_check_block_one_for(module, arena, block_ref, return_type_ref, ctx, idx) != 0) {
            if (getenv("SHUX_DEBUG_PIPE"))
              fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] check_block fail func=%d sk=for idx=%d\n",
                      (int)ctx->current_func_index, (int)idx);
            pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
            return -1;
          }
        }
      } else if (sk == 5) {
        if (idx >= 0 && idx < nif) {
          if (pipeline_typeck_check_block_one_if_dbg_c(module, arena, block_ref, return_type_ref, ctx, idx) != 0) {
            if (getenv("SHUX_DEBUG_PIPE"))
              fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] check_block fail func=%d block=%d sk=if idx=%d\n",
                      (int)ctx->current_func_index, (int)block_ref, (int)idx);
            pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
            return -1;
          }
        }
      }
      si = si + 1;
    }
  } else {
    i = 0;
    while (i < nc) {
      if (typeck_check_block_one_const(module, arena, block_ref, return_type_ref, ctx, i) != 0) {
        pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
        return -1;
      }
      i = i + 1;
    }
    i = 0;
    while (i < nl) {
      if (typeck_check_block_one_let(module, arena, block_ref, return_type_ref, ctx, i) != 0) {
        pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
        return -1;
      }
      i = i + 1;
    }
    i = 0;
    while (i < nlp) {
      if (typeck_check_block_one_while(module, arena, block_ref, return_type_ref, ctx, i) != 0) {
        pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
        return -1;
      }
      i = i + 1;
    }
    i = 0;
    while (i < nfp) {
      if (typeck_check_block_one_for(module, arena, block_ref, return_type_ref, ctx, i) != 0) {
        pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
        return -1;
      }
      i = i + 1;
    }
    i = 0;
    while (i < nif) {
      if (pipeline_typeck_check_block_one_if_dbg_c(module, arena, block_ref, return_type_ref, ctx, i) != 0) {
        pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
        return -1;
      }
      i = i + 1;
    }
    i = 0;
    while (i < nes && i < 32) {
      es_ref = ast_ast_block_expr_stmt_ref(arena, block_ref, i);
      if (pipeline_typeck_check_expr_c(module, arena, es_ref, return_type_ref, ctx) != 0) {
        pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
        return -1;
      }
      i = i + 1;
    }
  }
  if (typeck_check_block_final(module, arena, block_ref, return_type_ref, ctx, fin0) != 0) {
    if (getenv("SHUX_DEBUG_PIPE"))
      fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] check_block fail func=%d block=%d sk=final fin0=%d\n",
              (int)ctx->current_func_index, (int)block_ref, (int)fin0);
    pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
    return -1;
  }
  pipeline_typeck_block_impl_restore_ctx_c(ctx, saved_block_ref);
  return 0;
}

/** glue-only 链无 typeck.o 时回退 impl_c。 */
__attribute__((weak)) int32_t check_block_impl(struct ast_Module *module, struct ast_ASTArena *arena, int32_t block_ref,
                                              int32_t return_type_ref, struct ast_PipelineDepCtx *ctx) {
  return pipeline_typeck_check_block_impl_c(module, arena, block_ref, return_type_ref, ctx);
}

extern int32_t typeck_check_block(struct ast_Module *module, struct ast_ASTArena *arena, int32_t block_ref,
                                  int32_t return_type_ref, struct ast_PipelineDepCtx *ctx);

/** typeck.x::check_block 的 C 委托：边界检查后委托 typeck_x.o::typeck_check_block（与嵌套 if/while 同一路径，勿混用 glue monolithic impl）。 */
int32_t pipeline_typeck_check_block_c(struct ast_Module *module, struct ast_ASTArena *arena, int32_t block_ref,
                                      int32_t return_type_ref, struct ast_PipelineDepCtx *ctx) {
  if (ast_ref_is_null(block_ref))
    return 0;
  if (block_ref <= 0 || !arena || block_ref > arena->num_blocks)
    return 0;
  return typeck_check_block(module, arena, block_ref, return_type_ref, ctx);
}

/** typeck.x::check_block_as_loop_body 的 C 委托：loop_depth push/pop + check_block（无 typeck.o 时自包含）。 */
int32_t pipeline_typeck_check_block_as_loop_body_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                   int32_t body_ref, int32_t return_type_ref,
                                                   struct ast_PipelineDepCtx *ctx) {
  int32_t saved_ld;
  int32_t rc;

  if (!ctx)
    return -1;
  saved_ld = pipeline_typeck_loop_depth_push_c(ctx);
  rc = pipeline_typeck_check_block_c(module, arena, body_ref, return_type_ref, ctx);
  pipeline_typeck_loop_depth_pop_c(ctx, saved_ld);
  return rc;
}

extern int32_t check_block(struct ast_Module *module, struct ast_ASTArena *arena, int32_t block_ref,
                           int32_t return_type_ref, struct ast_PipelineDepCtx *ctx);

/**
 * typeck.x::typeck_x_ast_check_one_func 的 C 委托：有 typeck.o 时由 X 强符号覆盖；否则 glue 调 pipeline_typeck_check_block_c。
 */
int32_t pipeline_typeck_x_ast_check_one_func_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                                struct ast_PipelineDepCtx *ctx, int32_t func_idx) {
  int32_t body_ref;
  int32_t ret_ty_ref;
  uint8_t fn_name_buf[64];
  int32_t fn_name_len;

  if (!module || !arena || !ctx)
    return 0;
  pipeline_typeck_linear_reset_c();
  if (pipeline_module_func_num_generic_params_at(module, func_idx) > 0)
    return 0;
  body_ref = pipeline_module_func_body_ref_at(module, func_idx);
  if (ast_ref_is_null(body_ref) || pipeline_module_func_is_extern_at(module, func_idx) != 0)
    return 0;
  ret_ty_ref = pipeline_module_func_return_type_at(module, func_idx);
  if (pipeline_typeck_check_block_c(module, arena, body_ref, ret_ty_ref, ctx) != 0) {
    fn_name_len = pipeline_module_func_name_len_at(module, func_idx);
    pipeline_asm_module_func_name_copy64(module, func_idx, fn_name_buf);
    driver_diagnostic_typeck_func_fail(func_idx, fn_name_buf, fn_name_len, -5);
    return -5;
  }
  if (!ast_ref_is_null(ret_ty_ref)) {
    int32_t rt_kind = pipeline_type_kind_ord_at(arena, ret_ty_ref);
    if (rt_kind != (int32_t)ast_TypeKind_TYPE_VOID &&
        pipeline_typeck_func_body_has_implicit_return_tail_c(arena, body_ref) != 0) {
      fn_name_len = pipeline_module_func_name_len_at(module, func_idx);
      pipeline_asm_module_func_name_copy64(module, func_idx, fn_name_buf);
      driver_diagnostic_typeck_func_fail(func_idx, fn_name_buf, fn_name_len, -6);
      return -6;
    }
  }
  return 0;
}

/**
 * typeck.x::typeck_x_ast_impl 的 C 委托：遍历有体函数（无 typeck.o 时 glue while 自包含）。
 */
int32_t pipeline_typeck_x_ast_impl_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                      struct ast_PipelineDepCtx *ctx) {
  int32_t mi;
  int32_t ret_kind;
  int32_t i;

  if (!module || !arena || !ctx)
    return -2;
  mi = pipeline_module_main_func_index(module);
  if (pipeline_module_func_is_extern_at(module, mi) != 0 &&
      ast_ref_is_null(pipeline_module_func_body_ref_at(module, mi)))
    return -1;
  if (ast_ref_is_null(pipeline_module_func_body_ref_at(module, mi)) &&
      ast_ref_is_null(pipeline_module_func_body_expr_ref_at(module, mi)))
    return -2;
  if (ast_ref_is_null(pipeline_module_func_return_type_at(module, mi)))
    return -3;
  ret_kind = pipeline_type_kind_ord_at(arena, pipeline_module_func_return_type_at(module, mi));
  if (ret_kind != (int32_t)ast_TypeKind_TYPE_I32 && ret_kind != (int32_t)ast_TypeKind_TYPE_I64)
    return -4;
  if (pipeline_typeck_validate_struct_layouts_zero_padding_c(module, arena) != 0)
    return -7;
  pipeline_typeck_patch_all_body_parent_links_c(module, arena);
  pipeline_typeck_set_entry_module_for_dep_map_c(module);
  i = 0;
  while (i < module->num_funcs) {
    int32_t body_ref;
    int32_t ret_ty_ref;
    uint8_t fn_name_buf[64];
    int32_t fn_name_len;
    int32_t num_generic_params;

    pipeline_dep_ctx_set_current_func_index(ctx, i);
    pipeline_typeck_linear_reset_c();
    num_generic_params = pipeline_module_func_num_generic_params_at(module, i);
    if (num_generic_params > 0) {
      pipeline_dep_ctx_set_current_func_index(ctx, -1);
      i = i + 1;
      continue;
    }
    body_ref = pipeline_module_func_body_ref_at(module, i);
    if (!ast_ref_is_null(body_ref) && pipeline_module_func_is_extern_at(module, i) == 0) {
      ret_ty_ref = pipeline_module_func_return_type_at(module, i);
      if (pipeline_typeck_check_block_c(module, arena, body_ref, ret_ty_ref, ctx) != 0) {
        fn_name_len = pipeline_module_func_name_len_at(module, i);
        pipeline_asm_module_func_name_copy64(module, i, fn_name_buf);
        if (getenv("SHUX_DEBUG_PIPE")) {
          fn_name_buf[fn_name_len > 0 && fn_name_len < 64 ? fn_name_len : 0] = '\0';
          fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] library typeck fail i=%d name=%s\n", (int)i,
                  fn_name_len > 0 ? (char *)fn_name_buf : "?");
          fflush(stderr);
        }
        driver_diagnostic_typeck_func_fail(i, fn_name_buf, fn_name_len, -5);
        pipeline_dep_ctx_set_current_func_index(ctx, -1);
        return -5;
      }
      if (!ast_ref_is_null(ret_ty_ref)) {
        int32_t rt_kind;

        rt_kind = pipeline_type_kind_ord_at(arena, ret_ty_ref);
        if (rt_kind != (int32_t)ast_TypeKind_TYPE_VOID &&
            pipeline_typeck_func_body_has_implicit_return_tail_c(arena, body_ref) != 0) {
          fn_name_len = pipeline_module_func_name_len_at(module, i);
          pipeline_asm_module_func_name_copy64(module, i, fn_name_buf);
          driver_diagnostic_typeck_func_fail(i, fn_name_buf, fn_name_len, -6);
          pipeline_dep_ctx_set_current_func_index(ctx, -1);
          return -6;
        }
      }
    }
    pipeline_dep_ctx_set_current_func_index(ctx, -1);
    i = i + 1;
  }
  return 0;
}

/** typeck.x::typeck_x_ast_library 的 C 委托：库模块无 main（无 typeck.o 时 glue while 自包含）。 */
int32_t pipeline_typeck_x_ast_library_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                         struct ast_PipelineDepCtx *ctx) {
  int32_t i;

  if (!module || !arena || !ctx) {
    if (getenv("SHUX_DEBUG_PIPE"))
      fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] typeck_x_ast_library_c null arg m=%p a=%p ctx=%p\n", (void *)module,
              (void *)arena, (void *)ctx);
    return -5;
  }
  if (getenv("SHUX_DEBUG_PIPE"))
    fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] enter library_c module->num_funcs=%d pipeline_num=%d\n",
            (int)module->num_funcs, (int)pipeline_module_num_funcs(module));
  if (pipeline_typeck_validate_struct_layouts_zero_padding_c(module, arena) != 0)
    return -7;
  pipeline_typeck_patch_all_body_parent_links_c(module, arena);
  pipeline_typeck_set_entry_module_for_dep_map_c(module);
  i = 0;
  while (i < module->num_funcs) {
    int32_t body_ref;
    int32_t ret_ty_ref;
    uint8_t fn_name_buf[64];
    int32_t fn_name_len;
    int32_t num_generic_params;

    pipeline_dep_ctx_set_current_func_index(ctx, i);
    pipeline_typeck_linear_reset_c();
    num_generic_params = pipeline_module_func_num_generic_params_at(module, i);
    if (num_generic_params > 0) {
      pipeline_dep_ctx_set_current_func_index(ctx, -1);
      i = i + 1;
      continue;
    }
    body_ref = pipeline_module_func_body_ref_at(module, i);
    if (!ast_ref_is_null(body_ref) && pipeline_module_func_is_extern_at(module, i) == 0) {
      ret_ty_ref = pipeline_module_func_return_type_at(module, i);
      if (pipeline_typeck_check_block_c(module, arena, body_ref, ret_ty_ref, ctx) != 0) {
        fn_name_len = pipeline_module_func_name_len_at(module, i);
        pipeline_asm_module_func_name_copy64(module, i, fn_name_buf);
        if (getenv("SHUX_DEBUG_PIPE")) {
          fn_name_buf[fn_name_len > 0 && fn_name_len < 64 ? fn_name_len : 0] = '\0';
          fprintf(stderr, "shux: [SHUX_DEBUG_PIPE] library typeck fail i=%d name=%s\n", (int)i,
                  fn_name_len > 0 ? (char *)fn_name_buf : "?");
          fflush(stderr);
        }
        driver_diagnostic_typeck_func_fail(i, fn_name_buf, fn_name_len, -5);
        pipeline_dep_ctx_set_current_func_index(ctx, -1);
        return -5;
      }
      if (!ast_ref_is_null(ret_ty_ref)) {
        int32_t rt_kind;

        rt_kind = pipeline_type_kind_ord_at(arena, ret_ty_ref);
        if (rt_kind != (int32_t)ast_TypeKind_TYPE_VOID &&
            pipeline_typeck_func_body_has_implicit_return_tail_c(arena, body_ref) != 0) {
          fn_name_len = pipeline_module_func_name_len_at(module, i);
          pipeline_asm_module_func_name_copy64(module, i, fn_name_buf);
          driver_diagnostic_typeck_func_fail(i, fn_name_buf, fn_name_len, -6);
          pipeline_dep_ctx_set_current_func_index(ctx, -1);
          return -6;
        }
      }
    }
    pipeline_dep_ctx_set_current_func_index(ctx, -1);
    i = i + 1;
  }
  return 0;
}

/**
 * dep prerun 专用 typeck：仅 struct padding 校验 + parent link 补丁，不遍历函数体。
 * 避免 codegen.x 等大库模块在 dep prerun 阶段全量 check_block 失败（entry 阶段再完整 typeck）。
 */
int32_t pipeline_typeck_dep_prerun_module_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                            struct ast_PipelineDepCtx *ctx) {
  if (!module || !arena || !ctx)
    return -5;
  if (pipeline_typeck_validate_struct_layouts_zero_padding_c(module, arena) != 0)
    return -7;
  pipeline_typeck_patch_all_body_parent_links_c(module, arena);
  return 0;
}

/** typeck.x::typeck_x_ast 的 C 委托：校验 main 下标后委托 impl_c。 */
int32_t pipeline_typeck_x_ast_c(struct ast_Module *module, struct ast_ASTArena *arena,
                                 struct ast_PipelineDepCtx *ctx) {
  int32_t mi;

  if (!module)
    return -10;
  mi = pipeline_module_main_func_index(module);
  if (mi < 0)
    return -10;
  if (mi >= module->num_funcs)
    return -11;
  return pipeline_typeck_x_ast_impl_c(module, arena, ctx);
}

