/**
 * typeck.x / asm glue 统一入口：委托 C metrics，勿再调 gen2 自举 X typeck_struct_layout_metrics。
 */
int32_t typeck_typeck_struct_layout_metrics(struct ast_Module *module, struct ast_ASTArena *arena, int32_t li,
                                            int32_t depth, int32_t check_pad, int32_t *out_sz, int32_t *out_al) {
  return glue_struct_layout_metrics_c(module, arena, li, depth, check_pad, out_sz, out_al);
}

int32_t typeck_validate_struct_layouts_zero_padding_glue(struct ast_Module *module, struct ast_ASTArena *arena) {
  int32_t li;
  int32_t nsl;
  if (!module || !arena)
    return -1;
  nsl = pipeline_module_num_struct_layouts_at(module);
  for (li = 0; li < nsl; li++) {
    int32_t dz = 0;
    int32_t da = 1;
    if (typeck_typeck_struct_layout_metrics(module, arena, li, 0, 1, &dz, &da) != 0)
      return -1;
  }
  return 0;
}

/** TYPE_NAMED 且命中 struct_layout 时算 size；C 栈 out 参数，.x check_block 勿 &local。 */
int32_t typeck_x_type_size_from_layout_glue(struct ast_Module *module, struct ast_ASTArena *arena, int32_t li,
    int32_t depth) {
  int32_t z2 = 0;
  int32_t al2 = 1;
  if (li < 0)
    return 0;
  if (typeck_typeck_struct_layout_metrics(module, arena, li, depth, 0, &z2, &al2) != 0)
    return 0;
  return z2;
}

/** TYPE_NAMED 且命中 struct_layout 时算 align；与 typeck.x typeck_x_type_align ko==8 分支一致。 */
int32_t typeck_x_type_align_from_layout_glue(struct ast_Module *module, struct ast_ASTArena *arena, int32_t li,
    int32_t depth) {
  int32_t z2 = 0;
  int32_t al2 = 1;
  if (li < 0)
    return 1;
  if (typeck_typeck_struct_layout_metrics(module, arena, li, depth, 0, &z2, &al2) != 0)
    return 1;
  return al2 > 0 ? al2 : 1;
}
